const LS_KEY='MyCosmos_users'; // localStorage fallback when IndexedDB unavailable (file://); legacy ProgressTracker_users merged on first run
(function migrateLegacyLocalStorageKeys(){
  try{
    const legacy='ProgressTracker_users';
    const old=localStorage.getItem(legacy);
    if(!old)return;
    const cur=localStorage.getItem(LS_KEY);
    if(cur){
      try{
        const a=JSON.parse(cur);
        const b=JSON.parse(old);
        localStorage.setItem(LS_KEY,JSON.stringify(Object.assign({},b,a)));
      }catch(e1){
        localStorage.setItem(LS_KEY,old);
      }
    }else{
      localStorage.setItem(LS_KEY,old);
    }
    localStorage.removeItem(legacy);
  }catch(e2){}
})();

function openMyCosmosDb(){
  return new Promise((resolve,reject)=>{
    const request=indexedDB.open('MyCosmosDB',1);
    request.onerror=()=>reject(request.error);
    request.onsuccess=()=>resolve(request.result);
    request.onupgradeneeded=(e)=>{
      const database=e.target.result;
      if(!database.objectStoreNames.contains('users')){
        database.createObjectStore('users',{keyPath:'username'});
      }
    };
  });
}
function countUsersInDb(database){
  return new Promise(resolve=>{
    try{
      if(!database.objectStoreNames.contains('users')){resolve(0);return;}
      const tx=database.transaction('users','readonly');
      const rq=tx.objectStore('users').getAllKeys();
      rq.onsuccess=()=>{
        const keys=(rq.result||[]).filter(k=>String(k)!=='__directoryHandle__');
        resolve(keys.length);
      };
      rq.onerror=()=>resolve(0);
    }catch(e){resolve(0);}
  });
}
function migrateProgressTrackerDbToMyCosmos(){
  return new Promise(resolve=>{
    if(!('indexedDB' in window)){resolve(false);return;}
    const oldReq=indexedDB.open('ProgressTrackerDB');
    oldReq.onerror=()=>resolve(false);
    oldReq.onsuccess=()=>{
      const oldDb=oldReq.result;
      if(!oldDb.objectStoreNames.contains('users')){
        oldDb.close();
        resolve(false);
        return;
      }
      const txo=oldDb.transaction('users','readonly');
      const getAll=txo.objectStore('users').getAll();
      getAll.onsuccess=()=>{
        const rows=getAll.result||[];
        oldDb.close();
        if(rows.length===0){
          try{indexedDB.deleteDatabase('ProgressTrackerDB');}catch(e3){}
          resolve(false);
          return;
        }
        const newReq=indexedDB.open('MyCosmosDB',1);
        newReq.onupgradeneeded=(e)=>{
          const d=e.target.result;
          if(!d.objectStoreNames.contains('users'))
            d.createObjectStore('users',{keyPath:'username'});
        };
        newReq.onsuccess=()=>{
          const newDb=newReq.result;
          const txw=newDb.transaction('users','readwrite');
          const store=txw.objectStore('users');
          rows.forEach(row=>store.put(row));
          txw.oncomplete=()=>{
            newDb.close();
            try{indexedDB.deleteDatabase('ProgressTrackerDB');}catch(e4){}
            resolve(true);
          };
          txw.onerror=()=>{newDb.close();resolve(false);};
        };
        newReq.onerror=()=>resolve(false);
      };
      getAll.onerror=()=>{oldDb.close();resolve(false);};
    };
  });
}

// Initialize IndexedDB (MyCosmosDB; one-time copy from legacy ProgressTrackerDB)
async function initDB(){
  if(!('indexedDB' in window))return null;
  let database=null;
  try{
    database=await openMyCosmosDb();
  }catch(e5){
    database=null;
  }
  if(database){
    const n=await countUsersInDb(database);
    if(n>0){
      db=database;
      return db;
    }
    database.close();
  }
  await migrateProgressTrackerDbToMyCosmos();
  try{
    db=await openMyCosmosDb();
  }catch(e6){
    db=null;
  }
  return db;
}

/** Graph may be top-level `{nodes,edges}` or nested `{ data: { nodes, edges } }` (preload / export). */
function graphRootDoc(d){
  if(!d||typeof d!=='object')return d;
  const inner=d.data;
  if(inner&&typeof inner==='object'&&(Array.isArray(inner.nodes)||Array.isArray(inner.edges)||inner.nodes&&typeof inner.nodes==='object'||inner.edges&&typeof inner.edges==='object'))
    return inner;
  return d;
}
/** Node/edge count whether stored as array or id→object map */
function graphNodeCount(d){
  const r=graphRootDoc(d);
  if(!r)return 0;
  const n=r.nodes;
  if(Array.isArray(n))return n.length;
  if(n&&typeof n==='object')return Object.keys(n).length;
  return 0;
}
function graphEdgeCount(d){
  const r=graphRootDoc(d);
  if(!r)return 0;
  const e=r.edges;
  if(Array.isArray(e))return e.length;
  if(e&&typeof e==='object')return Object.keys(e).length;
  return 0;
}
/**
 * Return a plain portable graph `{nodes[],edges[],...}` for storage / `G`
 * (collapses `.data` wrapper, coerces nodes/edges to arrays).
 */
function normalizeUserGraphState(d){
  if(!d||typeof d!=='object')return null;
  try{
    const root=graphRootDoc(d);
    const out=JSON.parse(JSON.stringify(root));
    if(!Array.isArray(out.nodes)){
      const n=out.nodes;
      out.nodes=n&&typeof n==='object'&&!Array.isArray(n)?Object.values(n):[];
    }
    if(!Array.isArray(out.edges)){
      const e=out.edges;
      out.edges=e&&typeof e==='object'&&!Array.isArray(e)?Object.values(e):[];
    }
    return out;
  }catch(err){
    console.warn('normalizeUserGraphState failed',err);
    return null;
  }
}
/** Use after ST.load / fetch so login and counts see real nodes inside `.data`. */
function finalizeLoadedUserGraph(raw){
  if(!raw)return null;
  return normalizeUserGraphState(raw)||raw;
}

/** True when the app is served from this project's Node server (data/ on disk, one file per user). */
function isLocalDiskServerApp(){
  try{
    if(typeof location==='undefined'||location.protocol!=='http:')return false;
    const h=location.hostname;
    if(h!=='localhost'&&h!=='127.0.0.1')return false;
    return String(location.port||'')==='3000';
  }catch(e){return false;}
}

function indexedDbKeyToUserStem(k){
  const s=String(k);
  const i=s.indexOf('_sp_');
  if(i>0)return s.slice(0,i);
  return s;
}

/** When server JSON is the portable source of truth: never let a newer empty IndexedDB win over a full graph on disk. */
function pickLocalVersusServer(local,server){
  const sn=graphNodeCount(server),sE=graphEdgeCount(server);
  const serverHas=sn>0||sE>0;
  if(!server||typeof server!=='object')return local;
  if(!serverHas)return local;
  if(local==null||local===undefined)return server;
  const ln=graphNodeCount(local),lE=graphEdgeCount(local);
  const localEmpty=ln===0&&lE===0;
  if(localEmpty&&serverHas)return server;
  const st=server.lastSaved?new Date(server.lastSaved).getTime():0;
  const lt=local.lastSaved?new Date(local.lastSaved).getTime():0;
  if(lt>0&&st>0){
    if(lt>st+2000)return local;
    if(st>lt+2000)return server;
  }
  if(sn>ln||(sn===ln&&sE>lE))return server;
  if(sn<ln||(sn===ln&&sE<lE))return local;
  return st>lt?server:local;
}

function apiLoginUsernameVariants(u){
  if(!u)return[];
  const s=String(u);
  const out=[];
  const add=x=>{if(x&&out.indexOf(x)<0)out.push(x)};
  add(s);
  if(!s.endsWith('_data'))add(s+'_data');
  else{const b=s.replace(/_data$/,'');if(b)add(b);}
  return out;
}

/** Same rules as server `sanitize` + `storageBaseKey` — one logical account for `name` vs `name_data`. */
function sanitizeForStorageKey(name){
  return String(name||'').replace(/[^a-zA-Z0-9_\-]/g,'').toLowerCase().slice(0,50);
}
function canonicalUserStorageKey(u){
  const s=sanitizeForStorageKey(u);
  return (s.replace(/_data$/,'')||s);
}

/** `data/template-user_data.json` — default UI shell only; never a real login account. */
const TEMPLATE_USER_STORAGE_KEY='template-user';
function isTemplateUserStorageKey(u){
  return canonicalUserStorageKey(u||'')===TEMPLATE_USER_STORAGE_KEY;
}

/**
 * Defaults for new accounts (workspaces tabs, expandPages, theme, etc.). No task graph.
 * Served as static `data/template-user_data.json` or from the local app server.
 */
async function loadNewUserShell(){
  const minimal=()=>({nodes:[],edges:[],displayName:'',autoSave:true,tutorialNotes:true,workspaces:[{id:'home',name:'Home',icon:'🏠'}],cws:'home',nodeOrder:{},todayGoals:{},expandPages:[],expandHubDev2026Seeded:false,notesCatalogHidden:[],notesCatalogHideCompletedNotes:true,todoList:[],todoPool:[],todoActiveTab:'today',todoHideCompleted:false,todoDaysCompleted:null});
  const urls=['data/template-user_data.json'];
  if(window.location.protocol==='file:')urls.push('http://localhost:3000/data/template-user_data.json');
  for(const url of urls){
    try{
      const r=await fetch(url);
      if(!r.ok)continue;
      const t=await r.json();
      if(!t||typeof t!=='object')continue;
      const o=JSON.parse(JSON.stringify(t));
      delete o._comment;
      o.nodes=[];
      o.edges=[];
      o.todayGoals={};
      o.todoList=[];
      o.todoPool=[];
      o.notesCatalogHidden=[];
      o.nodeOrder={};
      delete o.lastSaved;
      delete o.spTime;
      delete o.todoLastDateKey;
      if(!Array.isArray(o.workspaces)||!o.workspaces.length)o.workspaces=[{id:'home',name:'Home',icon:'🏠'}];
      if(!o.cws)o.cws='home';
      if(!Array.isArray(o.expandPages))o.expandPages=[];
      if(!('notesCatalogHideCompletedNotes' in o))o.notesCatalogHideCompletedNotes=true;
      if(!('todoHideCompleted' in o))o.todoHideCompleted=false;
      if(!('todoDaysCompleted' in o))o.todoDaysCompleted=null;
      o.autoSave=o.autoSave!==false;
      return o;
    }catch(e){}
  }
  const m=minimal();
  m.theme='galaxy';
  m.backgroundColor='#0a0e27';
  m.backgroundSound=false;
  m.shortcuts={'double-space':'Space'};
  m.expandPages=['progress','pathbehind','pagetree','pageagents','pageinterstellar'];
  m.expandHubDev2026Seeded=true;
  return m;
}

/**
 * Load user JSON: on file:// tries data/<key>_data.json and data/<key>.json first (same folder as index.html),
 * then optional local dev server. On http(s) uses /api/data/ only.
 */
async function fetchJsonUserFromApi(usernameKey,serverFallback){
  if(window.location.protocol==='file:'){
    for(const rel of [`data/${usernameKey}_data.json`,`data/${usernameKey}.json`]){
      try{
        const r=await fetch(rel);
        if(r.ok)return await r.json();
      }catch(e){}
    }
    if(serverFallback){
      try{
        const r=await fetch(`${serverFallback}/api/data/${encodeURIComponent(usernameKey)}`);
        if(r.ok)return await r.json();
      }catch(e){}
    }
    return null;
  }
  const base=serverFallback!==undefined&&serverFallback!==null?serverFallback:'';
  try{
    const r=await fetch(`${base}/api/data/${encodeURIComponent(usernameKey)}`);
    if(r.ok)return await r.json();
  }catch(e){}
  return null;
}

/**
 * Checkpoint files look like: username_sp_2026-03-19T12-00-00-000Z.json (or _sp_<millis>).
 * Not the main portable file (*_data.json) and not arbitrary names containing "_sp_" by accident.
 */
function looksLikeSavepointExportFilename(name){
  if(!name||!/\.json$/i.test(name))return false;
  return !!name.match(/_sp_(?:\d{4}-\d{2}-\d{2}|\d{10,})/i);
}
function cloneForPersist(data){
  try{
    if(typeof structuredClone==='function')return structuredClone(data);
  }catch(e){}
  return JSON.parse(JSON.stringify(data||{}));
}
function isQuotaLikeError(err){
  const n=String(err?.name||'').toLowerCase();
  const m=String(err?.message||'').toLowerCase();
  return n.includes('quota')||m.includes('quota')||m.includes('disk is full')||m.includes('database or disk is full');
}

const ST={
  k(u){return'pn_'+u},
  // Save to localStorage (fallback when IndexedDB fails, e.g. file://)
  saveToLocalStorage(u,d){
    try{
      const all=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
      all[u]={data:d,lastSaved:d.lastSaved||new Date().toISOString()};
      localStorage.setItem(LS_KEY,JSON.stringify(all));
      return true;
    }catch(e){console.error('localStorage save error:',e);return false;}
  },
  loadFromLocalStorage(u){
    try{
      const all=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
      const r=all[u];
      return r?r.data:null;
    }catch(e){return null;}
  },
  usersFromLocalStorage(){
    try{
      const all=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
      const byCanon=new Map();
      Object.entries(all).filter(([k])=>!k.includes('_sp_')).forEach(([raw,r])=>{
        const c=canonicalUserStorageKey(raw);
        if(isTemplateUserStorageKey(c))return;
        const nc=graphNodeCount(r.data);
        const t=r.data?.lastSaved?new Date(r.data.lastSaved).getTime():0;
        const ex=byCanon.get(c);
        if(!ex||nc>ex.c||(nc===ex.c&&t>ex.t))
          byCanon.set(c,{u:c,n:r.data?.displayName||c,c:nc,t});
      });
      return [...byCanon.values()].map(x=>({u:x.u,n:x.n,c:x.c}));
    }catch(e){return [];}
  },
  /** Remove IndexedDB / localStorage copies of users that have no JSON file in data/ (local server mode). */
  async _purgeCachesNotOnDisk(keepCanonicalSet){
    const keep=keepCanonicalSet instanceof Set?keepCanonicalSet:new Set(keepCanonicalSet||[]);
    if(keep.size===0)return;
    if(db){
      try{
        await new Promise(resolve=>{
          const tx=db.transaction(['users'],'readwrite');
          const store=tx.objectStore('users');
          const rq=store.getAllKeys();
          rq.onsuccess=()=>{
            (rq.result||[]).forEach(k=>{
              const s=String(k);
              if(s==='__directoryHandle__')return;
              const base=canonicalUserStorageKey(indexedDbKeyToUserStem(s));
              if(!keep.has(base))store.delete(k);
            });
            resolve();
          };
          rq.onerror=()=>resolve();
        });
      }catch(e){}
    }
    try{
      const all=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
      let changed=false;
      Object.keys(all).forEach(k=>{
        if(k.includes('_sp_'))return;
        if(!keep.has(canonicalUserStorageKey(k))){delete all[k];changed=true;}
      });
      if(changed)localStorage.setItem(LS_KEY,JSON.stringify(all));
    }catch(e){}
  },
  // Fix "0 nodes" on login cards when IndexedDB is empty but preload, API, or data/*.json has a real graph
  async mergeLoginUserCounts(userList){
    if(!userList||!userList.length)return userList;
    userList=userList.filter(u=>u&&!isTemplateUserStorageKey(u.u));
    if(!userList.length)return[];
    const pre=window.__PRELOAD_USER_DATA__;
    const preN=graphNodeCount(pre?.data);
    const bump=(u,c)=>u.c===0&&c>0&&canonicalUserStorageKey(pre?.username||'')===u.u;
    let out=userList.map(u=>(preN>0&&bump(u,preN)?{u:u.u,n:u.n,c:preN}:u));
    const serverFb=window.location.protocol==='file:'?'http://localhost:3000':'';
    for(let i=0;i<out.length;i++){
      if(out[i].c!==0)continue;
      let best=0;
      for(const v of apiLoginUsernameVariants(out[i].u)){
        const d=await fetchJsonUserFromApi(v,serverFb);
        const nc=graphNodeCount(d);
        if(nc>best)best=nc;
      }
      if(best>0)out[i]={...out[i],c:best};
    }
    return out;
  },
  _lastSaveError:'',
  _saveChain:Promise.resolve(),
  async _putIndexedDbRecord(u,d){
    await new Promise((resolve,reject)=>{
      const tx=db.transaction(['users'],'readwrite');
      tx.oncomplete=()=>resolve();
      tx.onerror=()=>reject(tx.error||new Error('IndexedDB transaction error'));
      tx.onabort=()=>reject(tx.error||new Error('IndexedDB transaction aborted'));
      const req=tx.objectStore('users').put({username:u,data:d,lastSaved:d.lastSaved||new Date().toISOString()});
      req.onerror=()=>reject(req.error);
    });
  },
  async _pruneIndexedDbSavepointsForUser(u,keepNewest){
    if(!db||!u)return 0;
    const keep=Math.max(0,keepNewest==null?8:keepNewest);
    const key=canonicalUserStorageKey(u);
    const prefix=key+'_sp_';
    return await new Promise(resolve=>{
      try{
        const tx=db.transaction(['users'],'readwrite');
        const store=tx.objectStore('users');
        const rq=store.getAllKeys();
        rq.onsuccess=()=>{
          const keys=(rq.result||[]).map(k=>String(k)).filter(k=>k.startsWith(prefix)).sort();
          if(keys.length<=keep){resolve(0);return;}
          const doomed=keys.slice(0,keys.length-keep);
          doomed.forEach(k=>store.delete(k));
          tx.oncomplete=()=>resolve(doomed.length);
          tx.onerror=()=>resolve(0);
          tx.onabort=()=>resolve(0);
        };
        rq.onerror=()=>resolve(0);
      }catch(e){resolve(0);}
    });
  },
  // Save to IndexedDB (primary storage - works in Safari and Chrome)
  async saveToIndexedDB(u,d){
    this._lastSaveError='';
    if(!db){
      this._lastSaveError='IndexedDB not available (private mode, blocked storage, or init failed)';
      return false;
    }
    try{
      await this._putIndexedDbRecord(u,d);
      return true;
    }catch(e){
      if(isQuotaLikeError(e)&&!String(u).includes('_sp_')){
        try{
          const removed=await this._pruneIndexedDbSavepointsForUser(u,0);
          if(removed>0){
            try{await this._putIndexedDbRecord(u,d);
            console.warn(`IndexedDB quota reached; pruned ${removed} savepoint(s) and retried save.`);
            return true;}catch(e3){}
          }
        }catch(e2){
          console.warn('IndexedDB retry after prune failed:',e2);
        }
      }
      console.error('IndexedDB save error:',e);
      this._lastSaveError=e?.message||String(e);
      return false;
    }
  },
  // Load from IndexedDB (primary storage)
  async loadFromIndexedDB(u){
    if(!db)return null;
    try{
      const tx=db.transaction(['users'],'readonly');
      const store=tx.objectStore('users');
      const request=store.get(u);
      return new Promise((resolve)=>{
        request.onsuccess=()=>{
          const result=request.result;
          resolve(result?result.data:null);
        };
        request.onerror=()=>resolve(null);
      });
    }catch(e){
      return null;
    }
  },
  // Export user data to JSON file (for saving to data/ folder)
  exportToFile(u,d){
    const blob=new Blob([JSON.stringify(d,null,2)],{type:'application/json'});
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a');
    a.href=url;
    a.download=`${u}_data.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  },
  // Import user data from JSON file (for loading from data/ folder)
  async importFromFile(file){
    return new Promise((resolve,reject)=>{
      const reader=new FileReader();
      reader.onload=(e)=>{
        try{
          let text=e.target.result;
          if(typeof text==='string'&&text.charCodeAt(0)===0xFEFF)text=text.slice(1);
          const data=JSON.parse(text);
          if(data&&(data.nodes||data.edges))walkAndFixMojibake(data);
          else if(data&&data.data&&(data.data.nodes||data.data.edges))walkAndFixMojibake(data.data);
          resolve(data);
        }catch(err){
          reject(new Error('Invalid JSON file'));
        }
      };
      reader.onerror=()=>reject(new Error('Failed to read file'));
      reader.readAsText(file,'UTF-8');
    });
  },
  /** Restore persisted data/ folder handle, or prompt once and store it in IndexedDB (Chrome/Edge). */
  async acquireWritableDataDirectoryInteractive(){
    if(directoryHandle)return true;
    if(await this._restoreDirectoryHandle())return true;
    if(!('showDirectoryPicker' in window))return false;
    try{
      directoryHandle=await window.showDirectoryPicker({id:'my-cosmos-data',mode:'readwrite',startIn:'documents'});
      await this._persistDirectoryHandle(directoryHandle);
      return true;
    }catch(e){
      if(e.name!=='AbortError')console.error('Directory picker error:',e);
      return false;
    }
  },
  async initDirectory(){
    return this.acquireWritableDataDirectoryInteractive();
  },
  /** Non-interactive: only reuse a handle already granted (IndexedDB restore). */
  async ensureDirectory(){
    if(directoryHandle)return true;
    return await this._restoreDirectoryHandle();
  },
  async saveToFile(u,d){
    if(!directoryHandle){
      console.warn('No directory handle - cannot save to file');
      return false;
    }
    try{
      const fileName=`${u}_data.json`;
      const fileHandle=await directoryHandle.getFileHandle(fileName,{create:true});
      const writable=await fileHandle.createWritable();
      const jsonData=JSON.stringify(d,null,2);
      await writable.write(jsonData);
      await writable.close();
      console.log(`File saved: ${fileName} (${jsonData.length} bytes)`);
      return true;
    }catch(e){
      console.error('File save error:',e);
      console.error('Error details:',{
        name:e.name,
        message:e.message,
        stack:e.stack
      });
      return false;
    }
  },
  async loadFromFile(u){
    if(!directoryHandle)return null;
    try{
      const fileName=`${u}_data.json`;
      const fileHandle=await directoryHandle.getFileHandle(fileName);
      const file=await fileHandle.getFile();
      const text=await file.text();
      return JSON.parse(text);
    }catch(e){
      if(e.name!=='NotFoundError')console.error('File load error:',e);
      return null;
    }
  },
  async listFiles(){
    if(!directoryHandle)return [];
    const files=[];
    try{
      for await(const entry of directoryHandle.values()){
        if(entry.kind==='file'&&entry.name.endsWith('_data.json')){
          const user=entry.name.replace('_data.json','');
          files.push({u:user,n:user,c:0});
        }
      }
    }catch(e){
      console.error('List files error:',e);
    }
    return files;
  },
  _fileMirrorTimer:null,
  // Debounced write to a linked folder (File System Access API) so `username_data.json` on disk stays the portable copy
  queueMirrorToFolder(u){
    if(!directoryHandle||!u)return;
    clearTimeout(this._fileMirrorTimer);
    this._fileMirrorTimer=setTimeout(async ()=>{
      this._fileMirrorTimer=null;
      if(u!==CU)return;
      try{
        await this.saveToFile(u,G);
      }catch(e){
        console.warn('Linked folder backup failed:',e);
      }
    },2500);
  },
  _lastSaveOk:false,
  async _writeFileBoot(snapshot,key){
    if(!directoryHandle)return;
    try{
      const payload=JSON.stringify({username:key,data:snapshot});
      const js='window.__PRELOAD_USER_DATA__='+payload+';\n';
      const fh=await directoryHandle.getFileHandle('file_boot.js',{create:true});
      const w=await fh.createWritable();
      await w.write(js);
      await w.close();
    }catch(e){console.warn('file_boot.js write failed:',e);}
  },
  async _restoreDirectoryHandle(){
    if(directoryHandle)return true;
    if(!db)return false;
    try{
      const tx=db.transaction(['users'],'readonly');
      const rq=tx.objectStore('users').get('__directoryHandle__');
      const record=await new Promise(r=>{rq.onsuccess=()=>r(rq.result);rq.onerror=()=>r(null);});
      if(!record||!record.data)return false;
      const handle=record.data;
      if(typeof handle.queryPermission!=='function')return false;
      let perm=await handle.queryPermission({mode:'readwrite'});
      if(perm==='granted'){directoryHandle=handle;return true;}
      try{perm=await handle.requestPermission({mode:'readwrite'});}catch(e){}
      if(perm==='granted'){directoryHandle=handle;return true;}
      return false;
    }catch(e){return false;}
  },
  async _persistDirectoryHandle(handle){
    if(!db||!handle)return;
    try{
      const tx=db.transaction(['users'],'readwrite');
      tx.objectStore('users').put({username:'__directoryHandle__',data:handle,lastSaved:new Date().toISOString()});
    }catch(e){}
  },
  async save(u,d,opts){
    if(!u)return;
    const key=canonicalUserStorageKey(u);
    if(key===CU&&d===G&&!(opts&&opts.skipDomFlush)){
      try{if(typeof flushDomToGraphBeforePersist==='function')flushDomToGraphBeforePersist();}catch(e){console.warn('flushDomToGraphBeforePersist',e);}
    }
    const ts=new Date().toISOString();
    d.lastSaved=ts;
    const snapshot=cloneForPersist(d);
    snapshot.lastSaved=ts;

    this._saveChain=(this._saveChain||Promise.resolve()).catch(()=>{}).then(async()=>{
      let anyOk=false;
      const idbOk=await this.saveToIndexedDB(key,snapshot);
      if(idbOk)anyOk=true;
      if(!idbOk)this.saveToLocalStorage(key,snapshot);

      let serverOk=false;
      try{
        const apiBase=window.location.protocol==='file:'?'http://localhost:3000':'';
        const bodyStr=JSON.stringify(snapshot);
        let byteLen=bodyStr.length;
        try{byteLen=new TextEncoder().encode(bodyStr).length;}catch(_){}
        if(window.__PUBLIC_MODE__&&window.__MC_TIER__==='ephemeral'){
          // Ephemeral accounts keep their graph in the browser only — never upload
          // the full data (saves bandwidth); just report the usage size.
          try{await fetch(`${apiBase}/api/usage/${encodeURIComponent(key)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({bytes:byteLen})});}catch(_){}
        }else{
          const r=await fetch(`${apiBase}/api/data/${encodeURIComponent(key)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:bodyStr});
          if(r.ok){serverOk=true;anyOk=true;}
          else if(r.status===413){
            let j=null;try{j=await r.json();}catch(_){}
            if(j&&j.overLimit)showStorageLimitAlert(j);
          }else{
            let j=null;try{j=await r.json();}catch(_){}
            if(j&&j.ephemeral)window.__MC_TIER__='ephemeral'; // server downgraded us to browser-only
          }
        }
      }catch(e){}

      if(directoryHandle){
        try{
          await this.saveToFile(key,snapshot);
          await this._writeFileBoot(snapshot,key);
          anyOk=true;
        }catch(e){console.warn('File save failed:',e);}
      }else{
        this.queueMirrorToFolder(key);
      }

      this._lastSaveOk=anyOk;

      if(!anyOk&&window.location.protocol==='file:'&&!isLocalDiskServerApp()&&!this._showedFolderBanner){
        this._showedFolderBanner=true;
        showSaveFolderBanner();
      }

      if(!opts||!opts.skipFlash){
        const f=document.getElementById('save-flash');
        if(f){
          if(!anyOk){
            f.textContent='⚠ Save failed';
            f.classList.add('show','save-error');
            clearTimeout(f._t);f._t=setTimeout(()=>{f.classList.remove('show','save-error');f.textContent='✓ Saved'},4000);
          }else{
            f.textContent='✓ Saved';
            f.classList.remove('save-error');
            f.classList.add('show');clearTimeout(f._t);f._t=setTimeout(()=>f.classList.remove('show'),900);
          }
        }
      }
    });
    return this._saveChain;
  },
  async load(u){
    const canon=canonicalUserStorageKey(u);
    const variantKeys=apiLoginUsernameVariants(canon);
    this._publicLoadError=false;
    // Hosted/public mode: the server (backed by GitHub) is the source of truth.
    // Load it authoritatively and FAIL CLOSED — on any error other than a clean
    // 404 (genuinely new account) we flag an error so loginAs won't fabricate a
    // starter graph that would overwrite the user's cloud data.
    if(isLocalDiskServerApp()||window.__PUBLIC_MODE__){
      try{
        const r=await fetch(`/api/data/${encodeURIComponent(canon)}`);
        if(r.ok){
          const d=await r.json();
          const nd=finalizeLoadedUserGraph(d)||d;
          (await this.saveToIndexedDB(canon,nd))||this.saveToLocalStorage(canon,nd);
          return nd;
        }
        // 404 = no cloud data yet (new account) → let the normal path/shell run.
        if(window.__PUBLIC_MODE__&&r.status!==404){this._publicLoadError=true;return null;}
      }catch(e){if(window.__PUBLIC_MODE__){this._publicLoadError=true;return null;}}
    }
    let data=null;
    for(const vk of variantKeys){
      const idbData=await this.loadFromIndexedDB(vk);
      const lsData=this.loadFromLocalStorage(vk);
      const idbTime=idbData?.lastSaved?new Date(idbData.lastSaved).getTime():0;
      const lsTime=lsData?.lastSaved?new Date(lsData.lastSaved).getTime():0;
      const slot=idbTime>=lsTime?idbData:lsData;
      if(!slot)continue;
      data=data?pickLocalVersusServer(data,slot):slot;
    }
    // Try loading from linked folder (File System Access API)
    if(directoryHandle){
      try{
        const fileData=await this.loadFromFile(canon);
        if(fileData&&(graphNodeCount(fileData)>0||graphEdgeCount(fileData)>0)){
          data=data?pickLocalVersusServer(data,fileData):fileData;
        }
      }catch(e){}
    }
    const pre=window.__PRELOAD_USER_DATA__;
    const graphEmpty=!data||(graphNodeCount(data)===0&&graphEdgeCount(data)===0);
    if(graphEmpty&&pre?.data&&(graphNodeCount(pre.data)>0||graphEdgeCount(pre.data)>0)&&canonicalUserStorageKey(pre.username||'')===canon){
      data=finalizeLoadedUserGraph(pre.data)||pre.data;
      (await this.saveToIndexedDB(canon,data))||this.saveToLocalStorage(canon,data);
    }
    const applyServerPayload=async(payload)=>{
      if(payload==null||typeof payload!=='object')return;
      const merged=pickLocalVersusServer(data,payload);
      if(merged!==undefined&&merged!==null){
        data=finalizeLoadedUserGraph(merged)||merged;
        (await this.saveToIndexedDB(canon,data))||this.saveToLocalStorage(canon,data);
      }
    };
    if(window.location.protocol!=='file:'){
      try{
        const r=await fetch(`/api/data/${encodeURIComponent(canon)}`);
        if(r.ok)await applyServerPayload(await r.json());
      }catch(e){}
    }else{
      try{
        let payload=null;
        for(const vk of variantKeys){
          payload=await fetchJsonUserFromApi(vk,'http://localhost:3000');
          if(payload)break;
        }
        await applyServerPayload(payload);
      }catch(e){}
    }
    if(data)return finalizeLoadedUserGraph(data)||data;
    if(pre&&pre.data&&(graphNodeCount(pre.data)>0||graphEdgeCount(pre.data)>0)&&canonicalUserStorageKey(pre.username||'')===canon)return finalizeLoadedUserGraph(pre.data)||pre.data;
    if(window.location.protocol==='file:'){
      try{
        for(const v of variantKeys){
          for(const fn of [`${v}_data.json`,`${v}.json`]){
            const r=await fetch(`data/${fn}`);
            if(!r.ok)continue;
            const d=await r.json();
            const fd=finalizeLoadedUserGraph(d)||d;
            if(graphNodeCount(fd)>0||graphEdgeCount(fd)>0){ (await this.saveToIndexedDB(canon,fd))||this.saveToLocalStorage(canon,fd); return fd; }
          }
        }
      }catch(e2){}
    }
    return null;
  },
  async users(){
    if(isLocalDiskServerApp()){
      try{
        const r=await fetch('/api/users');
        if(r.ok){
          const j=await r.json();
          const raw=(j.users||[]).filter(u=>u&&!isTemplateUserStorageKey(u.username));
          const keep=new Set(raw.map(u=>canonicalUserStorageKey(u.username)));
          await this._purgeCachesNotOnDisk(keep);
          if(!raw.length)return[];
          return await this.mergeLoginUserCounts(raw.map(u=>({u:u.username,n:u.displayName||u.username,c:u.nodeCount||0})));
        }
      }catch(e){}
    }
    // PRIMARY: Get users from IndexedDB
    if(db){
      try{
        const tx=db.transaction(['users'],'readonly');
        const store=tx.objectStore('users');
        const request=store.getAll();
        const idbUsers=await new Promise((resolve,reject)=>{
          request.onsuccess=()=>{
            const byCanon=new Map();
            request.result.filter(r=>!r.username.includes('_sp_')).forEach(r=>{
              const c=canonicalUserStorageKey(r.username);
              if(isTemplateUserStorageKey(c))return;
              const nc=graphNodeCount(r.data);
              const t=r.data?.lastSaved?new Date(r.data.lastSaved).getTime():0;
              const ex=byCanon.get(c);
              if(!ex||nc>ex.c||(nc===ex.c&&t>ex.t))
                byCanon.set(c,{u:c,n:r.data?.displayName||c,c:nc,t});
            });
            const users=[...byCanon.values()].map(x=>({u:x.u,n:x.n,c:x.c}));
            resolve(users);
          };
          request.onerror=()=>resolve([]);
        });
        if(idbUsers.length>0)return await this.mergeLoginUserCounts(idbUsers);
      }catch(e){}
    }
    const lsUsers=this.usersFromLocalStorage();
    if(lsUsers.length>0)return await this.mergeLoginUserCounts(lsUsers);
    const pre=window.__PRELOAD_USER_DATA__;
    if(pre&&pre.data) return [{u:pre.username,n:pre.data.displayName||pre.username,c:graphNodeCount(pre.data)}];
    // FALLBACK: Fetch from server API when IndexedDB empty (e.g. first load via server)
    try{
      const apiBase=window.location.protocol==='file:'?'http://localhost:3000':'';
      const r=await fetch(`${apiBase}/api/users`);
      if(r.ok){
        const j=await r.json();
        if(j.users&&j.users.length>0){
          return await this.mergeLoginUserCounts(j.users.filter(u=>u&&!isTemplateUserStorageKey(u.username)).map(u=>({u:u.username,n:u.displayName||u.username,c:u.nodeCount||0})));
        }
      }
    }catch(e){}
    if(window.location.protocol==='file:') try{
      const ir=await fetch('data/users_index.json');
      if(ir.ok){
        const ij=await ir.json();
        const fl=Array.isArray(ij)?ij:(ij.files||[]);
        const out=[];
        for(const ent of fl){
          const f=typeof ent==='string'?ent:(ent.file||'');
          if(!f||!/\.json$/i.test(f))continue;
          const clean=String(f).replace(/^.*[\\/]/,'');
          let jd=null,c=0;
          try{
            const jr=await fetch('data/'+clean);
            if(jr.ok){jd=await jr.json();c=graphNodeCount(jd)}
          }catch(e){}
          const stem=clean.replace(/\.json$/i,'');
          const ukey=(stem.endsWith('_data')?stem:stem+'_data').toLowerCase().replace(/[^a-z0-9_-]/g,'').replace(/_+/g,'_').replace(/^_|_$/g,'').slice(0,50);
          if(!ukey)continue;
          if(isTemplateUserStorageKey(ukey))continue;
          out.push({u:ukey,n:(jd&&jd.displayName)||ukey,c});
        }
        if(out.length)return await this.mergeLoginUserCounts(out);
      }
    }catch(e2){}
    return [];
  },
  async sp(u,d){
    d.spTime=new Date().toISOString();
    await this.save(u,d,{skipFlash:true});
    
    if(db){
      await this._pruneIndexedDbSavepointsForUser(u,2).catch(()=>{});
      await this.saveToIndexedDB(u+'_sp_'+Date.now(),d).catch(()=>{});
    }
    
    if(directoryHandle){
      try{
        const ts=new Date().toISOString().replace(/[:.]/g,'-');
        const fileName=`${u}_sp_${ts}.json`;
        const fileHandle=await directoryHandle.getFileHandle(fileName,{create:true});
        const writable=await fileHandle.createWritable();
        await writable.write(JSON.stringify(d));
        await writable.close();
        // Prune old savepoint files in directory (keep 5 newest)
        try{
          const spFiles=[];
          for await(const [name] of directoryHandle.entries()){
            if(name.endsWith('.json')&&name.includes('_sp_')&&name.startsWith(u))spFiles.push(name);
          }
          if(spFiles.length>5){
            spFiles.sort().reverse();
            for(const old of spFiles.slice(5)){
              try{await directoryHandle.removeEntry(old)}catch(e){}
            }
          }
        }catch(e){}
      }catch(e){
        console.error('Savepoint file save error:',e);
      }
    }

    // Mirror checkpoint to project data/savepoints/ when local server is used
    try{
      const apiBase=window.location.protocol==='file:'?'http://localhost:3000':'';
      const r=await fetch(`${apiBase}/api/savepoint/${encodeURIComponent(u)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});
      if(!r.ok&&window.location.protocol!=='file:')console.warn('Server savepoint failed:',r.status);
    }catch(e){
      if(window.location.protocol!=='file:')console.warn('Server savepoint failed:',e);
    }
  },
  // Import all users from data/ folder (called on startup)
  async importAllFromFiles(files){
    if(!files||files.length===0)return 0;
    if(typeof initDB==='function')await initDB().catch(()=>{});
    let imported=0;
    let errors=[];
    let lastFailReason='';
    let skippedSavepointFiles=0;
    const existingUsers=await this.users();
    const existingNames=new Set(existingUsers.map(r=>r.u));
    const slug=(s)=>{
      if(!s||typeof s!=='string')return'';
      return s.normalize('NFKD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/[^a-z0-9_-]+/g,'_').replace(/^_+|_+$/g,'').slice(0,50);
    };
    const toArray=(v)=>{
      if(Array.isArray(v))return v;
      if(v&&typeof v==='object')return Object.values(v);
      return [];
    };
    for(const file of files){
      const isJson=/\.json$/i.test(file.name);
      if(isJson&&looksLikeSavepointExportFilename(file.name)){
        skippedSavepointFiles++;
        lastFailReason='Checkpoint files are named like user_sp_2026-03-19T….json. Use "↩️ Restore checkpoint" on the login screen, not "Import". (Main graphs use names like xianl_data.json.)';
        continue;
      }
      if(isJson){
        try{
          let data=await this.importFromFile(file);
          if(!data||typeof data!=='object'||Array.isArray(data)){
            lastFailReason='Not a JSON object';
            console.warn(`Invalid data in ${file.name}`);
            continue;
          }
          let wrapperUsername=null;
          if(typeof data.username==='string'&&data.username.trim())wrapperUsername=data.username.trim();
          // Unwrap nested { data: { ... } } (preload, API, double-wrapped exports)
          for(let depth=0;depth<4;depth++){
            if(data.data&&typeof data.data==='object'&&!Array.isArray(data.data)&&('nodes' in data.data||'edges' in data.data)){
              data=data.data;
            }else break;
          }
          if(data&&(data.nodes||data.edges))walkAndFixMojibake(data);
          data.nodes=toArray(data.nodes);
          data.edges=toArray(data.edges);
          if(data.nodes.length===0&&data.graph&&typeof data.graph==='object'){
            data.nodes=toArray(data.graph.nodes);
            data.edges=data.edges.length?data.edges:toArray(data.graph.edges);
          }
          if(data.nodes.length===0&&data.edges.length===0){
            lastFailReason='No nodes or edges found (need array or object map of nodes/edges)';
            console.warn(`No nodes or edges in ${file.name}`);
            continue;
          }
          // Username: filename stem → displayName → wrapper username → root username → fallback
          let base=file.name.replace(/\.json$/i,'').replace(/_data$/i,'');
          let baseUsername=slug(base)||'';
          if(data.displayName){
            const fromDisp=slug(data.displayName);
            if(fromDisp)baseUsername=fromDisp;
          }
          if(!baseUsername&&wrapperUsername)baseUsername=slug(wrapperUsername);
          if(!baseUsername&&typeof data.username==='string')baseUsername=slug(data.username);
          if(!baseUsername)baseUsername='imported_'+Date.now()+'_'+Math.random().toString(36).slice(2,8);
          baseUsername=(baseUsername||'imported_user').toLowerCase().replace(/[^a-z0-9_-]/g,'').replace(/_+/g,'_').replace(/^_|_$/g,'').slice(0,50);
          if(!baseUsername)baseUsername='imported_'+Date.now();
          // If base username exists, add number suffix (xianl→xianl2, xianl2→xianl3) for past-version imports
          let username=baseUsername;
          const sk0=canonicalUserStorageKey(username);
          if(existingNames.has(sk0)){
            let n=2;
            while(existingNames.has(canonicalUserStorageKey(baseUsername+n)))n++;
            username=baseUsername+n;
          }
          const storageKey=canonicalUserStorageKey(username);
          existingNames.add(storageKey);
          
          // Large graphs (often 10–30MB JSON) exceed localStorage; IndexedDB may also fail — persist to disk via local server first.
          const LS_SAFE=4.5*1024*1024;
          data.lastSaved=data.lastSaved||new Date().toISOString();
          let serverOk=false;
          try{
            const apiBase=window.location.protocol==='file:'?'http://localhost:3000':'';
            const r=await fetch(`${apiBase}/api/data/${encodeURIComponent(storageKey)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
            serverOk=r.ok;
          }catch(e){
            console.warn('Import → server failed:',e);
          }
          const idbOk=await this.saveToIndexedDB(storageKey,data);
          let lsOk=false;
          if(!idbOk&&file.size<LS_SAFE)lsOk=this.saveToLocalStorage(storageKey,data);
          const saved=serverOk||idbOk||lsOk;
          if(saved){
            imported++;
            if(typeof directoryHandle!=='undefined'&&directoryHandle){
              this.saveToFile(storageKey,data).catch(e=>console.warn('Could not copy import to linked folder:',e));
            }
          }else if(file.size>=LS_SAFE&&!idbOk&&!serverOk){
            lastFailReason=this._lastSaveError
              ?`IndexedDB save failed (${this._lastSaveError}) and server save failed. This file is ~${Math.round(file.size/1024/1024)}MB. Run: node scripts/server.js — open http://localhost:3000 — import again (saves to data/).`
              :`~${Math.round(file.size/1024/1024)}MB: localStorage limit exceeded. Run node scripts/server.js, open http://localhost:3000, import again so data is written to data/.`;
          }else if(!saved){
            lastFailReason=(this._lastSaveError||'IndexedDB save failed')+(!serverOk?'. Start node scripts/server.js at http://localhost:3000 and import again, or copy the JSON into data/.':'.');
          }
        }catch(e){
          lastFailReason=e.message||String(e);
          console.error(`Failed to import ${file.name}:`,e);
          errors.push(file.name);
        }
      }
    }
    if(errors.length>0){
      console.warn('Failed to import:',errors);
    }
    const jsonPicked=files.filter(f=>/\.json$/i.test(f.name));
    if(imported===0&&skippedSavepointFiles===jsonPicked.length&&jsonPicked.length>0){
      this._lastImportHint='Only checkpoint files (*_sp_<date-or-time>*.json) were selected. Use "↩️ Restore checkpoint", not "Import". A full portable backup is usually named like username_data.json.';
    }else{
      this._lastImportHint=lastFailReason;
      if(imported===0&&skippedSavepointFiles>0)
        this._lastImportHint=(this._lastImportHint?this._lastImportHint+'\n\n':'')+`${skippedSavepointFiles} checkpoint file(s) were skipped — use "Restore checkpoint".`;
    }
    return imported;
  }
};

// IndexedDB will be initialized on page load (see bottom of file)

/* ═══ STATE ═══ */
let CU=null; // current user
let G={nodes:[],edges:[],displayName:'',autoSave:true,tutorialNotes:true,workspaces:[{id:'home',name:'Home',icon:'🏠'}],cws:'home',nodeOrder:{},expandPages:[],notesCatalogHidden:[]};
let _nodeMap=new Map();
let _nodeMapDirty=true;
let _chCache=new Map();
function rebuildNodeMap(){_nodeMap=new Map(G.nodes.map(n=>[n.id,n]));_nodeMapDirty=false}
function gn(id){if(_nodeMapDirty)rebuildNodeMap();return _nodeMap.get(id)||null}
function dirtyNodeMap(){_nodeMapDirty=true;_chCache.clear()}
let viewStack=[]; // navigation path
let expandedId=null; // which node is expanded as bubble at current level (primary)
let expandedIds=new Set(); // set of all expanded node IDs (for multiple spheres)
let selectedNodeId=null; // node selected for adding children via bottom input
let nodeSelectorId=null; // node selected by selector (red outline)
let lastEnterPressTime=0; // Track last Enter key press for double-Enter detection
let spaceKeyPressed=false; // Track if Space key is currently pressed
let enterKeyPressed=false; // Track if Enter key is currently pressed
let lastSpacePressTime=0; // Track when Space was last pressed (for Space+Arrow detection)
let lastSpaceBarPressTime=0; // Track last Space bar press for double-press detection
let commandKeyPressed=false; // Track if Command/Ctrl key is currently pressed
let commandKeyPressTime=0; // Track when Command key was pressed
let otherKeyPressedWithCommand=false; // Track if another key was pressed while Command is held
let lastCtrlFPressTime=0; // Track when Ctrl+F was last pressed (to prevent bottom input activation)
let keysProcessed=new Set(); // Track keys that have already triggered their action (to prevent long-press repetition)
let nodeUnderCursor=null; // node currently under cursor for Enter key toggle
let copiedNodeData=null; // node data copied for paste operation
let sim=null; // main simulation
let childSim=null; // simulation for children inside bubble
let childSims=new Map(); // Map of expandedId -> childSim for multiple spheres
let lastParentPositions=new Map(); // Map of parentId -> {x,y} for syncing content nodes when parent moves
let contentSyncTimer=null; // d3.timer handle for frame-by-frame content node sync
let connMode=false,connSrc=null;
let cxId=null,editId=null;
let dragTarget=null,dragTimer=null;
let rpOpen=true,npExp={};
let rpLevel=0; // 0=root (level1 nodes), 1=first expanded (children), etc.
let currentView='home'; // 'home' or 'calendar'
let calendarDate=new Date(); // current week for calendar
let calendarDayView=null; // null or Date for day detail view
let calendarScrollLeft=0; // horizontal scroll position
let calendarScrollTop=0; // vertical scroll position
let calendarPreserveFromNotesOpen=false; // when switching notes → calendar, keep scroll
let calendarCenterOnAnchorNextRender=false; // when opening from elsewhere or prev/next, center on calendarDate
let calendarSmoothRecenter=false; // Space bar / explicit smooth scroll to anchor
let draggedTodoSectionIdx=null; // todo list: drag-reorder category sections
let calendarExpandedEvent=null; // currently expanded event node ID
let calendarTimezone='America/New_York'; // default EST
let calendarSearchTerm=''; // current search term for highlighting
let pendingRoutineAction=null; // {action: 'delete'|'changeTime', nodeId: string, occurrenceDate: Date, newDate?: Date}
let editCalendarOccurrenceDate=null; // When editing a routine occurrence from calendar, ISO string of that occurrence so "Only this event" applies to the correct date
let findTimeMode=null; // 'auto'|'manual'
let findTimeStartDate=null; // Date
let findTimeEndDate=null; // Date
let findTimeFlexMinutes=30; // default 30 minutes
let findTimeUnitMinutes=30; // default 30 minutes per unit
let priorityVisible=true; // priority glow visibility toggle (default: on)
let findTimeSelectedRanges=[]; // Array of {start:Date, end:Date} for manual selection
let showByFilter=null; // Current filter: 'routine', 'priority', 'buffer', 'tbd', or category id
let bringEdgesEnabled=false; // When true, show tasks connected to filtered tasks

// Use local YYYY-MM-DD to match grid columns. UTC (toISOString().split) breaks evening times (e.g. 8:15pm → next UTC day) and can hide routine overrides / exceptions.
function calendarDateKeyLocal(d){
  const t=d instanceof Date?d:new Date(d);
  if(isNaN(t.getTime()))return'';
  return t.getFullYear()+'-'+String(t.getMonth()+1).padStart(2,'0')+'-'+String(t.getDate()).padStart(2,'0');
}
function calendarExceptionHidesOccurrence(n,occDate){
  if(!n.exceptionDates||!n.exceptionDates.length)return false;
  if(!occDate||isNaN(occDate.getTime()))return false;
  return n.exceptionDates.includes(calendarDateKeyLocal(occDate))||n.exceptionDates.includes(occDate.toISOString().split('T')[0]);
}
// Calendar: allow any past or future time — clear min/max on datetime-local (browsers may default min to "now")
function clearCalendarDatetimeInputConstraints(input){
  if(!input||!input.removeAttribute)return;
  input.removeAttribute('min');
  input.removeAttribute('max');
  input.removeAttribute('step');
}
function clearCalEvDatetimeInputs(){
  clearCalendarDatetimeInputConstraints(document.getElementById('cal-ev-start'));
  clearCalendarDatetimeInputConstraints(document.getElementById('cal-ev-end'));
}
function clearFindTimeDatetimeInputs(){
  clearCalendarDatetimeInputConstraints(document.getElementById('findtime-start'));
  clearCalendarDatetimeInputConstraints(document.getElementById('findtime-end'));
}

function cPid(){return viewStack.length?viewStack[viewStack.length-1]:null}
function eI(x){return x?.id!==undefined?x.id:x}
function ch(pid){
  const cacheKey=pid||'__root__';
  const cached=_chCache.get(cacheKey);
  if(cached)return cached;
  const ws=G.cws||'home';const children=G.nodes.filter(n=>{
    if(n.notesTabOnly)return false;
    if((n.parentId||null)!==(pid||null)||(n.wsId||'home')!==ws)return false;
    if(!n.parentId){
      const hasTaskProperties=n.type||n.routine||n.priority||n.buffer||(n.TBD&&n.TBD!=='none');
      if(!hasTaskProperties)return false;
    }
    return true;
  });
  const orderKey=pid||'root';
  if(G.nodeOrder&&G.nodeOrder[orderKey]){
    const orderMap=new Map(G.nodeOrder[orderKey].map((id,idx)=>[id,idx]));
    children.sort((a,b)=>{
      const aIdx=orderMap.get(a.id);
      const bIdx=orderMap.get(b.id);
      if(aIdx===undefined)return 1;
      if(bIdx===undefined)return -1;
      return aIdx-bIdx;
    });
  }else{
    const parentEdges=G.edges.filter(e=>eI(e.source)===(pid||null));
    children.sort((a,b)=>{
      const aEdgeIdx=parentEdges.findIndex(e=>eI(e.target)===a.id);
      const bEdgeIdx=parentEdges.findIndex(e=>eI(e.target)===b.id);
      if(aEdgeIdx===-1)return 1;
      if(bEdgeIdx===-1)return -1;
      return aEdgeIdx-bEdgeIdx;
    });
  }
  _chCache.set(cacheKey,children);
  return children;
}
function isL(id){return!G.nodes.some(n=>n.parentId===id)}
function allD(id){const s=new Set();(function w(i){G.nodes.filter(n=>n.parentId===i).forEach(n=>{s.add(n.id);w(n.id)})})(id);return s}
function allDS(id){const s=allD(id);s.add(id);return s}
function nPath(id){const p=[];let c=gn(id);while(c){p.unshift(c);c=c.parentId?gn(c.parentId):null}return p}
// Returns nodes sorted hierarchically: level 1 first, then level 2 grouped by level1, then level 3, etc.
// Uses ch() which respects G.nodeOrder. predicate(node)=>bool, excludeId to exclude from list.
function getCategoryOptionsSorted(predicate,excludeId){
  const exclude=excludeId?new Set([excludeId]):new Set();
  const seen=new Set();
  const result=[];
  function traverse(pid){
    ch(pid).forEach(c=>{
      if(exclude.has(c.id))return;
      if(predicate&&!predicate(c))return;
      if(seen.has(c.id))return;
      seen.add(c.id);
      result.push(c);
      traverse(c.id);
    });
  }
  traverse(null);
  // Append nodes not reached (e.g. orphans, note-only roots) by depth then name
  const pred=n=>!exclude.has(n.id)&&(!predicate||predicate(n));
  G.nodes.filter(pred).filter(n=>!seen.has(n.id)&&!n.notesTabOnly)
    .sort((a,b)=>{const da=nPath(a.id).length,db=nPath(b.id).length;return da!==db?da-db:(a.name||'').localeCompare(b.name||'');})
    .forEach(n=>result.push(n));
  return result;
}
// Helper function to get filtered task IDs based on "show by" filter
// Logic: Start from deepest nodes, find matching tasks (task A), keep task A and all ancestors (channels)
// If "bring edges": only include tasks directly connected to task A (not to parents of task A)
// Returns {filteredTaskIds: Set, filteredNoteIds: Set}
function getFilteredTaskIds(){
  if(!showByFilter)return {filteredTaskIds:new Set(),filteredNoteIds:new Set()};
  
  const filteredTaskIds=new Set();
  const filteredNoteIds=new Set();
  
  // Step 1: Find all tasks that match the filter (these are "task A")
  // We check all tasks, starting from deepest level conceptually
  const allTasks=G.nodes.filter(n=>isTaskNode(n));
  const matchingTasks=allTasks.filter(n=>matchesFilter(n));
  
  // Step 2: For each matching task (task A), add it and all its ancestors (channels)
  // Parents serve as channels to show where task A lives, regardless of whether they match
  matchingTasks.forEach(taskA=>{
    filteredTaskIds.add(taskA.id);
    let current=taskA.parentId?gn(taskA.parentId):null;
    while(current){
      filteredTaskIds.add(current.id);
      current=current.parentId?gn(current.parentId):null;
    }
  });
  
  if(bringEdgesEnabled){
    const connectedTaskIds=new Set();
    
    matchingTasks.forEach(taskA=>{
      G.edges.forEach(edge=>{
        const sourceId=eI(edge.source);
        const targetId=eI(edge.target);
        
        if(sourceId===taskA.id){
          const targetNode=gn(targetId);
          if(targetNode&&isTaskNode(targetNode)){
            connectedTaskIds.add(targetId);
          }
        }else if(targetId===taskA.id){
          const sourceNode=gn(sourceId);
          if(sourceNode&&isTaskNode(sourceNode)){
            connectedTaskIds.add(sourceId);
          }
        }
      });
    });
    
    connectedTaskIds.forEach(id=>filteredTaskIds.add(id));
    
    connectedTaskIds.forEach(connectedId=>{
      let current=gn(connectedId);
      if(current&&current.parentId){
        current=G.nodes.find(n=>n.id===current.parentId);
        while(current){
          // Only add if not already added (might overlap with task A's ancestors)
          if(!filteredTaskIds.has(current.id)){
            filteredTaskIds.add(current.id);
          }
          current=current.parentId?gn(current.parentId):null;
        }
      }
    });
  }
  
  // Step 4: Include notes that belong to visible tasks
  const allNotes=G.nodes.filter(n=>!isTaskNode(n));
  allNotes.forEach(note=>{
    if(note.parentId&&filteredTaskIds.has(note.parentId)){
      filteredNoteIds.add(note.id);
    }
  });
  
  return {filteredTaskIds,filteredNoteIds};
}
function getParentPathString(nodeId){
  const path=nPath(nodeId);
  if(path.length<=1)return ''; // No parent path for root nodes
  // Return parent path (excluding the node itself) joined with hyphens
  return path.slice(0,-1).map(n=>n.name).join('-');
}
function aggP(id){const n=G.nodes.find(x=>x.id===id);if(!n)return{t:0,d:0};const c=G.nodes.filter(x=>x.parentId===id);if(!c.length){const t=n.progress?n.progress.length:0,d=n.progress?n.progress.filter(p=>p.done).length:0;return{t,d}}let t=0,d=0;c.forEach(x=>{const s=aggP(x.id);t+=s.t;d+=s.d});return{t,d}}
function visN(){return ch(cPid())}
function visE(){const v=new Set(visN().map(n=>n.id));return G.edges.filter(e=>v.has(eI(e.source))&&v.has(eI(e.target)))}
// Merge duplicate nodes that are the same task: same parent chain, same name, same type.
// Nodes with a calendarDate are never merged (allows repeated same-named meetings in same category/type).
function mergeDuplicateMeetingNodes(){
  const byKey=new Map(); // key = parentId + '\n' + name + '\n' + type + (calendarDate or ''), value = [nodes]
  G.nodes.forEach(n=>{
    if(!n.parentId)return; // only task nodes (children) are deduped
    const t=n.type||getDefaultTypeFromTitle(n.name);
    const name=(n.name||'').trim();
    if(!name)return;
    // Include calendarDate in key so calendar events are never merged (each occurrence stays separate)
    const key=(n.parentId||'')+'\n'+name+'\n'+(t||'task')+(n.calendarDate?'\n'+n.calendarDate:'');
    if(!byKey.has(key))byKey.set(key,[]);
    byKey.get(key).push(n);
  });
  const toRemove=new Set();
  byKey.forEach((nodes)=>{
    if(nodes.length<=1)return;
    nodes.sort((a,b)=>a.id.localeCompare(b.id));
    const keep=nodes[0];
    for(let i=1;i<nodes.length;i++){
      const n=nodes[i];
      toRemove.add(n.id);
      if(n.calendarDate&&!keep.calendarDate){ keep.calendarDate=n.calendarDate; keep.calendarDuration=n.calendarDuration; keep.calendarDisplayName=n.calendarDisplayName; }
      if(n.exceptionDates&&n.exceptionDates.length){ if(!keep.exceptionDates)keep.exceptionDates=[]; n.exceptionDates.forEach(d=>{ if(!keep.exceptionDates.includes(d))keep.exceptionDates.push(d); }); }
      if(n.routineTimeOverrides&&Object.keys(n.routineTimeOverrides).length){ if(!keep.routineTimeOverrides)keep.routineTimeOverrides={}; Object.assign(keep.routineTimeOverrides,n.routineTimeOverrides); }
      if(n.progress&&n.progress.length){ if(!keep.progress)keep.progress=[]; keep.progress=keep.progress.concat(n.progress); }
      if(n.postEventNotes&&!keep.postEventNotes)keep.postEventNotes=n.postEventNotes;
      if(n.postEventNotesByDate&&Object.keys(n.postEventNotesByDate).length){ if(!keep.postEventNotesByDate)keep.postEventNotesByDate={}; Object.keys(n.postEventNotesByDate).forEach(dk=>{ if(!keep.postEventNotesByDate[dk]||!keep.postEventNotesByDate[dk].trim())keep.postEventNotesByDate[dk]=n.postEventNotesByDate[dk]; }); }
    }
  });
  if(toRemove.size===0)return;
  G.nodes=G.nodes.filter(n=>!toRemove.has(n.id));dirtyNodeMap();
  G.edges=G.edges.filter(e=>!toRemove.has(eI(e.source))&&!toRemove.has(eI(e.target)));
  if(G.nodeOrder){ Object.keys(G.nodeOrder).forEach(orderKey=>{ G.nodeOrder[orderKey]=G.nodeOrder[orderKey].filter(id=>!toRemove.has(id)); }); }
}
let _svDirty=false,_svTimer=null;
const _svDelay=220;
function sv(){if(!G.autoSave)return;_svDirty=true;if(_svTimer)clearTimeout(_svTimer);_svTimer=setTimeout(()=>{_svTimer=null;_svDirty=false;ST.save(CU,G)},_svDelay);}
function svFlush(){if(_svTimer){clearTimeout(_svTimer);_svTimer=null;}_svDirty=false;return ST.save(CU,G);}
function svImmediate(){_svDirty=false;if(_svTimer){clearTimeout(_svTimer);_svTimer=null;}ST.save(CU,G);}
function svWithUndo(){saveState();sv()}
function esc(s){const d=document.createElement('div');d.textContent=s;return d.innerHTML}

/* ═══ LOGIN ═══ */
let loginSelectedIndex=-1; // -1 = input field, 0+ = user card index
let loginUserList=[]; // users list for Enter/dblclick lookup
async function initLg(){
  const us=await ST.users();
  loginUserList=us;
  const sec=document.getElementById('ux'),ul=document.getElementById('ul');
  loginSelectedIndex=-1; // Reset to input field
  if(us.length){
    sec.style.display='';
    ul.innerHTML=us.map((u,i)=>`<div class="uc ${i===loginSelectedIndex?'selected':''}" data-index="${i}" data-u="${esc(u.u)}" data-n="${esc(u.n)}" onclick="selectLoginCard(${i})" ondblclick="event.preventDefault();loginAs('${esc(u.u)}','${esc(u.n)}')"><div class="ua">${u.n.charAt(0).toUpperCase()}</div><div class="ui"><b>${esc(u.n)}</b><span>${u.c} nodes</span></div><div class="uc-actions"><button class="uc-btn" onclick="event.stopPropagation();archiveUser('${esc(u.u)}')" title="Archive to file">📦</button><button class="uc-btn del" onclick="event.stopPropagation();deleteUser('${esc(u.u)}')" title="Delete">🗑️</button></div></div>`).join('');
    updateLoginSelection();
  }else{
    sec.style.display='none';
  }
}
function selectLoginCard(i){loginSelectedIndex=i;updateLoginSelection()}
function updateLoginSelection(){
  const input=document.getElementById('lg-name');
  const cards=document.querySelectorAll('#ul .uc');
  // Remove all selections
  cards.forEach(c=>c.classList.remove('selected'));
  input.classList.remove('selected');
  // Add selection to current index
  if(loginSelectedIndex===-1){
    input.classList.add('selected');
    input.focus();
  }else if(cards[loginSelectedIndex]){
    cards[loginSelectedIndex].classList.add('selected');
    cards[loginSelectedIndex].scrollIntoView({behavior:'smooth',block:'nearest'});
  }
}
function handleLoginNavigation(e){
  const loginScreen=document.getElementById('scr-login');
  if(loginScreen.classList.contains('hide')){
    // Not on login page - don't interfere with main app navigation
    return;
  }
  
  const input=document.getElementById('lg-name');
  const cards=Array.from(document.querySelectorAll('#ul .uc'));
  const totalItems=cards.length+1; // input + cards
  
  // Handle all four arrow keys independently
  if(e.key==='ArrowDown'||e.key==='ArrowRight'){
    e.preventDefault();
    e.stopPropagation(); // Prevent event from reaching main app handler
    loginSelectedIndex++;
    if(loginSelectedIndex>=totalItems)loginSelectedIndex=-1; // Wrap to input
    updateLoginSelection();
  }else if(e.key==='ArrowUp'||e.key==='ArrowLeft'){
    e.preventDefault();
    e.stopPropagation(); // Prevent event from reaching main app handler
    loginSelectedIndex--;
    if(loginSelectedIndex<-1)loginSelectedIndex=totalItems-2; // Wrap to last card
    updateLoginSelection();
  }else if(e.key==='Enter'){
    e.preventDefault();
    e.stopPropagation(); // Prevent event from reaching main app handler
    if(loginSelectedIndex===-1){
      // Input field selected, do login
      doLogin();
    }else{
      // Card selected, load user (same as double-click)
      const u=loginUserList[loginSelectedIndex];
      if(u)loginAs(u.u,u.n);
    }
  }
}
async function deleteUser(u){
  const variants=apiLoginUsernameVariants(canonicalUserStorageKey(u));
  if(!confirm('Delete all data for "'+variants[0]+'"?'))return;
  try{
    const apiBase=window.location.protocol==='file:'?'http://localhost:3000':'';
    const k=canonicalUserStorageKey(u);
    await fetch(`${apiBase}/api/data/${encodeURIComponent(k)}`,{method:'DELETE'});
  }catch(e){}
  // Remove from IndexedDB (all keys that map to the same logical user)
  if(db){
    try{
      const tx=db.transaction(['users'],'readwrite');
      const store=tx.objectStore('users');
      variants.forEach(v=>store.delete(v));
      const allRequest=store.getAll();
      allRequest.onsuccess=()=>{
        (allRequest.result||[]).forEach(r=>{
          if(!r.username||!r.username.includes('_sp_'))return;
          for(const v of variants){
            if(r.username.startsWith(v+'_sp_')){ store.delete(r.username); break; }
          }
        });
      };
    }catch(e){}
  }
  try{
    const all=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
    variants.forEach(v=>{ delete all[v]; });
    localStorage.setItem(LS_KEY,JSON.stringify(all));
  }catch(e){}
  initLg();
}
async function archiveUser(u){
  // Load from IndexedDB, preload, or server API (same as login)
  const data=await ST.load(u);
  if(!data){
    alert('No data found for this user');
    return;
  }
  const key=canonicalUserStorageKey(u);
  await ST._restoreDirectoryHandle();
  const apiBase=window.location.protocol==='file:'?'http://localhost:3000':'';
  let serverWrote=false;
  try{
    const r=await fetch(`${apiBase}/api/data/${encodeURIComponent(key)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
    serverWrote=r.ok;
  }catch(e){}
  await ST.sp(u,data);
  const flashArchive=()=>{
    const f=document.getElementById('save-flash');
    if(!f)return;
    f.textContent='📦 Archived!';
    f.classList.add('show');
    clearTimeout(f._t);
    f._t=setTimeout(()=>{
      f.classList.remove('show');
      f.textContent='✓ Saved';
    },2000);
  };
  if(serverWrote||directoryHandle){
    flashArchive();
    return;
  }
  if('showDirectoryPicker' in window){
    if(await ST.acquireWritableDataDirectoryInteractive()){
      await ST.sp(u,data);
      flashArchive();
      return;
    }
  }
  
  // Fallback: Use download API (for Safari/other browsers or if File System Access fails)
  const ts=new Date().toISOString().replace(/[:.]/g,'-');
  // Download savepoint
  const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;
  a.download=`${u}_sp_${ts}.json`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  // Also download main data file
  const blob2=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
  const url2=URL.createObjectURL(blob2);
  const a2=document.createElement('a');
  a2.href=url2;
  a2.download=`${u}_data.json`;
  document.body.appendChild(a2);
  a2.click();
  document.body.removeChild(a2);
  URL.revokeObjectURL(url2);
  flashArchive();
}
// Import from data/ folder (uses IndexedDB or localStorage fallback when file://)
function importFromDataFolder(){
  // Open file picker SYNCHRONOUSLY - browsers block it if we await first (user activation is lost)
  const input=document.createElement('input');
  input.type='file';
  input.multiple=true;
  input.accept='.json,application/json';
  input.onchange=async (e)=>{
      const files=Array.from(e.target.files||[]);
      input.value='';
      if(files.length===0)return;
      try{
        console.log(`Attempting to import ${files.length} file(s)...`);
        const imported=await ST.importAllFromFiles(files);
        if(imported>0){
          const f=document.getElementById('save-flash');
          if(f){
            f.textContent=`✓ Imported ${imported} user(s)!`;
            f.classList.add('show');
            clearTimeout(f._t);
            f._t=setTimeout(()=>{
              f.classList.remove('show');
              f.textContent='✓ Saved';
            },3000);
          }
          initLg();
        }else{
          const hint=ST._lastImportHint?`\n\nDetail: ${ST._lastImportHint}`:'';
          alert('No valid user files imported.\n\nExpected: JSON with a "nodes" array (or object map) and/or "edges". Wrapped exports like { "data": { "nodes": [...] } } are OK.\n\nOpening via double-click: run node scripts/prepare.js after changing data/*.json (updates data/file_boot.js for Chrome). Large files: use node scripts/server.js + http://localhost:3000, or Import while the server runs.'+hint);
        }
      }catch(err){
        console.error('Import error:',err);
        alert('Import failed: '+(err.message||String(err)));
      }
    };
    input.click();
}

/** Unwrap / normalize graph JSON (shared by import + checkpoint restore) */
function normalizeImportedGraphData(raw){
  let data=raw;
  if(!data||typeof data!=='object')return null;
  for(let depth=0;depth<4;depth++){
    if(data.data&&typeof data.data==='object'&&!Array.isArray(data.data)&&('nodes' in data.data||'edges' in data.data)){
      data=data.data;
    }else break;
  }
  const toArray=(v)=>{
    if(Array.isArray(v))return v;
    if(v&&typeof v==='object')return Object.values(v);
    return [];
  };
  if(data&&(data.nodes||data.edges))walkAndFixMojibake(data);
  data.nodes=toArray(data.nodes);
  data.edges=toArray(data.edges);
  if(data.nodes.length===0&&data.graph&&typeof data.graph==='object'){
    data.nodes=toArray(data.graph.nodes);
    data.edges=data.edges.length?data.edges:toArray(data.graph.edges);
  }
  return data;
}

/** Restore main user graph from a checkpoint file (*_sp_*.json). */
function importCheckpointRestore(){
  const input=document.createElement('input');
  input.type='file';
  input.accept='.json,application/json';
  input.onchange=async (e)=>{
    const file=e.target.files&&e.target.files[0];
    input.value='';
    if(!file)return;
    try{
      const raw=await ST.importFromFile(file);
      const data=normalizeImportedGraphData(raw);
      if(!data||(!data.nodes?.length&&!data.edges?.length)){
        alert('This file does not look like a graph checkpoint (no nodes or edges).');
        return;
      }
      let targetUser=null;
      const stem=file.name.replace(/\.json$/i,'');
      if(stem.includes('_sp_'))targetUser=stem.split('_sp_')[0];
      if(!targetUser){
        targetUser=prompt('Enter the login username key to restore into (e.g. xianl_data).\nTip: checkpoint files are named like that key plus _sp_ plus a timestamp.');
        if(!targetUser||!targetUser.trim())return;
        targetUser=targetUser.trim();
      }
      if(!confirm(`Replace ALL data for "${targetUser}" with this checkpoint?\n\nFile: ${file.name}`))return;
      data.lastSaved=new Date().toISOString();
      (await ST.saveToIndexedDB(targetUser,data))||ST.saveToLocalStorage(targetUser,data);
      await ST.save(targetUser,data);
      const f=document.getElementById('save-flash');
      if(f){
        f.textContent='✓ Checkpoint restored';
        f.classList.add('show');
        clearTimeout(f._t);
        f._t=setTimeout(()=>{f.classList.remove('show');f.textContent='✓ Saved'},3000);
      }
      initLg();
    }catch(err){
      console.error(err);
      alert('Restore failed: '+(err.message||String(err)));
    }
  };
  input.click();
}

/** List checkpoints from data/savepoints via local server and restore one */
async function pickCheckpointFromServer(){
  if(window.location.protocol==='file:'){
    alert('Open the app at http://localhost:3000 to use server checkpoints, or use "Restore checkpoint" to pick a .json file.');
    return;
  }
  const uRaw=prompt('Username key (same as on login card), e.g. xianl_data:');
  if(!uRaw)return;
  const u=uRaw.trim();
  try{
    const apiBase=window.location.protocol==='file:'?'http://localhost:3000':'';
    const r=await fetch(`${apiBase}/api/savepoints/${encodeURIComponent(u)}`);
    if(!r.ok){
      alert('Could not list savepoints (is the server running?).');
      return;
    }
    const j=await r.json();
    const list=j.savepoints||[];
    if(!list.length){
      alert('No savepoints on server for this user. Use Ctrl/Cmd+S in the app to create one.');
      return;
    }
    const lines=list.map((s,i)=>`${i+1}. ${s.filename} (${Math.round(s.size/1024)} KB)`).join('\n');
    const choice=prompt(`Savepoints in data/savepoints/:\n\n${lines}\n\nEnter number 1–${list.length}:`);
    const idx=parseInt(choice,10)-1;
    if(idx<0||idx>=list.length||Number.isNaN(idx)){
      alert('Cancelled or invalid number.');
      return;
    }
    const fn=list[idx].filename;
    if(!confirm(`Replace ALL data for "${u}" with:\n${fn} ?`))return;
    const dr=await fetch(`${apiBase}/api/savepoint-file/${encodeURIComponent(u)}/${encodeURIComponent(fn)}`);
    if(!dr.ok){
      alert('Failed to load checkpoint file.');
      return;
    }
    const raw=await dr.json();
    const data=normalizeImportedGraphData(raw);
    if(!data||(!data.nodes?.length&&!data.edges?.length)){
      alert('Checkpoint file has no usable nodes/edges.');
      return;
    }
    data.lastSaved=new Date().toISOString();
    (await ST.saveToIndexedDB(u,data))||ST.saveToLocalStorage(u,data);
    await ST.save(u,data);
    const f=document.getElementById('save-flash');
    if(f){
      f.textContent='✓ Checkpoint restored';
      f.classList.add('show');
      clearTimeout(f._t);
      f._t=setTimeout(()=>{f.classList.remove('show');f.textContent='✓ Saved'},3000);
    }
    initLg();
  }catch(e){
    alert(e.message||String(e));
  }
}

// Export all users to data/ folder (uses IndexedDB or localStorage fallback when file://)
async function exportAllToDataFolder(){
  try{
    if(!db)await initDB().catch(()=>{});
    // Get users from IndexedDB or localStorage
    let users=[];
    if(db){
      try{
        const tx=db.transaction(['users'],'readonly');
        const store=tx.objectStore('users');
        const request=store.getAll();
        users=await new Promise((resolve,reject)=>{
          request.onsuccess=()=>resolve(request.result.filter(r=>!r.username.includes('_sp_')));
          request.onerror=()=>resolve([]);
        });
      }catch(e){}
    }
    if(users.length===0)users=ST.usersFromLocalStorage().map(u=>({username:u.u,data:ST.loadFromLocalStorage(u.u)})).filter(r=>r.data);
    if(users.length===0){
      alert('No users to export');
      return;
    }
    await ST._restoreDirectoryHandle();
    const apiBase=window.location.protocol==='file:'?'http://localhost:3000':'';
    const writeUsersViaDirectory=async()=>{
      if(!directoryHandle)return 0;
      let exported=0;
      for(const user of users){
        try{
          const key=canonicalUserStorageKey(user.username);
          const fileName=`${key}_data.json`;
          const fileHandle=await directoryHandle.getFileHandle(fileName,{create:true});
          const writable=await fileHandle.createWritable();
          await writable.write(JSON.stringify(user.data,null,2));
          await writable.close();
          exported++;
        }catch(e){
          console.error(`Failed to export ${user.username}:`,e);
        }
      }
      return exported;
    };
    if(directoryHandle){
      const ex=await writeUsersViaDirectory();
      if(ex>0){
        const f=document.getElementById('save-flash');
        if(f){
          f.textContent=`Exported ${ex} user(s)!`;
          f.classList.add('show');
          clearTimeout(f._t);
          f._t=setTimeout(()=>{
            f.classList.remove('show');
            f.textContent='✓ Saved';
          },2000);
        }
        return;
      }
    }
    let serverOk=0;
    for(const user of users){
      const key=canonicalUserStorageKey(user.username);
      try{
        const r=await fetch(`${apiBase}/api/data/${encodeURIComponent(key)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(user.data)});
        if(r.ok)serverOk++;
      }catch(e){}
    }
    if(serverOk===users.length){
      const f=document.getElementById('save-flash');
      if(f){
        f.textContent=`Exported ${serverOk} user(s) to data/`;
        f.classList.add('show');
        clearTimeout(f._t);
        f._t=setTimeout(()=>{
          f.classList.remove('show');
          f.textContent='✓ Saved';
        },2000);
      }
      return;
    }
    if('showDirectoryPicker' in window){
      if(!directoryHandle){
        if(!await ST.acquireWritableDataDirectoryInteractive())return;
      }
      const exPick=await writeUsersViaDirectory();
      if(exPick>0){
        const f=document.getElementById('save-flash');
        if(f){
          f.textContent=`Exported ${exPick} user(s)!`;
          f.classList.add('show');
          clearTimeout(f._t);
          f._t=setTimeout(()=>{
            f.classList.remove('show');
            f.textContent='✓ Saved';
          },2000);
        }
        return;
      }
      alert('Failed to export users to the selected folder.');
      return;
    }
    for(let i=0;i<users.length;i++){
      const user=users[i];
      const blob=new Blob([JSON.stringify(user.data,null,2)],{type:'application/json'});
      const url=URL.createObjectURL(blob);
      const a=document.createElement('a');
      a.href=url;
      a.download=`${canonicalUserStorageKey(user.username)}_data.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      if(i<users.length-1)await new Promise(r=>setTimeout(r,200));
    }
    alert(`Downloaded ${users.length} user file(s). Please save them to your data/ folder.`);
  }catch(err){
    console.error('Export error:',err);
    alert('Export failed: '+(err.message||String(err)));
  }
}
