const _lgRandAdj=['peaceful','wild','silent','golden','ancient','brave','gentle','quiet','bright','calm','cozy','misty','rocky','sandy','stormy','lunar','solar','emerald','sapphire','velvet'];
const _lgRandLoc=['ocean','forest','mountain','valley','river','meadow','island','desert','harbor','cave','canyon','glacier','lagoon','reef','prairie','tundra','volcano','grove','fjord','delta'];
const _lgRandNounA=['adventure','journey','dream','whisper','horizon','compass','pathway','wanderer','melody','echo','lantern','vessel','timber','canvas','story','voyage','summit'];
const _lgRandAdv=['excitingly','softly','boldly','quietly','swiftly','gently','wildly','brightly','slowly','freely','deeply','lightly','steadily','merrily','deftly'];
const _lgRandVerb=['dancing','wandering','dreaming','soaring','drifting','glowing','flowing','leaping','shining','resting','hunting','building','sailing','twirling','gathering'];
const _lgRandNounB=['sealion','dolphin','falcon','otter','badger','heron','maple','thunder','riverstone','coral','aurora','willow','cedar','ember','starlight'];
function _lgPick(a){return a[Math.floor(Math.random()*a.length)]}
function randomLoginSlug(){
  if(Math.random()<0.5)return `${_lgPick(_lgRandAdj)}-${_lgPick(_lgRandLoc)}-${_lgPick(_lgRandNounA)}`;
  return `${_lgPick(_lgRandAdv)}-${_lgPick(_lgRandVerb)}-${_lgPick(_lgRandNounB)}`;
}
function rollLoginName(){
  const inp=document.getElementById('lg-name'),btn=document.getElementById('lg-dice');
  if(!inp)return;
  if(btn){
    btn.classList.remove('rolling');
    void btn.offsetWidth;
    btn.classList.add('rolling');
    setTimeout(()=>{btn.classList.remove('rolling')},450);
  }
  inp.value=randomLoginSlug();
  loginSelectedIndex=-1;
  updateLoginSelection();
}
function lgShakeNameTaken(inp,msg){
  if(!inp)return;
  inp.classList.remove('lg-name-shake','lg-name-warn');
  void inp.offsetWidth;
  inp.classList.add('lg-name-shake','lg-name-warn');
  inp.setAttribute('title',msg||'This name is already in use. Pick a different name, or open your profile from the list below.');
  const onEdit=()=>{
    inp.classList.remove('lg-name-warn');
    inp.removeEventListener('input',onEdit);
    inp.removeEventListener('keydown',onEdit);
    inp.removeAttribute('title');
  };
  inp.addEventListener('input',onEdit,{once:true});
  inp.addEventListener('keydown',onEdit,{once:true});
  setTimeout(()=>inp.classList.remove('lg-name-shake'),600);
}
async function doLogin(){
  const inp=document.getElementById('lg-name');
  if(!inp)return;
  const n=inp.value.trim();
  if(!n)return;
  const u=n.toLowerCase().replace(/[^a-z0-9_-]/g,'').slice(0,50);
  if(!u)return;
  const cu=canonicalUserStorageKey(u);
  if(isTemplateUserStorageKey(cu)){
    alert('The name "template-user" is reserved for built-in default settings. Choose a different username.');
    return;
  }
  const [raw,users]=await Promise.all([ST.load(cu),ST.users()]);
  const d=raw?finalizeLoadedUserGraph(raw)||raw:null;
  const loadedHas=d&&(graphNodeCount(d)>0||graphEdgeCount(d)>0);
  if(loadedHas){
    loginAs(u,n);
    return;
  }
  const row=users.find(x=>canonicalUserStorageKey(x.u)===cu);
  if(row&&row.c>0){
    lgShakeNameTaken(inp);
    return;
  }
  loginAs(u,n);
}
async function loginAs(u,dn){
  const cu=canonicalUserStorageKey(u);
  if(isTemplateUserStorageKey(cu)){
    alert('The name "template-user" is reserved for built-in default settings. Choose a different username.');
    return;
  }
  if(CU!==null&&CU!==cu)pageAgentsResetForUserChange();
  CU=cu;
  const raw=await ST.load(CU);
  const d=raw?finalizeLoadedUserGraph(raw)||raw:null;
  if(d&&(graphNodeCount(d)>0||graphEdgeCount(d)>0)){
    const material=finalizeLoadedUserGraph(d)||d;
    walkAndFixMojibake(material);
    G=material;dirtyNodeMap();
    if(!Array.isArray(G.nodes)){
      const n=G.nodes;
      G.nodes=n&&typeof n==='object'&&!Array.isArray(n)?Object.values(n):[];
    }
    if(!Array.isArray(G.edges)){
      const e=G.edges;
      G.edges=e&&typeof e==='object'&&!Array.isArray(e)?Object.values(e):[];
    }
    if(!G.workspaces)G.workspaces=[{id:'home',name:'Home',icon:'🏠'}];
    if(!G.cws)G.cws='home';
    G.autoSave=G.autoSave!==false;
    if(!('tutorialNotes' in G))G.tutorialNotes=true;
    if(!G.todayGoals)G.todayGoals={};
    if(!Array.isArray(G.notesCatalogHidden))G.notesCatalogHidden=[];
    if(!('notesCatalogHideCompletedNotes' in G))G.notesCatalogHideCompletedNotes=true;
    if(!G.expandPages)G.expandPages=[];
    if('todoList' in G&&!Array.isArray(G.todoList))G.todoList=[];
    if(!Array.isArray(G.todoPool))G.todoPool=[];
    if(G.todoActiveTab!=='pool')G.todoActiveTab='today';
    if(!('todoHideCompleted' in G))G.todoHideCompleted=false;
    if(!('todoDaysCompleted' in G))G.todoDaysCompleted=null;
    migrateLegacyTodoLocalStorageOnce();
    syncTodoStateFromGraph();
  // Initialize sphereOpen status for all nodes if not present
  G.nodes.forEach(n=>{if(n.sphereOpen===undefined)n.sphereOpen=false});
  // Initialize TBD property for all nodes if not present
  G.nodes.forEach(n=>{if(n.TBD===undefined)n.TBD='none'});
  G.nodes.forEach(n=>{if(n.nah===undefined)n.nah=false});
  // Initialize type property for all nodes if not present (migration)
  G.nodes.forEach(n=>{
    if(!n.type){
      n.type=getDefaultTypeFromTitle(n.name);
    }
  });
  mergeDuplicateMeetingNodes();
    viewStack=[];expandedId=null;expandedIds=new Set();rpLevel=0;show('app');
    // Blur login input and focus canvas to ensure keyboard events work immediately
    const loginInput=document.getElementById('lg-name');
    if(loginInput)loginInput.blur();
    // Make canvas focusable and focus it
    const canvasEl=document.getElementById('canvas');
    if(canvasEl){
      canvasEl.setAttribute('tabindex','0');
      canvasEl.style.outline='none';
      // Use setTimeout to ensure this happens after screen transition
      setTimeout(()=>{
        canvasEl.focus();
      },50);
    }
    initApp();
    updateLeftSidebarVisibility();
  }else{
    // Hosted mode: if the cloud load errored (network/auth/5xx, not a clean 404),
    // do NOT create a starter graph — that would overwrite real cloud data on the
    // next save. Bail back to login so the user can retry.
    if(window.__PUBLIC_MODE__&&ST._publicLoadError){
      CU=null;
      if(typeof publicAuthMsg==='function')publicAuthMsg('Couldn’t load your account data — check your connection and try again.',true);
      else try{alert('Couldn’t load your account data — check your connection and try again.');}catch(_){}
      return;
    }
    const shell=await loadNewUserShell();
    G=shell;
    G.displayName=dn||u;
    if(!G.workspaces)G.workspaces=[{id:'home',name:'Home',icon:'🏠'}];
    if(!G.cws)G.cws='home';
    G.autoSave=G.autoSave!==false;
    if(!('tutorialNotes' in G))G.tutorialNotes=true;
    if(!G.todayGoals)G.todayGoals={};
    if(!Array.isArray(G.notesCatalogHidden))G.notesCatalogHidden=[];
    if(!('notesCatalogHideCompletedNotes' in G))G.notesCatalogHideCompletedNotes=true;
    if(!Array.isArray(G.expandPages))G.expandPages=['progress','pathbehind','pagetree','pageagents','pageinterstellar'];
    if('todoList' in G&&!Array.isArray(G.todoList))G.todoList=[];
    if(!Array.isArray(G.todoPool))G.todoPool=[];
    if(G.todoActiveTab!=='pool')G.todoActiveTab='today';
    if(!('todoHideCompleted' in G))G.todoHideCompleted=false;
    if(!('todoDaysCompleted' in G))G.todoDaysCompleted=null;
    show('wiz');initWiz()
  }
}
