  if(!cat)return;
  const used=new Set(cat.tasks.map(t=>wizTaskText(t).toLowerCase()).filter(Boolean));
  cloud.querySelectorAll('.w1-node').forEach(node=>{
    const nm=(node.getAttribute('data-name')||'').toLowerCase();
    const on=used.has(nm);
    node.classList.toggle('w1-node--used',on);
    node.draggable=!on;
  });
