function wizTierForCatName(name){
  const lc=String(name||'').toLowerCase().trim();
  const hit=WIZ_CATEGORY_SUGGESTIONS.find(s=>String(s.name||'').toLowerCase()===lc);
  return hit?hit.tier:1;
}
function wizNameHintMatch(catName,hint){
  const n=String(catName||'').toLowerCase().trim();
  const h=String(hint||'').toLowerCase().trim();
  return n===h||n.includes(h)||h.includes(n);
}
function wizFindCatForHints(hints){
  for(const h of hints){
    const hit=wCats.find(c=>wizNameHintMatch(c.name,h));
    if(hit)return hit;
  }
  return null;
}
function wizWouldCreateCycle(childId,wantParentId){
  if(!wantParentId||childId===wantParentId)return true;
  let p=wantParentId;
  const seen=new Set();
  for(let guard=0;guard<80&&p;guard++){
    if(p===childId)return true;
    if(seen.has(p))break;
    seen.add(p);
    const node=wCats.find(x=>x.id===p);
    if(!node)break;
    p=node.parentId||null;
  }
  return false;
}
function wizNestDrop(targetCatId,ev){
  if(ev){
    ev.preventDefault();
    const pill=ev.currentTarget;
    if(pill&&pill.style)pill.style.borderColor='';
  }
  const dragId=window._ndid;
  if(!dragId||dragId===targetCatId)return;
  if(wizWouldCreateCycle(dragId,targetCatId))return;
  const x=wCats.find(z=>z.id===dragId);
  if(x)x.parentId=targetCatId;
  window._ndid=null;
  rNT();
}
function wizNestRootDrop(ev){
  if(ev){
    ev.preventDefault();
    if(ev.currentTarget&&ev.currentTarget.style)ev.currentTarget.style.borderColor='var(--bdr)';
  }
  const x=wCats.find(z=>z.id===window._ndid);
  if(x)x.parentId=null;
  window._ndid=null;
  rNT();
}
function wizApplyAutoNest(ev){
  if(ev)ev.preventDefault();
  for(const pack of WIZ_SEMANTIC_PACKS){
    const U=wizFindCatForHints(pack.umbrella);
    if(!U)continue;
    if(pack.members){
      for(const m of pack.members){
        const C=wizFindCatForHints([m]);
        if(!C||C.id===U.id)continue;
        if(!wizWouldCreateCycle(C.id,U.id))C.parentId=U.id;
      }
    }
    if(pack.chains){
      for(const ch of pack.chains){
        const P=wizFindCatForHints(ch.parent||[]);
        if(!P)continue;
        for(const childHint of ch.children||[]){
          const K=wizFindCatForHints([childHint]);
          if(!K||K.id===P.id)continue;
          if(!wizWouldCreateCycle(K.id,P.id))K.parentId=P.id;
        }
      }
    }
  }
  rNT();
}
function placeWizardChromeInStructureHead(){
  const head=document.querySelector('#wbod .w1-wrap .w1-front > .w1-head');
  const wh=document.querySelector('.wh');
  const dots=document.getElementById('wdots');
  if(!head||!wh||!dots)return;
  head.insertBefore(wh,head.firstChild);
  head.insertBefore(dots,wh.nextSibling);
}
