function rWCL(){const l=document.getElementById('wcl');if(!l)return;l.innerHTML=wCats.map((c,i)=>`<div class="cpill"><div class="cd" style="background:${c.color}"></div><span class="cn">${esc(c.name)}</span><span class="nb">${c.tasks.length}</span><button class="cr" onclick="wCats.splice(${i},1);rWCL();syncWizCloudUsed()">×</button></div>`).join('');requestAnimationFrame(()=>{w1NudgeNodesFromExclusion();const w=document.getElementById('wcl');if(w)w.scrollTop=w.scrollHeight})}
