function isHelpVoiceContinueIntent(text){
  const tl=(text||'').trim().toLowerCase();
  return /^(continue|go\s+on|keep\s+going|finish|never\s+mind|resume)$/i.test(tl)||/^just\s+continue$/i.test(tl);
}
function speakHelpReply(plainText){
  /* Voice help: text-only output in chatbox, no speaker. Kept for API compatibility. */
  if(plainText) helpLastSpokenReply=plainText;
}
function startHelpVoiceListenAfterSpeak(){
  if(!helpVoiceRecognition)return;
  helpVoiceListenAfterSpeakMode=true;
  const btn=document.getElementById('help-voice-btn');
  if(btn){ btn.classList.add('recording'); btn.title='Listening… (speak to interrupt or say "continue")'; }
  try{ helpVoiceRecognition.start(); }catch(err){ helpVoiceListenAfterSpeakMode=false; if(btn){ btn.classList.remove('recording'); btn.title='Voice: click to record, transcribe and send to help chat'; } }
}
function sendHelpChatMessage(fromVoice){
  if(window.speechSynthesis) speechSynthesis.cancel();
  const inp=document.getElementById('help-chat-inp');
  const text=(inp.value||'').trim();
  if(!text)return;
  appendHelpChatMessage('user',text);
  inp.value='';
  const result=executeHelpChatCommand(text);
  let reply='';
  if(result!==null){
    reply=result;
  }else{
    reply='Got it. Add a task (e.g. "add a task named \'see eye doctor\'" or "prep slides for anthony lab meeting"), then say "mark that done" or "completed" to mark it completed.';
  }
  /* Voice help: text-only in chatbox; report completed-task results as bullet points */
  if(reply&&reply.indexOf('\n')===-1) reply='• '+reply;
  appendHelpChatMessage('bot',reply);
}

/* ── Help voice (record → transcribe → send to chat) ── */
var helpVoiceRecognition=null;
var helpVoiceRecording=false;
function toggleVoiceHelp(){
  if(window.speechSynthesis) speechSynthesis.cancel();
  const SpeechRecognitionAPI=window.SpeechRecognition||window.webkitSpeechRecognition;
  if(!SpeechRecognitionAPI){
    if(!document.getElementById('help-chat-box').classList.contains('open')) toggleHelpChat();
    appendHelpChatMessage('bot','Voice input is not supported in this browser. Try Chrome or Edge.');
    return;
  }
  const btn=document.getElementById('help-voice-btn');
  const bz=document.getElementById('b-zone');
  const chatBox=document.getElementById('help-chat-box');
  const inp=document.getElementById('help-chat-inp');
  if(helpVoiceRecording&&helpVoiceRecognition){
    helpVoiceListenAfterSpeakMode=false;
    helpVoiceRecognition.stop();
    return;
  }
  bz.classList.add('vis');
  if(!chatBox.classList.contains('open')) toggleHelpChat();
  if(!helpVoiceRecognition){
    helpVoiceRecognition=new SpeechRecognitionAPI();
    helpVoiceRecognition.continuous=false;
    helpVoiceRecognition.interimResults=false;
    helpVoiceRecognition.lang='en-US';
    helpVoiceRecognition.onstart=function(){ helpVoiceRecording=true; const b=document.getElementById('help-voice-btn'); if(b){ b.classList.add('recording'); b.title=helpVoiceListenAfterSpeakMode?'Listening… (speak to interrupt or say "continue")':'Listening… Click to stop'; } };
    helpVoiceRecognition.onend=function(){ helpVoiceRecording=false; const b=document.getElementById('help-voice-btn'); if(b){ b.classList.remove('recording'); b.title='Voice: click to record, transcribe and send to help chat'; } if(helpVoicePendingListenAfterSpeak){ helpVoicePendingListenAfterSpeak=false; startHelpVoiceListenAfterSpeak(); } };
    helpVoiceRecognition.onerror=function(e){
      helpVoiceRecording=false;
      const b=document.getElementById('help-voice-btn'); if(b){ b.classList.remove('recording'); b.title='Voice: click to record, transcribe and send to help chat'; }
      if(e.error==='not-allowed') appendHelpChatMessage('bot','Microphone access was denied. Allow mic in browser settings and try again.');
      else if(e.error!=='aborted') appendHelpChatMessage('bot','Voice error: '+e.error);
    };
    helpVoiceRecognition.onresult=function(e){
      if(window.speechSynthesis) speechSynthesis.cancel();
      const r=e.results[e.resultIndex];
      if(r&&!r.isFinal) return;
      const transcript=(r&&r[0])?r[0].transcript:'';
      const text=transcript.trim();
      if(!text) return;
      if(helpVoiceListenAfterSpeakMode&&isHelpVoiceContinueIntent(text)){ return; }
      const inEl=document.getElementById('help-chat-inp');
      if(inEl){ inEl.value=text; sendHelpChatMessage(true); }
    };
  }
  helpVoiceListenAfterSpeakMode=false;
  helpVoiceRecognition.start();
}

/* ── Search ── */
let srMode=false,srVS=[];
function doSearch(){const q=document.getElementById('s-inp').value.trim().toLowerCase();if(!q){exitSearch();return}srVS=[...viewStack];srMode=true;
  const res=G.nodes.filter(n=>!n.notesTabOnly&&(n.name.toLowerCase().includes(q)||(n.description||'').toLowerCase().includes(q)));
  rSR(res)}
function doCalendarSearch(){
  const q=document.getElementById('rp-s-inp').value.trim().toLowerCase();
  if(!q){exitSearch();return}
  srVS=[...viewStack];
  srMode=true;
  const res=G.nodes.filter(n=>!n.notesTabOnly&&(n.name.toLowerCase().includes(q)||(n.description||'').toLowerCase().includes(q)));
  rSR(res);
}
function doRightPanelSearch(){
  const q=document.getElementById('rp-s-inp').value.trim().toLowerCase();
  if(!q){exitSearch();return}
  srVS=[...viewStack];
  srMode=true;
  // Search through all nodes (including nested ones) in name, description, and notes
  const res=G.nodes.filter(n=>{
    if(n.notesTabOnly)return false;
    const nameMatch=n.name.toLowerCase().includes(q);
    const descMatch=(n.description||'').toLowerCase().includes(q);
    const notesMatch=(n.postEventNotes||'').toLowerCase().includes(q)||(n.postEventNotesByDate&&Object.values(n.postEventNotesByDate).some(t=>(t||'').toLowerCase().includes(q)));
    return nameMatch||descMatch||notesMatch;
  });
  rSR(res);
}
function exitSearch(){srMode=false;const inp=document.getElementById('rp-s-inp');if(inp)inp.value='';rPanel()}
function rSR(res){
  // Filter completed tasks if hideCompleted is enabled
  const filteredRes=res.filter(n=>shouldShowCompletedTask(n));
  const b=document.getElementById('rp-body');
  const rpTitle=document.getElementById('rp-title');
  
  // Add star icon to title (same as in rPanel)
  const starColor=hideCompleted?'#ffeb3b':'#888888';
  const starFilter=hideCompleted?'drop-shadow(0 0 2px rgba(255,235,59,0.5))':'none';
  rpTitle.innerHTML=`<span>Search (${filteredRes.length})</span><span class="rt-hide-completed" onclick="event.stopPropagation();${hideCompleted?'showHideCompletedDropdown(event)':'toggleHideCompleted()'}" title="${hideCompleted?'Show completed tasks':'Hide completed tasks'}" style="margin-left:8px;cursor:pointer;font-size:16px;color:${starColor};filter:${starFilter};position:relative">✦</span>`;
  
  b.innerHTML=filteredRes.length?filteredRes.map(n=>`<div class="nh" draggable="true" ondragstart="event.dataTransfer.setData('text/plain','${n.id}');event.dataTransfer.effectAllowed='move';this.style.opacity='0.5'" ondragend="this.style.opacity='1'" onclick="navTo('${n.id}');exitSearch()" style="cursor:move"><button class="rt-act rt-add-todo" onclick="event.stopPropagation();addToTodoList('${n.id}')" title="Add to Today's to-do list" style="opacity:0.6;margin-right:4px;padding:2px 6px;font-size:16px;line-height:1">+</button><div class="nd" style="background:${n.color}"></div><div class="nn">${esc(n.name)}</div><div class="nb" style="font-size:9px">${esc(nPath(n.id).map(x=>x.name).join(' › '))}</div></div>`).join(''):'<p style="color:var(--t3);text-align:center;padding:20px">No results</p>'
}

/* ── Right panel: recursive task tree ── */
function rpNavUp(){
  // Navigate up level - show parent-level nodes (without changing main screen)
  if(rpLevel>0){
    rpLevel--;
    // Just update the panel, don't change main screen nodes
    rPanel();
    // Refocus main screen to center all nodes
    setTimeout(()=>{
      zFit();
    },100);
  }else if(viewStack.length>0){
    // Go up view stack - just update panel level
    if(viewStack.length>0){
      viewStack.pop();
      if(viewStack.length>0)rpLevel=1;
      else rpLevel=0;
    }
    rPanel();
    // Refocus main screen to center all nodes
    setTimeout(()=>{
      zFit();
    },100);
  }
}
function rpNavDown(){
  // Navigate down level - show children (without changing main screen)
  if(rpLevel===0){
    // Find first expanded node to show its children
    if(expandedId){
    rpLevel=1;
    rPanel();
    }else if(expandedIds.size>0){
      // Use first expanded node
      const firstExpanded=Array.from(expandedIds)[0];
      expandedId=firstExpanded;
      rpLevel=1;
      rPanel();
    }
  }else if(rpLevel===1&&expandedId){
    // Go deeper - find first child node
    const kids=ch(expandedId);
    if(kids.length>0){
      viewStack.push(expandedId);
      expandedId=kids[0].id;
      rpLevel=2; // Deeper level
      rPanel();
    }
  }
}
function rPanel(){
  if(srMode)return;
  Object.keys(npExp).forEach(k=>{
    if(k.endsWith('_notes')&&npExp[k]){
      const nodeId=k.replace(/_notes$/,'');
      saveInlineNoteBeforeJump(nodeId);
    }
  });
  const b=document.getElementById('rp-body');
  let nodes,parentNode;
  
  // Special handling for PathBehind view - show completed tasks
  if(currentView==='pathbehind'){
    const dateSelector=document.getElementById('pathbehind-date-selector');
    const selectedDate=dateSelector?.value||null;
    
    // Get all completed tasks
    nodes=G.nodes.filter(n=>n.status==='completed');
    
    // Filter by date if viewing by day
    if(selectedDate){
      const targetDate=new Date(selectedDate);
      const targetDateStr=targetDate.toDateString();
      nodes=nodes.filter(n=>{
        if(!n.completedAt)return false;
        const completedDate=new Date(n.completedAt);
        return completedDate.toDateString()===targetDateStr;
      });
    }
    
    // Sort by completion date (most recent first)
    nodes.sort((a,b)=>{
      const dateA=a.completedAt?new Date(a.completedAt).getTime():0;
      const dateB=b.completedAt?new Date(b.completedAt).getTime():0;
      return dateB-dateA;
    });
    
    parentNode=null;
    const rpTitle=document.getElementById('rp-title');
    rpTitle.textContent=selectedDate?`Completed Tasks (${nodes.length})`:`All Completed Tasks (${nodes.length})`;
    
    // Render completed tasks
    if(nodes.length===0){
      b.innerHTML='<p style="color:var(--t3);text-align:center;padding:16px;font-size:14px">No completed tasks'+(selectedDate?' for this day':' yet')+'.</p>';
    }else{
      b.innerHTML=nodes.map(n=>renderCompletedTaskItem(n)).join('');
    }
    
    // Hide todo section for pathbehind view
    const todoSection=document.getElementById('rp-todo-section');
    if(todoSection)todoSection.style.display='none';
    
    return;
  }
  
  if(currentView==='pagetree'){
    const rpTitle=document.getElementById('rp-title');
    if(rpTitle)rpTitle.textContent='Tree';
    const nodes=collectPageTreeNodes();
    if(nodes.length===0){
      b.innerHTML='<p style="color:var(--t3);text-align:center;padding:16px;font-size:14px">No nodes in this home view yet.</p>';
    }else{
      b.innerHTML=nodes.slice(0,40).map(n=>`<div class="rt-item" style="padding:10px 12px;border-bottom:1px solid var(--bdr);cursor:pointer" onclick="swView('home');setTimeout(function(){navTo(${JSON.stringify(n.id)})},80)"><span style="color:${esc(n.color||'#6c63ff')}">●</span> ${esc(n.name||'')}</div>`).join('')+(nodes.length>40?`<p style="color:var(--t3);padding:12px;font-size:13px">…and ${nodes.length-40} more (see Tree page)</p>`:'');
    }
    const todoSection=document.getElementById('rp-todo-section');
    if(todoSection)todoSection.style.display='none';
    return;
  }
  if(currentView==='pageinterstellar'){
    const rpTitle=document.getElementById('rp-title');
    if(rpTitle)rpTitle.textContent='Interstellar';
    b.innerHTML='<p style="color:var(--t3);text-align:center;padding:16px;font-size:14px">Use the main panel for this page.</p>';
    const todoSection=document.getElementById('rp-todo-section');
    if(todoSection)todoSection.style.display='none';
    return;
  }
  
  // Always show all tasks whose nodes are visible on main screen
  // At root level (rpLevel=0): show all visible nodes
  if(rpLevel===0){
    nodes=visN(); // All visible nodes on main screen
    parentNode=null;
  }
  // At level 1: show children of the primary expanded node
  else if(rpLevel===1&&expandedId){
    nodes=ch(expandedId);
    parentNode=G.nodes.find(n=>n.id===expandedId);
  }
  // Deeper levels (future expansion)
  else{
    nodes=[];
    parentNode=null;
  }
  
  // Apply "show by" filter if set
  if(showByFilter){
    const {filteredTaskIds,filteredNoteIds}=getFilteredTaskIds();
    
    // Filter nodes to only include those in our filtered set
    nodes=nodes.filter(n=>{
      if(isTaskNode(n)){
        return filteredTaskIds.has(n.id);
      }else{
        return filteredNoteIds.has(n.id);
      }
    });
  }
  
  const rpTitle=document.getElementById('rp-title');
  const titleText=parentNode?esc(parentNode.name):'Categories';
  const isCategoriesView=!parentNode;
  
  // Check if all nodes at current level are expanded (only nodes with children)
  let allExpanded=false;
  if(nodes.length>0){
    const nodesWithChildren=nodes.filter(n=>ch(n.id).length>0);
    allExpanded=nodesWithChildren.length>0&&nodesWithChildren.every(n=>npExp[n.id]);
  }
  
  // Update title with dropdown arrow and hide completed toggle (always show at all levels)
  // Star is lit (yellow) when hiding completed, grey when showing completed
  const starColor=hideCompleted?'#ffeb3b':'#888888';
  const starFilter=hideCompleted?'drop-shadow(0 0 2px rgba(255,235,59,0.5))':'none';
  rpTitle.innerHTML=`<span>${titleText}</span><span class="rt-category-arrow" onclick="event.stopPropagation();toggleAllAtCurrentLevel(${allExpanded})" title="${allExpanded?'Collapse':'Expand'} all task tabs" style="margin-left:8px;cursor:pointer">${allExpanded?'▾':'▸'}</span><span class="rt-hide-completed" onclick="event.stopPropagation();${hideCompleted?'showHideCompletedDropdown(event)':'toggleHideCompleted()'}" title="${hideCompleted?'Show completed tasks':'Hide completed tasks'}" style="margin-left:8px;cursor:pointer;font-size:16px;color:${starColor};filter:${starFilter};position:relative">✦</span>`;
  
  // Back/forward buttons always clickable
  document.getElementById('rp-up').disabled=false;
  document.getElementById('rp-down').disabled=rpLevel===0||!expandedId||!ch(expandedId).length;
  
  // Filter completed tasks if hideCompleted is enabled
  const nodesToRender=nodes.filter(n=>shouldShowCompletedTask(n));
  
  // Render nodes (no unpack all section)
  b.innerHTML=nodesToRender.map(n=>renderTreeItem(n,0)).join('');
  
  // Always add input box at the end (only for current level) - replace button with input
  if(parentNode){
    if(!nodes.length) b.innerHTML='<p style="color:var(--t3);text-align:center;padding:16px;font-size:14px">No nodes here.</p>';
    b.innerHTML+=`<div class="rt-add" style="margin-top:8px"><input id="rt-input-${parentNode.id}-root" placeholder="Add task..." onkeydown="if(event.key==='Enter'){event.preventDefault();event.stopPropagation();const inp=this;addFromPanel('${parentNode.id}',inp.value,false);inp.value='';setTimeout(()=>inp.focus(),10)}" onclick="event.stopPropagation()"><button onclick="event.stopPropagation();const i=document.getElementById('rt-input-${parentNode.id}-root');addFromPanel('${parentNode.id}',i.value,false);i.value='';setTimeout(()=>i.focus(),10)">+</button></div>`;
  }else{
    if(!nodes.length) b.innerHTML='<p style="color:var(--t3);text-align:center;padding:16px;font-size:14px">No nodes here.</p>';
    b.innerHTML+=`<div class="rt-add" style="margin-top:8px"><input id="rt-input-root" placeholder="Add task..." onkeydown="if(event.key==='Enter'){event.preventDefault();event.stopPropagation();const inp=this;addFromRootPanel(inp.value);inp.value='';setTimeout(()=>inp.focus(),10)}" onclick="event.stopPropagation()"><button onclick="event.stopPropagation();const i=document.getElementById('rt-input-root');addFromRootPanel(i.value);i.value='';setTimeout(()=>i.focus(),10)">+</button></div>`;
  }
  
  // Show todo section if there are any todos
  const todoSection=document.getElementById('rp-todo-section');
  if(todoSection){
    // Handle day transition (remove completed tasks, keep unchecked ones)
    handleDayTransition();
    // Auto-add today's calendar events to todo list
    autoAddTodayCalendarEventsToTodoList();
    todoSection.style.display='block';
    // Initialize position if not already set
    if(!todoSection.style.top||todoSection.style.top===''){
      const rpPanel=document.getElementById('rp');
      const rpHeader=document.querySelector('.rp-h');
      const rpSearch=document.getElementById('rp-search-container');
      const headerHeight=rpHeader?rpHeader.offsetHeight:0;
      const searchHeight=rpSearch&&rpSearch.style.display!=='none'?rpSearch.offsetHeight:0;
      const headerTotalHeight=headerHeight+searchHeight;
      // Default to bottom of panel, but allow it to be positioned higher
      const defaultHeight=300;
      const defaultTop=Math.max(headerTotalHeight+10,rpPanel.offsetHeight-defaultHeight);
      todoSection.style.top=defaultTop+'px';
      todoSection.style.maxHeight=(rpPanel.offsetHeight-defaultTop)+'px';
    }
    renderTodoList();
    loadTodayGoals();
  }
  
  // Set up drag and drop handlers
  setupTaskDragAndDrop();
  setupRightPanelDragAndDrop();
  refreshInlineNoteEditorsInRPanel();
  // Wire dwell-tooltip on the task bar (truncated names → full text on hover) and
  // reserve scroll headroom under the absolutely-positioned today's-to-do overlay.
  bindTaskHoverTooltipOn(document.getElementById('rp-body'));
  adjustRpBodyForTodoOverlay();
}

function renderTreeItem(n, depth) {
  const kids=ch(n.id);
  const leaf=isL(n.id);
  const{t,d}=aggP(n.id);
  const pct=t?Math.round(d/t*100):0;
  const isComplete=n.status==='completed';
  const exp=npExp[n.id];
  const hasContent=kids.length>0;
  const notesOpen=npExp[n.id+'_notes']||false;
  const notes=getNoteContentForNode(n,null)||'';
  const notesDisplayHtml=notesOpen?getEditableNoteContentForInline(notes):formatNoteContentForPreview(notes);
  const notesPlainText=notes?(()=>{
    const tempDiv=document.createElement('div');
    tempDiv.innerHTML=notes;
    return tempDiv.textContent||tempDiv.innerText||'';
  })():'';

  let childrenHTML='';
  if(exp){
    // Show sub-nodes as nested tree items (recursive)
    if(kids.length){
      // Filter completed tasks if hideCompleted is enabled
      const kidsToRender=kids.filter(k=>shouldShowCompletedTask(k));
      childrenHTML=kidsToRender.map(k=>renderTreeItem(k,depth+1)).join('');
    }
    // Add task input
    childrenHTML+=`<div class="rt-add"><input id="rt-input-${n.id}" placeholder="Add task..." onkeydown="if(event.key==='Enter'){event.preventDefault();event.stopPropagation();const inp=this;addFromPanel('${n.id}',inp.value,false);inp.value='';setTimeout(()=>inp.focus(),10)}" onclick="event.stopPropagation()"><button onclick="event.stopPropagation();const i=document.getElementById('rt-input-${n.id}');addFromPanel('${n.id}',i.value,false);i.value='';setTimeout(()=>i.focus(),10)">+</button></div>`;
  }

  const timer=n.timer||null;
  const timerActive=timer&&timer.endTime>Date.now();
  const pctRemaining=timerActive?timer.remaining/timer.duration:0;
  const circumference=2*Math.PI*12;
  const elapsed=circumference*(1-pctRemaining);
  const remaining=circumference*pctRemaining;
  const timerHTML=timerActive?`<div class="timer-pie-alarm" style="left:4px;top:4px;animation:${pctRemaining<0.2?'pulseAlarm 1s infinite':''}">
    <svg width="30" height="30" style="filter:drop-shadow(0 0 4px ${pctRemaining<0.2?'#ef4444':n.color})">
      <circle cx="12" cy="12" r="10" fill="none" stroke="#22c55e" stroke-width="3" stroke-dasharray="${remaining} ${circumference}" transform="rotate(-90 12 12)" opacity="0.9"/>
      <circle cx="12" cy="12" r="10" fill="none" stroke="#ef4444" stroke-width="3" stroke-dasharray="${elapsed} ${circumference}" transform="rotate(-90 12 12)" opacity="0.9"/>
    </svg>
  </div>`:'';
  // Determine if this is a category (has children)
  const isCategory=hasContent;
  
  return`<div class="rt-item ${isComplete?'completed':''}" style="margin-left:${depth>0?8:0}px;cursor:move" data-nid="${n.id}" draggable="true" ondragstart="event.dataTransfer.setData('text/plain','${n.id}');event.dataTransfer.setData('application/node-link','task');event.dataTransfer.effectAllowed='copyMove';this.style.opacity='0.5'" ondragend="this.style.opacity=''">
    <div class="rt-header" style="position:relative;${timerActive&&pctRemaining<0.2?'background:rgba(239,68,68,0.1);border-left:3px solid #ef4444;':''}">
      ${timerHTML}
      <button class="rt-act rt-add-todo" onclick="event.stopPropagation();addToTodoList('${n.id}')" title="Add to Today's to-do list" style="opacity:0.6;margin-right:4px;padding:2px 6px;font-size:16px;line-height:1">+</button>
      <input type="checkbox" class="rt-check" ${isComplete?'checked':''} onclick="event.stopPropagation();completeNode('${n.id}',this)" style="accent-color:${n.color}">
      <div class="rt-dot" style="background:${n.color}"></div>
      <span class="rt-name ${isComplete?'done':''}" onclick="event.stopPropagation();enterN('${n.id}')" style="${isComplete?'cursor:not-allowed':''}">${esc(n.name)}</span>
      ${t?`<span class="rt-pct">${pct}%</span>`:''}
      ${timerActive?`<span class="rt-pct" style="background:${pctRemaining<0.2?'#ef4444':'var(--ylw)'};color:#000;font-weight:700;animation:${pctRemaining<0.2?'pulseAlarm 1s infinite':''}">${Math.ceil(timer.remaining/60000)}m</span>`:''}
      <div class="rt-acts" style="${isComplete?'opacity:0.3;pointer-events:none':''}">
        <button class="rt-act" onclick="event.stopPropagation();toggleNotes('${n.id}')" title="Notes">📝</button>
        <button class="rt-act" onclick="event.stopPropagation();openTimer('${n.id}')" title="Set timer">⏱️</button>
        <button class="rt-act" onclick="event.stopPropagation();openEdit('${n.id}')" title="Settings">⚙️</button>
        <button class="rt-act" onclick="event.stopPropagation();delN('${n.id}')" title="Delete">🗑</button>
        <button class="rt-act" onclick="event.stopPropagation();npExp['${n.id}']=!npExp['${n.id}'];rPanel()" title="Toggle" style="${!hasContent?'opacity:0.5':''}">${exp?'▾':'▸'}</button>
      </div>
      ${timerHTML}
    </div>
    ${notesOpen?`<div class="rt-notes-box open" data-notes-id="${n.id}"><div class="rt-notes-preview">${notesDisplayHtml}</div><button class="rt-notes-jump-btn" onclick="event.stopPropagation();saveInlineNoteBeforeJump('${n.id}');swView('notes');setTimeout(()=>openNoteEditor('${n.id}'),100)" title="Jump to note page">↗</button></div>`:''}
    ${!notesOpen&&notes?`<div class="rt-notes-mini vis" onclick="toggleNotes('${n.id}')">${esc(notesPlainText.length>50?notesPlainText.slice(0,50)+'...':notesPlainText)}</div>`:''}
    <div class="rt-children ${exp?'open':''}">${childrenHTML}</div>
  </div>`;
}

function renderCompletedTaskItem(n){
  const completedDate=n.completedAt?new Date(n.completedAt):null;
  const dateStr=completedDate?completedDate.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})+' '+completedDate.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'}):'Unknown date';
  
  return`<div class="rt-item completed" style="margin-bottom:8px" data-nid="${n.id}">
    <div class="rt-header" style="position:relative">
      <input type="checkbox" class="rt-check" checked onclick="event.stopPropagation();completeNode('${n.id}',this)" style="accent-color:${n.color}" disabled>
      <div class="rt-dot" style="background:${n.color}"></div>
      <span class="rt-name done" onclick="event.stopPropagation();swView('home');setTimeout(()=>navTo('${n.id}'),100)" style="cursor:pointer">${esc(n.name)}</span>
      <div style="font-size:11px;color:var(--t3);margin-left:8px">${dateStr}</div>
    </div>
  </div>`;
}

function addFromPanel(parentId, text, isLeafTask) {
  text=text.trim(); if(!text)return;
  svWithUndo();
  // Always add as a sub-node (task node)
    const id='n'+Date.now();
  const defaultType=getDefaultTypeFromTitle(text);
  const panelColor=currentView==='home'?randomPaletteColor():P[G.nodes.length%P.length];
  G.nodes.push({id,name:text,color:panelColor,description:'',status:'active',parentId,wsId:G.cws||'home',progress:[],notes:'',sphereOpen:false,routine:false,routineFrequency:null,priority:false,buffer:false,TBD:'none',type:defaultType});
    G.edges.push({source:parentId,target:id});
  sv();render();rPanel();
  // Keep focus on input for next task
  setTimeout(()=>{
    const inp=document.getElementById(`rt-input-${parentId}`);
    if(inp)inp.focus();
  },50);
}

function toggleLeafTask(nodeId, idx, checkbox) {
  svWithUndo();
  const n=G.nodes.find(x=>x.id===nodeId);
  if(!n||!n.progress[idx])return;
  const wasDone=n.progress[idx].done;
  n.progress[idx].done=!wasDone;
  if(!wasDone) firework(checkbox); // celebrate completion!
  sv();render();
  if(currentView==='calendar')renderCalendar();
}

// To-do list state — stored on G (saved with user JSON), not browser-only localStorage
let todayTodos=[];
let poolTodos=[];
let hideCompleted=false;
let daysToShowCompleted=null;

function persistTodoStateToGraph(){
  if(!G)return;
  G.todoList=todayTodos.filter(t=>t&&t.nodeId).map(t=>({nodeId:String(t.nodeId)}));
  G.todoPool=poolTodos.filter(t=>t&&t.nodeId).map(t=>({nodeId:String(t.nodeId)}));
  G.todoHideCompleted=!!hideCompleted;
  G.todoDaysCompleted=daysToShowCompleted;
}

function saveTodoStateToUser(){
  persistTodoStateToGraph();
  if(typeof CU!=='undefined'&&CU&&typeof sv==='function')sv();
}

function syncTodoStateFromGraph(){
  if(!G)return;
  if(!Array.isArray(G.todoList))G.todoList=[];
  if(!Array.isArray(G.todoPool))G.todoPool=[];
  todayTodos=G.todoList.filter(t=>t&&t.nodeId).map(t=>({nodeId:String(t.nodeId)}));
  poolTodos=G.todoPool.filter(t=>t&&t.nodeId).map(t=>({nodeId:String(t.nodeId)}));
  hideCompleted=!!G.todoHideCompleted;
  const d=G.todoDaysCompleted;
  daysToShowCompleted=(d===undefined)?null:d;
}

