function addToTodoList(nodeId){
  // Add to todo list without date restriction - persists across days
  if(todayTodos.some(t=>t.nodeId===nodeId))return;
  if(typeof svWithUndo==='function'){try{svWithUndo();}catch(_){}}
  todayTodos.push({nodeId});
  localStorage.setItem('todayTodos',JSON.stringify(todayTodos));
  persistTodoStateToGraph();
  if(typeof sv==='function'){try{sv();}catch(_){}}
  renderTodoList();
  const todoSection=document.getElementById('rp-todo-section');
  if(todoSection)todoSection.style.display='block';
  rPanel(); // Refresh to show updated state
}

function addTaskFromTodoList(text,parentId){
  text=(text||'').trim(); if(!text)return;
  svWithUndo();
  const id='n'+Date.now();
  const defaultType=getDefaultTypeFromTitle(text);
  const pid=(parentId&&G.nodes.some(x=>x.id===parentId))?parentId:null;
  const todoColor=currentView==='home'?randomPaletteColor():P[G.nodes.length%P.length];
  G.nodes.push({id,name:text,color:todoColor,description:'',status:'active',parentId:pid,wsId:G.cws||'home',progress:[],notes:'',sphereOpen:false,routine:false,routineFrequency:null,priority:false,buffer:false,TBD:'none',nah:false,type:defaultType});
  if(pid)G.edges.push({source:pid,target:id});
  todayTodos.push({nodeId:id});
  persistTodoStateToGraph();
  try{ localStorage.setItem('todayTodos',JSON.stringify(todayTodos));}catch(e){}
  sv();render();rPanel();renderTodoList();
  setTimeout(()=>{
    const fallback=document.getElementById('rt-input-todo-add');
    const catInp=pid?document.getElementById(`rt-input-todo-cat-${pid}`):null;
    const inp=catInp||fallback;
    if(inp)inp.focus();
  },50);
}

function removeFromTodoList(nodeId){
  // Remove from todo list regardless of date
  if(!todayTodos.some(t=>t.nodeId===nodeId))return;
  if(typeof svWithUndo==='function'){try{svWithUndo();}catch(_){}}
  todayTodos=todayTodos.filter(t=>t.nodeId!==nodeId);
  localStorage.setItem('todayTodos',JSON.stringify(todayTodos));
  persistTodoStateToGraph();
  if(typeof sv==='function'){try{sv();}catch(_){}}
  renderTodoList();
  // Only hide the section when BOTH tabs are empty AND we're on the today tab; pool
  // entries are also "in the to-do list" from the user's perspective.
  const todoSection=document.getElementById('rp-todo-section');
  if(todoSection&&getTodoActiveTab()==='today'&&getTodayTodos().length===0&&getPoolTodos().length===0){
    todoSection.style.display='none';
  }
}

function autoAddTodayCalendarEventsToTodoList(){
  // Get today's date
  const today=new Date();
  today.setHours(0,0,0,0);
  const todayStr=today.toDateString();
  
  // Get all calendar events for today that are type 'task' (not meeting or event)
  // Exclude TBD tasks - they should only be added manually via the + button
  const todayEvents=G.nodes.filter(n=>{
    if(!n.calendarDate)return false;
    const eventDate=new Date(n.calendarDate);
    eventDate.setHours(0,0,0,0);
    if(eventDate.toDateString()!==todayStr||n.status==='completed'||n.status==='canceled')return false;
    // Exclude TBD tasks - they should only be added manually
    if(n.TBD&&n.TBD!=='none')return false;
    // Only auto-add explicit calendar *tasks*; meetings/events/custom types stay off the list unless added manually
    return n.type==='task';
  });
  
  // Get current todos
  const currentTodos=getTodayTodos();
  
  // Filter out events that are already in the todo list
  const eventsToAdd=todayEvents.filter(n=>!currentTodos.includes(n.id));
  
  if(eventsToAdd.length===0)return;
  
  // Sort events by time (temporal sequence)
  eventsToAdd.sort((a,b)=>{
    const timeA=a.calendarDate?new Date(a.calendarDate).getTime():0;
    const timeB=b.calendarDate?new Date(b.calendarDate).getTime():0;
    return timeA-timeB;
  });
  
  // Add events to todo list in temporal sequence
  eventsToAdd.forEach(n=>{
    if(!todayTodos.some(t=>t.nodeId===n.id)){
      todayTodos.push({nodeId:n.id});
    }
  });

  localStorage.setItem('todayTodos',JSON.stringify(todayTodos));
  // Mirror to G + flush so the user JSON on disk includes these auto-adds. Without
  // this, the in-memory list diverged from G.todoList every render and a refresh
  // forgot whatever the user did after the auto-add ran.
  persistTodoStateToGraph();
  if(typeof sv==='function'){try{sv();}catch(_){}}
  renderTodoList();
  const todoSection=document.getElementById('rp-todo-section');
  if(todoSection)todoSection.style.display='block';
}

// Any todo with a valid parent stays under that mother in the list (even when it is the only child left).
function planEntryNodeIds(entry,ordered){
  // Every to-do id displayed in this section, including nested descendants, so a
  // section drag moves the whole subtree as one unit.
  const list=ordered||[];
  const todoSet=new Set(list);
  const acc=[];
  const collect=id=>{acc.push(id);todoDisplayChildren(id,list,todoSet).forEach(collect);};
  if(entry.type==='single'){collect(entry.id);return acc;}
  entry.childIds.forEach(collect);
  return acc;
}
function filterTodoPlanEntries(plan){
  return plan.filter(entry=>{
    if(entry.type==='single')return true;
    return !!(G.nodes.find(x=>x.id===entry.parentId));
  });
}
function moveTodoSectionTo(fromIdx,destIdx){
  if(fromIdx===destIdx)return;
  const todos=getTodayTodos();
  const todoSet=new Set(todos);
  const plan=filterTodoPlanEntries(buildTodoListDisplayPlan(todos,todoSet));
  if(fromIdx<0||fromIdx>=plan.length)return;
  const item=plan[fromIdx];
  const rest=plan.filter((_,i)=>i!==fromIdx);
  let d=destIdx;
  if(fromIdx<destIdx)d--;
  d=Math.max(0,Math.min(d,rest.length));
  rest.splice(d,0,item);
  const newFlat=[];
  rest.forEach(e=>planEntryNodeIds(e,todos).forEach(id=>newFlat.push(id)));
  const setOld=new Set(todos);
  if(newFlat.length!==todos.length)return;
  for(const id of newFlat){ if(!setOld.has(id))return; }
  todayTodos=newFlat.map(nodeId=>({nodeId}));
  persistTodoStateToGraph();
  try{ localStorage.setItem('todayTodos',JSON.stringify(todayTodos));}catch(e){}
  if(typeof sv==='function')sv();
  renderTodoList();
}
function onTodoSectionDragStart(e){
  if(e.target.closest('input,button,textarea,.rt-item')){e.preventDefault();return;}
  const sec=e.currentTarget.closest&&e.currentTarget.closest('.rt-todo-section')||e.currentTarget;
  if(!sec||!sec.dataset)return;
  draggedTodoSectionIdx=parseInt(sec.dataset.sectionIndex,10);
  e.dataTransfer.setData('application/x-todo-section','1');
  e.dataTransfer.effectAllowed='move';
  sec.style.opacity='0.65';
}
function onTodoSectionDragEnd(e){
  const sec=e.currentTarget.closest&&e.currentTarget.closest('.rt-todo-section')||e.currentTarget;
  if(sec)sec.style.opacity='';
  draggedTodoSectionIdx=null;
  document.querySelectorAll('#rp-todo-list .rt-todo-section').forEach(s=>{
    s.style.borderTop='';s.style.borderBottom='';s.classList.remove('drag-over');
  });
}
function onTodoSectionDragOver(e){
  const dt=e.dataTransfer&&e.dataTransfer.types&&e.dataTransfer.types.includes('application/x-todo-section');
  if(!dt)return;
  e.preventDefault();
  e.dataTransfer.dropEffect='move';
}
function onTodoSectionDrop(e){
  const types=e.dataTransfer&&e.dataTransfer.types;
  const has=(function(){
    if(!types)return false;
    try{
      if(types.contains&&typeof types.contains==='function')return types.contains('application/x-todo-section');
      return Array.from(types).indexOf('application/x-todo-section')>=0;
    }catch(err){return false;}
  })();
  if(!has)return;
  e.preventDefault();
  e.stopPropagation();
  const targetSec=e.target.closest('.rt-todo-section');
  if(!targetSec||draggedTodoSectionIdx==null||draggedTodoSectionIdx===undefined)return;
  const fromIdx=draggedTodoSectionIdx;
  const targetIdx=parseInt(targetSec.dataset.sectionIndex,10);
  if(isNaN(targetIdx))return;
  const rect=targetSec.getBoundingClientRect();
  const before=e.clientY<rect.top+rect.height/2;
  let destIdx=before?targetIdx:targetIdx+1;
  moveTodoSectionTo(fromIdx,destIdx);
}

/** Nearest ancestor of `id` that is itself in the to-do list (`todoSet`), or null.
 *  A task nests under this ancestor in the display; if there is none it is a
 *  top-level row. Walks past non-todo intermediate categories. */
function todoParentOf(id,todoSet){
  let n=G.nodes.find(x=>x.id===id),guard=0;
  while(n&&n.parentId&&guard++<1000){
    if(todoSet.has(n.parentId))return n.parentId;
    n=G.nodes.find(x=>x.id===n.parentId);
  }
  return null;
}
/** Direct display-children of `id`: tasks in `ordered` whose nearest in-list
 *  ancestor is `id` (so each task appears under exactly one parent). */
function todoDisplayChildren(id,ordered,todoSet){
  return ordered.filter(oid=>oid!==id&&todoParentOf(oid,todoSet)===id);
}
function buildTodoListDisplayPlan(ordered,todoSet){
  // Only TOP-LEVEL tasks (those with no in-list ancestor) get their own section;
  // every other task nests recursively under its nearest in-list ancestor at
  // render time. The previous one-level grouping silently dropped the children of
  // any in-list sub-category, which made removing one task look like it removed
  // its siblings too. This forest model renders every task exactly once.
  const topLevel=ordered.filter(id=>todoParentOf(id,todoSet)===null);
  const plan=[];
  const processed=new Set();
  for(const id of topLevel){
    if(processed.has(id))continue;
    const n=G.nodes.find(x=>x.id===id);
    // Group top-level tasks under a shared mother-category header only when that
    // mother exists in the graph but is NOT itself in the list (an in-list mother
    // would be the to-do ancestor, so its tasks wouldn't be top-level here).
    const motherId=(n&&n.parentId&&G.nodes.some(x=>x.id===n.parentId)&&!todoSet.has(n.parentId))?n.parentId:null;
    if(motherId){
      const members=topLevel.filter(t=>{const tn=G.nodes.find(x=>x.id===t);return tn&&tn.parentId===motherId;});
      members.forEach(m=>processed.add(m));
      plan.push({type:'group',parentId:motherId,parentInList:false,childIds:members});
    }else{
      processed.add(id);
      plan.push({type:'single',id});
    }
  }
  return plan;
}

function renderTodoListMotherHeader(parentNode){
  const pid=parentNode.id;
  return`<div class="rt-todo-mother-hdr" style="margin-bottom:2px;padding:2px 0 4px 0;border-bottom:1px solid var(--bg3)">
    <div style="display:flex;align-items:center;gap:6px">
      <div class="rt-dot" style="background:${parentNode.color};flex-shrink:0"></div>
      <span class="rt-name" onclick="event.stopPropagation();enterN('${pid}')" style="font-weight:600;cursor:pointer;color:var(--t2)">${esc(parentNode.name)}</span>
    </div>
  </div>`;
}
/** Add-task row for a category; place after child listings (end of section). */
function renderTodoListCategoryAddRow(parentId,placeholderText){
  const pid=parentId;
  const ph=esc(placeholderText||'Add task…');
  return`<div class="rt-add" style="margin-top:8px"><input id="rt-input-todo-cat-${pid}" placeholder="${ph}" onkeydown="if(event.key==='Enter'){event.preventDefault();event.stopPropagation();const inp=this;addTaskFromTodoList(inp.value,'${pid}');inp.value='';setTimeout(()=>inp.focus(),10)}" onclick="event.stopPropagation()"><button onclick="event.stopPropagation();const i=document.getElementById('rt-input-todo-cat-${pid}');addTaskFromTodoList(i.value,'${pid}');i.value='';setTimeout(()=>i.focus(),10)">+</button></div>`;
}

function renderTodoListItemHtml(nodeId,depth,nestedChildrenHtml,listKind){
  const n=G.nodes.find(x=>x.id===nodeId);
  if(!n)return'';
  const tabKind=listKind==='pool'?'pool':'today';
  const isComplete=n.status==='completed'||n.status==='canceled';
  const kids=ch(n.id);
  const{t,d}=aggP(n.id);
  const pct=t?Math.round(d/t*100):0;
  const hasContent=kids.length>0;
  const notesOpen=npExp[n.id+'_notes']||false;
  const notes=getNoteContentForNode(n,null)||'';
  const notesDisplayHtml=notesOpen?getEditableNoteContentForInline(notes):formatNoteContentForPreview(notes);
  const notesPlainText=notes?(()=>{
    const tempDiv=document.createElement('div');
    tempDiv.innerHTML=notes;
    return tempDiv.textContent||tempDiv.innerText||'';
  })():'';
  const timer=n.timer||null;
  const timerActive=timer&&timer.endTime>Date.now();
  const pctRemaining=timerActive?timer.remaining/timer.duration:0;
  const circumference=2*Math.PI*12;
  const elapsed=circumference*(1-pctRemaining);
  const remaining=circumference*pctRemaining;
  const timerHTML=timerActive?`<div class="timer-pie-alarm" style="left:4px;top:4px;animation:${pctRemaining<0.2?'pulseAlarm 1s infinite':''}">
    <svg width="30" height="30" style="filter:drop-shadow(0 0 4px ${pctRemaining<0.2?'#ef4444':n.color})">
      <circle cx="12" cy="12" r="10" fill="none" stroke="#22c55e" stroke-width="3" stroke-dasharray="${remaining} ${circumference}" transform="rotate(-90 12 12)" opacity="0.9"/>
      <circle cx="12" cy="12" r="10" fill="none" stroke="#ef4444" stroke-width="3" stroke-dasharray="${elapsed} ${circumference}" transform="rotate(-90 12 12)" opacity="0.9"/>
    </svg>
  </div>`:'';
  const nahPale=n.nah?'opacity:0.45;filter:grayscale(0.35);':'';
  const hasCalendarEvent=n.calendarDate?true:false;
  const bgColor=hasCalendarEvent?'background:var(--bg3);opacity:0.7;':(timerActive&&pctRemaining<0.2?'background:rgba(239,68,68,0.1);border-left:3px solid #ef4444;':'');
  const ml=depth>0?8:0;
  return`<div class="rt-item ${isComplete?'completed':''} ${hasCalendarEvent?'on-calendar':''}" data-nid="${nodeId}" draggable="true" ondragstart="event.stopPropagation();event.dataTransfer.setData('text/plain','${nodeId}');event.dataTransfer.setData('application/node-link','task');event.dataTransfer.effectAllowed='copyMove';this.style.opacity='0.5'" ondragend="this.style.opacity=''" style="margin-left:${ml}px;margin-bottom:4px;cursor:move;${nahPale}">
    <div class="rt-header" style="position:relative;${bgColor}">
      ${timerHTML}
      <input type="checkbox" class="rt-check" ${isComplete?'checked':''} onclick="event.stopPropagation();completeNode('${nodeId}',this)" style="accent-color:${n.color}">
      <div class="rt-dot" style="background:${n.color}"></div>
      <span class="rt-name ${isComplete?'done':''}" onclick="event.stopPropagation();enterN('${nodeId}')" style="${isComplete?'cursor:not-allowed':''}">${esc(n.name)}</span>
      ${t?`<span class="rt-pct">${pct}%</span>`:''}
      ${timerActive?`<span class="rt-pct" style="background:${pctRemaining<0.2?'#ef4444':'var(--ylw)'};color:#000;font-weight:700;animation:${pctRemaining<0.2?'pulseAlarm 1s infinite':''}">${Math.ceil(timer.remaining/60000)}m</span>`:''}
      <div class="rt-acts" style="${isComplete?'opacity:0.3;pointer-events:none':''}">
        <button class="rt-act" onclick="event.stopPropagation();toggleNotes('${nodeId}')" title="Notes">📝</button>
        <button class="rt-act" onclick="event.stopPropagation();openTimer('${nodeId}')" title="Set timer">⏱️</button>
        <button class="rt-act" onclick="event.stopPropagation();openEdit('${nodeId}')" title="Settings">⚙️</button>
        <button class="rt-act" onclick="event.stopPropagation();delN('${nodeId}')" title="Delete">🗑</button>
        ${tabKind==='today'
          ?`<button class="rt-act rt-act--icon" onclick="event.stopPropagation();moveTodoToPool('${nodeId}')" title="Move to pool (work on this sometime soon, not today)" aria-label="Move to pool">${POOL_ICON_SVG(14)}</button>`
          :`<button class="rt-act rt-act--icon" onclick="event.stopPropagation();movePoolToToday('${nodeId}')" title="Move to today's list" aria-label="Move to today's list">${POOL_PROMOTE_ICON_SVG(14)}</button>`}
        <button class="rt-act" onclick="event.stopPropagation();${tabKind==='today'?`removeFromTodoList('${nodeId}')`:`removeFromPool('${nodeId}')`}" title="${tabKind==='today'?'Remove from to-do list':'Remove from pool'}" style="${!hasContent?'opacity:0.5':''}">×</button>
      </div>
    </div>
    ${notesOpen?`<div class="rt-notes-box open" data-notes-id="${nodeId}"><div class="rt-notes-preview">${notesDisplayHtml}</div><button class="rt-notes-jump-btn" onclick="event.stopPropagation();saveInlineNoteBeforeJump('${nodeId}');swView('notes');setTimeout(()=>openNoteEditor('${nodeId}'),100)" title="Jump to note page">↗</button></div>`:''}
    ${!notesOpen&&notes?`<div class="rt-notes-mini vis" onclick="toggleNotes('${nodeId}')">${esc(notesPlainText.length>50?notesPlainText.slice(0,50)+'...':notesPlainText)}</div>`:''}
    ${nestedChildrenHtml?`<div class="rt-children open">${nestedChildrenHtml}</div>`:''}
  </div>`;
}

/** Render a to-do task and all of its nested in-list descendants (recursively),
 *  so an in-list sub-category shows its own children instead of dropping them. */
function renderTodoTaskTree(id,depth,ordered,todoSet,tab){
  const kids=todoDisplayChildren(id,ordered,todoSet);
  const nested=kids.map(c=>renderTodoTaskTree(c,depth+1,ordered,todoSet,tab)).join('');
  return renderTodoListItemHtml(id,depth,nested,tab);
}

function renderTodoList(){
  const todoListEl=document.getElementById('rp-todo-list');
  if(!todoListEl)return;
  updateTodoTabButtons();
  const tab=getTodoActiveTab();
  let todos=tab==='pool'?getPoolTodos():getTodayTodos();
  // Filter out note-only items
  todos=todos.filter(nodeId=>{
    const n=G.nodes.find(x=>x.id===nodeId);
    return n&&isTaskNode(n);
  });
  todos=todos.filter(nodeId=>{
    const n=G.nodes.find(x=>x.id===nodeId);
    return n&&shouldShowCompletedTask(n);
  });
  // Load today's goals when rendering todo list
  loadTodayGoals();
  const todoSet=new Set(todos);
  const plan=buildTodoListDisplayPlan(todos,todoSet);
  const planFiltered=filterTodoPlanEntries(plan);
  const htmlParts=planFiltered.map((entry,secIdx)=>{
    let inner;
    if(entry.type==='single'){
      // Top-level task; nest any of its own in-list descendants beneath it. When it
      // acts as a category (has nested tasks) keep the inline "add task here" row.
      inner=renderTodoTaskTree(entry.id,0,todos,todoSet,tab);
      if(tab==='today'&&todoDisplayChildren(entry.id,todos,todoSet).length){
        inner+=renderTodoListCategoryAddRow(entry.id,'Add task in this group…');
      }
    }else{
      const mother=G.nodes.find(x=>x.id===entry.parentId);
      if(!mother)return'';
      inner=renderTodoListMotherHeader(mother)+
        `<div class="rt-children open">${entry.childIds.map(cid=>renderTodoTaskTree(cid,1,todos,todoSet,tab)).join('')}</div>`+
        (tab==='today'?renderTodoListCategoryAddRow(mother.id,'Add task in «'+mother.name+'»…'):'');
    }
    return`<div class="rt-todo-section" draggable="true" data-section-index="${secIdx}" ondragstart="onTodoSectionDragStart(event)" ondragend="onTodoSectionDragEnd(event)" ondragover="onTodoSectionDragOver(event)" ondrop="onTodoSectionDrop(event)">${inner}</div>`;
  });
  todoListEl.innerHTML=htmlParts.join('');
  if(todos.length===0){
    const empty=tab==='pool'
      ?'No tasks in the pool yet. Click the pool icon on a today\'s task to park it here for later.'
      :'No tasks in today\'s to-do list';
    todoListEl.innerHTML=`<p style="color:var(--t3);text-align:center;padding:8px;font-size:13px">${empty}</p>`;
  }
  if(tab==='today'){
    todoListEl.innerHTML+=`<div class="rt-add" style="margin-top:8px"><input id="rt-input-todo-add" placeholder="Add task..." onkeydown="if(event.key==='Enter'){event.preventDefault();event.stopPropagation();const inp=this;addTaskFromTodoList(inp.value);inp.value='';setTimeout(()=>inp.focus(),10)}" onclick="event.stopPropagation()"><button onclick="event.stopPropagation();const i=document.getElementById('rt-input-todo-add');addTaskFromTodoList(i.value);i.value='';setTimeout(()=>i.focus(),10)">+</button></div>`;
  }

  // Re-setup drag and drop after rendering (since HTML was recreated)
  setupTaskDragAndDrop();
  refreshInlineNoteEditorsInRPanel();
  ensureTodoHoverTooltip();
}

/* ── Hover tooltip: dwell 1 s on any .rt-item to see its full name + description ──
 *  Shared by the right-panel task bar (#rp-body) and today's to-do list (#rp-todo-list)
 *  so the same dwell + popup behaviour applies wherever a row's name is truncated. */
let _todoHoverTimer=null;
let _todoTooltipEl=null;
let _todoTooltipCurrentItem=null;
function ensureTaskHoverTooltipElement(){
  if(_todoTooltipEl)return;
  _todoTooltipEl=document.createElement('div');
  _todoTooltipEl.id='rp-task-tooltip';
  _todoTooltipEl.style.cssText='position:fixed;max-width:340px;padding:8px 12px;background:var(--bg1);color:var(--t0);border:1px solid var(--bdr);border-radius:6px;box-shadow:0 6px 18px rgba(0,0,0,.45);font-size:12.5px;line-height:1.5;z-index:5000;pointer-events:none;white-space:pre-wrap;word-break:break-word;display:none';
  document.body.appendChild(_todoTooltipEl);
}
function bindTaskHoverTooltipOn(root){
  if(!root)return;
  ensureTaskHoverTooltipElement();
  if(root.dataset.taskTooltipBound==='1')return;
  root.dataset.taskTooltipBound='1';
  const hide=()=>{
    if(_todoHoverTimer){clearTimeout(_todoHoverTimer);_todoHoverTimer=null;}
    _todoTooltipCurrentItem=null;
    if(_todoTooltipEl)_todoTooltipEl.style.display='none';
  };
  const show=(itemEl,cx,cy)=>{
    if(!itemEl||!_todoTooltipEl)return;
    const nid=itemEl.getAttribute('data-nid');
    if(!nid)return;
    const n=G.nodes.find(x=>x.id===nid);
    if(!n)return;
    let html=`<div style="font-weight:700;color:var(--t0);margin-bottom:4px">${esc(n.name||'')}</div>`;
    if(n.description){
      const d=String(n.description);
      html+=`<div style="color:var(--t2);font-size:12px">${esc(d.length>600?d.slice(0,600)+'…':d)}</div>`;
    }
    _todoTooltipEl.innerHTML=html;
    _todoTooltipEl.style.display='block';
    // Clamp inside viewport — flip above the cursor if we'd overflow below.
    const pad=12;
    const w=_todoTooltipEl.offsetWidth;
    const h=_todoTooltipEl.offsetHeight;
    let x=cx+14;
    let y=cy+14;
    if(x+w>window.innerWidth-pad)x=Math.max(pad,window.innerWidth-pad-w);
    if(y+h>window.innerHeight-pad)y=Math.max(pad,cy-14-h);
    _todoTooltipEl.style.left=x+'px';
    _todoTooltipEl.style.top=y+'px';
  };
  root.addEventListener('mouseover',(e)=>{
    const item=e.target.closest&&e.target.closest('.rt-item[data-nid], .nh[onclick]');
    if(!item){hide();return;}
    if(item===_todoTooltipCurrentItem)return;
    if(_todoHoverTimer){clearTimeout(_todoHoverTimer);_todoHoverTimer=null;}
    if(_todoTooltipEl)_todoTooltipEl.style.display='none';
    _todoTooltipCurrentItem=item;
    const cx=e.clientX, cy=e.clientY;
    _todoHoverTimer=setTimeout(()=>{
      if(_todoTooltipCurrentItem===item)show(item,cx,cy);
    },1000);
  });
  root.addEventListener('mouseout',(e)=>{
    const item=e.target.closest&&e.target.closest('.rt-item[data-nid], .nh[onclick]');
    if(!item)return;
    const to=e.relatedTarget;
    if(to&&item.contains(to))return;
    if(_todoTooltipCurrentItem===item)hide();
  });
  // Any interaction inside the row (click, drag, button press) should suppress the tooltip.
  ['mousedown','dragstart','click','wheel','keydown'].forEach(ev=>root.addEventListener(ev,hide,true));
}
function ensureTodoHoverTooltip(){
  bindTaskHoverTooltipOn(document.getElementById('rp-todo-list'));
}
/** Right-panel task bar needs scrollroom past the bottom — the today's-to-do section
 *  is absolutely positioned on top of #rp-body, so without this padding any task that
 *  falls under the overlap is unreachable even with the panel's overflow:auto.
 *  Recomputed after every render and after divider drags. */
function adjustRpBodyForTodoOverlay(){
  const rp=document.getElementById('rp');
  const rpb=document.getElementById('rp-body');
  const ts=document.getElementById('rp-todo-section');
  if(!rp||!rpb)return;
  let pad=0;
  if(ts&&ts.style.display!=='none'){
    const rpRect=rp.getBoundingClientRect();
    const tsRect=ts.getBoundingClientRect();
    // Visible portion of the todo section that sits over the rp panel — height it
    // obstructs from the body's perspective.
    pad=Math.max(0,Math.min(rpRect.bottom,tsRect.bottom)-Math.max(rpRect.top,tsRect.top));
  }
  rpb.style.paddingBottom=(pad+16)+'px';
}

// Drag and drop for task reordering and todo list
let dragOverHandler=null;
let dragLeaveHandler=null;
let dropHandler=null;

function setupTaskDragAndDrop(){
  const todoListEl=document.getElementById('rp-todo-list');
  if(!todoListEl)return;
  
  // Remove old listeners if they exist
  if(dragOverHandler)todoListEl.removeEventListener('dragover',dragOverHandler);
  if(dragLeaveHandler)todoListEl.removeEventListener('dragleave',dragLeaveHandler);
  if(dropHandler)todoListEl.removeEventListener('drop',dropHandler);
  
  // Create new handlers
  dragOverHandler=(e=>{
      // Only handle drags that are actually over the todo list
      if(!todoListEl.contains(e.target)&&e.target!==todoListEl)return;
      
      e.preventDefault();
      e.dataTransfer.dropEffect='move';
      
      // Visual feedback - find closest item to drop point
      const allItems=Array.from(todoListEl.querySelectorAll('.rt-item[draggable="true"]'));
      const dropY=e.clientY;
      
      // Remove all indicators
      allItems.forEach(i=>{
        i.classList.remove('drag-over');
        i.style.borderTop='';
        i.style.borderBottom='';
      });
      
      // Find the closest item to the drop point
      let closestItem=null;
      let closestDistance=Infinity;
      
      allItems.forEach(item=>{
        // Skip the dragged item by comparing nodeId (use global draggedNodeId if available)
        const itemNodeId=item.dataset.nid;
        if(draggedNodeId&&itemNodeId===draggedNodeId)return;
        if(!draggedNodeId){
          // Fallback: try to get from dataTransfer (may not work in dragover)
          try{
            const dtNodeId=e.dataTransfer.getData('text/plain');
            if(dtNodeId&&itemNodeId===dtNodeId)return;
          }catch(err){}
        }
        const box=item.getBoundingClientRect();
        const itemCenter=box.top+box.height/2;
        const distance=Math.abs(dropY-itemCenter);
        
        if(distance<closestDistance){
          closestDistance=distance;
          closestItem=item;
        }
      });
      
      // Add indicator to insertion point
      if(closestItem){
        const targetBox=closestItem.getBoundingClientRect();
        const elementCenter=targetBox.top+targetBox.height/2;
        
        if(dropY>elementCenter){
          // Insert after this element - show border-bottom
          closestItem.style.borderBottom='2px solid var(--acc)';
        }else{
          // Insert before this element - show border-top
          closestItem.classList.add('drag-over');
          closestItem.style.borderTop='2px solid var(--acc)';
        }
      }else if(allItems.length>0){
        // No closest item found, check if inserting at start or end
        const firstItem=allItems[0];
        const firstBox=firstItem.getBoundingClientRect();
        const lastItem=allItems[allItems.length-1];
        const lastBox=lastItem.getBoundingClientRect();
        
        if(dropY<firstBox.top){
          // Insert before first item
          firstItem.style.borderTop='2px solid var(--acc)';
        }else if(dropY>lastBox.bottom){
          // Insert after last item (at end) - show border-bottom
          lastItem.style.borderBottom='2px solid var(--acc)';
        }
      }
    });
  
  dragLeaveHandler=(e=>{
      if(!todoListEl.contains(e.relatedTarget)){
      todoListEl.style.background='';
        document.querySelectorAll('.rt-item').forEach(i=>{
          i.classList.remove('drag-over');
          i.style.borderTop='';
          i.style.borderBottom='';
        });
      }
    });
  
  dropHandler=(e=>{
      // Only handle drops that are actually on the todo list
      if(!todoListEl.contains(e.target)&&e.target!==todoListEl)return;
      
      e.preventDefault();
      todoListEl.style.background='';
      const nodeId=e.dataTransfer.getData('text/plain');
      if(!nodeId)return;
      
      const draggedItem=todoListEl.querySelector(`[data-nid="${nodeId}"]`);
      if(draggedItem){
        // Reordering within todo list
        const todos=getTodayTodos();
        const currentIndex=todos.indexOf(nodeId);
        if(currentIndex===-1)return;
        
        // Find target index by finding the closest element to the drop point
        const allItems=Array.from(todoListEl.querySelectorAll('.rt-item[draggable="true"]'));
        const dropY=e.clientY;
        let targetIndex;
        
        if(allItems.length===0){
          targetIndex=0;
        }else{
          // Find the closest item to the drop point (excluding dragged item)
          let closestItem=null;
          let closestDistance=Infinity;
          
          allItems.forEach(item=>{
            // Skip the dragged item by comparing nodeId
            if(item.dataset.nid===nodeId)return;
            const box=item.getBoundingClientRect();
            const itemCenter=box.top+box.height/2;
            const distance=Math.abs(dropY-itemCenter);
            
            if(distance<closestDistance){
              closestDistance=distance;
              closestItem=item;
            }
          });
          
          if(closestItem){
            const targetNodeId=closestItem.dataset.nid;
            targetIndex=todos.indexOf(targetNodeId);
            if(targetIndex===-1)return;
            
            // Determine if drop point is in upper or lower half of closest element
            const targetBox=closestItem.getBoundingClientRect();
            const elementCenter=targetBox.top+targetBox.height/2;
            
            if(dropY>elementCenter){
              // Drop is in lower half - insert after this element
              targetIndex++;
            }
            // Otherwise drop is in upper half - insert before (at targetIndex)
          }else{
            // No other items found, check if we should insert at start or end
            const firstItem=allItems[0];
            const firstBox=firstItem.getBoundingClientRect();
            const lastItem=allItems[allItems.length-1];
            const lastBox=lastItem.getBoundingClientRect();
            
            if(dropY<firstBox.top){
              targetIndex=0;
            }else if(dropY>lastBox.bottom){
              targetIndex=todos.length;
            }else{
              targetIndex=todos.length;
            }
          }
        }
        
        // Don't do anything if dropping at same position
        if(currentIndex===targetIndex)return;
        
        const reorderedTodos=[...todos];
        const [removed]=reorderedTodos.splice(currentIndex,1);
        // Adjust target index if we removed an item before it
        if(targetIndex>currentIndex)targetIndex--;
        reorderedTodos.splice(targetIndex,0,removed);
        
        // Update todo list order (persists across days)
        // Remove all current todos and re-add in new order
        const existingTodos=todayTodos.map(t=>t.nodeId);
        todayTodos=todayTodos.filter(t=>!reorderedTodos.includes(t.nodeId));
        reorderedTodos.forEach(id=>{
          if(!todayTodos.some(t=>t.nodeId===id)){
            todayTodos.push({nodeId:id});
          }
        });
        localStorage.setItem('todayTodos',JSON.stringify(todayTodos));
        // Reorder is a user operation — must round-trip into G + disk so undo/redo
        // works and a refresh keeps the same order.
        if(typeof svWithUndo==='function'){try{svWithUndo();}catch(_){}}
        persistTodoStateToGraph();
        if(typeof sv==='function'){try{sv();}catch(_){}}
        renderTodoList();
      }else{
        // Adding new item to todo list
        addToTodoList(nodeId);
      }
      
      // Remove visual indicators
      document.querySelectorAll('.rt-item').forEach(i=>{
        i.classList.remove('drag-over');
        i.style.borderTop='';
        i.style.borderBottom='';
      });
    });
  
  // Add new listeners
  todoListEl.addEventListener('dragover',dragOverHandler);
  todoListEl.addEventListener('dragleave',dragLeaveHandler);
  todoListEl.addEventListener('drop',dropHandler);
  
  // Set up drag handlers for task items (these are already in the HTML via ondragstart/ondragend)
  // The drag handlers are already set up in renderTodoList via inline handlers
}

