function setupInlineNoteEditor(box){
  if(!box||box._inlineNoteSetup)return;
  const nodeId=box.dataset.notesId;
  const preview=box.querySelector('.rt-notes-preview');
  if(!preview||!nodeId)return;
  box._inlineNoteSetup=true;
  preview.contentEditable='true';
  preview.dataset.placeholder='Add notes...';
  setupNodeLinkHandlers(preview);
  ensureLinksOpenInNewTab(preview);
  let saveTimer=null;
  const save=()=>{
    if(saveTimer)clearTimeout(saveTimer);
    saveTimer=setTimeout(()=>{saveInlineNoteContent(nodeId,preview.innerHTML);saveTimer=null;},300);
  };
  preview.addEventListener('input',save);
  preview.addEventListener('blur',()=>{if(saveTimer){clearTimeout(saveTimer);saveTimer=null;}saveInlineNoteContent(nodeId,preview.innerHTML);});
  preview.addEventListener('paste',(e)=>{
    e.preventDefault();
    const text=e.clipboardData.getData('text/plain');
    document.execCommand('insertText',false,text);
  });
}
