/* ── Data mutations ── */
function updF(id,f,v){const n=G.nodes.find(x=>x.id===id);if(n){svWithUndo();n[f]=v;sv();render()}}
function delN(id){svWithUndo();const td=allDS(id);G.nodes=G.nodes.filter(n=>!td.has(n.id));G.edges=G.edges.filter(e=>!td.has(eI(e.source))&&!td.has(eI(e.target)));dirtyNodeMap();if(expandedId===id)expandedId=null;td.forEach(nodeId=>{todayTodos=todayTodos.filter(t=>t.nodeId!==nodeId);poolTodos=poolTodos.filter(t=>t.nodeId!==nodeId);localStorage.setItem('todayTodos',JSON.stringify(todayTodos));});persistTodoStateToGraph();renderTodoList();sv();clrHL();render();if(currentView==='calendar')renderCalendar()}

/* ── Rename ── */
function startRn(d,ev){const ex=document.querySelector('.node-rename');if(ex)ex.remove();const i=document.createElement('input');i.className='node-rename';i.value=d.name;i.style.left=(ev.clientX-60)+'px';i.style.top=(ev.clientY-16)+'px';document.body.appendChild(i);i.focus();i.select();const fin=()=>{const v=i.value.trim();if(v&&v!==d.name)updF(d.id,'name',v);i.remove()};i.onkeydown=e=>{if(e.key==='Enter')fin();if(e.key==='Escape')i.remove()};i.onblur=fin}

