function cxA(a){const id=cxId;document.getElementById('ctx').classList.remove('vis');if(!id)return;
  if(a==='enter')enterN(id);else if(a==='rename'){const sn=sim?.nodes().find(n=>n.id===id)||(childSim?.nodes().find(n=>n.id===id));if(sn){const r=document.getElementById('canvas').getBoundingClientRect();startRn(sn,{clientX:r.left+r.width/2,clientY:r.top+r.height/2})}}
  else if(a==='edit')openEdit(id);else if(a==='agent'){if(typeof openAssignAgentModal==='function')openAssignAgentModal(id)}else if(a==='add')openAdd(id);else if(a==='conn')enterConn(id);else if(a==='del')delN(id)}
