function openConn(s,t){const sn=G.nodes.find(n=>n.id===s),tn=G.nodes.find(n=>n.id===t);if(!sn||!tn)return;
  document.getElementById('cc-sd').style.background=sn.color;document.getElementById('cc-sn').textContent=sn.name;
  document.getElementById('cc-td').style.background=tn.color;document.getElementById('cc-tn').textContent=tn.name;
  const existingEdge=G.edges.find(e=>(eI(e.source)===s&&eI(e.target)===t)||(eI(e.source)===t&&eI(e.target)===s));
  document.getElementById('cc-r').value=existingEdge?.reason||'';
  document.getElementById('cc-thickness').value=existingEdge?.thickness||1;
  document.getElementById('cc-direction').value=existingEdge?.direction||'none';
  document.getElementById('cc-color').value=existingEdge?.color||'grey';
  document.getElementById('cc-linetype').value=existingEdge?.linetype||'solid';
  document.getElementById('m-conn').querySelector('h3').textContent=existingEdge?'Edit Connection':'Connect Nodes';
  document.getElementById('m-conn')._src=s;document.getElementById('m-conn')._tgt=t;
  document.getElementById('m-conn')._editing=!!existingEdge;
  document.getElementById('m-conn').classList.add('open');
  setupModalKeyboardNavigation('m-conn');}
function saveConn(){const m=document.getElementById('m-conn'),s=m._src,t=m._tgt,r=document.getElementById('cc-r').value.trim();
  const thickness=parseInt(document.getElementById('cc-thickness').value)||1;
  const direction=document.getElementById('cc-direction').value||'none';
  const color=document.getElementById('cc-color').value||'grey';
  const linetype=document.getElementById('cc-linetype').value||'solid';
  if(s&&t&&s!==t){
    if(m._editing){
      const edge=G.edges.find(e=>(eI(e.source)===s&&eI(e.target)===t)||(eI(e.source)===t&&eI(e.target)===s));
      if(edge){
        if(r)edge.reason=r;else delete edge.reason;
        edge.thickness=thickness;
        edge.direction=direction;
        edge.color=color;
        edge.linetype=linetype;
        svWithUndo();render();
      }
    }else if(!G.edges.some(e=>(eI(e.source)===s&&eI(e.target)===t)||(eI(e.source)===t&&eI(e.target)===s))){
      const e={source:s,target:t};
      if(r)e.reason=r;
      e.thickness=thickness;
      e.direction=direction;
      e.color=color;
      e.linetype=linetype;
      G.edges.push(e);svWithUndo();render();
    }
  }
  m._editing=false;
  clMo('m-conn');
}

/* ── Edge Actions ── */
let selectedEdge=null;
function showEdgeActions(d,ev){
  ev.stopPropagation();
  hideEdgeActions(); // Hide any previously shown actions
  selectedEdge=d;
  const ns=sim.nodes();
  const src=ns.find(n=>n.id===eI(d.source));
  const tgt=ns.find(n=>n.id===eI(d.target));
  if(!src||!tgt)return;
  const angle=Math.atan2(tgt.y-src.y,tgt.x-src.x);
  const dist=Math.sqrt(Math.pow(tgt.x-src.x,2)+Math.pow(tgt.y-src.y,2));
      const iconSpacing=38; // Spacing for icons
  const startOffset=dist*0.25; // Start at 25% along the edge
  const actionsGroup=linkG.select('.edge-actions-group');
  actionsGroup.selectAll('*').remove();
  const icons=[
    {id:'edit',svg:'<svg width="30" height="30" viewBox="0 0 16 16"><defs><linearGradient id="editGrad" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" style="stop-color:#6B46C1;stop-opacity:1"/><stop offset="100%" style="stop-color:#9333EA;stop-opacity:1"/></linearGradient></defs><path d="M2 12 L4 14 L12 6 L10 4 Z" fill="url(#editGrad)" stroke="#4C1D95" stroke-width="0.8" rx="1"/><path d="M10 4 L12 6" stroke="#FFD700" stroke-width="1.5" stroke-linecap="round"/><circle cx="3.5" cy="12.5" r="0.8" fill="#FFD700"/></svg>',action:()=>editEdge(d),class:'edit'},
    {id:'enhance',svg:'<svg width="30" height="30" viewBox="0 0 16 16"><defs><linearGradient id="enhanceGrad" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" style="stop-color:#F59E0B;stop-opacity:1"/><stop offset="100%" style="stop-color:#F97316;stop-opacity:1"/></linearGradient></defs><ellipse cx="8" cy="10" rx="4" ry="3" fill="url(#enhanceGrad)" stroke="#D97706" stroke-width="0.8"/><path d="M6 6 Q8 4 10 6" stroke="#FCD34D" stroke-width="1.5" fill="none" stroke-linecap="round"/><circle cx="5" cy="8" r="0.6" fill="#FCD34D"/><circle cx="11" cy="8" r="0.6" fill="#FCD34D"/><path d="M4 12 L6 10 M12 12 L10 10" stroke="#FCD34D" stroke-width="1" stroke-linecap="round"/></svg>',action:()=>enhanceEdge(d),class:'enhance'},
    {id:'direction',svg:'<svg width="30" height="30" viewBox="0 0 16 16"><defs><linearGradient id="dirGrad" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" style="stop-color:#8B5CF6;stop-opacity:1"/><stop offset="100%" style="stop-color:#A78BFA;stop-opacity:1"/></linearGradient></defs><path d="M3 8 L13 8" stroke="url(#dirGrad)" stroke-width="2" stroke-linecap="round"/><path d="M11 5 L13 8 L11 11" fill="url(#dirGrad)" stroke="#6D28D9" stroke-width="0.8"/><path d="M5 11 L3 8 L5 5" fill="url(#dirGrad)" stroke="#6D28D9" stroke-width="0.8"/><circle cx="8" cy="8" r="1.2" fill="#FCD34D"/></svg>',action:()=>toggleEdgeDirection(d),class:'direction'},
    {id:'trash',svg:'<svg width="30" height="30" viewBox="0 0 16 16"><defs><linearGradient id="trashGrad" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" style="stop-color:#EF4444;stop-opacity:1"/><stop offset="100%" style="stop-color:#DC2626;stop-opacity:1"/></linearGradient></defs><rect x="4" y="5" width="8" height="8" rx="1" fill="url(#trashGrad)" stroke="#991B1B" stroke-width="0.8"/><rect x="5" y="2" width="6" height="2" rx="0.5" fill="#FCA5A5"/><path d="M6 7 L6 11 M8 7 L8 11 M10 7 L10 11" stroke="#FFF" stroke-width="1" stroke-linecap="round"/><line x1="3" y1="5" x2="13" y2="5" stroke="#991B1B" stroke-width="1"/></svg>',action:()=>deleteEdge(d),class:'trash'}
  ];
  icons.forEach((icon,idx)=>{
    const offsetAlongEdge=startOffset+iconSpacing*idx;
    const iconX=src.x+Math.cos(angle)*offsetAlongEdge;
    const iconY=src.y+Math.sin(angle)*offsetAlongEdge;
    const g=actionsGroup.append('g').attr('class','edge-actions visible')
      .attr('transform',`translate(${iconX},${iconY})`);
    g.html(icon.svg);
    g.select('svg')
      .attr('class','edge-action-icon')
      .style('cursor','pointer')
      .style('pointer-events','all')
      .on('click',(ev)=>{ev.stopPropagation();icon.action();});
  });
}
function hideEdgeActions(d){
  // Don't hide if clicking on action icons - check if event target is an icon
  if(d3.event&&d3.event.target){
    const target=d3.event.target;
    if(target.classList.contains('edge-action-icon')||target.closest('.edge-actions')){
      return;
    }
  }
  if(d&&selectedEdge&&(eI(selectedEdge.source)!==eI(d.source)||eI(selectedEdge.target)!==eI(d.target)))return;
  // Only hide if explicitly called, not when clicking icons
  linkG.select('.edge-actions-group').selectAll('*').remove();
  selectedEdge=null;
  // Also remove hover class from all edges
  linkG.selectAll('line.link').classed('hovered',false);
}
function editEdge(d){
  const srcId=eI(d.source),tgtId=eI(d.target);
  const edge=G.edges.find(e=>(eI(e.source)===srcId&&eI(e.target)===tgtId)||(eI(e.source)===tgtId&&eI(e.target)===srcId));
  if(edge){
    const sn=G.nodes.find(n=>n.id===srcId),tn=G.nodes.find(n=>n.id===tgtId);
    if(sn&&tn){
      document.getElementById('cc-sd').style.background=sn.color;
      document.getElementById('cc-sn').textContent=sn.name;
      document.getElementById('cc-td').style.background=tn.color;
      document.getElementById('cc-tn').textContent=tn.name;
      document.getElementById('cc-r').value=edge.reason||'';
      document.getElementById('cc-thickness').value=edge.thickness||1;
      document.getElementById('cc-direction').value=edge.direction||'none';
      document.getElementById('cc-color').value=edge.color||'grey';
      document.getElementById('cc-linetype').value=edge.linetype||'solid';
      document.getElementById('m-conn').querySelector('h3').textContent='Edit Connection';
      document.getElementById('m-conn')._src=srcId;
      document.getElementById('m-conn')._tgt=tgtId;
      document.getElementById('m-conn')._editing=true;
      document.getElementById('m-conn').classList.add('open');
      setupModalKeyboardNavigation('m-conn');
      // Don't hide edge actions - keep them visible
    }
  }
}
function enhanceEdge(d){
  const srcId=eI(d.source),tgtId=eI(d.target);
  const edge=G.edges.find(e=>(eI(e.source)===srcId&&eI(e.target)===tgtId)||(eI(e.source)===tgtId&&eI(e.target)===srcId));
  if(edge){
    const currentThickness=edge.thickness||1;
    edge.thickness=currentThickness===1?2:currentThickness===2?3:1;
    svWithUndo();
    render();
    // Icons will be preserved by render() function
  }
}
function toggleEdgeDirection(d){
  const srcId=eI(d.source),tgtId=eI(d.target);
  const edge=G.edges.find(e=>(eI(e.source)===srcId&&eI(e.target)===tgtId)||(eI(e.source)===tgtId&&eI(e.target)===srcId));
  if(edge){
    const currentDir=edge.direction||'none';
    edge.direction=currentDir==='none'?'bidirectional':currentDir==='bidirectional'?'a-to-b':currentDir==='a-to-b'?'b-to-a':'none';
    svWithUndo();
    render();
    // Icons will be preserved by render() function
  }
}
function deleteEdge(d){
  const srcId=eI(d.source),tgtId=eI(d.target);
  G.edges=G.edges.filter(e=>!(eI(e.source)===srcId&&eI(e.target)===tgtId)&&!(eI(e.source)===tgtId&&eI(e.target)===srcId));
  svWithUndo();
  // Hide icons immediately since edge is being deleted
  hideEdgeActions();
  render();
}

/* ── Add/Edit modal ── */
function getDefaultTypeFromTitle(title){
  if(!title)return 'task';
  const lowerTitle=title.toLowerCase();
  if(lowerTitle.includes('meeting')||lowerTitle.includes('meet')){
    return 'meeting';
  }
  return 'task';
}

