function bldLeg(){const l=document.getElementById('legend');const n=expandedId?ch(expandedId):visN();if(!n.length){l.style.display='none';return}l.style.display='flex';l.innerHTML=n.slice(0,8).map(x=>`<div class="li"><div class="ld" style="background:${x.color}"></div>${esc(x.name)}</div>`).join('')}
function updSt(){document.getElementById('stn').textContent=(expandedId?ch(expandedId):visN()).length+' nodes';document.getElementById('ste').textContent=G.edges.length+' edges'}

/* ── Workspaces ── */
/* ── View switching ── */
function hidePageShellViews(){
  ['calendar-view','progress-view','pathbehind-view','notes-view','expand-view','settings-view','pagetree-view','pageagents-view','pageinterstellar-view'].forEach(id=>{
    const el=document.getElementById(id);
    if(el)el.style.display='none';
  });
  if(pageAgentsRaf!==null){cancelAnimationFrame(pageAgentsRaf);pageAgentsRaf=null;}
  const gs=document.getElementById('graph-svg');
  if(gs)gs.style.display='none';
  const leg=document.getElementById('legend');
  const stats=document.getElementById('stats');
  const sTr=document.getElementById('s-trigger');
  const bTr=document.getElementById('b-trigger');
  if(leg)leg.style.display='none';
  if(stats)stats.style.display='none';
  if(sTr)sTr.style.pointerEvents='none';
  if(bTr)bTr.style.pointerEvents='none';
}

function swView(view){
  const previousView=currentView;
  // Save note editor content before leaving notes view (so edits persist when navigating away)
  if(currentView==='notes'&&view!=='notes')saveCurrentNoteEditorContent();
  // Drop any never-used agents when leaving the agents page so they don't reappear
  // when the user comes back later in the session.
  if(currentView==='pageagents'&&view!=='pageagents'){
    try{if(typeof pageAgentsPruneEmptyAgents==='function')pageAgentsPruneEmptyAgents();}catch(_){}
  }
  // Save inline note editors before leaving home view
  if(currentView==='home'&&view!=='home')Object.keys(npExp).forEach(k=>{if(k.endsWith('_notes')&&npExp[k])saveInlineNoteBeforeJump(k.replace(/_notes$/,''));});
  // Blur active element to prevent focus-related scroll jumps during view switch
  if(document.activeElement&&document.activeElement!==document.body)document.activeElement.blur();
  currentView=view;
  document.getElementById('lt-home').classList.toggle('on',view==='home');
  document.getElementById('lt-calendar').classList.toggle('on',view==='calendar');
  document.getElementById('lt-progress').classList.toggle('on',view==='progress');
  document.getElementById('lt-pathbehind').classList.toggle('on',view==='pathbehind');
  document.getElementById('lt-notes').classList.toggle('on',view==='notes');
  document.getElementById('lt-expand').classList.toggle('on',view==='expand');
  document.getElementById('lt-pagetree').classList.toggle('on',view==='pagetree');
  document.getElementById('lt-pageagents').classList.toggle('on',view==='pageagents');
  document.getElementById('lt-pageinterstellar').classList.toggle('on',view==='pageinterstellar');
  document.getElementById('lt-settings').classList.toggle('on',view==='settings');
  // Apply theme when switching views to ensure it's consistent
  if(G.theme)applyTheme(G.theme);
  if(view!=='home') closeHelpChat();
  
  if(view==='home'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('graph-svg').style.display='block';
    document.getElementById('s-zone').style.display='';
    document.getElementById('b-zone').style.display='';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    render();
    const sTr=document.getElementById('s-trigger');
    const bTr=document.getElementById('b-trigger');
    const stats=document.getElementById('stats');
    if(sTr)sTr.style.pointerEvents='';
    if(bTr)bTr.style.pointerEvents='';
    if(stats)stats.style.display='flex';
    updateBackgroundColor();
    // Restore the keyboard-navigation preconditions the initial load sets up, so the
    // home shortcuts (Space+Enter expand/collapse, Enter open/dive, Space+Arrow level
    // change) keep working after navigating away and back. Without this, returning to
    // home leaves focus on a now-hidden input from the other view — making every
    // Space/Enter/Arrow handler think it's "in an input" (inI) and silently no-op —
    // and leaves the node selector unseated (Enter / Space+Down have no target).
    // Mouse click/drag interactions are unaffected. (See guideline.md keyboard matrix.)
    if(previousView!=='home'){
      const canvasEl=document.getElementById('canvas');
      if(canvasEl){
        if(!canvasEl.hasAttribute('tabindex')){canvasEl.setAttribute('tabindex','0');canvasEl.style.outline='none';}
        const ae=document.activeElement;
        const typingInHomeInput=ae&&(ae.id==='b-inp'||ae.id==='s-inp');
        if(!typingInHomeInput)setTimeout(()=>{try{canvasEl.focus();}catch(_){}},0);
      }
      setTimeout(()=>{try{initializeNodeSelector();}catch(_){}},260);
    }
  }else if(view==='calendar'){
    if(previousView==='notes'){
      calendarPreserveFromNotesOpen=true;
      calendarCenterOnAnchorNextRender=false;
    }else{
      calendarPreserveFromNotesOpen=false;
      calendarCenterOnAnchorNextRender=true;
      const calAnchor=new Date();
      calAnchor.setHours(0,0,0,0);
      calendarDate=new Date(calAnchor);
    }
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('calendar-view').style.display='flex';
    document.getElementById('s-zone').style.display='none';
    document.getElementById('b-zone').style.display='none';
    setupCalendarDragAndDrop();
    setTimeout(()=>{
      if(document.getElementById('calendar-tbd-tabs-container')){
        const tabs=document.getElementById('calendar-tbd-tabs-container').querySelectorAll('.tbd-micro-tab');
        if(tabs.length>0)startTBDTabFloating();
      }
    },200);
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    renderCalendar();
    document.documentElement.scrollTop=0;
    document.body.scrollTop=0;
    updateBackgroundColor();
  }else if(view==='progress'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('progress-view').style.display='flex';
    document.getElementById('s-zone').style.display='none';
    document.getElementById('b-zone').style.display='none';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    renderProgress();
    updateBackgroundColor();
  }else if(view==='pathbehind'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('pathbehind-view').style.display='flex';
    document.getElementById('s-zone').style.display='none';
    document.getElementById('b-zone').style.display='none';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    renderPathBehind();
    updateBackgroundColor();
  }else if(view==='notes'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('notes-view').style.display='flex';
    document.getElementById('s-zone').style.display='none';
    setTimeout(()=>{ initNotesResizer(); setupNotesEditorToolbarSelectionSave(); },100);
    document.getElementById('b-zone').style.display='none';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    renderNotes();
    updateBackgroundColor();
  }else if(view==='expand'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('expand-view').style.display='flex';
    document.getElementById('s-zone').style.display='none';
    document.getElementById('b-zone').style.display='none';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    renderExpand();
    updateBackgroundColor();
  }else if(view==='pagetree'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('pagetree-view').style.display='flex';
    document.getElementById('s-zone').style.display='none';
    document.getElementById('b-zone').style.display='none';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    renderPageTree();
    updateBackgroundColor();
  }else if(view==='pageagents'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('pageagents-view').style.display='flex';
    document.getElementById('s-zone').style.display='none';
    document.getElementById('b-zone').style.display='none';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    pageAgentsRestoreLocal();
    pageAgentsModelChange();
    pageAgentsStartPlayground();
    pageAgentsOnAgentsViewShown();
    updateBackgroundColor();
  }else if(view==='pageinterstellar'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('pageinterstellar-view').style.display='flex';
    document.getElementById('s-zone').style.display='none';
    document.getElementById('b-zone').style.display='none';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    pageInterstellarRestoreLocal();
    updateBackgroundColor();
  }else if(view==='settings'){
    stopTBDTabFloating();
    hidePageShellViews();
    document.getElementById('settings-view').style.display='block';
    document.getElementById('s-zone').style.display='none';
    document.getElementById('b-zone').style.display='none';
    if(progressChartInterval){clearInterval(progressChartInterval);progressChartInterval=null;}
    populateSettings();
    updateBackgroundColor();
  }
  rPanel();
}

function openSettings(){
  // Switch to settings view
  swView('settings');
}

/* ── Expand Page Drag and Drop ── */
function handlePageDragStart(event,pageId){
  event.dataTransfer.setData('text/plain',pageId);
  event.dataTransfer.effectAllowed='move';
  event.currentTarget.style.opacity='0.5';
}

function handlePageDragEnd(event){
  event.currentTarget.style.opacity='1';
}

function handleExpandDragOver(event){
  event.preventDefault();
  event.dataTransfer.dropEffect='move';
}

function handleExpandDragEnter(event){
  event.preventDefault();
  const expandEl=document.getElementById('lt-expand');
  if(expandEl){
    expandEl.style.background='var(--acc)';
    expandEl.style.opacity='0.8';
  }
}

function handleExpandDragLeave(event){
  const expandEl=document.getElementById('lt-expand');
  if(expandEl){
    expandEl.style.background='transparent';
    expandEl.style.opacity='1';
  }
}

function handleExpandDrop(event){
  event.preventDefault();
  const expandEl=document.getElementById('lt-expand');
  if(expandEl){
    expandEl.style.background='transparent';
    expandEl.style.opacity='1';
  }
  
  const pageId=event.dataTransfer.getData('text/plain');
  if(!pageId||pageId==='expand'||pageId==='home')return; // Don't allow dragging expand or home into itself
  
  // Remove from expandPages if already there
  if(!G.expandPages)G.expandPages=[];
  G.expandPages=G.expandPages.filter(p=>p!==pageId);
  
  // Add to expandPages
  G.expandPages.push(pageId);
  
  // Save state
  if(G.autoSave)ST.save(CU,G);
  
  // Update UI
  updateLeftSidebarVisibility();
  renderExpand();
  
  // Reset dragged element opacity
  const draggedEl=document.querySelector(`[data-page-id="${pageId}"]`);
  if(draggedEl)draggedEl.style.opacity='1';
}


