function pageAgentsBuildSpriteSvg(seed,opts){
  const o=opts||{};
  const slugSeed=(seed>>>0)||1;
  const rng=pageAgentsMulberry32(slugSeed);
  if(PAGE_AGENTS_USE_FIELD_MODE){
    if(PAGE_AGENTS_FIELD_STYLE==='minecraft'){
      const t=Math.floor(rng()*4);
      if(t===0)return pageAgentsMcSteve(rng);
      if(t===1)return pageAgentsMcAlex(rng);
      if(t===2)return pageAgentsMcCreeper(rng);
      return pageAgentsMcZombie(rng);
    }
    const t=Math.floor(rng()*4);
    if(t===0)return pageAgentsTrainerBoy(rng);
    if(t===1)return pageAgentsTrainerGirl(rng);
    if(t===2)return pageAgentsTrainerHiker(rng);
    return pageAgentsTrainerFisher(rng);
  }
  // Grouping signals: model picks the sprite TYPE (so same-model agents share kind
  // — astronaut / robot / alien / critter), model+project picks the THEME palette
  // (so same-project siblings echo each other's colours). The per-slug rng then
  // drives all individual details so siblings stay distinguishable. No grouping
  // info ⇒ fall back to slug-only random pick (legacy behaviour for orphans).
  const hasModel=!!o.model;
  const hasGroup=hasModel||!!o.project;
  let type;
  if(hasModel){
    type=pageAgentsHashStr(o.model)%4;
  }else{
    type=Math.floor(rng()*4);
  }
  let themeIdx=-1;
  if(hasGroup){
    const mh=hasModel?pageAgentsHashStr(o.model):0;
    const ph=pageAgentsHashStr(String(o.project||''));
    themeIdx=(((mh*2654435761)^(ph*40503))>>>0)%32;
  }
  if(type===0)return pageAgentsSpriteAstronaut(rng,themeIdx);
  if(type===1)return pageAgentsSpriteRobot(rng,themeIdx);
  if(type===2)return pageAgentsSpriteAlien(rng,themeIdx);
  return pageAgentsSpriteCritter(rng,themeIdx);
}

function pageAgentsUpdatePlayHint(){
  const hint=document.getElementById('pageagents-play-hint');
  if(hint)hint.style.display=pageAgentsSprites.length?'none':'flex';
}

function pageAgentsSetAgentWorkingUi(agent,on){
  if(!agent)return;
  agent.working=!!on;
  if(agent.badge)agent.badge.style.display=on?'block':'none';
  if(agent.barWrap){
    agent.barWrap.style.opacity=on?'1':'0';
    if(!on&&agent.barInner)agent.barInner.style.width='0%';
  }
  // Spotlight: shimmering green glow + amplified name + hammer swing while working.
  if(agent.wrap){
    agent.wrap.classList.toggle('pageagents-sprite-wrap--working-active',!!on);
    if(agent.nameEl)agent.nameEl.classList.toggle('pageagents-sprite-name--working',!!on);
    pageAgentsToggleHammerOverlay(agent,!!on);
  }
  // Starting a new task implicitly acknowledges any leftover "just-done" glow from
  // a previous run — without this, the sprite wrap keeps the `--just-done` class
  // alongside `--working-active`, and since the yellow rule comes later in CSS
  // with equal specificity it wins, making working agents glow yellow instead of
  // green. Clearing the flag + classes restores the intended green-when-working.
  if(on)try{pageAgentsClearJustDoneFlag(agent.slug);}catch(_){}
  // Mirror working state onto the chat slot's label above its message box.
  try{pageAgentsApplySlotLabelStateForSlug(agent.slug);}catch(_){}
  // Working state changed → re-evaluate the deck spotlight (single agent → focus-zoom in,
  // multiple agents → zoom out to fit them all with amplified glow).
  try{pageAgentsRefreshDeckSpotlight();}catch(_){}
}

/** Add or remove the swinging hammer SVG above the sprite when it's working. */
function pageAgentsToggleHammerOverlay(agent,on){
  if(!agent||!agent.wrap)return;
  let h=agent.wrap.querySelector('.pageagents-sprite-hammer');
  if(on){
    if(!h){
      h=document.createElement('div');
      h.className='pageagents-sprite-hammer';
      // Anchor at the bottom-center of the icon so it pivots around the handle base, mimicking a swing.
      h.style.cssText='position:absolute;left:50%;top:-22px;transform-origin:50% 100%;width:28px;height:28px;margin-left:-14px;z-index:8;pointer-events:none;animation:pageagentsHammerSwing 0.55s ease-in-out infinite';
      h.innerHTML='<svg viewBox="0 0 32 32" width="28" height="28" xmlns="http://www.w3.org/2000/svg"><rect x="14.4" y="10" width="3.2" height="20" rx="1.4" fill="#a5754a" stroke="#5a3014" stroke-width="0.8"/><rect x="6" y="4" width="20" height="9" rx="1.6" fill="#7a8a9c" stroke="#1a2438" stroke-width="1.1"/><rect x="6" y="4" width="20" height="2" fill="#b9c5d4"/></svg>';
      agent.wrap.appendChild(h);
    }
  }else if(h){
    try{h.remove();}catch(_){}
  }
}

/** Highlight the agent that just completed a task: yellow glow + amplified yellow name.
 *  Persists until the user opens that agent's tab in LOGS AND HISTORY (acknowledgement).
 *  The "needs ack" flag is stored on the archive record so it survives page reloads. */
function pageAgentsFlashAgentJustDone(agent){
  if(!agent||!agent.wrap)return;
  const slug=agent.slug;
  const rec=slug&&pageAgentsArchive.agents&&pageAgentsArchive.agents[slug];
  if(rec){rec.justDoneNeedsAck=true;pageAgentsFlushArchiveDebounced();}
  pageAgentsApplyJustDoneClasses(agent,true);
  try{pageAgentsRefreshDeckSpotlight();}catch(_){}
}

/** Apply or remove the just-done glow + name styles on a sprite. */
function pageAgentsApplyJustDoneClasses(agent,on){
  if(!agent||!agent.wrap)return;
  agent.wrap.classList.toggle('pageagents-sprite-wrap--just-done',!!on);
  if(agent.nameEl)agent.nameEl.classList.toggle('pageagents-sprite-name--just-done',!!on);
  // Mirror just-done state onto the chat slot's label above its message box.
  try{pageAgentsApplySlotLabelStateForSlug(agent.slug);}catch(_){}
}

/** Update the chat slot label class to reflect the agent's current working / just-done state.
 *  Working takes precedence — once the agent is no longer working, just-done glows until the
 *  user opens the LOGS AND HISTORY tab for that agent (acknowledgement). */
function pageAgentsApplySlotLabelStateForSlug(slug){
  if(!slug)return;
  const sp=pageAgentsSprites.find(s=>s.slug===slug);
  const rec=pageAgentsArchive.agents&&pageAgentsArchive.agents[slug];
  const working=!!(sp&&sp.working);
  const justDone=!working&&!!(rec&&rec.justDoneNeedsAck);
  // Regular chat slot — single index-keyed lbl above the textarea.
  const idx=pageAgentsSlotSlug.indexOf(slug);
  if(idx>=0){
    const lbl=document.getElementById('pageagents-slot-lbl-'+idx);
    if(lbl){
      lbl.classList.toggle('pageagents-slot-lbl--working',working);
      lbl.classList.toggle('pageagents-slot-lbl--just-done',justDone);
    }
  }
  // Terminal slot — the agent name in the header pin + the lbl above the xterm
  // host both mirror the sprite's working / just-done state, matching the
  // shimmer applied to regular chat slot labels.
  const tslot=document.getElementById('pageagents-chat-slot-'+slug);
  if(tslot&&tslot.dataset&&tslot.dataset.kind==='terminal'){
    const targets=[
      tslot.querySelector('[id^="pageagents-term-name-"]'),
      tslot.querySelector('[id^="pageagents-term-lbl-"]'),
    ];
    targets.forEach(el=>{
      if(!el)return;
      el.classList.toggle('pageagents-slot-lbl--working',working);
      el.classList.toggle('pageagents-slot-lbl--just-done',justDone);
    });
  }
}

/** Clear the just-done flag for an agent (called when user opens its tab). */
function pageAgentsClearJustDoneFlag(slug){
  if(!slug)return;
  const rec=pageAgentsArchive.agents&&pageAgentsArchive.agents[slug];
  if(rec&&rec.justDoneNeedsAck){
    delete rec.justDoneNeedsAck;
    pageAgentsFlushArchiveDebounced();
  }
  const sp=pageAgentsSprites.find(s=>s.slug===slug);
  if(sp)pageAgentsApplyJustDoneClasses(sp,false);
  try{pageAgentsRefreshDeckSpotlight();}catch(_){}
}

/** Restore the just-done glow on every sprite whose archive record still has the flag set
 *  (e.g. user reloaded the page before clicking the tab). */
function pageAgentsRestoreJustDoneFlags(){
  const ag=pageAgentsArchive.agents||{};
  for(const sp of pageAgentsSprites){
    const rec=ag[sp.slug];
    if(rec&&rec.justDoneNeedsAck)pageAgentsApplyJustDoneClasses(sp,true);
  }
  try{pageAgentsRefreshDeckSpotlight();}catch(_){}
}

/** Mount the hover tooltip helper on a sprite wrap. Shows the user's most recent request
 *  to the agent as a thought bubble above the sprite, and magnifies the sprite name.
 *  Idempotent. */
function pageAgentsBindSpriteHoverTooltip(wrap){
  if(!wrap||wrap.dataset.tipBound==='1')return;
  wrap.dataset.tipBound='1';
  let tip=null;
  let mouseHandler=null;
  const remove=()=>{
    if(tip){try{tip.remove();}catch(_){}tip=null;}
    if(mouseHandler){document.removeEventListener('mousemove',mouseHandler,true);mouseHandler=null;}
    wrap.classList.remove('pageagents-sprite-wrap--hovered');
  };
  wrap.addEventListener('mouseenter',()=>{
    if(tip)return; // already shown
    const slug=wrap.dataset.agentSlug;
    if(!slug)return;
    const sp=pageAgentsSprites.find(s=>s.slug===slug);
    const rec=pageAgentsArchive.agents&&pageAgentsArchive.agents[slug];
    // The user's MOST RECENT REQUEST to this agent — the task they last sent, not the
    // agent's reply. Falls through to terminal transcript for terminal agents, then to
    // sprite.lastTask, then to an empty-state hint.
    let line='';
    if(rec&&Array.isArray(rec.runs)&&rec.runs.length){
      const lr=rec.runs[rec.runs.length-1];
      const t=String((lr&&lr.task)||'').trim();
      if(t)line=t.slice(0,200)+(t.length>200?'…':'');
    }
    if(!line&&rec&&rec.kind==='terminal'){
      const tr=String((rec&&rec.transcript)||'').trim();
      line=tr?'Terminal · last activity: '+(tr.split('\n').slice(-3).join(' ').replace(/\s+/g,' ').trim().slice(0,140)+(tr.length>140?'…':'')):'';
    }
    if(!line&&sp&&sp.lastTask)line=String(sp.lastTask).slice(0,200);
    if(!line)line='No requests yet — Send a message to put this agent to work.';
    // Magnify the name on the deck while hovered.
    wrap.classList.add('pageagents-sprite-wrap--hovered');
    // Anchor to the agent's island plot (a stationary element) when available, so the
    // tooltip stays put as the agent walks around. Falls back to the sprite wrap.
    let plot=null;
    try{plot=document.querySelector('.pageagents-plot-el[data-slug="'+CSS.escape(slug)+'"]');}catch(_){}
    // Mount the tip in <body> with position:fixed so it's NOT scaled by the world's
    // transform — guaranteed readable size at any zoom level. Thought-bubble variant
    // renders with rounded cloud edges + two small bubble trails toward the sprite.
    tip=document.createElement('div');
    tip.className='pageagents-sprite-tip pageagents-sprite-tip--floating pageagents-sprite-tip--thought';
    const body=document.createElement('div');
    body.className='pageagents-sprite-tip-body';
    body.textContent=line;
    tip.appendChild(body);
    document.body.appendChild(tip);
    const positionTip=()=>{
      if(!tip)return;
      const target=plot||wrap;
      const r=target.getBoundingClientRect();
      const tipW=tip.offsetWidth||180,tipH=tip.offsetHeight||40;
      // Centre horizontally above the plot's TOP edge, with a comfortable gap so the
      // bubble never overlaps the agent walking inside the island.
      let left=r.left+r.width/2-tipW/2;
      // Keep within viewport horizontally.
      left=Math.max(8,Math.min(window.innerWidth-tipW-8,left));
      let top=r.top-tipH-12;
      // If there's no room above, flip to below.
      if(top<8)top=r.bottom+12;
      tip.style.left=left+'px';
      tip.style.top=top+'px';
    };
    positionTip();
    if(plot){
      // Tip persists until the cursor leaves the entire ISLAND bounding box (not just
      // the small sprite hit-box). Re-fetch the plot rect each move so it tracks any
      // pan/zoom the user does mid-hover.
      mouseHandler=(ev)=>{
        const r=plot.getBoundingClientRect();
        const x=ev.clientX,y=ev.clientY;
        if(x<r.left||x>r.right||y<r.top||y>r.bottom)remove();
        else positionTip();
      };
      document.addEventListener('mousemove',mouseHandler,true);
    }else{
      // No plot DOM — fall back to leaving on sprite-wrap mouseleave.
      const onLeave=()=>{remove();wrap.removeEventListener('mouseleave',onLeave);};
      wrap.addEventListener('mouseleave',onLeave);
    }
  });
}

/** Track + persist the last-operated agent so the deck auto-focuses on it on page show
 *  and after each task finish. */
function pageAgentsSetLastOperated(slug){
  if(!slug)return;
  pageAgentsArchive.lastOperatedSlug=String(slug);
  pageAgentsFlushArchiveDebounced();
}
function pageAgentsAutoFocusLastOperated(){
  const slug=pageAgentsArchive&&pageAgentsArchive.lastOperatedSlug;
  if(!slug)return;
  const sp=pageAgentsSprites.find(s=>s.slug===slug);
  if(!sp)return;
  pageAgentsFocusZoomOnSprite(slug,0.20);
}

function pageAgentsEnsureMotionLoop(){
  if(pageAgentsRaf!==null)return;
  const footOff=10;
  const tick=()=>{
    if(currentView!=='pageagents'){pageAgentsRaf=null;return;}
    // Skip frame work entirely when the tab isn't visible — rAF can still fire
    // at a reduced rate in some browsers, and there's no value in running the
    // O(N²) physics + style writes against a hidden DOM.
    if(typeof document!=='undefined'&&document.hidden){pageAgentsRaf=requestAnimationFrame(tick);return;}
    const world=pageAgentsGetPlayWorld();
    if(!world||pageAgentsSprites.length===0){pageAgentsRaf=null;return;}
    const{W,H}=pageAgentsWorldDims();
    const t=Date.now()/1000;
    pageAgentsSprites.forEach(s=>{
      if(s.badge&&s.working)s.badge.style.opacity=String(0.5+0.5*(0.5+0.5*Math.sin(t*3.5+s.id)));
      const bw=pageAgentsSpriteBW(s),bh=pageAgentsSpriteBH(s);
      const cx=s.x+bw/2;
      const pi=s.planetIdx??0;
      const targetFoot=PAGE_AGENTS_USE_FIELD_MODE?0:pageAgentsSurfaceFootY(cx,pi);
      const foot=s.y+bh-footOff;
      // Travel-on-access: when an agent reads a collaborator's space it walks over to
      // their island for a few seconds. This overrides the working-freeze below so the
      // character actually crosses the bridge mid-run.
      const traveling=!!(s.travelTo&&Date.now()<s.travelTo.until);
      if(s.working&&!traveling){
        const idleBob=Math.sin(t*2.2+s.id)*1.1;
        if(s.svgBox){
          const slope=PAGE_AGENTS_USE_FIELD_MODE?0:pageAgentsSurfaceSlopeAt(cx,pi);
          const lean=Math.max(-11,Math.min(11,-slope*20));
          s.svgBox.style.transform=`translateX(-50%) translateY(${idleBob}px) rotate(${lean}deg)`;
        }
        s.wrap.style.zIndex=String(200+Math.round(s.y));
        return;
      }
      if(s.sleeping){
        // Stay put on the island; gentle breathing only. No walking, no neighbour push.
        const breathe=Math.sin(t*1.4+s.id)*0.7;
        if(s.svgBox)s.svgBox.style.transform=`translateX(-50%) translateY(${breathe}px) rotate(0deg)`;
        s.wrap.style.zIndex=String(200+Math.round(s.y));
        // Decay any leftover velocity so they don't drift on first sleep.
        s.vx*=0.6;s.vy*=0.6;
        return;
      }
      let ax=0,ay=0;
      const sx=s.x+bw/2,sy=s.y+bh/2;
      if(PAGE_AGENTS_USE_FIELD_MODE){
        // Each agent patrols its own island, but if it has any active
        // collaborators it can ALSO wander to the partner's island via the bridge.
        const plot=PAGE_AGENTS_PLOTS[(s.plotIdx??0)%PAGE_AGENTS_PLOTS.length];
        if(plot){
          const ISL_HW=100,ISL_HH=55;
          // Find collaborator plots once per frame, cached on sprite for the clamp pass
          const collabPlots=[];
          for(let oi=0;oi<pageAgentsSprites.length;oi++){
            const oo=pageAgentsSprites[oi];
            if(oo===s||oo.plotIdx==null)continue;
            if(pageAgentsSlugCollabLinked(s.slug,oo.slug)){
              const op=PAGE_AGENTS_PLOTS[oo.plotIdx];
              if(op)collabPlots.push(op);
            }
          }
          s._collabPlots=collabPlots;
          if(traveling){
            // Deliberate visit to a collaborator's island (set by travel-on-access).
            // Lock the wander target onto the travel point until the visit expires.
            s.wanderTargetX=s.travelTo.x;
            s.wanderTargetY=s.travelTo.y;
            s.wanderUntil=t+1;
          }else{
            if(s.travelTo)s.travelTo=null; // visit ended — resume normal wandering home
            // Pick a wander target. If we have collaborators, ~45% chance the
            // next target is on a partner's island (so the agent crosses the bridge).
            if(s.wanderTargetX==null||t>(s.wanderUntil||0)){
              const useCollab=collabPlots.length>0&&Math.random()<0.45;
              const tgt=useCollab?collabPlots[Math.floor(Math.random()*collabPlots.length)]:plot;
              s.wanderTargetX=tgt.x+(Math.random()*2-1)*ISL_HW*0.75;
              s.wanderTargetY=tgt.y+(Math.random()*2-1)*ISL_HH*0.6;
              s.wanderUntil=t+2+Math.random()*4;
            }
          }
          const fy=s.y+bh-footOff;
          ax+=(s.wanderTargetX-sx)*0.0040;
          ay+=(s.wanderTargetY-fy)*0.0040;
          // Detect: is the agent currently on any bridge corridor? If yes, suppress the
          // perpendicular swerve (it would push them OFF the bridge edge) and instead
          // apply along-bridge-axis "yield" so opposing agents shuffle past lengthwise.
          const BR_HW_NEIGHBOR=64;
          let onBridge=null;
          for(let oi=0;oi<collabPlots.length;oi++){
            const op=collabPlots[oi];
            const dxb=op.x-plot.x,dyb=op.y-plot.y;
            const lsq=dxb*dxb+dyb*dyb;
            if(lsq<1)continue;
            const tt=((sx-plot.x)*dxb+(fy-plot.y)*dyb)/lsq;
            if(tt<=0||tt>=1)continue;
            const cb=plot.x+tt*dxb,cby=plot.y+tt*dyb;
            const ddx=sx-cb,ddy=fy-cby;
            if(ddx*ddx+ddy*ddy<=BR_HW_NEIGHBOR*BR_HW_NEIGHBOR){onBridge={p1:plot,p2:op,axisX:dxb/Math.sqrt(lsq),axisY:dyb/Math.sqrt(lsq)};break;}
          }
          for(let oi=0;oi<pageAgentsSprites.length;oi++){
            const oo=pageAgentsSprites[oi];
            if(oo===s)continue;
            const obw=pageAgentsSpriteBW(oo),obh=pageAgentsSpriteBH(oo);
            const ox=oo.x+obw/2,oy=oo.y+obh-footOff;
            let dxa=sx-ox,dya=fy-oy;
            const dst=Math.sqrt(dxa*dxa+dya*dya)||0.001;
            if(dst<58){
              dxa/=dst;dya/=dst;
              const push=(58-dst)/58;
              if(onBridge){
                // On the bridge: only push along the bridge axis, never perpendicular.
                // This makes both agents slow down or back up rather than getting shoved
                // off the side.
                const along=dxa*onBridge.axisX+dya*onBridge.axisY;
                ax+=onBridge.axisX*along*0.10*push;
                ay+=onBridge.axisY*along*0.10*push;
              }else{
                // Perpendicular yield-to-the-right swerve only on islands (lateral space).
                const perpX=-dya,perpY=dxa;
                const sym=((s.id|0)+(oo.id|0))%2===0?1:-1;
                ax+=(dxa+perpX*0.6*sym)*0.11*push;
                ay+=(dya+perpY*0.6*sym)*0.11*push;
              }
            }
          }
          // If currently on a bridge, add a soft pull toward the bridge centerline so
          // pushes don't drift the agent toward the edge.
          if(onBridge){
            const dxb=onBridge.p2.x-onBridge.p1.x,dyb=onBridge.p2.y-onBridge.p1.y;
            const lsq=dxb*dxb+dyb*dyb;
            const tt=((sx-onBridge.p1.x)*dxb+(fy-onBridge.p1.y)*dyb)/lsq;
            const cb=onBridge.p1.x+tt*dxb,cby=onBridge.p1.y+tt*dyb;
            ax+=(cb-sx)*0.018;
            ay+=(cby-fy)*0.018;
          }
        }
      }else{
        const pl=PAGE_AGENTS_PLANETS[pi];
        const angFrac=(s.clusterId%7)/7;
        const pAng=(angFrac-0.5)*Math.PI*1.1;
        const idealX=pl.cx+Math.sin(pAng)*pl.r*0.56-bw/2;
        const idealFoot=pageAgentsSurfaceFootY(idealX+bw/2,pi);
        ax+=(idealX+bw/2-sx)*0.00088;
        ay+=(idealFoot-bh/2-sy)*0.0011;
        ay+=(targetFoot-foot)*0.016;
        // Cross-agent forces only matter in planet mode (agents share a surface)
        pageAgentsSprites.forEach(o=>{
          if(o===s)return;
          const obw=pageAgentsSpriteBW(o),obh=pageAgentsSpriteBH(o);
          const ox=o.x+obw/2,oy=o.y+obh/2;
          let dx=ox-sx,dy=oy-sy;
          const dist=Math.sqrt(dx*dx+dy*dy)||0.001;
          dx/=dist;dy/=dist;
          const minCenterDist=Math.hypot(bw+obw,bh+obh)*0.5+12;
          if(dist<minCenterDist){
            const push=(minCenterDist-dist)/minCenterDist;
            ax-=dx*0.12*push;
            ay-=dy*0.12*push;
          }
          if(o.working)return;
          const jac=pageAgentsJaccard(s.lastTokens,o.lastTokens);
          const linked=pageAgentsSlugCollabLinked(s.slug,o.slug);
          if(linked){
            const pull=Math.min(1.6,(dist-88)/130);
            ax+=dx*pull*0.024;
            ay+=dy*pull*0.024;
          }
          if(jac>0.28){
            ax+=dx*0.01;
            ay+=dy*0.01;
          }else if(jac<0.1&&dist<130){
            ax-=dx*0.052;
            ay-=dy*0.052;
          }
        });
      }
      s.vx=(s.vx+ax)*0.985;
      s.vy=(s.vy+ay)*0.983;
      // Slower cap in field mode so robots feel deliberate, not gliding
      const cap=PAGE_AGENTS_USE_FIELD_MODE?1.15:1.65;
      s.vx=Math.max(-cap,Math.min(cap,s.vx));
      s.vy=Math.max(-cap,Math.min(cap,s.vy));
      const prevX=s.x,prevY=s.y;
      s.x+=s.vx*1.05;
      s.y+=s.vy*1.05;
      // Faster walk phase increment so each step is more visible
      s.walkPhase=(s.walkPhase||0)+Math.hypot(s.x-prevX,s.y-prevY)*0.30;
      if(PAGE_AGENTS_USE_FIELD_MODE){
        // SOFT island bounds: the agent must be on its own island, OR on a
        // collaborator's island, OR on the bridge corridor between own & a collaborator.
        // If the new position isn't in any allowed area, project to the closest one.
        const plot=PAGE_AGENTS_PLOTS[(s.plotIdx??0)%PAGE_AGENTS_PLOTS.length];
        if(plot){
          const ISL_HW=100,ISL_HH=55,BR_HW=64;
          const cx2=s.x+bw/2;
          const fy=s.y+bh-footOff;
          const inIsl=(px,py,p)=>Math.abs(px-p.x)<=ISL_HW&&Math.abs(py-p.y)<=ISL_HH;
          const inBr=(px,py,p1,p2,hw)=>{
            const dxb=p2.x-p1.x,dyb=p2.y-p1.y;
            const lsq=dxb*dxb+dyb*dyb;
            if(lsq<1)return false;
            const tt=((px-p1.x)*dxb+(py-p1.y)*dyb)/lsq;
            if(tt<0||tt>1)return false;
            const cb=p1.x+tt*dxb,cby=p1.y+tt*dyb;
            const ddx=px-cb,ddy=py-cby;
            return ddx*ddx+ddy*ddy<=hw*hw;
          };
          // Closest-point projections so we can soft-clamp instead of revert.
          const projIsl=(px,py,p)=>({
            x:Math.max(p.x-ISL_HW,Math.min(p.x+ISL_HW,px)),
            y:Math.max(p.y-ISL_HH,Math.min(p.y+ISL_HH,py)),
          });
          const projBr=(px,py,p1,p2,hw)=>{
            const dxb=p2.x-p1.x,dyb=p2.y-p1.y;
            const lsq=dxb*dxb+dyb*dyb;
            if(lsq<1)return{x:p1.x,y:p1.y};
            let tt=((px-p1.x)*dxb+(py-p1.y)*dyb)/lsq;
            tt=Math.max(0,Math.min(1,tt));
            const cb=p1.x+tt*dxb,cby=p1.y+tt*dyb;
            const ddx=px-cb,ddy=py-cby;
            const dl=Math.sqrt(ddx*ddx+ddy*ddy);
            if(dl<=hw)return{x:px,y:py};
            return{x:cb+ddx/dl*hw,y:cby+ddy/dl*hw};
          };
          let allowed=inIsl(cx2,fy,plot);
          const collabPlots=s._collabPlots||[];
          if(!allowed){
            for(let oi=0;oi<collabPlots.length;oi++){
              const op=collabPlots[oi];
              if(inIsl(cx2,fy,op)||inBr(cx2,fy,plot,op,BR_HW)){allowed=true;break;}
            }
          }
          if(!allowed){
            // Soft-clamp: snap the foot to the closest point of any allowed region
            // (own island, collab island, or bridge corridor). Velocity damped, but
            // wander target is preserved so the agent keeps moving toward its goal.
            let bestDist=Infinity,bestX=cx2,bestY=fy;
            const tryPt=(p)=>{const d=Math.hypot(cx2-p.x,fy-p.y);if(d<bestDist){bestDist=d;bestX=p.x;bestY=p.y;}};
            tryPt(projIsl(cx2,fy,plot));
            for(let oi=0;oi<collabPlots.length;oi++){
              const op=collabPlots[oi];
              tryPt(projIsl(cx2,fy,op));
              tryPt(projBr(cx2,fy,plot,op,BR_HW));
            }
            if(bestDist<Infinity){
              s.x=bestX-bw/2;
              s.y=bestY-bh+footOff;
              s.vx*=0.5;s.vy*=0.5;
            }else{
              // Shouldn't happen (own plot always exists), but as a safety net revert.
              s.x=prevX;s.y=prevY;
              s.vx*=0.3;s.vy*=0.3;
            }
            // Don't reset wander target: that was the bug that caused mid-bridge
            // ping-pong. Let the existing target keep pulling.
          }
          // Stuck-detector: if the agent has barely moved for a few seconds AND has a
          // wander target, pick a fresh one — handles the "stuck after crossing" case
          // where damping pinned the agent at zero velocity inside an allowed region.
          const moved=Math.hypot(s.x-(s._stuckPrevX??s.x),s.y-(s._stuckPrevY??s.y));
          if(moved>2){s._stuckPrevX=s.x;s._stuckPrevY=s.y;s._stuckSince=t;}
          else if(s._stuckSince==null){s._stuckSince=t;s._stuckPrevX=s.x;s._stuckPrevY=s.y;}
          if(s._stuckSince!=null&&t-s._stuckSince>3.5){
            // Force a new wander target. Bias toward own island to avoid orphan limbo.
            const useCollab=collabPlots.length>0&&Math.random()<0.3;
            const tgt=useCollab?collabPlots[Math.floor(Math.random()*collabPlots.length)]:plot;
            s.wanderTargetX=tgt.x+(Math.random()*2-1)*ISL_HW*0.5;
            s.wanderTargetY=tgt.y+(Math.random()*2-1)*ISL_HH*0.4;
            s.wanderUntil=t+2.5+Math.random()*2;
            // Kick it out of zero-velocity stasis with a small impulse toward the target.
            const kx=s.wanderTargetX-(s.x+bw/2),ky=s.wanderTargetY-(s.y+bh-footOff);
            const kl=Math.hypot(kx,ky)||1;
            s.vx+=kx/kl*0.6;s.vy+=ky/kl*0.6;
            s._stuckSince=null;
          }
        }
      }else{
        const _pl=PAGE_AGENTS_PLANETS[pi];
        const _maxDx=_pl.r*0.83;
        s.x=Math.max(_pl.cx-_maxDx-bw/2+3,Math.min(_pl.cx+_maxDx-bw/2-3,s.x));
      }
    });
    pageAgentsResolveAgentOverlaps(W,H);
    if(!PAGE_AGENTS_USE_FIELD_MODE){
      pageAgentsSprites.forEach(s=>{
        const bw=pageAgentsSpriteBW(s),bh=pageAgentsSpriteBH(s);
        const cx=s.x+bw/2;
        const tgt=pageAgentsSurfaceFootY(cx,s.planetIdx??0)-bh+footOff;
        s.y=s.y*0.12+tgt*0.88;
        s.vy*=0.72;
      });
    }
    pageAgentsSprites.forEach(s=>{
      const bw=pageAgentsSpriteBW(s),bh=pageAgentsSpriteBH(s);
      const cx=s.x+bw/2;
      const pi2=s.planetIdx??0;
      const speed=Math.hypot(s.vx,s.vy);
      const traveling=!!(s.travelTo&&Date.now()<s.travelTo.until);
      if(s.working&&!traveling){
        if(!PAGE_AGENTS_USE_FIELD_MODE){
          const tgt=pageAgentsSurfaceFootY(cx,pi2)-bh+footOff;
          s.y=s.y*0.28+tgt*0.72;
        }
        s.wrap.style.left=s.x+'px';
        s.wrap.style.top=s.y+'px';
        s.wrap.style.transform='translateZ(0)';
        s.wrap.style.zIndex=String(200+Math.round(s.y));
        return;
      }
      const stride=Math.sin(s.walkPhase||0);
      const moving=speed>0.05;
      // Pronounced step: lift body UP at mid-step (foot in air), drop at foot-strike.
      // Plus lateral SWAY (weight shifts side to side as feet alternate). Robots stomp.
      const stepLift=moving?(1-Math.abs(stride))*6:0;
      const sway=moving?stride*4:0;
      const slope=PAGE_AGENTS_USE_FIELD_MODE?0:pageAgentsSurfaceSlopeAt(cx,pi2);
      const lean=Math.max(-13,Math.min(13,-slope*21+stride*3));
      if(s.svgBox)s.svgBox.style.transform=`translateX(calc(-50% + ${sway}px)) translateY(${-stepLift}px) rotate(${lean}deg)`;
      s.wrap.style.left=s.x+'px';
      s.wrap.style.top=s.y+'px';
      s.wrap.style.transform='translateZ(0)';
      s.wrap.style.zIndex=String(100+Math.round(s.y));
    });
    // Throttle collab-connection refresh (catches edge-graph changes ~5x/sec)
    pageAgents_connTick=(pageAgents_connTick||0)+1;
    if(PAGE_AGENTS_USE_FIELD_MODE&&pageAgents_connTick%12===0)pageAgentsRefreshConnections();
    pageAgentsRaf=requestAnimationFrame(tick);
  };
  pageAgentsRaf=requestAnimationFrame(tick);
}
let pageAgents_connTick=0;
/* ── COLLABORATION TOGGLE (shift-click) ──
   First shift-click on a sprite → marks it as the pending collab partner (purple ring).
   Second shift-click on a different sprite → toggles the edge between them
   (creates one if none exists, removes it if it does), then refreshes the bridge layer.
   Shift-click the pending sprite again, or click any non-sprite area, → cancel pending. */
let pageAgents_collabPendingSlug=null;
function pageAgentsClearCollabPending(){
  pageAgents_collabPendingSlug=null;
  document.querySelectorAll('.pageagents-sprite-wrap--collab-pending').forEach(el=>el.classList.remove('pageagents-sprite-wrap--collab-pending'));
}
function pageAgentsToggleCollabEdge(slugA,slugB){
  if(!slugA||!slugB||slugA===slugB)return;
  if(!pageAgentsArchive.graph)pageAgentsArchive.graph={nodes:[],edges:[]};
  if(!Array.isArray(pageAgentsArchive.graph.edges))pageAgentsArchive.graph.edges=[];
  const E=pageAgentsArchive.graph.edges;
  const idx=E.findIndex(e=>e&&((e.source===slugA&&e.target===slugB)||(e.source===slugB&&e.target===slugA)));
  const added=idx<0;
  if(idx>=0){E.splice(idx,1);}
  else{E.push({source:slugA,target:slugB});}
  // Persist if the archive has a flush mechanism
  if(typeof pageAgentsScheduleArchiveFlush==='function')pageAgentsScheduleArchiveFlush();
  // When a link is newly established, draw their islands close together; otherwise
  // just redraw the (now removed) connection.
  if(added&&typeof pageAgentsArrangeCollabIslands==='function')pageAgentsArrangeCollabIslands(slugA);
  else pageAgentsRefreshConnections();
}
function pageAgentsHandleSpriteShiftClick(slug){
  if(!slug)return;
  if(!pageAgents_collabPendingSlug){
    // First shift-click — mark this sprite as pending
    pageAgents_collabPendingSlug=slug;
    document.querySelectorAll('.pageagents-sprite-wrap').forEach(w=>{
      w.classList.toggle('pageagents-sprite-wrap--collab-pending',w.dataset.agentSlug===slug);
    });
    return;
  }
  if(pageAgents_collabPendingSlug===slug){
    // Same sprite shift-clicked again → cancel pending state
    pageAgentsClearCollabPending();
    return;
  }
  // Second sprite — toggle the edge, clear pending
  pageAgentsToggleCollabEdge(pageAgents_collabPendingSlug,slug);
  pageAgentsClearCollabPending();
}

function pageAgentsCreateAgentForTask(){
  const play=document.getElementById('pageagents-play');
  const world=pageAgentsGetPlayWorld()||play;
  if(!world)return null;
  const maxAgents=PAGE_AGENTS_MAX_SPRITES;
  while(pageAgentsSprites.length>=maxAgents){
    const rm=pageAgentsSprites.shift();
    if(pageAgentsFocusedSlug&&rm&&rm.slug===pageAgentsFocusedSlug)pageAgentsSetFocus(null);
    if(rm&&rm.slug)pageAgentsInvalidateSlotsForSlug(rm.slug);
    if(rm&&rm.wrap&&rm.wrap.parentNode)rm.wrap.remove();
  }
  const idty=pageAgentsAllocateNewAgentIdentity();
  const id=idty.id;
  const seed=idty.seed;
  const nameInField=document.getElementById('pageagents-agent-name');
  const custom=nameInField&&String(nameInField.value||'').trim().slice(0,80);
  // No two agents may share the same name — suffix _2/_3/… on collision.
  let name=pageAgentsMakeUniqueAgentName(custom||idty.name);
  let slug=pageAgentsMakeAgentSlug(name,idty.id);
  let bump=0;
  while(pageAgentsSlugInUse(slug)&&bump<200){
    bump++;
    slug=pageAgentsMakeAgentSlug(name,idty.id+bump);
  }
  const wrap=document.createElement('div');
  wrap.className='pageagents-sprite-wrap';
  wrap.dataset.agentId=String(id);
  wrap.dataset.agentSlug=slug;
  wrap.title='Click to select. Double-click or right-click for options (Close / Rename / Diverge). Shift-click two robots to link / unlink collaboration (bridge).';
  const bw=56,bh=94;
  wrap.style.cssText=`position:absolute;width:${bw}px;height:${bh}px;pointer-events:auto;cursor:pointer;z-index:5`;
  wrap.addEventListener('click',(ev)=>{
    ev.stopPropagation();
    const sp=pageAgentsSprites.find(z=>z.wrap===wrap);
    if(!sp||sp.working)return;
    if(ev.shiftKey){pageAgentsHandleSpriteShiftClick(sp.slug);return;}
    pageAgentsSetFocus(sp.slug===pageAgentsFocusedSlug?null:sp.slug);
    pageAgentsHideSpriteActionMenu();
  });
  // Action popup (Close / Rename / Diverge) opens on double-click or right-click only.
  const openActionMenu=(ev)=>{
    ev.preventDefault();
    ev.stopPropagation();
    const sp=pageAgentsSprites.find(z=>z.wrap===wrap);
    if(!sp||sp.working)return;
    pageAgentsSetFocus(sp.slug);
    pageAgentsShowSpriteActionMenu(sp.slug);
  };
  wrap.addEventListener('dblclick',openActionMenu);
  wrap.addEventListener('contextmenu',openActionMenu);
  const badge=document.createElement('div');
  badge.className='pageagents-work-badge';
  badge.setAttribute('aria-label','Working');
  badge.style.cssText='display:none;position:absolute;left:50%;top:-2px;transform:translateX(-50%);z-index:4;width:24px;height:24px';
  badge.innerHTML='<svg width="24" height="24" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="9.5" fill="#6C63FF" stroke="#FFD700" stroke-width="1.4"/><path d="M12 7v3M12 14v3M8 12h3M13 12h3" stroke="#FFD700" stroke-width="1.3" stroke-linecap="round"/></svg>';
  const svgBox=document.createElement('div');
  svgBox.style.cssText='position:absolute;left:50%;top:12px;transform:translateX(-50%);width:48px;height:58px';
  svgBox.innerHTML=pageAgentsBuildSpriteSvg(seed,pageAgentsSpriteOptsForSlug(slug));
  const nameEl=document.createElement('div');
  nameEl.className='pageagents-sprite-name';
  nameEl.textContent=name;
  nameEl.style.cssText='position:absolute;left:-18px;right:-18px;top:73px;text-align:center;font-size:13px;line-height:1.2;color:var(--t0);white-space:normal;overflow-wrap:anywhere;word-break:break-word;font-weight:800;letter-spacing:.01em;text-shadow:0 1px 3px rgba(0,0,0,.9),0 0 6px rgba(0,0,0,.55)';
  const barWrap=document.createElement('div');
  barWrap.style.cssText='position:absolute;left:2px;right:2px;top:88px;height:5px;border-radius:3px;background:var(--bg3);border:1px solid var(--bdr);overflow:hidden;opacity:0;transition:opacity 0.18s';
  const barInner=document.createElement('div');
  barInner.style.cssText='height:100%;width:0%;background:linear-gradient(90deg,var(--acc),#8b84ff);border-radius:2px;transition:width 0.1s linear';
  barWrap.appendChild(barInner);
  const groundSh=document.createElement('div');
  groundSh.className='pageagents-sprite-ground-shadow';
  wrap.appendChild(groundSh);
  wrap.appendChild(badge);
  wrap.appendChild(svgBox);
  wrap.appendChild(nameEl);
  wrap.appendChild(barWrap);
  world.appendChild(wrap);
  const planetIdx=pageAgentsSprites.length%PAGE_AGENTS_PLANETS.length;
  const plotIdx=PAGE_AGENTS_USE_FIELD_MODE?pageAgentsAllocateNextPlot():pageAgentsSprites.length%PAGE_AGENTS_PLOTS.length;
  let x,y;
  if(PAGE_AGENTS_USE_FIELD_MODE){
    const plot=PAGE_AGENTS_PLOTS[plotIdx];
    x=plot.x-bw/2;
    // Foot exactly on island top: s.y + bh - footOff = plot.y  →  s.y = plot.y - bh + footOff
    y=plot.y-bh+10;
  }else{
    const sp=pageAgentsRandomSpawnXY(bw,bh,null,planetIdx);
    x=sp.x;y=sp.y;
    const footOff=10;
    y=pageAgentsSurfaceFootY(x+bw/2,planetIdx)-bh+footOff;
  }
  wrap.style.left=x+'px';wrap.style.top=y+'px';
  const sprite={slug,wrap,id,name,seed,x,y,vx:(Math.random()-0.5)*0.35,vy:(Math.random()-0.5)*0.35,badge,barInner,barWrap,nameEl,svgBox,working:false,lastTask:'',lastTokens:new Set(),clusterId:0,walkPhase:0,_prevX:x,planetIdx,plotIdx};
  pageAgentsSprites.push(sprite);
  pageAgentsUpdatePlayHint();
  pageAgentsEnsureMotionLoop();
  if(PAGE_AGENTS_USE_FIELD_MODE)pageAgentsRefreshPlots();
  return sprite;
}

function collectPageTreeNodes(){
  const ws=G.cws||'home';
  const seen=new Set();
  const out=[];
  function addNode(n){
    if(!n||seen.has(n.id))return;
    if((n.wsId||'home')!==ws)return;
    if(n.notesTabOnly)return;
    seen.add(n.id);
    out.push(n);
  }
  function walkFrom(pid){
    ch(pid).forEach(c=>{
      addNode(c);
      walkFrom(c.id);
    });
  }
  const root=cPid();
  if(root){
    const rn=gn(root);
    if(rn)addNode(rn);
    walkFrom(root);
  }else walkFrom(null);
  return out;
}

function computePageTreeRootsFromCh(out){
  const idSet=new Set(out.map(n=>n.id));
  const incoming=new Set();
  out.forEach(p=>{
    ch(p.id).forEach(c=>{
      if(c&&idSet.has(c.id))incoming.add(c.id);
    });
  });
  return out.filter(n=>!incoming.has(n.id));
}

function packPageTreeHierarchyNode(n,idSet){
  const kids=ch(n.id).filter(c=>c&&idSet.has(c.id));
  const o={
    id:n.id,
    name:n.name||'',
    color:n.color,
    _node:n
  };
  if(kids.length)o.children=kids.map(c=>packPageTreeHierarchyNode(c,idSet));
  return o;
}

function layoutPageTreeHierarchy(nodes){
  const idSet=new Set(nodes.map(n=>n.id));
  const roots=computePageTreeRootsFromCh(nodes);
  const ws=G.cws||'home';
  const wsLabel=(G.workspaces||[]).find(w=>w.id===ws)?.name||ws;
  const childData=roots.map(r=>packPageTreeHierarchyNode(r,idSet));
  const wrap={
    id:'__pagetree_vroot',
    name:wsLabel,
    _virtualRoot:true,
    children:childData
  };
  const hier=d3.hierarchy(wrap,d=>d.children||null);
  d3.tree().nodeSize([216,92]).separation((a,b)=>a.parent===b.parent?1:1.22)(hier);
  const pos=new Map();
  const nodeH=44;
  const vRootH=40;
  hier.each(d=>{
    pos.set(d.data.id,{x:d.x,y:d.y,isVirtual:!!d.data._virtualRoot});
  });
  return{hier,pos,nodeH,vRootH,idSet,links:hier.links()};
}

function pageTreeCurvedLinkPath(sNode,tNode,sH,tH){
  const x1=sNode.x,y1=sNode.y+sH/2,x2=tNode.x,y2=tNode.y-tH/2;
  const mid=y1+Math.max(32,(y2-y1)*0.48);
  return`M${x1},${y1}C${x1},${mid} ${x2},${mid} ${x2},${y2}`;
}

function renderPageTree(){
  if(currentView!=='pagetree')return;
  const svgEl=document.getElementById('pagetree-svg');
  if(!svgEl)return;
  const theme=G.theme||'galaxy';
  const gridColor=theme==='bright'?'#d2d2d7':'#fff';
  const gridOpacity=theme==='bright'?0.28:0.08;
  if(!pageTreeSvg){
    pageTreeSvg=d3.select('#pagetree-svg');
    pageTreeSvg.selectAll('*').remove();
    const defs=pageTreeSvg.append('defs');
    defs.append('pattern').attr('id','pagetree-grid').attr('width',40).attr('height',40).attr('patternUnits','userSpaceOnUse').append('path').attr('d','M 40 0 L 0 0 0 40').attr('fill','none').attr('stroke',gridColor).attr('stroke-width',0.15).attr('stroke-opacity',gridOpacity);
    pageTreeG=pageTreeSvg.append('g');
    pageTreeG.append('rect').attr('fill','url(#pagetree-grid)').attr('x',-8000).attr('y',-8000).attr('width',16000).attr('height',16000).attr('pointer-events','all').style('cursor','grab');
    pageTreeLinkG=pageTreeG.append('g').attr('class','pagetree-links');
    pageTreeNodeG=pageTreeG.append('g').attr('class','pagetree-nodes');
    pageTreeZoom=d3.zoom().scaleExtent([0.12,4]).on('zoom',e=>{pageTreeG.attr('transform',e.transform);});
    pageTreeSvg.call(pageTreeZoom);
    const updateDim=()=>{
      const r=svgEl.getBoundingClientRect();
      pageTreeSvg.attr('width',r.width).attr('height',r.height);
    };
    updateDim();
    if(!pageTreeViewportBound){
      bindViewportChange(updateDim);
      pageTreeViewportBound=true;
    }
  }
  pageTreeLinkG.selectAll('*').remove();
  pageTreeNodeG.selectAll('*').remove();
  const nodes=collectPageTreeNodes();
  if(nodes.length===0){
    pageTreeNodeG.append('text').attr('x',0).attr('y',0).attr('text-anchor','middle').attr('fill','var(--t3)').style('font-size','15px').text('No nodes in this home view yet.');
    return;
  }
  let hier,pos,nodeH,vRootH,links;
  try{
    const L=layoutPageTreeHierarchy(nodes);
    hier=L.hier;pos=L.pos;nodeH=L.nodeH;vRootH=L.vRootH;links=L.links;
  }catch(err){
    console.warn('Tree layout failed',err);
    pageTreeNodeG.append('text').attr('x',0).attr('y',0).attr('text-anchor','middle').attr('fill','var(--t3)').style('font-size','14px').text('Could not build tree layout for this graph.');
    return;
  }
  const treeLinks=links.filter(l=>l.target.depth>0);
  pageTreeLinkG.selectAll('path').data(treeLinks).enter().append('path')
    .attr('d',l=>{
      const sh=l.source.data._virtualRoot?vRootH:nodeH;
      const th=l.target.data._virtualRoot?vRootH:nodeH;
      return pageTreeCurvedLinkPath(l.source,l.target,sh,th);
    })
    .attr('fill','none')
    .attr('stroke','var(--acc)')
    .attr('stroke-opacity',l=>l.source.data._virtualRoot?0.52:0.3)
    .attr('stroke-width',l=>l.source.data._virtualRoot?2.2:1.45);
  const desc=hier.descendants().sort((a,b)=>a.depth-b.depth||a.x-b.x);
  const ng=pageTreeNodeG.selectAll('g.pagetree-node').data(desc).enter().append('g').attr('class','pagetree-node').attr('transform',d=>`translate(${d.x},${d.y})`).style('cursor','pointer').on('click',(ev,d)=>{
      if(d.data._virtualRoot){swView('home');goRoot();return;}
      const id=d.data._node?.id||d.data.id;
      if(!id)return;
      swView('home');
      setTimeout(()=>navTo(id),80);
    });
  ng.each(function(d){
    const g=d3.select(this);
    const isV=!!d.data._virtualRoot;
    const h=isV?vRootH:nodeH;
    const w=isV?112:100;
    const fill=isV?'var(--bg3)':'var(--bg2)';
    const stroke=isV?'var(--acc)':'var(--bdr)';
    g.append('rect').attr('x',-w).attr('y',-h/2).attr('width',2*w).attr('height',h).attr('rx',isV?12:10).attr('fill',fill).attr('stroke',stroke).attr('stroke-width',isV?1.8:1.15).attr('stroke-opacity',isV?0.85:1);
    if(!isV&&d.data.color){
      g.append('rect').attr('x',-w).attr('y',-h/2).attr('width',5).attr('height',h).attr('rx',2).attr('fill',d.data.color);
    }
    const label=isV?(d.data.name||'Workspace'):((d.data.name||'').length>20?(d.data.name||'').slice(0,20)+'…':(d.data.name||''));
    g.append('text').attr('text-anchor','middle').attr('dy','0.35em').attr('fill','var(--t0)').style('font-size',isV?'13px':'12px').style('font-weight',isV?'600':'500').text(label);
  });
  const rect=svgEl.getBoundingClientRect();
  const xs=[],ys=[],hs=[];
  desc.forEach(d=>{
    xs.push(d.x);ys.push(d.y);
    hs.push(d.data._virtualRoot?vRootH:nodeH);
  });
  const padX=140,padY=70;
  const minX=Math.min(...xs)-padX,maxX=Math.max(...xs)+padX;
  const minY=Math.min(...ys.map((y,i)=>y-hs[i]/2))-padY,maxY=Math.max(...ys.map((y,i)=>y+hs[i]/2))+padY;
  const cx=(minX+maxX)/2,cy=(minY+maxY)/2;
  const scale=Math.min(rect.width/Math.max(1,maxX-minX),rect.height/Math.max(1,maxY-minY),1.35)*0.82;
  pageTreeSvg.transition().duration(400).call(pageTreeZoom.transform,d3.zoomIdentity.translate(rect.width/2,rect.height/2).scale(scale||0.5).translate(-cx,-cy));
}

function pageAgentsRestoreLocal(){
  try{
    const t=localStorage.getItem('expandAgents_hf');
    const u=localStorage.getItem('expandAgents_customUrl');
    const k=localStorage.getItem('expandAgents_customKey');
    const hf=document.getElementById('pageagents-hf-token');
    const cu=document.getElementById('pageagents-custom-url');
    const ck=document.getElementById('pageagents-custom-key');
    if(hf&&t)hf.value=t;
    if(cu&&u)cu.value=u;
    if(ck&&k)ck.value=k;
  }catch(e){}
}

function pageAgentsModelChange(){
  const m=document.getElementById('pageagents-model');
  const v=m?m.value:'local';
  if(m)m._lastModel=v;
  const uw=document.getElementById('pageagents-custom-url-wrap');
  const kw=document.getElementById('pageagents-custom-key-wrap');
  const hf=document.getElementById('pageagents-hf-wrap');
  const isTerminal=v==='terminal';
  const isClaude=v==='custom-claude';
  const showHf=!isTerminal&&(v==='distilgpt2'||v==='gemma2');
  const showCustom=!isTerminal&&(v==='custom'||isClaude);
  if(hf)hf.style.display=showHf?'block':'none';
  if(uw)uw.style.display=showCustom?'block':'none';
  if(kw)kw.style.display=showCustom?'block':'none';
  // Repurpose the URL+Key inputs for Claude: URL field becomes "Model name", key field is the
  // Anthropic API key. Restore OpenAI-style labels otherwise.
  const urlLbl=document.getElementById('pageagents-custom-url-lbl');
  const urlInp=document.getElementById('pageagents-custom-url');
  const keyLbl=document.getElementById('pageagents-custom-key-lbl');
  const keyInp=document.getElementById('pageagents-custom-key');
  if(isClaude){
    if(urlLbl)urlLbl.textContent='Claude model name';
    if(urlInp){urlInp.type='text';urlInp.placeholder='claude-opus-4-7 (or claude-sonnet-4-6, claude-haiku-4-5-20251001…)';
      if(!urlInp.value)urlInp.value=localStorage.getItem('expandAgents_claudeModel')||'claude-opus-4-7';}
    if(keyLbl)keyLbl.textContent='Anthropic API key';
    if(keyInp){keyInp.placeholder='sk-ant-…';
      if(!keyInp.value)keyInp.value=localStorage.getItem('expandAgents_claudeKey')||'';}
  }else if(showCustom){
    if(urlLbl)urlLbl.textContent='Endpoint URL';
    if(urlInp){urlInp.type='url';urlInp.placeholder='https://api.openai.com/v1/chat/completions';}
    if(keyLbl)keyLbl.textContent='API key';
    if(keyInp){keyInp.placeholder='';}
  }
  // Reflect intent on the rightmost "+" tile so the user knows what their next click will do.
  const adder=document.getElementById('pageagents-chat-add-slot');
  if(adder){
    if(isTerminal){
      adder.title='Open a new Terminal column (MODEL is set to Terminal)';
      adder.setAttribute('aria-label','Open a new Terminal column');
      adder.classList.add('pageagents-chat-add--terminal');
    }else{
      adder.title='Add agent chat column';
      adder.setAttribute('aria-label','Add agent chat column');
      adder.classList.remove('pageagents-chat-add--terminal');
    }
  }
}
/* ── TERMINAL-AS-AGENT helpers ──
   Each open terminal is a first-class entry in pageAgentsArchive.agents
   with kind:'terminal' and a rolling transcript field. Sprites use the
   Industrial robot variant so they're visually distinct on the deck. */
const PAGE_AGENTS_TERMINAL_TRANSCRIPT_CAP=100*1024;
const PAGE_AGENTS_TERMINAL_COLLAB_TAIL=3000;
// Cap per-agent runs[] so long-lived terminals don't grow unbounded — each run
// holds a task string + xterm screen snapshot; the detail panel rebuilds them
// all per render, so the array length directly costs render time. Older runs
// drop off the front; the agent's transcript still keeps a rolling tail.
const PAGE_AGENTS_RUNS_CAP=200;

/** Cached sprite box dimensions to avoid offsetWidth/offsetHeight reads in the
 *  per-frame motion loop. Sprite wraps have fixed CSS sizes and only change on
 *  explicit class swaps; the cache is read in O(1) and invalidated when the
 *  sprite is rebuilt or marked dirty. Reading offsetWidth in the hot loop forces
 *  synchronous layout — with N sprites this is O(N²) layout thrashes per frame.
 *  Defaults match the historical fallbacks at the call sites (56×94). */
function pageAgentsSpriteBW(s){
  if(s._bw)return s._bw;
  const w=s.wrap?s.wrap.offsetWidth:0;
  // Only cache a real measurement — if the wrap isn't laid out yet (mount race,
  // display:none, etc.) fall back to the historical default but keep _bw=0 so
  // the next frame retries and locks in the real size.
  if(w>0){s._bw=w;return w;}
  return 56;
}
function pageAgentsSpriteBH(s){
  if(s._bh)return s._bh;
  const h=s.wrap?s.wrap.offsetHeight:0;
  if(h>0){s._bh=h;return h;}
  return 94;
}
function pageAgentsInvalidateSpriteDims(s){if(s){s._bw=0;s._bh=0;}}

/** Strip ANSI / OSC / control sequences from raw PTY bytes for the saved transcript.
 *  Keeps printable text + \n + \t. Removes CR, BEL, ESC[…], ESC]…BEL/ST, single-char ESC, etc. */
function pageAgentsStripAnsi(s){
  if(!s)return '';
  let out=String(s);
  // OSC: ESC ] ... (BEL or ESC \)
  out=out.replace(/\x1B\][^\x07\x1B]*(?:\x07|\x1B\\)/g,'');
  // CSI: ESC [ ... final byte @-~
  out=out.replace(/\x1B\[[0-?]*[ -/]*[@-~]/g,'');
  // Other ESC sequences (ESC + single byte or ESC P/X/^/_ ... ST)
  out=out.replace(/\x1B[PX^_][^\x1B]*(?:\x1B\\|$)/g,'');
  out=out.replace(/\x1B[@-Z\\-_a-z]/g,'');
  // Bare ESC and other C0/C1 controls except \n and \t
  out=out.replace(/[\x00-\x08\x0B-\x1F\x7F]/g,'');
  // Backspace handling: collapse 'X\b' as best-effort (we already removed \b above).
  return out;
}

/** Aggressive second-pass cleanup: drops escape-sequence-shaped residue that the
 *  primary stripper missed because the leading ESC byte arrived in a different ws
 *  chunk than its CSI/SS3 tail. Strips bracketed-paste markers ([200~ / [201~),
 *  every single or repeated CSI shape ([A, [B, [O, [I, [200~, [?2004h, [0m, [1;2H…),
 *  standalone SS3 arrow-key residue (OA/OB/OC/OD at word boundaries), and orphan
 *  bracket runs. In terminal-log context a stripped "[A]" in prose is an acceptable
 *  trade for a clean log free of "[[[[[[" garbage. */
function pageAgentsStripCsiResidue(s){
  let t=String(s||'');
  // 1. Bracketed-paste markers — common residue when the user pastes text or when
  //    bracketed-paste mode is toggled. Strip explicitly first so the [200/[201
  //    prefixes don't bleed into the more general regex below.
  t=t.replace(/\[(?:200|201)~/g,'');
  // 2. CSI residue (any count, no minimum). The final byte covers every CSI
  //    terminator: A-Z, a-z, @, ~. This catches:
  //    [A [B [C [D (arrows), [H [F (home/end), [I [O (focus reports),
  //    [J [K (erase), [P [X (delete), [m / [0m / [<n>m (SGR colors),
  //    [<r>;<c>H (cursor positioning), [<n>~ (function keys),
  //    [?<n>h / [?<n>l (DEC private modes — e.g. [?2004h bracketed paste enable).
  t=t.replace(/\[[\?>!]?[0-9;]*[@A-Za-z~]/g,'');
  // 3. SS3 arrow-key residue (OA/OB/OC/OD) — only when at a word boundary so
  //    "macOS", "iOS", legitimate prose stays intact.
  t=t.replace(/(^|[^A-Za-z0-9])O([A-D])(?![A-Za-z0-9])/g,'$1');
  // 4. Stray `[` runs (2+) left behind by anything above.
  t=t.replace(/\[{2,}/g,'');
  // 5. Collapse the blank lines introduced by the strips.
  t=t.replace(/\n{3,}/g,'\n\n');
  return t;
}

/** One-shot pass over every terminal-kind agent in the archive: clean residue out of
 *  the saved transcript and each run's task/output so a refresh shows clean logs
 *  even for records captured before the stripper existed. Idempotent — re-running
 *  on already-clean data is a no-op. Persists changes via the standard debounced flush. */
function pageAgentsCleanupTerminalLogsOnce(){
  const ag=pageAgentsArchive&&pageAgentsArchive.agents;
  if(!ag)return 0;
  let cleaned=0;
  Object.keys(ag).forEach(slug=>{
    const rec=ag[slug];
    if(!rec||rec.kind!=='terminal')return;
    let changed=false;
    if(typeof rec.transcript==='string'&&rec.transcript){
      const t2=pageAgentsStripCsiResidue(rec.transcript);
      if(t2!==rec.transcript){rec.transcript=t2;changed=true;}
    }
    if(Array.isArray(rec.runs)){
      rec.runs.forEach(r=>{
        if(!r)return;
        if(typeof r.task==='string'&&r.task){
          const v=pageAgentsStripCsiResidue(r.task).trim();
          if(v!==r.task){r.task=v;changed=true;}
        }
        if(typeof r.output==='string'&&r.output){
          const v=pageAgentsStripCsiResidue(r.output);
          if(v!==r.output){r.output=v;changed=true;}
        }
      });
    }
    if(changed)cleaned++;
  });
  if(cleaned){
    try{pageAgentsFlushArchiveDebounced();}catch(_){}
  }
  return cleaned;
}

/** Cross-message tail buffer for the ANSI stripper. Maps slug → unterminated ESC
 *  prefix that should be held over until the next chunk arrives so the full
 *  sequence can be matched + stripped in one pass. */
const _terminalEscTail=new Map();

/** Resolve a display name to one that doesn't collide with any other agent's name.
 *  Collisions are case-insensitive; suffix is "_2", "_3", … starting at 2.
 *  `ignoreSlug` lets a rename of an existing agent skip its own current name. */
function pageAgentsMakeUniqueAgentName(name,ignoreSlug){
  const ag=(pageAgentsArchive&&pageAgentsArchive.agents)||{};
  const taken=new Set();
  Object.keys(ag).forEach(s=>{
    if(s===ignoreSlug)return;
    const r=ag[s];
    if(r&&r.name)taken.add(String(r.name).toLowerCase());
  });
  const base=String(name||'').trim()||'Agent';
  if(!taken.has(base.toLowerCase()))return base;
  for(let i=2;i<10000;i++){
    const cand=base+'_'+i;
    if(!taken.has(cand.toLowerCase()))return cand;
  }
  return base+'_'+Date.now().toString(36);
}

/** True if an agent record has no recorded activity AND no user-configured settings —
 *  nothing to preserve. Regular agents: empty runs + empty collab log. Terminal
 *  agents: empty transcript too. Explicit user choices (hide-from-load-list,
 *  manual deactivation, a chosen preferred model) all count as activity, so an
 *  intentionally-hidden agent is NOT pruned and its settings survive reload. */
function pageAgentsAgentIsEmpty(rec){
  if(!rec)return true;
  const runs=Array.isArray(rec.runs)?rec.runs:[];
  if(runs.length>0)return false;
  const collab=Array.isArray(rec.collabLog)?rec.collabLog:[];
  if(collab.length>0)return false;
  const tr=String(rec.transcript||'').trim();
  if(tr)return false;
  // User-set crew-deck settings count as meaningful state — don't wipe them.
  if(rec.hiddenFromLoadList===true)return false;
  if(rec.active===false)return false;
  if(typeof rec.preferredModel==='string'&&rec.preferredModel)return false;
  // Persisted waitlist counts as meaningful state too — if the user queued
  // anything for this agent, the record stays so reopen restores those items.
  if(Array.isArray(rec.waitlist)&&rec.waitlist.length>0)return false;
  // Agent ↔ task feature: an agent linked to one or more tasks, or given a goal /
  // approach / collaborators, is meaningful even before it has run — keep it.
  if(Array.isArray(rec.taskNodeIds)&&rec.taskNodeIds.length>0)return false;
  if(typeof rec.goalMd==='string'&&rec.goalMd.trim())return false;
  if(typeof rec.approachMd==='string'&&rec.approachMd.trim())return false;
  if(Array.isArray(rec.collaborators)&&rec.collaborators.length>0)return false;
  return true;
}

/** Sweep agents archive and drop any record with no activity. Removes sprite, graph
 *  node, open slot, archive entry — i.e. it's as if the agent was never created.
 *  Returns the number removed. */
function pageAgentsPruneEmptyAgents(){
  const ag=(pageAgentsArchive&&pageAgentsArchive.agents)||{};
  const slugs=Object.keys(ag);
  let removed=0;
  for(const slug of slugs){
    if(!pageAgentsAgentIsEmpty(ag[slug]))continue;
    // Skip the agent that's currently focused if its slot is still open and the user is mid-edit.
    if(pageAgentsFocusedSlug===slug){
      const slotIdx=Array.isArray(pageAgentsSlotSlug)?pageAgentsSlotSlug.indexOf(slug):-1;
      const termOpen=document.getElementById('pageagents-chat-slot-'+slug);
      if(slotIdx>=0||termOpen)continue;
    }
    const isTerm=ag[slug]&&ag[slug].kind==='terminal';
    if(isTerm&&typeof pageAgentsRemoveTerminalAgent==='function'){
      pageAgentsRemoveTerminalAgent(slug);
      removed++;
      continue;
    }
    const ci=Array.isArray(pageAgentsSlotSlug)?pageAgentsSlotSlug.indexOf(slug):-1;
    if(ci>=0)pageAgentsCloseChatSlot(ci);
    const si=pageAgentsSprites.findIndex(s=>s.slug===slug);
    if(si>=0){
      const sp=pageAgentsSprites[si];
      if(sp&&sp.wrap&&sp.wrap.parentNode)sp.wrap.remove();
      pageAgentsSprites.splice(si,1);
    }
    const g=pageAgentsArchive.graph||{};
    if(Array.isArray(g.nodes))g.nodes=g.nodes.filter(n=>!n||n.id!==slug);
    if(Array.isArray(g.edges))g.edges=g.edges.filter(e=>e&&e.source!==slug&&e.target!==slug);
    delete ag[slug];
    if(pageAgentsFocusedSlug===slug)pageAgentsFocusedSlug=null;
    if(pageAgentsActiveTab===slug)pageAgentsActiveTab='summary';
    removed++;
  }
  if(removed){
    try{if(typeof pageAgentsRenderTabs==='function')pageAgentsRenderTabs();}catch(_){}
    try{if(typeof pageAgentsRenderActiveTab==='function')pageAgentsRenderActiveTab();}catch(_){}
    try{if(typeof pageAgentsRefreshPastAgentSelect==='function')pageAgentsRefreshPastAgentSelect();}catch(_){}
    if(PAGE_AGENTS_USE_FIELD_MODE&&typeof pageAgentsRefreshPlots==='function')pageAgentsRefreshPlots();
    if(typeof pageAgentsRefreshConnections==='function')pageAgentsRefreshConnections();
    pageAgentsFlushArchiveDebounced();
  }
  return removed;
}

/* ── Diverge (fork) a terminal agent into a new branch ──
 *  Past runs + transcript are deep-copied into the new agent so it starts with the
 *  same log history at the fork point. From then on each agent keeps its own log.
 *  If the spawned shell is inside a git working tree, the new terminal also creates
 *  (or switches to) a matching git branch — original branch stays on the original. */
const PAGE_AGENTS_DIVERGE_WORDS=[
  'alpha','beacon','candor','dawn','echo','fern','glide','harbor','indigo','jade',
  'kindle','lumen','mirage','nova','onyx','prism','quartz','river','spark','tide',
  'umbra','vista','willow','xenon','yonder','zephyr','flux','halo','quest','rune',
];
function pageAgentsRandomDivergeSuffix(){
  return PAGE_AGENTS_DIVERGE_WORDS[Math.floor(Math.random()*PAGE_AGENTS_DIVERGE_WORDS.length)];
}
/** Constrain to git-branch-safe chars so we can interpolate the value into a shell command
 *  without quoting. Lowercase + [a-z0-9_/-], no leading/trailing dashes, capped length. */
function pageAgentsSanitizeBranchName(s){
  let b=String(s||'').toLowerCase();
  b=b.replace(/[^a-z0-9_\-\/]+/g,'-');
  b=b.replace(/-{2,}/g,'-');
  b=b.replace(/^[\-\/]+|[\-\/]+$/g,'');
  if(!b)b='diverged-'+Date.now().toString(36);
  return b.slice(0,80);
}
async function pageAgentsDivergeTerminal(originalSlug){
  const rec=pageAgentsArchive.agents&&pageAgentsArchive.agents[originalSlug];
  if(!rec||rec.kind!=='terminal'){
    try{await pageAgentsModalConfirm({title:'Diverge unavailable',message:'Diverge only works on terminal agents.',okLabel:'OK',cancelLabel:''});}catch(_){alert('Diverge only works on terminal agents.');}
    return;
  }
  const defaultName=(rec.name||'Terminal')+'_'+pageAgentsRandomDivergeSuffix();
  const nm=await pageAgentsModalPrompt({
    title:'Diverge terminal agent',
    message:'Name the new branch agent. Past history is copied at this fork point; afterwards each agent keeps its own log. If the shell is in a git repo, the new terminal will check out a branch matching this name.',
    value:defaultName,
    placeholder:'New agent name',
    okLabel:'Diverge',
    validate:(s)=>{
      const t=String(s||'').trim();
      if(!t)return 'Name cannot be empty.';
      return '';
    }
  });
  if(nm==null)return;
  const trimmed=String(nm).trim().slice(0,80);
  if(!trimmed)return;
  const newName=pageAgentsMakeUniqueAgentName(trimmed);
  const tid=Date.now().toString(36)+'-'+Math.floor(Math.random()*1e4).toString(36);
  const newSlug='term-'+tid;
  // Flatten any grouped history back into rec.runs before copying so the new
  // agent inherits the full chronological log and the forkRunIndex below
  // matches a contiguous run array (the tree builder iterates parent's runs
  // linearly to find fork anchors).
  try{pageAgentsUngroupRuns(rec);}catch(_){}
  // Deep-clone the historical records so future edits on either side don't bleed.
  const runsCopy=Array.isArray(rec.runs)?JSON.parse(JSON.stringify(rec.runs)):[];
  const collabCopy=Array.isArray(rec.collabLog)?JSON.parse(JSON.stringify(rec.collabLog)):[];
  pageAgentsArchive.agents[newSlug]={
    slug:newSlug,
    name:newName,
    kind:'terminal',
    runs:runsCopy,
    collabLog:collabCopy,
    transcript:String(rec.transcript||''),
    createdAt:Date.now(),
    lastActivity:Date.now(),
    divergedFrom:originalSlug,
    // The shared prefix length at fork time — the tree builder uses this to branch
    // the duplicate off from after the parent's last shared run instead of redrawing
    // the same chain twice.
    forkRunIndex:runsCopy.length,
  };
  if(typeof pageAgentsEnsureGraphNode==='function')pageAgentsEnsureGraphNode(newSlug,newName);
  if(typeof pageAgentsMountTerminalSprite==='function')pageAgentsMountTerminalSprite(newSlug,newName);
  pageAgentsFlushArchiveDebounced();
  try{if(typeof pageAgentsRenderTabs==='function')pageAgentsRenderTabs();}catch(_){}
  try{if(typeof pageAgentsRenderActiveTab==='function')pageAgentsRenderActiveTab();}catch(_){}
  try{if(typeof pageAgentsRefreshPastAgentSelect==='function')pageAgentsRefreshPastAgentSelect();}catch(_){}
  // Compose the post-connect command for the new terminal: announce the fork, and
  // (only if cwd is inside a git work tree) create-or-switch to a branch matching
  // the diverged agent's name. Branch is sanitized to a safe ident so we can paste
  // it into the shell command without further quoting.
  const branch=pageAgentsSanitizeBranchName(newName);
  const origLabel=String(rec.name||originalSlug).replace(/[^A-Za-z0-9_ \-./]+/g,'');
  const banner='echo "── diverged from '+origLabel+' — branch: '+branch+' ──"';
  const gitCmd='if git rev-parse --is-inside-work-tree >/dev/null 2>&1; then git checkout -b '+branch+' 2>/dev/null || git checkout '+branch+'; else echo "(not in a git repo — no branch created)"; fi';
  pageAgentsBuildTerminalSlot(newSlug,{initialCommand:banner+' ; '+gitCmd+'\r'});
}

/* ── Styled in-app modal helpers (cyberpunk style; replace native confirm/prompt) ──
 *  All agent-page popups (rename, delete confirmation, diverge naming) route through
 *  these so they match the project's modal pattern (`.mo`/`.md` from css/app.css).
 *  Promise-based; Enter submits / Escape cancels / backdrop click cancels. */
function pageAgentsModalEnsureWrap(){
  let w=document.getElementById('pageagents-modal-wrap');
  if(w)return w;
  w=document.createElement('div');
  w.id='pageagents-modal-wrap';
  w.className='mo';
  document.body.appendChild(w);
  return w;
}
function pageAgentsModalPrompt(opts){
  return new Promise(resolve=>{
    const O=Object.assign({title:'Edit',message:'',value:'',placeholder:'',okLabel:'Save',cancelLabel:'Cancel',validate:null,maxLength:80},opts||{});
    const w=pageAgentsModalEnsureWrap();
    const md=document.createElement('div');
    md.className='md';
    md.innerHTML=
      '<h3>'+esc(O.title)+'</h3>'+
      (O.message?'<p style="color:var(--t2);font-size:13px;margin-bottom:12px;line-height:1.45">'+esc(O.message)+'</p>':'')+
      '<input class="inp pageagents-modal-input" type="text" placeholder="'+esc(O.placeholder)+'" autocomplete="off" maxlength="'+(O.maxLength|0)+'" style="font-size:14px;padding:10px 14px">'+
      '<div class="pageagents-modal-err" style="color:#fca5a5;font-size:12px;margin-top:8px;min-height:16px"></div>'+
      '<div class="md-act">'+
        '<button type="button" class="btn btn-g pageagents-modal-cancel">'+esc(O.cancelLabel)+'</button>'+
        '<button type="button" class="btn btn-p pageagents-modal-ok">'+esc(O.okLabel)+'</button>'+
      '</div>';
    w.innerHTML='';
    w.appendChild(md);
    w.classList.add('open');
    const inp=md.querySelector('.pageagents-modal-input');
    const err=md.querySelector('.pageagents-modal-err');
    const ok=md.querySelector('.pageagents-modal-ok');
    const cancel=md.querySelector('.pageagents-modal-cancel');
    inp.value=String(O.value||'');
    setTimeout(()=>{try{inp.focus();inp.select();}catch(_){}},10);
    const close=(result)=>{
      w.classList.remove('open');
      setTimeout(()=>{try{w.innerHTML='';}catch(_){}},200);
      document.removeEventListener('keydown',onKey,true);
      w.removeEventListener('mousedown',onBackdrop,true);
      resolve(result);
    };
    const submit=()=>{
      const v=String(inp.value||'').trim();
      if(typeof O.validate==='function'){
        const msg=O.validate(v);
        if(msg){err.textContent=msg;inp.focus();return;}
      }
      close(v);
    };
    ok.addEventListener('click',submit);
    cancel.addEventListener('click',()=>close(null));
    const onKey=(e)=>{
      if(e.key==='Enter'&&document.activeElement===inp){e.preventDefault();submit();}
      else if(e.key==='Escape'){e.preventDefault();close(null);}
    };
    const onBackdrop=(e)=>{if(e.target===w)close(null);};
    document.addEventListener('keydown',onKey,true);
    w.addEventListener('mousedown',onBackdrop,true);
  });
}
function pageAgentsModalConfirm(opts){
  return new Promise(resolve=>{
    const O=Object.assign({title:'Confirm',message:'',okLabel:'Confirm',cancelLabel:'Cancel',danger:false},opts||{});
    const w=pageAgentsModalEnsureWrap();
    const md=document.createElement('div');
    md.className='md';
    md.innerHTML=
      '<h3>'+esc(O.title)+'</h3>'+
      '<p style="color:var(--t1);font-size:13px;margin-bottom:14px;line-height:1.5;white-space:pre-wrap">'+esc(O.message)+'</p>'+
      '<div class="md-act">'+
        (O.cancelLabel?('<button type="button" class="btn btn-g pageagents-modal-cancel">'+esc(O.cancelLabel)+'</button>'):'')+
        '<button type="button" class="btn btn-p pageagents-modal-ok"'+(O.danger?' style="background:var(--red);color:#fff"':'')+'>'+esc(O.okLabel)+'</button>'+
      '</div>';
    w.innerHTML='';
    w.appendChild(md);
    w.classList.add('open');
    const ok=md.querySelector('.pageagents-modal-ok');
    const cancel=md.querySelector('.pageagents-modal-cancel');
    setTimeout(()=>{try{((O.danger&&cancel)?cancel:ok).focus();}catch(_){}},10);
    const close=(result)=>{
      w.classList.remove('open');
      setTimeout(()=>{try{w.innerHTML='';}catch(_){}},200);
      document.removeEventListener('keydown',onKey,true);
      w.removeEventListener('mousedown',onBackdrop,true);
      resolve(result);
    };
    ok.addEventListener('click',()=>close(true));
    if(cancel)cancel.addEventListener('click',()=>close(false));
    const onKey=(e)=>{
      if(e.key==='Escape'){e.preventDefault();close(false);}
      else if(e.key==='Enter'&&document.activeElement!==cancel){e.preventDefault();close(true);}
    };
    const onBackdrop=(e)=>{if(e.target===w)close(false);};
    document.addEventListener('keydown',onKey,true);
    w.addEventListener('mousedown',onBackdrop,true);
  });
}

/** Rename an existing agent — slug stays, only display name changes. The new name
 *  goes through pageAgentsMakeUniqueAgentName (ignoring this slug) so two agents
 *  can never collide, then propagates to every visible surface: sprite label,
 *  terminal title bar, log tabs, past-agent dropdown, agent-detail meta. The change
 *  is written to disk via the standard archive flush, so refresh shows the new name. */
async function pageAgentsRenameAgent(slug){
  const rec=pageAgentsArchive.agents&&pageAgentsArchive.agents[slug];
  if(!rec)return;
  const cur=rec.name||slug;
  const v=await pageAgentsModalPrompt({
    title:'Rename agent',
    message:'Pick a new name. The agent’s history stays the same; only the display name changes.',
    value:cur,
    placeholder:'New name',
    okLabel:'Save',
    validate:(s)=>{
      if(!s)return 'Name cannot be empty.';
      if(s.length>80)return 'Keep it under 80 characters.';
      return null;
    }
  });
  if(v==null)return;
  const trimmed=String(v).trim().slice(0,80);
  if(!trimmed||trimmed===cur)return;
  const unique=pageAgentsMakeUniqueAgentName(trimmed,slug);
  rec.name=unique;
  rec.lastActivity=Date.now();
  // Reflect on every visible surface so the user sees the new name immediately.
  const sp=pageAgentsSprites.find(s=>s.slug===slug);
  if(sp){
    sp.name=unique;
    if(sp.nameEl)sp.nameEl.textContent=unique;
  }
  // Terminal slot header (if open).
  const termSlot=document.getElementById('pageagents-chat-slot-'+slug);
  if(termSlot){
    const sid=String(slug).replace(/[^a-z0-9_-]/gi,'').slice(-32);
    const nameElT=termSlot.querySelector('#pageagents-term-name-'+sid);
    const lblElT=termSlot.querySelector('#pageagents-term-lbl-'+sid);
    if(nameElT)nameElT.textContent=unique;
    if(lblElT)lblElT.textContent=unique+' · terminal';
  }
  try{pageAgentsRefreshSlotChatLabels();}catch(_){}
  try{pageAgentsRenderTabs();}catch(_){}
  try{pageAgentsRenderActiveTab();}catch(_){}
  try{pageAgentsRefreshPastAgentSelect();}catch(_){}
  try{if(typeof pageAgentsRenderCrewChooserPanel==='function'){
    const panel=document.getElementById('pageagents-crew-chooser-panel');
    if(panel&&panel.style.display!=='none'&&panel.style.display!=='')pageAgentsRenderCrewChooserPanel();
  }}catch(_){}
  pageAgentsFlushArchiveDebounced();
}

