function notesApplySlideColorDefault(which){
  const prev=document.getElementById('notes-slide-'+(which==='font'?'font':'bg')+'-color-preview');
  const cmd=which==='font'?'foreColor':'backColor';
  const raw=prev?(getComputedStyle(prev).backgroundColor||prev.style.background||''):'';
  const toHex=(c)=>{
    if(!c)return which==='font'?'#f0f2f5':'#0b0d14';
    const m=c.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
    if(m)return'#'+[1,2,3].map(i=>('0'+parseInt(m[i]).toString(16)).slice(-2)).join('');
    return c.startsWith('#')?c:(which==='font'?'#f0f2f5':'#0b0d14');
  };
  notesFormat(cmd,toHex(raw));
}

