// Insert bullet with 2-unit indent
function notesInsertBullet(style){
  const editor=document.getElementById('notes-editor-content');
  if(!editor)return;
  
  // Close dropdown
  document.getElementById('bullet-dropdown-menu').classList.remove('show');
  
  // Check if editor is visible
  const editorView=document.getElementById('notes-editor');
  if(!editorView||editorView.style.display==='none')return;
  
  editor.focus();
  
  // Save selection (use notesBulletSavedRange when selection was lost by clicking dropdown)
  const sel=window.getSelection();
  let savedRange=null;
  if(sel.rangeCount>0&&editor.contains(sel.anchorNode)){
    savedRange=sel.getRangeAt(0).cloneRange();
  }
  if(!savedRange&&notesBulletSavedRange){
    try{
      if(editor.contains(notesBulletSavedRange.startContainer))savedRange=notesBulletSavedRange.cloneRange();
    }catch(_){}
  }
  notesBulletSavedRange=null;
  
  // Restore selection
  if(savedRange){
    try{
      sel.removeAllRanges();
      sel.addRange(savedRange);
    }catch(e){
      const range=document.createRange();
      range.selectNodeContents(editor);
      range.collapse(false);
      sel.removeAllRanges();
      sel.addRange(range);
    }
  }
  
  // For multi-block selection, always use manual path (execCommand often only converts first block)
  const rangeToUse=savedRange||(sel.rangeCount>0?sel.getRangeAt(0):null);
  let blocksBefore=rangeToUse?getNotesBlocksForRange(editor,rangeToUse):[];
  // Split blocks that contain <br> so each line gets its own bullet (handles single block with multiple lines)
  blocksBefore=expandNotesBlocksByLineBreaks(editor,blocksBefore);
  if(blocksBefore.length>1){
    notesApplyListManuallyForBlocks(editor,blocksBefore,'ul',style);
  }else{
    document.execCommand('insertUnorderedList',false,null);
    const inLi=sel.rangeCount>0&&(sel.anchorNode&&(sel.anchorNode.nodeType===Node.TEXT_NODE?sel.anchorNode.parentElement:sel.anchorNode).closest?.('li'));
    if(!inLi&&blocksBefore.length>0){
      notesApplyListManuallyForBlocks(editor,blocksBefore,'ul',style);
    }
  }

  // Apply custom bullet style and indent
  setTimeout(()=>{
    const sel2=window.getSelection();
    if(sel2.rangeCount>0){
      const range=sel2.getRangeAt(0);
      let listItem=range.commonAncestorContainer;
      if(listItem.nodeType===Node.TEXT_NODE)listItem=listItem.parentElement;
      
      // Find the list
      while(listItem&&listItem!==editor){
        if(listItem.tagName==='UL'||listItem.tagName==='OL'){
          // Set list style
          if(listItem.tagName==='UL'){
            listItem.style.listStyleType=style;
          }
          // Set indent to 2 units (2em)
          listItem.style.marginLeft='2em';
          listItem.style.paddingLeft='1.25em';
          break;
        }
        listItem=listItem.parentElement;
      }
    }
    editor.focus();
    updateNotesToolbarState();
  },10);
}

