// Margin drag functionality
let marginDragState=null;

function startMarginDrag(event,side){
  event.preventDefault();
  event.stopPropagation();
  
  const editor=document.getElementById('notes-editor-content');
  if(!editor)return;
  
  const wrapper=document.getElementById('notes-editor-wrapper');
  const startX=event.clientX;
  const currentMargin=parseInt(window.getComputedStyle(editor)[side==='left'?'marginLeft':'marginRight'])||0;
  
  marginDragState={
    side:side,
    startX:startX,
    startMargin:currentMargin,
    dragging:true
  };
  
  document.addEventListener('mousemove',handleMarginDrag);
  document.addEventListener('mouseup',stopMarginDrag);
  
  // Prevent text selection
  document.body.style.userSelect='none';
  document.body.style.cursor='col-resize';
}

function handleMarginDrag(event){
  if(!marginDragState||!marginDragState.dragging)return;
  
  const editor=document.getElementById('notes-editor-content');
  if(!editor)return;
  
  const deltaX=event.clientX-marginDragState.startX;
  const newMargin=Math.max(0,Math.min(400,marginDragState.startMargin+(marginDragState.side==='left'?deltaX:-deltaX)));
  
  editor.style[marginDragState.side==='left'?'marginLeft':'marginRight']=newMargin+'px';
  if(marginDragState.side==='left'&&typeof renderNotesSlideLayer==='function')renderNotesSlideLayer();
}

function stopMarginDrag(event){
  if(marginDragState){
    marginDragState.dragging=false;
    marginDragState=null;
  }
  
  document.removeEventListener('mousemove',handleMarginDrag);
  document.removeEventListener('mouseup',stopMarginDrag);
  
  document.body.style.userSelect='';
  document.body.style.cursor='';
  if(typeof renderNotesSlideLayer==='function')renderNotesSlideLayer();
}

// Update toolbar to reflect current formatting state
function updateNotesToolbarState(){
  const editor=document.getElementById('notes-editor-content');
  if(!editor)return;
  
  const sel=window.getSelection();
  if(sel.rangeCount===0)return;
  const inEditor=editor.contains(sel.anchorNode);
  const inSlideText=document.activeElement&&document.activeElement.closest&&document.activeElement.closest('#notes-slide-layer .slide-text');
  if(!inEditor&&!inSlideText)return;
  
  try{
    // Update button states (bold, italic, underline)
    const boldBtn=document.querySelector('#notes-editor-toolbar button[onclick*="bold"]');
    const italicBtn=document.querySelector('#notes-editor-toolbar button[onclick*="italic"]');
    const underlineBtn=document.querySelector('#notes-editor-toolbar button[onclick*="underline"]');
    
    if(boldBtn){
      const isBold=document.queryCommandState('bold');
      boldBtn.classList.toggle('active',isBold);
    }
    if(italicBtn){
      const isItalic=document.queryCommandState('italic');
      italicBtn.classList.toggle('active',isItalic);
    }
    if(underlineBtn){
      const isUnderline=document.queryCommandState('underline');
      underlineBtn.classList.toggle('active',isUnderline);
    }
    const strikeBtn=document.querySelector('#notes-editor-toolbar button[onclick*="strikeThrough"]');
    if(strikeBtn)strikeBtn.classList.toggle('active',document.queryCommandState('strikeThrough'));
    const slideBold=document.getElementById('notes-slide-bold');
    const slideItalic=document.getElementById('notes-slide-italic');
    const slideUnderline=document.getElementById('notes-slide-underline');
    if(slideBold)slideBold.classList.toggle('active',document.queryCommandState('bold'));
    if(slideItalic)slideItalic.classList.toggle('active',document.queryCommandState('italic'));
    if(slideUnderline)slideUnderline.classList.toggle('active',document.queryCommandState('underline'));
    
    // Update font family if possible
    const fontFamily=document.queryCommandValue('fontName');
    const fontSelect=document.getElementById('notes-font-family');
    if(fontSelect&&fontFamily){
      const options=Array.from(fontSelect.options);
      const match=options.find(opt=>opt.value.toLowerCase()===fontFamily.toLowerCase());
      if(match)fontSelect.value=match.value;
    }
    const slideFontSelect=document.getElementById('notes-slide-font-family');
    if(slideFontSelect&&fontFamily){
      const options=Array.from(slideFontSelect.options);
      const match=options.find(opt=>opt.value.toLowerCase()===fontFamily.toLowerCase());
      if(match)slideFontSelect.value=match.value;
    }
    
    // Update font size display
    let pt=12;
    try{
      const range=sel.getRangeAt(0);
      const node=range.startContainer.nodeType===Node.TEXT_NODE?range.startContainer.parentElement:range.startContainer;
      const px=parseFloat(window.getComputedStyle(node).fontSize)||16;
      pt=Math.round(px*72/96)||12;
    }catch(_){}
    pt=Math.max(8,Math.min(72,pt));
    const sizeDisplay=document.getElementById('notes-font-size-display');
    if(sizeDisplay&&!sizeDisplay.querySelector('input'))sizeDisplay.textContent=pt;
    const slideSizeSelect=document.getElementById('notes-slide-font-size');
    if(slideSizeSelect){
      const map=[0,8,10,12,14,18,24,36];
      let best=3;
      for(let i=1;i<=7;i++){if(Math.abs(map[i]-pt)<=Math.abs(map[best]-pt))best=i;}
      slideSizeSelect.value=String(best);
    }
    
    const slideFontPrev=document.getElementById('notes-slide-font-color-preview');
    const slideFontInp=document.getElementById('notes-slide-font-color');
    const slideBgPrev=document.getElementById('notes-slide-bg-color-preview');
    const slideBgInp=document.getElementById('notes-slide-bg-color');
    try{
      const range=sel.getRangeAt(0);
      let node=range.startContainer;
      if(node.nodeType===Node.TEXT_NODE)node=node.parentElement;
      let fontColor='',bgColor='';
      for(let n=node;n&&n!==document.body;n=n.parentElement){
        if(n.style&&n.style.color){ fontColor=n.style.color; break; }
        const c=getComputedStyle(n).color;
        if(c&&c!=='rgba(0, 0, 0, 0)'&&c!=='transparent'){ fontColor=c; break; }
      }
      for(let n=node;n&&n!==document.body;n=n.parentElement){
        if(n.style&&n.style.backgroundColor){ bgColor=n.style.backgroundColor; break; }
        const c=getComputedStyle(n).backgroundColor;
        if(c&&c!=='rgba(0, 0, 0, 0)'&&c!=='transparent'){ bgColor=c; break; }
      }
      const toHex=(c)=>{
        if(!c)return'';
        const m=c.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
        if(m)return'#'+[1,2,3].map(i=>('0'+parseInt(m[i]).toString(16)).slice(-2)).join('');
        const m2=c.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
        if(m2)return'#'+[1,2,3].map(i=>('0'+parseInt(m2[i]).toString(16)).slice(-2)).join('');
        return c.startsWith('#')?c:'';
      };
      const fh=toHex(fontColor);
      const bh=toHex(bgColor);
      if(slideFontPrev)fh&&(slideFontPrev.style.background=fh);
      if(slideFontInp)fh&&(slideFontInp.value=fh);
      if(slideBgPrev)bh&&(slideBgPrev.style.background=bh);
      if(slideBgInp)bh&&(slideBgInp.value=bh);
    }catch(_){}
  }catch(e){
    // Silently fail - not critical
  }
}

function notesInsertLink(){
  const editor=document.getElementById('notes-editor-content');
  if(!editor)return;
  const sel=window.getSelection();
  let savedRange=null;
  if(sel.rangeCount>0&&editor.contains(sel.anchorNode)){
    savedRange=sel.getRangeAt(0).cloneRange();
  }else if(notesFormatSavedRange){
    try{
      if(editor.contains(notesFormatSavedRange.startContainer))savedRange=notesFormatSavedRange.cloneRange();
    }catch(_){}
  }
  notesFormatSavedRange=null;
  
  const url=prompt('Enter URL:');
  if(url&&url.trim()){
    editor.focus();
    let range=null;
    if(sel.rangeCount>0&&editor.contains(sel.anchorNode)){
      range=sel.getRangeAt(0);
    }else if(savedRange){
      sel.removeAllRanges();
      sel.addRange(savedRange);
      range=savedRange;
    }
    if(range){
      // If text is selected, create link from selection
      if(!range.collapsed){
        try{
          document.execCommand('createLink',false,url.trim());
          // execCommand doesn't set target and rel, so we need to fix it
          const links=editor.querySelectorAll('a[href="'+url.trim().replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+'"]');
          links.forEach(link=>{
            if(!link.target||link.target!=='_blank'){
              link.target='_blank';
              link.rel='noopener noreferrer';
            }
          });
        }catch(e){
          // Fallback: wrap selection in <a> tag
          const link=document.createElement('a');
          link.href=url.trim();
          link.target='_blank';
          link.rel='noopener noreferrer';
          link.textContent=range.toString();
          range.deleteContents();
          range.insertNode(link);
        }
      }else{
        // No selection - insert link text
        const link=document.createElement('a');
        link.href=url.trim();
        link.target='_blank';
        link.rel='noopener noreferrer';
        link.textContent=url.trim();
        range.insertNode(link);
        range.setStartAfter(link);
        range.collapse(true);
        sel.removeAllRanges();
        sel.addRange(range);
      }
      editor.focus();
      updateNotesToolbarState();
    }
  }
}

function notesInsertImage(){
  const editor=document.getElementById('notes-editor-content');
  if(!editor)return;
  editor.focus();
  
  const input=document.createElement('input');
  input.type='file';
  input.accept='image/*';
  input.onchange=(e)=>{
    const file=e.target.files[0];
    if(file){
      const reader=new FileReader();
      reader.onload=(event)=>{
        const img=document.createElement('img');
        img.src=event.target.result;
        img.style.maxWidth='100%';
        img.style.height='auto';
        img.style.borderRadius='4px';
        img.style.margin='8px 0';
        const figure=wrapImageInFigure(img);
        if(!figure)return;
        const sel=window.getSelection();
        if(sel.rangeCount>0){
          const range=sel.getRangeAt(0);
          range.deleteContents();
          range.insertNode(figure);
          range.setStartAfter(figure);
          range.collapse(true);
          sel.removeAllRanges();
          sel.addRange(range);
        }else{
          editor.appendChild(figure);
        }
        setupNoteFigureHandlers(figure);
        const n=G.nodes.find(x=>x.id===currentNoteId);
        if(n){
          svWithUndo();
          setNoteContentForNode(n,currentNoteDateKey,editor.innerHTML);
          if(n.postEventNotes===undefined&&!currentNoteDateKey)n.notes=editor.innerHTML;
          if(G.autoSave)svFlush();
        }
        editor.focus();
      };
      reader.readAsDataURL(file);
    }
  };
  input.click();
}

