/* ── Progress ── */
let progressChartInterval=null;
function renderProgress(){
  const todoListEl=document.getElementById('progress-todo-list');
  const chartSvg=document.getElementById('progress-chart-svg');
  if(!todoListEl||!chartSvg)return;
  
  // Get todos for today (always linked to today's to-do list, including completed items)
  const today=new Date();
  today.setHours(0,0,0,0);
  let todos=getTodosForDate(today);
  
  // Apply "show by" filter if set
  if(showByFilter){
    const {filteredTaskIds}=getFilteredTaskIds();
    
    // Filter todos to only include those in our filtered set
    todos=todos.filter(nodeId=>filteredTaskIds.has(nodeId));
  }
  
  // Filter and sort: only show completed tasks from past 24 hours, move them to bottom
  const now=Date.now();
  const twentyFourHoursAgo=now-24*60*60*1000;
  
  todos=todos.filter(nodeId=>{
    const n=G.nodes.find(x=>x.id===nodeId);
    if(!n)return false;
    // If task is completed, only show if completed within past 24 hours
    if(n.status==='completed'){
      if(!n.completedAt)return false;
      const completedTime=new Date(n.completedAt).getTime();
      return completedTime>=twentyFourHoursAgo;
    }
    // Show all incomplete tasks
    return true;
  });
  
  // Sort: incomplete tasks first, then completed tasks (by completion time, newest first)
  todos.sort((a,b)=>{
    const nodeA=G.nodes.find(x=>x.id===a);
    const nodeB=G.nodes.find(x=>x.id===b);
    if(!nodeA||!nodeB)return 0;
    
    const isCompleteA=nodeA.status==='completed';
    const isCompleteB=nodeB.status==='completed';
    
    // Incomplete tasks come before completed tasks
    if(isCompleteA!==isCompleteB){
      return isCompleteA?1:-1;
    }
    
    // If both completed, sort by completion time (newest first)
    if(isCompleteA&&isCompleteB){
      const timeA=nodeA.completedAt?new Date(nodeA.completedAt).getTime():0;
      const timeB=nodeB.completedAt?new Date(nodeB.completedAt).getTime():0;
      return timeB-timeA;
    }
    
    // If both incomplete, maintain original order
    return 0;
  });
  
  // Render numbered, draggable to-do list
  todoListEl.innerHTML=todos.map((nodeId,index)=>{
    const n=G.nodes.find(x=>x.id===nodeId);
    if(!n)return'';
    const isComplete=n.status==='completed'||n.status==='canceled';
    return`<div class="progress-todo-item" data-nid="${nodeId}" draggable="true" ondragstart="event.dataTransfer.setData('text/plain','${nodeId}');event.dataTransfer.setData('application/node-link','task');event.dataTransfer.effectAllowed='copyMove';this.style.opacity='0.5'" ondragend="this.style.opacity=''" style="display:flex;align-items:center;gap:8px;padding:10px;background:var(--bg2);border:1px solid var(--bdr);border-radius:var(--rad);cursor:move;margin-bottom:4px">
      <span style="font-weight:600;color:var(--t2);min-width:24px">${index+1}.</span>
      <span style="flex:1;color:var(--t0);${isComplete?'text-decoration:line-through;opacity:0.6':''}">${esc(n.name)}</span>
    </div>`;
  }).join('');
  
  // Set up drag and drop for reordering
  todoListEl.addEventListener('dragover',e=>{
    e.preventDefault();
    e.dataTransfer.dropEffect='move';
    const afterElement=getDragAfterElement(todoListEl,e.clientY);
    const draggable=document.querySelector('.progress-todo-item.dragging');
    if(draggable){
      if(afterElement==null){
        todoListEl.appendChild(draggable);
      }else{
        todoListEl.insertBefore(draggable,afterElement);
      }
    }
  });
  
  // Add dragging class on dragstart
  todoListEl.querySelectorAll('.progress-todo-item').forEach(item=>{
    item.addEventListener('dragstart',e=>{
      item.classList.add('dragging');
    });
    item.addEventListener('dragend',e=>{
      item.classList.remove('dragging');
    });
  });
  
  todoListEl.addEventListener('drop',e=>{
    e.preventDefault();
    const nodeId=e.dataTransfer.getData('text/plain');
    if(!nodeId)return;
    
    const draggedItem=todoListEl.querySelector(`[data-nid="${nodeId}"]`);
    if(draggedItem){
      const afterElement=getDragAfterElement(todoListEl,e.clientY);
      // Use the filtered and sorted todos from outer scope
      const currentIndex=todos.indexOf(nodeId);
      if(currentIndex===-1)return;
      
      let targetIndex;
      if(afterElement==null){
        targetIndex=todos.length;
      }else{
        const targetNodeId=afterElement.dataset.nid;
        targetIndex=todos.indexOf(targetNodeId);
        if(targetIndex===-1)return;
        targetIndex++;
      }
      
      if(currentIndex===targetIndex||(currentIndex+1===targetIndex&&currentIndex<targetIndex))return;
      
      const reorderedTodos=[...todos];
      const [removed]=reorderedTodos.splice(currentIndex,1);
      if(targetIndex>currentIndex)targetIndex--;
      reorderedTodos.splice(targetIndex,0,removed);
      
      // Update todo list order - get all todos first to maintain order for items not in filtered list
      const today=new Date();
      today.setHours(0,0,0,0);
      const allTodos=getTodosForDate(today);
      
      // Create a new order: items in reorderedTodos first (in their new order), then remaining items
      const reorderedSet=new Set(reorderedTodos);
      const remainingTodos=allTodos.filter(id=>!reorderedSet.has(id));
      const finalOrder=[...reorderedTodos,...remainingTodos];
      
      // Update todayTodos to match final order
      todayTodos=todayTodos.filter(t=>finalOrder.includes(t.nodeId));
      finalOrder.forEach(id=>{
        if(!todayTodos.some(t=>t.nodeId===id)){
          todayTodos.push({nodeId:id});
        }
      });
      localStorage.setItem('todayTodos',JSON.stringify(todayTodos));
      // Mirror to G + flush so the new order persists across reload — and let undo
      // step it back like every other data mutation in the app.
      if(typeof svWithUndo==='function'){try{svWithUndo();}catch(_){}}
      persistTodoStateToGraph();
      if(typeof sv==='function'){try{sv();}catch(_){}}
      renderProgress(); // Re-render to update numbers
    }
  });
  
  // Render horizontal bar chart
  renderProgressChart(todos);
  
  // Start interval to update chart if timers are active
  if(progressChartInterval)clearInterval(progressChartInterval);
  progressChartInterval=setInterval(()=>{
    if(currentView==='progress'){
      const today=new Date();
      today.setHours(0,0,0,0);
      let todos=getTodosForDate(today);
      
      // Apply same filtering and sorting as in renderProgress
      const now=Date.now();
      const twentyFourHoursAgo=now-24*60*60*1000;
      
      todos=todos.filter(nodeId=>{
        const n=G.nodes.find(x=>x.id===nodeId);
        if(!n)return false;
        if(n.status==='completed'){
          if(!n.completedAt)return false;
          const completedTime=new Date(n.completedAt).getTime();
          return completedTime>=twentyFourHoursAgo;
        }
        return true;
      });
      
      todos.sort((a,b)=>{
        const nodeA=G.nodes.find(x=>x.id===a);
        const nodeB=G.nodes.find(x=>x.id===b);
        if(!nodeA||!nodeB)return 0;
        const isCompleteA=nodeA.status==='completed';
        const isCompleteB=nodeB.status==='completed';
        if(isCompleteA!==isCompleteB){
          return isCompleteA?1:-1;
        }
        if(isCompleteA&&isCompleteB){
          const timeA=nodeA.completedAt?new Date(nodeA.completedAt).getTime():0;
          const timeB=nodeB.completedAt?new Date(nodeB.completedAt).getTime():0;
          return timeB-timeA;
        }
        return 0;
      });
      
      renderProgressChart(todos);
    }else{
      clearInterval(progressChartInterval);
      progressChartInterval=null;
    }
  },1000);
}

function renderProgressChart(todos){
  const chartSvg=document.getElementById('progress-chart-svg');
  if(!chartSvg)return;
  
  const container=chartSvg.parentElement;
  const width=container.clientWidth-40;
  const height=Math.max(400,todos.length*60+40);
  chartSvg.setAttribute('width',width);
  chartSvg.setAttribute('height',height);
  chartSvg.style.height=height+'px';
  
  // Clear previous content
  chartSvg.innerHTML='';
  
  if(todos.length===0){
    chartSvg.innerHTML=`<text x="${width/2}" y="${height/2}" text-anchor="middle" fill="var(--t2)" font-size="14">No tasks in to-do list</text>`;
    return;
  }
  
  const margin={top:20,right:20,bottom:20,left:200};
  const chartWidth=width-margin.left-margin.right;
  const chartHeight=height-margin.top-margin.bottom;
  const barHeight=40;
  const barSpacing=20;
  
  const g=d3.select(chartSvg).append('g').attr('transform',`translate(${margin.left},${margin.top})`);
  
  // Get max duration for scaling
  let maxDuration=0;
  todos.forEach(nodeId=>{
    const n=G.nodes.find(x=>x.id===nodeId);
    if(n&&n.timer&&n.timer.endTime>Date.now()){
      maxDuration=Math.max(maxDuration,n.timer.duration);
    }else if(n&&n.timer){
      // Timer finished but not cleared
      maxDuration=Math.max(maxDuration,n.timer.duration);
    }else{
      // No timer set, use default max
      maxDuration=Math.max(maxDuration,60*60*1000); // 1 hour default
    }
  });
  
  if(maxDuration===0)maxDuration=60*60*1000; // Default 1 hour
  
  const xScale=d3.scaleLinear().domain([0,maxDuration]).range([0,chartWidth]);
  
  // Add axis
  const xAxis=d3.axisBottom(xScale).tickFormat(d=>{
    const mins=Math.round(d/60000);
    return mins+'m';
  });
  g.append('g').attr('transform',`translate(0,${chartHeight})`).call(xAxis).attr('class','progress-axis');
  
  // Draw bars
  todos.forEach((nodeId,index)=>{
    const n=G.nodes.find(x=>x.id===nodeId);
    if(!n)return;
    
    const y=index*(barHeight+barSpacing);
    const isComplete=n.status==='completed'||n.status==='canceled';
    
    // Task label
    g.append('text')
      .attr('x',-10)
      .attr('y',y+barHeight/2)
      .attr('text-anchor','end')
      .attr('dominant-baseline','middle')
      .attr('fill',isComplete?'var(--t3)':'var(--t0)')
      .attr('font-size','13px')
      .text(n.name.length>25?n.name.slice(0,25)+'...':n.name);
    
    // Bar container group - make entire group clickable
    const barGroup=g.append('g')
      .attr('class','progress-bar-group')
      .style('cursor',isComplete?'default':'pointer');
    
    // Click handler function
    const handleClick=(e)=>{
      e.stopPropagation();
      if(!isComplete){
        openTimer(nodeId);
      }
    };
    
    // Make the group clickable
    barGroup.on('click',handleClick);
    
    // Bar outline (always visible)
    barGroup.append('rect')
      .attr('x',0)
      .attr('y',y)
      .attr('width',chartWidth)
      .attr('height',barHeight)
      .attr('fill','transparent')
      .attr('rx',4)
      .attr('stroke',isComplete?'#f59e0b':'#000')
      .attr('stroke-width',2)
      .attr('opacity',isComplete?0.8:0.3)
      .style('pointer-events','none');
    
    // Progress calculation - bar fills as time elapses
    // Each bar fills proportionally to its own timer duration
    let barWidth=0;
    let barColor='#06b6d4'; // Cold blue
    let timeRemaining=0;
    let hasTimer=false;
    let timerFinished=false;
    let pctComplete=0;
    
    if(isComplete){
      // Completed - show full golden bar
      barWidth=chartWidth;
      barColor='#f59e0b'; // Golden yellow
      pctComplete=1;
    }else if(n.timer&&n.timer.endTime>Date.now()){
      // Timer running - bar fills proportionally to timer duration
      hasTimer=true;
      timeRemaining=Math.max(0,n.timer.endTime-Date.now());
      n.timer.remaining=timeRemaining;
      const elapsed=n.timer.duration-timeRemaining; // Time elapsed in ms
      pctComplete=elapsed/n.timer.duration; // How much is filled (0 to 1)
      // Bar fills at rate proportional to its own duration
      // If timer is 100s and chartWidth is 100 units, fills at 1 unit/second
      barWidth=(pctComplete*chartWidth); // Direct proportion to chart width
      barColor='#06b6d4'; // Cold blue
    }else if(n.timer&&n.timer.endTime<=Date.now()){
      // Timer finished - show full bar
      hasTimer=true;
      timerFinished=true;
      timeRemaining=0;
      barWidth=chartWidth;
      barColor='#06b6d4';
      pctComplete=1;
      // Trigger popup if not already shown
      if(!n.timer.ringing){
        n.timer.ringing=true;
        showTimerAlert(n);
      }
    }else{
      // No timer - empty bar
      barWidth=0;
      pctComplete=0;
    }
    
    // Progress fill bar (with clipping for rounded corners)
    const clipId=`progress-clip-${nodeId}`;
    barGroup.append('defs').append('clipPath')
      .attr('id',clipId)
      .append('rect')
      .attr('x',0)
      .attr('y',y)
      .attr('width',barWidth)
      .attr('height',barHeight)
      .attr('rx',4);
    
    // Fill bar
    const fillBar=barGroup.append('rect')
      .attr('x',0)
      .attr('y',y)
      .attr('width',Math.max(0,barWidth))
      .attr('height',barHeight)
      .attr('fill',barColor)
      .attr('rx',4)
      .attr('clip-path',`url(#${clipId})`)
      .attr('opacity',barWidth>0?0.9:0)
      .style('pointer-events','none');
    
    // Bubbling animation (only when bar has content)
    if(barWidth>5){
      const bubbleGroup=barGroup.append('g')
        .attr('clip-path',`url(#${clipId})`)
        .style('pointer-events','none');
      // Add multiple bubbles with SVG animations - only within filled area
      const numBubbles=Math.min(5,Math.floor(barWidth/30));
      for(let i=0;i<numBubbles;i++){
        const bubbleX=5+(Math.random()*Math.max(0,barWidth-10));
        const startY=y+barHeight-3;
        const bubbleSize=2+Math.random()*2;
        const bubble=bubbleGroup.append('circle')
          .attr('cx',bubbleX)
          .attr('cy',startY)
          .attr('r',bubbleSize)
          .attr('fill',barColor)
          .attr('opacity',0.7);
        
        // Animate bubble rising
        bubble.append('animate')
          .attr('attributeName','cy')
          .attr('values',`${startY};${y-5}`)
          .attr('dur','2s')
          .attr('repeatCount','indefinite')
          .attr('begin',(i*0.4)+'s');
        bubble.append('animate')
          .attr('attributeName','opacity')
          .attr('values','0.7;0.9;0')
          .attr('dur','2s')
          .attr('repeatCount','indefinite')
          .attr('begin',(i*0.4)+'s');
        bubble.append('animate')
          .attr('attributeName','r')
          .attr('values',`${bubbleSize};${bubbleSize*1.2};${bubbleSize*0.8}`)
          .attr('dur','2s')
          .attr('repeatCount','indefinite')
          .attr('begin',(i*0.4)+'s');
      }
    }
    
    // Time label
    if(hasTimer&&timeRemaining>0){
      const timeText=Math.ceil(timeRemaining/60000)+'m';
      barGroup.append('text')
        .attr('x',Math.max(10,Math.min(barWidth-10,chartWidth-10)))
        .attr('y',y+barHeight/2)
        .attr('text-anchor',barWidth>chartWidth/2?'end':'start')
        .attr('dominant-baseline','middle')
        .attr('fill',barWidth>chartWidth/2?'#fff':'var(--t0)')
        .attr('font-size','12px')
        .attr('font-weight','600')
        .attr('pointer-events','none')
        .text(timeText);
    }else if(timerFinished){
      barGroup.append('text')
        .attr('x',chartWidth/2)
        .attr('y',y+barHeight/2)
        .attr('text-anchor','middle')
        .attr('dominant-baseline','middle')
        .attr('fill','#fff')
        .attr('font-size','12px')
        .attr('font-weight','600')
        .attr('pointer-events','none')
        .text('Timer Finished');
    }else if(!hasTimer&&!isComplete){
      barGroup.append('text')
        .attr('x',chartWidth/2)
        .attr('y',y+barHeight/2)
        .attr('text-anchor','middle')
        .attr('dominant-baseline','middle')
        .attr('fill','var(--t2)')
        .attr('font-size','12px')
        .attr('pointer-events','none')
        .text('Click to set timer');
    }else if(isComplete){
      barGroup.append('text')
        .attr('x',chartWidth/2)
        .attr('y',y+barHeight/2)
        .attr('text-anchor','middle')
        .attr('dominant-baseline','middle')
        .attr('fill','#fff')
        .attr('font-size','12px')
        .attr('font-weight','600')
        .attr('pointer-events','none')
        .text('✓ Completed');
    }
    
    // Add invisible clickable overlay on top (backup)
    if(!isComplete){
      barGroup.append('rect')
        .attr('x',0)
        .attr('y',y)
        .attr('width',chartWidth)
        .attr('height',barHeight)
        .attr('fill','transparent')
        .attr('rx',4)
        .style('cursor','pointer')
        .on('click',handleClick);
    }
  });
}

function getDragAfterElement(container,y){
  const draggableElements=[...container.querySelectorAll('.progress-todo-item:not(.dragging)')];
  return draggableElements.reduce((closest,child)=>{
    const box=child.getBoundingClientRect();
    const offset=y-box.top-box.height/2;
    if(offset<0&&offset>closest.offset){
      return{offset:offset,element:child};
    }else{
      return closest;
    }
  },{offset:Number.NEGATIVE_INFINITY}).element;
}

/* ── Calendar ── */
function renderCalendar(){
  const cv=document.getElementById('calendar-view');
  const grid=document.getElementById('calendar-time-grid');
  const header=document.getElementById('calendar-week-title');
  const scrollContainer=document.getElementById('calendar-scroll-container');
  if(!cv||!grid)return;
  
  // Auto-complete past routine occurrence note nodes
  autoCompleteRoutineOccurrenceNodes();
  
  // Clear FindTime highlights before re-rendering
  clearFindTimeHighlights();
  
  // Infinite scrolling: render many days and hours.
  // Anchor the grid on calendarDate (updated by Prev/Next week and when opening the calendar).
  const anchorDay=new Date(calendarDate);
  anchorDay.setHours(0,0,0,0);
  const centerStart=new Date(anchorDay);
  centerStart.setDate(centerStart.getDate()-centerStart.getDay());
  centerStart.setHours(0,0,0,0);
  
  // Render many days before and after center for infinite scrolling
  // Use large range to support infinite scrolling (180 days = ~6 months each direction)
  const daysBefore=180;
  const daysAfter=180;
  const start=new Date(centerStart);
  start.setDate(start.getDate()-daysBefore);
  const end=new Date(centerStart);
  end.setDate(end.getDate()+daysAfter+6);
  
  // Update header to show current month/year based on visible viewport
  // This will be updated dynamically based on scroll position
  // Note: dayWidth will be defined later, so we calculate it in the function
  const updateHeader=()=>{
    if(!scrollContainer||!header)return;
    const scrollLeft=scrollContainer.scrollLeft||0;
    const containerWidth=scrollContainer.clientWidth||800;
    const timeColumnWidth=120;
    const calcDayWidth=Math.floor((containerWidth-timeColumnWidth)/7);
    const visibleDayIndex=Math.floor(scrollLeft/calcDayWidth);
    // Calculate firstWeekStart
    const calcFirstWeekStart=new Date(centerStart);
    calcFirstWeekStart.setDate(calcFirstWeekStart.getDate()-calcFirstWeekStart.getDay());
    const weeksBefore=Math.ceil(daysBefore/7);
    calcFirstWeekStart.setDate(calcFirstWeekStart.getDate()-(weeksBefore*7));
    calcFirstWeekStart.setHours(0,0,0,0);
    const visibleDate=new Date(calcFirstWeekStart);
    visibleDate.setDate(visibleDate.getDate()+visibleDayIndex);
    // Get current date for comparison
    const now=new Date();
    const today=new Date(now.getFullYear(),now.getMonth(),now.getDate());
    // If visible date is today, show current date info
    if(visibleDate.toDateString()===today.toDateString()){
      const dayName=now.toLocaleDateString('en-US',{weekday:'long'});
      const monthYear=now.toLocaleDateString('en-US',{month:'long',year:'numeric'});
      header.textContent=`${dayName}, ${monthYear}`;
    }else{
      const monthYear=visibleDate.toLocaleDateString('en-US',{month:'long',year:'numeric'});
      header.textContent=monthYear;
    }
  };
  
  // Initial header update - use today's date for initial load
  if(scrollContainer&&header){
    const now=new Date();
    const today=new Date(now.getFullYear(),now.getMonth(),now.getDate());
    // On initial load, show today's date
    const dayName=now.toLocaleDateString('en-US',{weekday:'long'});
    const monthYear=now.toLocaleDateString('en-US',{month:'long',year:'numeric'});
    header.textContent=`${dayName}, ${monthYear}`;
  }
  
  // Render TBD micro event tabs
  renderTBDMicroTabs();
  
  // Set up scroll handler - only track position, no re-rendering
  if(scrollContainer&&!scrollContainer._scrollHandler){
    scrollContainer._scrollHandler=true;
    scrollContainer.addEventListener('scroll',()=>{
      // Update header based on scroll position
      updateHeader();
      // Just track scroll position for restoration
      calendarScrollLeft=scrollContainer.scrollLeft;
      calendarScrollTop=scrollContainer.scrollTop;
      // Sync time strip scroll with grid scroll (bidirectional)
      const timeStrip=document.getElementById('calendar-time-strip');
      if(timeStrip){
        // Temporarily remove listener to avoid infinite loop
        if(timeStrip._scrollListener){
          timeStrip.removeEventListener('scroll',timeStrip._scrollListener);
        timeStrip.scrollTop=scrollContainer.scrollTop;
          setTimeout(()=>{
            if(timeStrip._scrollListener){
              timeStrip.addEventListener('scroll',timeStrip._scrollListener);
            }
          },0);
        }else{
          timeStrip.scrollTop=scrollContainer.scrollTop;
        }
      }
    });
  }
  
  // Get all tasks: completed tasks with timers, completed tasks without timers, or tasks with calendarDate
  // Exclude tasks with TBD property set (not 'none') - these appear only in title section
  // Exclude canceled tasks (they don't have calendarDate after deletion)
  let allCalendarTasks=G.nodes.filter(n=>{
    // Exclude canceled tasks
    if(n.status==='canceled')return false;
    // Exclude routine occurrence note nodes (they are bookkeeping, not real events)
    if(n.linkedRoutineEventId&&n.linkedRoutineOccurrenceDateKey&&n.id!==n.linkedRoutineEventId)return false;
    // Exclude TBD events from calendar grid - they appear in title section only
    if(n.TBD&&n.TBD!=='none')return false;
    // Tasks with calendarDate
    if(n.calendarDate)return true;
    // Completed tasks with timer
    if(n.status==='completed'&&n.timer&&n.timer.completedAt)return true;
    // Completed tasks without timer (check-off time)
    if(n.status==='completed'&&!n.timer&&n.completedAt)return true;
    return false;
  });
  
  // Apply "show by" filter if set
  // Calendar should only show events from tasks that are visible on the home page
  // Use the same filtered task set as the home page (matching tasks + ancestors + connected if bring edges is on)
  if(showByFilter){
    const {filteredTaskIds,filteredNoteIds}=getFilteredTaskIds();
    
    // Filter calendar events to only include those whose parent task is in the filtered set
    // This ensures calendar only shows events from tasks visible on the home page
    allCalendarTasks=allCalendarTasks.filter(n=>{
      if(isTaskNode(n)){
        // For task nodes, check if the task itself is in the filtered set
        return filteredTaskIds.has(n.id);
      }else{
        // For notes, check if their parent task is in the filtered set
        return n.parentId&&filteredTaskIds.has(n.parentId);
      }
    });
  }
  
  const tasksByDateAndTime=new Map(); // Map: dateKey -> Map: timeKey -> tasks
  
  // Calculate date range for routine event expansion
  const renderStartDate=new Date(start);
  const renderEndDate=new Date(end);

  // Bucket an event occurrence into tasksByDateAndTime. A multi-day TIMED event is split
  // into one timed segment per calendar day so it spans across the day columns (e.g. Mon
  // 9am→Fri 3pm draws as Mon 9am–midnight, Tue/Wed/Thu full-height, Fri midnight–3pm)
  // instead of one giant block overflowing below the grid. Single-day events (and genuine
  // all-day events) are pushed unchanged. eventStartMs/eventEndMs carry the full span so the
  // renderer can label each segment with continuation arrows.
  const pushOccurrence=(node,startTime,duration,isAllDay)=>{
    const put=(key,timeKey,payload)=>{
      if(!tasksByDateAndTime.has(key))tasksByDateAndTime.set(key,new Map());
      const dayMap=tasksByDateAndTime.get(key);
      if(!dayMap.has(timeKey))dayMap.set(timeKey,[]);
      dayMap.get(timeKey).push(payload);
    };
    const startMs=startTime.getTime();
    const endMs=startMs+(duration||0);
    // First local midnight after the start; the event spans multiple days only if it ends
    // strictly after it (an event ending exactly at midnight stays a single day).
    const dayStart=new Date(startTime);dayStart.setHours(0,0,0,0);
    const firstMidnight=new Date(dayStart);firstMidnight.setDate(firstMidnight.getDate()+1);
    const spansMultiple=duration>0&&endMs>firstMidnight.getTime();
    if(isAllDay||!spansMultiple){
      const hour=startTime.getHours(),minute=startTime.getMinutes();
      const timeKey=isAllDay?-1:hour*60+minute;
      put(startTime.toDateString(),timeKey,{node,startTime,duration,isAllDay});
      return;
    }
    // Multi-day: emit a clamped timed segment for each day the event touches.
    let cursor=new Date(startTime);
    while(cursor.getTime()<endMs){
      const segDayStart=new Date(cursor);segDayStart.setHours(0,0,0,0);
      const nextMidnight=new Date(segDayStart);nextMidnight.setDate(nextMidnight.getDate()+1);
      const segStart=new Date(Math.max(cursor.getTime(),segDayStart.getTime()));
      const segEndMs=Math.min(endMs,nextMidnight.getTime());
      const segDuration=segEndMs-segStart.getTime();
      if(segDuration>0){
        const hour=segStart.getHours(),minute=segStart.getMinutes();
        put(segStart.toDateString(),hour*60+minute,{node,startTime:segStart,duration:segDuration,isAllDay:false,multiDay:true,eventStartMs:startMs,eventEndMs:endMs});
      }
      cursor=nextMidnight;
    }
  };

  allCalendarTasks.forEach(n=>{
    let d,startTime,duration;
    if(n.timer&&n.timer.completedAt){
      // Completed task with timer - use timer completion time
      startTime=new Date(n.timer.completedAt);
      duration=n.timer.duration||0;
      d=new Date(startTime);
    }else if(n.calendarDate){
      // Task with calendar event - use calendarDate and adjusted calendarDuration
      d=new Date(n.calendarDate);
      startTime=d;
      // If completed, use the adjusted calendarDuration (which was set when task was checked off)
      // Otherwise use the original calendarDuration or default 1 hour
      duration=n.calendarDuration||60*60*1000; // Use calendarDuration if set, otherwise default 1 hour
    }else if(n.status==='completed'&&n.completedAt){
      // Completed task without calendar event - use check-off time, span 30 mins
      d=new Date(n.completedAt);
      startTime=new Date(d.getTime()-30*60*1000); // 30 mins before check-off
      duration=30*60*1000; // 30 minutes
    }else return;
    
    // Check if this is a routine task that should appear on multiple dates
    if(n.routine&&n.routineFrequency&&n.calendarDate){
      // For routine tasks, generate virtual events for all matching dates
      const originalDate=new Date(n.calendarDate);
      const originalHour=originalDate.getHours();
      const originalMinute=originalDate.getMinutes();
      
      // Generate occurrences based on routineFrequency
      let currentDate=new Date(originalDate);
      const datesToShow=[];
      // routineEndDate caps the routine when the user picked "all future" from a later
      // occurrence: the original keeps producing past instances but stops emitting at
      // or after the split. Skip the seed and all forward iterations once past it.
      const routineEnd=n.routineEndDate?new Date(n.routineEndDate):null;
      const passesEnd=(dt)=>!routineEnd||dt<=routineEnd;

      // First, add the original date
      if(passesEnd(originalDate))datesToShow.push(new Date(originalDate));

      // Generate future occurrences
      while(currentDate<renderEndDate){
        let nextDate=new Date(currentDate);
        if(n.routineFrequency==='daily'){
          nextDate.setDate(nextDate.getDate()+1);
        }else if(n.routineFrequency==='2-5/week'){
          // For 2-5/week, add every 2-3 days (average ~3.5 days)
          nextDate.setDate(nextDate.getDate()+Math.floor(Math.random()*2)+2);
        }else if(n.routineFrequency==='weekly'){
          nextDate.setDate(nextDate.getDate()+7);
        }else if(n.routineFrequency==='biweekly'){
          nextDate.setDate(nextDate.getDate()+14);
        }else if(n.routineFrequency==='monthly'){
          nextDate.setMonth(nextDate.getMonth()+1);
        }else{
          break; // Unknown frequency, stop
        }

        if(routineEnd&&nextDate>routineEnd)break;
        if(nextDate<=renderEndDate&&nextDate>=renderStartDate){
          datesToShow.push(new Date(nextDate));
        }
        currentDate=nextDate;
      }
      
      // A routine only recurs FORWARD from its start date — never before it. The
      // anchor is calendarDate (originalDate); occurrences earlier than that must
      // not be drawn. routineStartDate, when present (set by an "all future" split),
      // is that same anchor for the split-off routine. Defaulting to originalDate
      // makes the floor apply to every routine, so the backward walk below stops
      // immediately at the start date instead of extending into the past.
      const routineStart=n.routineStartDate?new Date(n.routineStartDate):new Date(originalDate);
      currentDate=new Date(originalDate);
      while(currentDate>renderStartDate){
        let prevDate=new Date(currentDate);
        if(n.routineFrequency==='daily'){
          prevDate.setDate(prevDate.getDate()-1);
        }else if(n.routineFrequency==='2-5/week'){
          prevDate.setDate(prevDate.getDate()-(Math.floor(Math.random()*2)+2));
        }else if(n.routineFrequency==='weekly'){
          prevDate.setDate(prevDate.getDate()-7);
        }else if(n.routineFrequency==='biweekly'){
          prevDate.setDate(prevDate.getDate()-14);
        }else if(n.routineFrequency==='monthly'){
          prevDate.setMonth(prevDate.getMonth()-1);
        }else{
          break;
        }
        if(routineStart&&prevDate<routineStart)break;

        if(prevDate>=renderStartDate){
          datesToShow.push(new Date(prevDate));
        }
        currentDate=prevDate;
      }
      
      // Add all occurrences to the calendar (skip exception dates)
      datesToShow.forEach(occurrenceDate=>{
        if(calendarExceptionHidesOccurrence(n,occurrenceDate))return;
        const dateKeyLocal=calendarDateKeyLocal(occurrenceDate);
        const dateKeyUtc=occurrenceDate.toISOString().split('T')[0];
        // Use time override for this date if set (same routine meeting, different time/duration for that week)
        let virtualStartTime; let occurrenceDuration;
        const ov=n.routineTimeOverrides&&((dateKeyLocal&&n.routineTimeOverrides[dateKeyLocal])||(dateKeyUtc&&n.routineTimeOverrides[dateKeyUtc]));
        if(ov){
          virtualStartTime=new Date(ov.start);
          occurrenceDuration=ov.duration||duration;
        }else{
          virtualStartTime=new Date(occurrenceDate);
          virtualStartTime.setHours(originalHour,originalMinute,0,0);
          occurrenceDuration=duration;
        }
        const isAllDay=(virtualStartTime.getHours()===0&&virtualStartTime.getMinutes()===0&&(!occurrenceDuration||occurrenceDuration>=24*60*60*1000));
        pushOccurrence(n,virtualStartTime,occurrenceDuration,isAllDay);
      });
      // Add "moved to another day" overrides: starts in routineTimeOverrides whose *local* day is not a recurrence day
      if(n.routineTimeOverrides){
        for(const oKey of Object.keys(n.routineTimeOverrides)){
          const ov=n.routineTimeOverrides[oKey];
          if(!ov||ov.start==null)continue;
          const virtualStartTime=new Date(ov.start);
          if(isNaN(virtualStartTime.getTime()))continue;
          const localK=calendarDateKeyLocal(virtualStartTime);
          // Only skip stale oKey: do not skip when oKey===localK (storage key is the event's day) — exception list can wrongly list the same YYYY-MM-DD as a UTC "moved-from" day and the new instance would vanish
          if(n.exceptionDates&&n.exceptionDates.includes(oKey)&&oKey!==localK)continue;
          if(virtualStartTime<renderStartDate||virtualStartTime>renderEndDate)continue;
          const inRecSeries=datesToShow.some(d=>calendarDateKeyLocal(d)===localK);
          if(!inRecSeries){
            const occurrenceDuration=ov.duration||duration;
            const isAllDay=(virtualStartTime.getHours()===0&&virtualStartTime.getMinutes()===0&&(!occurrenceDuration||occurrenceDuration>=24*60*60*1000));
            pushOccurrence(n,virtualStartTime,occurrenceDuration,isAllDay);
          }
        }
      }
    }else{
      // Non-routine task or routine without frequency - add single occurrence
      const hour=startTime.getHours();
      const minute=startTime.getMinutes();
      // Check if it's an all-day event (no specific time, or time is 00:00)
      const isAllDay=!n.timer&&!n.completedAt&&(hour===0&&minute===0&&(!duration||duration>=24*60*60*1000));
      pushOccurrence(n,startTime,duration,isAllDay);
    }
  });
  
  grid.innerHTML='';
  const days=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const containerWidth=scrollContainer?scrollContainer.clientWidth:800;
  const timeColumnWidth=120; // Width for the Time column
  const dayWidth=Math.floor((containerWidth-timeColumnWidth)/7);
  const timeSlotHeight=60;
  
  // Calculate total days to render - render many weeks for infinite horizontal scrolling
  // Calculate weeks based on daysBefore and daysAfter for infinite scrolling
  const weeksBefore=Math.ceil(daysBefore/7); // Convert days to weeks (round up)
  const weeksAfter=Math.ceil(daysAfter/7); // Convert days to weeks (round up)
  const totalWeeks=weeksBefore+1+weeksAfter; // Center week + before + after
  const totalDays=totalWeeks*7; // Total days across all weeks
  // Render exactly 24 hours (one cycle)
  // All cycles show the SAME dates - only time changes
  const hourCycles=1; // Render 1 cycle of 24 hours (exactly 24 rows)
  const headerHeight=180; // Increased to accommodate month/year headers (30px month + ~150px day with goal and todo dropdown)
  const allDayRowHeight=40;
  const totalHeight=headerHeight+allDayRowHeight+(hourCycles*24*timeSlotHeight); // Header + all-day + hours
  const totalWidth=timeColumnWidth+(totalDays*dayWidth); // Time column + day columns (wider than container for scrolling)
  
  grid.style.width=totalWidth+'px';
  grid.style.height=totalHeight+'px';
  
  // Add global drop handler on grid for event delegation (more reliable than inline handlers)
  // Remove old handler if it exists
  const oldDropHandler=grid._todoDropHandler;
  if(oldDropHandler){
    grid.removeEventListener('drop',oldDropHandler);
  }
  grid._todoDropHandler=(e)=>{
    // Only handle drops on day columns
    const dayCol=e.target.closest('.cal-day-column');
    if(!dayCol)return;
    
    // Check if this is a file drop (ICS import) - let it bubble to document handler
    if(e.dataTransfer.files&&e.dataTransfer.files.length>0){
      const icsFile=Array.from(e.dataTransfer.files).find(file=>file.name.endsWith('.ics'));
      if(icsFile)return; // Let document handler process it
    }
    
    // Ignore drops on calendar events (time-based or all-day)
    if(e.target.classList.contains('cal-event')||e.target.closest('.cal-event')||e.target.classList.contains('cal-all-day-event')||e.target.closest('.cal-all-day-event')){
      return;
    }
    
    e.preventDefault();
    e.stopPropagation();
    
    // Get nodeId from dataTransfer
    const nodeId=e.dataTransfer.getData('text/plain');
    if(!nodeId||nodeId.trim()==='')return;
    
    // Get the day from the day column's dataset
    const dayStr=dayCol.dataset.date;
    if(!dayStr)return;
    const day=new Date(dayStr);
    
    // Calculate drop position
    const slot=dayCol.parentElement;
    if(!slot)return;
    const slotTop=parseFloat(slot.style.top)||0;
    const dayColRect=dayCol.getBoundingClientRect();
    const dropYRelative=e.clientY-dayColRect.top;
    const positionFromDayStart=slotTop-headerHeight-allDayRowHeight+dropYRelative;
    const totalMinutes=(positionFromDayStart/timeSlotHeight)*60;
    let dropHour=Math.floor(totalMinutes/60);
    const dropMinuteRaw=totalMinutes%60;
    let dropMinute=Math.round(dropMinuteRaw/15)*15;
    if(dropMinute>=60){
      dropMinute=0;
      dropHour+=1;
    }else if(dropMinute<0){
      dropMinute=0;
    }
    const finalHour=Math.max(0,Math.min(23,dropHour));
    const finalMinute=Math.max(0,Math.min(59,dropMinute));
    
    const newDate=new Date(day);
    newDate.setHours(finalHour,finalMinute,0,0);
    
    // Update or create event
    const node=G.nodes.find(n=>n.id===nodeId);
    if(!node)return;
    
    // Check if this is a routine event being moved
    if(node.calendarDate&&node.routine&&node.routineFrequency){
      const originalDateStr=e.dataTransfer.getData('occurrence-date');
      if(originalDateStr){
        const originalDate=new Date(originalDateStr);
        if(showRoutineActionModal('changeTime',node.id,originalDate,newDate)){
          return;
        }
      }
    }
    
    svWithUndo();
    // Use task name as event title (not category)
    const parentPath=nPath(nodeId);
    const eventDisplayName=node.name;
    
    if(!node.calendarDate){
      node.calendarDate=newDate.toISOString();
      node.calendarDuration=60*60*1000;
      node.TBD='none';
      if(parentPath.length>1){
        const categories=parentPath.slice(0,-1).map(n=>n.id);
        node.calendarCategories=categories;
      }
      node.calendarDisplayName=eventDisplayName;
      node.timer={startTime:newDate.toISOString(),endTime:new Date(newDate.getTime()+60*60*1000).toISOString(),duration:60*60*1000,remaining:60*60*1000};
    }else{
      node.calendarDate=newDate.toISOString();
      node.TBD='none';
      if(!node.calendarDuration){
        node.calendarDuration=60*60*1000;
      }
      node.calendarDisplayName=eventDisplayName;
      if(node.timer){
        const duration=node.timer.duration||node.calendarDuration||60*60*1000;
        node.timer.startTime=newDate.toISOString();
        node.timer.endTime=new Date(newDate.getTime()+duration).toISOString();
      }
    }
    sv();
    render();
    rPanel();
    renderCalendar();
    setTimeout(()=>renderTBDMicroTabs(),100);
  };
  grid.addEventListener('drop',grid._todoDropHandler);
  
  // Add dragover handler to allow drops on calendar
  // Remove old handler if it exists
  const oldDragOverHandler=grid._todoDragOverHandler;
  if(oldDragOverHandler){
    grid.removeEventListener('dragover',oldDragOverHandler);
  }
  grid._todoDragOverHandler=(e)=>{
    // Only allow drags over day columns
    const dayCol=e.target.closest('.cal-day-column');
    if(!dayCol)return;

    // Check if this is a file drag (ICS import) - let it bubble to the document handler.
    // During dragover the files list is empty (browsers only expose files on drop), so we
    // must detect file drags via dataTransfer.types ('Files'); using .files here would never
    // match and would wrongly force dropEffect='move', which the OS file drag rejects.
    if(e.dataTransfer.types&&Array.prototype.indexOf.call(e.dataTransfer.types,'Files')!==-1){
      return; // Let document handler process the file drop
    }

    // Must preventDefault for every dragover on a day column, including over event pills,
    // or some browsers block dropping onto a different day when the pointer passes over other events
    e.preventDefault();
    e.dataTransfer.dropEffect='move';
  };
  grid.addEventListener('dragover',grid._todoDragOverHandler);
  
  // Map to store all events per day for overlap detection: dateKey -> array of event data
  const dayEventsMap=new Map();
  
  // Create header row with Time column + Day headers
  const headerRow=document.createElement('div');
  headerRow.id='calendar-header-row';
  headerRow.style.position='sticky';
  headerRow.style.top='30px';
  headerRow.style.zIndex='99';
  headerRow.style.background='var(--bg1)';
  headerRow.style.borderBottom='2px solid var(--bdr)';
  headerRow.style.display='flex';
  headerRow.style.height='100px';
  headerRow.style.width=totalWidth+'px';
  
  // Create month/year header row (above day headers)
  const monthHeaderRow=document.createElement('div');
  monthHeaderRow.style.position='sticky';
  monthHeaderRow.style.top='0';
  monthHeaderRow.style.zIndex='101';
  monthHeaderRow.style.background='var(--bg1)';
  monthHeaderRow.style.borderBottom='1px solid var(--bdr)';
  monthHeaderRow.style.display='flex';
  monthHeaderRow.style.height='30px';
  monthHeaderRow.style.width=totalWidth+'px';
  
  // Time column header for month row
  const timeHeaderMonth=document.createElement('div');
  timeHeaderMonth.style.width=timeColumnWidth+'px';
  timeHeaderMonth.style.borderRight='1px solid var(--bdr)';
  timeHeaderMonth.style.flexShrink='0';
  timeHeaderMonth.style.position='sticky';
  timeHeaderMonth.style.left='0';
  timeHeaderMonth.style.zIndex='102';
  timeHeaderMonth.style.background='var(--bg1)';
  monthHeaderRow.appendChild(timeHeaderMonth);
  
  // Day headers - show all weeks (multiple weeks for horizontal scrolling)
  const firstWeekStart=new Date(centerStart);
  firstWeekStart.setDate(firstWeekStart.getDate()-firstWeekStart.getDay());
  firstWeekStart.setDate(firstWeekStart.getDate()-(weeksBefore*7)); // Start from weeksBefore weeks ago
  firstWeekStart.setHours(0,0,0,0);
  
  // Group days by month and create month headers
  let currentMonth=null;
  let monthStartIdx=0;
  for(let dayIdx=0;dayIdx<totalDays;dayIdx++){
    const day=new Date(firstWeekStart);
    day.setDate(day.getDate()+dayIdx);
    const month=day.getMonth();
    const year=day.getFullYear();
    const monthKey=`${year}-${month}`;
    
    if(currentMonth!==monthKey){
      // Close previous month header if exists
      if(currentMonth!==null){
        const prevMonthHeader=monthHeaderRow.lastElementChild;
        if(prevMonthHeader&&prevMonthHeader!==timeHeaderMonth){
          const prevMonthDays=dayIdx-monthStartIdx;
          prevMonthHeader.style.width=(prevMonthDays*dayWidth)+'px';
        }
      }
      // Start new month header
      const monthHeader=document.createElement('div');
      monthHeader.className='cal-month-header';
      monthHeader.style.borderRight='1px solid var(--bdr)';
      monthHeader.style.flexShrink='0';
      monthHeader.style.display='flex';
      monthHeader.style.alignItems='center';
      monthHeader.style.justifyContent='center';
      monthHeader.style.fontWeight='600';
      monthHeader.style.fontSize='14px';
      monthHeader.style.color='var(--t0)';
      monthHeader.textContent=day.toLocaleDateString('en-US',{month:'long',year:'numeric'});
      monthHeaderRow.appendChild(monthHeader);
      currentMonth=monthKey;
      monthStartIdx=dayIdx;
    }
  }
  // Close last month header
  if(currentMonth!==null){
    const lastMonthHeader=monthHeaderRow.lastElementChild;
    if(lastMonthHeader&&lastMonthHeader!==timeHeaderMonth){
      const lastMonthDays=totalDays-monthStartIdx;
      lastMonthHeader.style.width=(lastMonthDays*dayWidth)+'px';
    }
  }
  
  // Time column header
  const timeHeader=document.createElement('div');
  timeHeader.className='cal-day-header';
  timeHeader.style.width=timeColumnWidth+'px';
  timeHeader.style.borderRight='1px solid var(--bdr)';
  timeHeader.style.flexShrink='0';
  timeHeader.style.position='sticky';
  timeHeader.style.left='0';
  timeHeader.style.zIndex='100';
  timeHeader.style.background='var(--bg1)';
  timeHeader.innerHTML=`
    <div class="cal-day-name">Time</div>
  `;
  headerRow.appendChild(timeHeader);
  
  // Get today's date for comparison (updates dynamically)
  const todayForHeader=new Date();
  todayForHeader.setHours(0,0,0,0);
  const todayForHeaderStr=todayForHeader.toDateString();
  for(let dayIdx=0;dayIdx<totalDays;dayIdx++){
    const day=new Date(firstWeekStart);
    day.setDate(day.getDate()+dayIdx);
    const isToday=day.toDateString()===todayForHeaderStr;
    const dayOfWeek=day.getDay();
    const isWeekend=dayOfWeek===0||dayOfWeek===6; // Sunday or Saturday
    const dayName=days[dayOfWeek]; // Mon, Tue, etc.
    const dayNumber=day.getDate(); // 1-31
    
    const dayHeader=document.createElement('div');
    dayHeader.className='cal-day-header'+(isToday?' today-header':'')+(isWeekend?' weekend':'');
    dayHeader.style.width=dayWidth+'px';
    dayHeader.style.borderRight='1px solid var(--bdr)';
    dayHeader.style.flexShrink='0';
    
    // Get todos and goal for this day
    const dayTodos=getTodosForDate(day);
    const dayGoal=getGoalForDate(day);
    const dateKey=day.toISOString().split('T')[0];
    
    // Build todo dropdown HTML
    let todoDropdownHTML='';
    if(dayTodos.length>0){
      const todoItems=dayTodos.map(nodeId=>{
        const node=G.nodes.find(n=>n.id===nodeId);
        if(!node)return'';
        const isComplete=node.status==='completed';
        // Remove onclick - todo items should not navigate, just show the list
        return`<div class="cal-day-todo-item" style="text-decoration:${isComplete?'line-through':''};opacity:${isComplete?'0.6':'1'}">${esc(node.name)}</div>`;
      }).join('');
      todoDropdownHTML=`<div class="cal-day-todo-dropdown" data-date="${dateKey}" title="To-do list (${dayTodos.length} task${dayTodos.length!==1?'s':''}) - Click to expand">${todoItems}</div>`;
    }else{
      todoDropdownHTML=`<div class="cal-day-todo-dropdown" data-date="${dateKey}" style="opacity:0.5;font-style:italic" title="No tasks - Click to expand">No tasks</div>`;
    }
    
    // Build goal text HTML - show one line, truncate if longer
    const goalDisplayText=dayGoal.length>40?dayGoal.substring(0,40)+'...':dayGoal;
    const goalHTML=dayGoal?`<div class="cal-day-goal" data-date="${dateKey}" title="${esc(dayGoal)} - Click to expand">${esc(goalDisplayText)}</div>`:'';
    
    // MacBook calendar style: Simple format "Sun 8", "Mon 9", etc.
    dayHeader.innerHTML=`
      <div class="cal-day-name">${dayName} ${dayNumber}</div>
      <div class="cal-day-date ${isToday?'today':''}">${dayNumber}</div>
      ${goalHTML}
      ${todoDropdownHTML}
    `;
    // Attach click handlers after innerHTML is set
    if(dayGoal){
      const goalBox=dayHeader.querySelector('.cal-day-goal');
      if(goalBox){
        goalBox.style.cursor='pointer';
        goalBox.addEventListener('click',function(e){
          e.stopPropagation();
          e.preventDefault();
          if(window.toggleGoalBox){
            window.toggleGoalBox(this);
          }
        },{capture:false});
      }
    }
    const todoDropdown=dayHeader.querySelector('.cal-day-todo-dropdown');
    if(todoDropdown){
      todoDropdown.style.cursor='pointer';
      todoDropdown.addEventListener('click',function(e){
        e.stopPropagation();
        e.preventDefault();
        if(window.toggleTodoDropdown){
          window.toggleTodoDropdown(this);
        }
      },{capture:false});
    }
    headerRow.appendChild(dayHeader);
  }
  
  // Insert headers as first children of grid (month header first, then day header)
  grid.appendChild(monthHeaderRow);
  grid.appendChild(headerRow);
  
  // Create time slots (multiple 24-hour cycles + all-day)
  // CRITICAL: All cycles show the SAME dates - only time repeats
  // Vertical scrolling changes hours, NOT dates - dates stay fixed
  for(let cycle=0;cycle<hourCycles;cycle++){
    // All-day row at top of first cycle (after header)
    if(cycle===0){
      const slot=document.createElement('div');
      slot.className='cal-time-slot';
      slot.style.top=headerHeight+'px'; // Below headers (month + day)
      slot.style.left='0';
      slot.style.width=totalWidth+'px';
      
      // Time column cell for "All Day"
      const timeCell=document.createElement('div');
      timeCell.className='cal-time-label all-day';
      timeCell.style.position='sticky';
      timeCell.style.left='0';
      timeCell.style.top='0';
      timeCell.style.width=timeColumnWidth+'px';
      timeCell.style.height='40px';
      timeCell.style.zIndex='10';
      timeCell.style.background='var(--bg1)';
      timeCell.style.borderRight='1px solid var(--bdr)';
      timeCell.style.display='flex';
      timeCell.style.alignItems='center';
      timeCell.style.justifyContent='center';
      timeCell.textContent='All Day';
      slot.appendChild(timeCell);
      
      // Create all-day columns for all days (using all weeks for horizontal scrolling)
      for(let dayIdx=0;dayIdx<totalDays;dayIdx++){
        const day=new Date(firstWeekStart);
        day.setDate(day.getDate()+dayIdx);
        const isToday=day.toDateString()===new Date().toDateString();
        const dayOfWeek=day.getDay();
        const isWeekend=dayOfWeek===0||dayOfWeek===6; // Sunday or Saturday
        const dateKey=day.toDateString();
        const dayCol=document.createElement('div');
        dayCol.className='cal-day-column'+(isToday?' today':'')+(isWeekend?' weekend':'');
        dayCol.style.left=(timeColumnWidth+dayIdx*dayWidth)+'px'; // After time column
        dayCol.style.width=dayWidth+'px';
        dayCol.style.height='40px';
        dayCol.dataset.date=day.toISOString();
        // Add all-day events
        const allDayTasks=tasksByDateAndTime.get(dateKey);
        if(allDayTasks&&allDayTasks.has(-1)){
          let allDayY=0;
          allDayTasks.get(-1).forEach(t=>{
            const event=document.createElement('div');
            event.className='cal-all-day-event'+(t.node.status==='completed'?' completed-task':'');
            event.style.top=allDayY+'px';
            event.style.borderLeftColor=t.node.color;
            if(t.node.nah){ event.style.opacity='0.45'; event.style.filter='grayscale(0.35)'; }
            // Check if event is priority and in the future
            const now=new Date();
            const isPriorityFuture=t.node.priority&&t.startTime>now&&priorityVisible;
            if(isPriorityFuture){
              event.classList.add('priority-future');
              dayCol.classList.add('has-priority-future');
            }
            // Draggable: move all-day event to another day (all-day row or time slot)
            event.draggable=true;
            event.style.cursor='move';
            event.dataset.nodeId=t.node.id;
            event.dataset.occurrenceDate=t.startTime.toISOString();
            event.ondragstart=(e)=>{
              if(e.target.classList.contains('cal-event-delete')||e.target.classList.contains('cal-event-edit-btn')||e.target.classList.contains('cal-event-note-btn')){
                e.preventDefault();
                return false;
              }
              e.dataTransfer.setData('text/plain',t.node.id);
              e.dataTransfer.setData('occurrence-date',t.startTime.toISOString());
              e.dataTransfer.effectAllowed='move';
              event.style.opacity='0.5';
            };
            event.ondragend=(e)=>{
              event.style.opacity='1';
            };
            // Click handler - toggle expand/collapse for all-day events
            event.onclick=(e)=>{
              // Don't toggle if clicking on buttons or links
              if(e.target.classList.contains('cal-event-delete')||e.target.classList.contains('cal-event-edit-btn')||e.target.classList.contains('cal-event-note-btn')||e.target.closest('.cal-event-note-btn')||e.target.closest('a')){
                return;
              }
              e.stopPropagation();
              // Toggle expanded state
              const wasExpanded=event.classList.contains('expanded');
              event.classList.toggle('expanded');
              if(!wasExpanded){
                // Expanding - store original z-index and set to top layer
                if(!event.dataset.originalZIndex){
                  event.dataset.originalZIndex=event.style.zIndex||'10';
                }
                const contentHeight=event.scrollHeight;
                const maxHeight=Math.min(contentHeight+10,400); // Max 400px height
                event.style.height=Math.max(38,maxHeight)+'px';
                event.style.zIndex='1000'; // Top layer when expanded
              }else{
                // Collapsing - restore original height and z-index
                event.style.height='38px';
                event.style.zIndex=event.dataset.originalZIndex||'10';
              }
            };
            // Create delete button for all-day events (top-right)
            const deleteBtn=document.createElement('div');
            deleteBtn.className='cal-event-delete';
            deleteBtn.innerHTML='🗑️';
            deleteBtn.title='Delete event';
            deleteBtn.onclick=(e)=>{
              e.stopPropagation();
              const node=G.nodes.find(n=>n.id===t.node.id);
              if(!node)return;
              
              // Check if this is a routine event
              if(node.routine&&node.routineFrequency){
                // Show modal for routine event
                const occurrenceDate=new Date(t.startTime);
                if(showRoutineActionModal('delete',node.id,occurrenceDate)){
                  return; // Modal will handle the action
                }
              }
              
              // Non-routine event - delete directly
              svWithUndo();
              node.calendarDate=null;
              node.calendarDuration=null;
              node.calendarDisplayName=null;
              sv();
              renderTodoList(); // Refresh todo list to update grey background
              renderCalendar();
            };
            // Create edit button for all-day events (bottom-right)
            const editBtn=document.createElement('div');
            editBtn.className='cal-event-edit-btn';
            editBtn.innerHTML='✏️';
            editBtn.title='Edit event';
            editBtn.onclick=(e)=>{
              e.stopPropagation();
              if(t.node.calendarDate){
                openEditCalendarEvent(t.node.id,t.node.routine?t.startTime.toISOString():undefined);
              }else{
                openEdit(t.node.id);
              }
            };
            // Create note button for all-day events (bottom-left)
            const noteBtn=document.createElement('div');
            noteBtn.className='cal-event-note-btn';
            noteBtn.innerHTML='<svg width="10" height="10" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="3" y="2" width="18" height="20" rx="2" fill="#6C63FF" opacity="0.3" stroke="#6C63FF" stroke-width="1.5"/><rect x="3" y="2" width="18" height="5" rx="2" fill="#8b84ff" opacity="0.6"/><line x1="6" y1="5" x2="18" y2="5" stroke="#FFD700" stroke-width="1.5" stroke-linecap="round"/><line x1="6" y1="9" x2="15" y2="9" stroke="#87CEEB" stroke-width="1.2" stroke-linecap="round"/><circle cx="18" cy="18" r="2.5" fill="#FF6B35" opacity="0.8"/></svg>';
            noteBtn.title='Open note';
            noteBtn.onclick=(e)=>{
              e.stopPropagation();
              openCalendarEventNoteFromCalendar(t.node,t.startTime||t.node.calendarDate||null);
            };
            // Use calendarDisplayName if available, otherwise use node name
            const displayName=t.node.calendarDisplayName||t.node.name;
            // Create URL or location preview (partially visible when collapsed)
            let previewHTML='';
            if(t.node.link){
              previewHTML=`<div class="cal-event-link-preview" onclick="event.stopPropagation();window.open('${esc(t.node.link)}','_blank')" title="${esc(t.node.link)}" style="margin-top:2px">🔗 ${esc(t.node.link.length>35?t.node.link.substring(0,35)+'...':t.node.link)}</div>`;
            }else if(t.node.location){
              const locationUrl=`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(t.node.location)}`;
              previewHTML=`<div class="cal-event-location-preview" onclick="event.stopPropagation();window.open('${locationUrl}','_blank')" title="${esc(t.node.location)}" style="margin-top:2px">📍 ${esc(t.node.location.length>35?t.node.location.substring(0,35)+'...':t.node.location)}</div>`;
            }
            // Full content (shown when expanded)
            const linkHTML=t.node.link?`<div class="cal-event-link" style="margin-top:4px;font-size:11px"><a href="${esc(t.node.link)}" target="_blank" rel="noopener noreferrer" style="color:var(--acc);text-decoration:underline;word-break:break-all" onclick="event.stopPropagation()">${esc(t.node.link)}</a></div>`:'';
            const locationHTML=t.node.location?`<div class="cal-event-location" style="margin-top:4px;font-size:11px"><a href="https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(t.node.location)}" target="_blank" rel="noopener noreferrer" style="color:var(--acc);text-decoration:underline;word-break:break-all" onclick="event.stopPropagation()">📍 ${esc(t.node.location)}</a></div>`:'';
            const eventDateKey=t.startTime?t.startTime.toISOString().split('T')[0]:null;
            const eventDescription=getDescriptionContentForNode(t.node,eventDateKey);
            event.innerHTML=`<div class="cal-event-name">${esc(displayName)}</div>${previewHTML}${eventDescription?`<div class="cal-event-desc" style="font-size:12px;color:var(--t2);margin-top:4px">${esc(eventDescription)}</div>`:''}${linkHTML}${locationHTML}`;
            event.appendChild(deleteBtn);
            event.appendChild(editBtn);
            event.appendChild(noteBtn);
            
            // Add hover handlers for all-day events - icons appear on hover, hide when cursor moves away
            let allDayHoverTimeout;
            let isMouseOverAllDayEvent=false;
            
            const showAllDayIcons=()=>{
              clearTimeout(allDayHoverTimeout);
              isMouseOverAllDayEvent=true;
              event.classList.add('show-icons');
            };
            
            const hideAllDayIcons=()=>{
              clearTimeout(allDayHoverTimeout);
              isMouseOverAllDayEvent=false;
              allDayHoverTimeout=setTimeout(()=>{
                if(!isMouseOverAllDayEvent){
                  event.classList.remove('show-icons');
                }
              },100);
            };
            
            event.addEventListener('mouseenter',showAllDayIcons);
            event.addEventListener('mouseleave',(e)=>{
              const relatedTarget=e.relatedTarget;
              if(relatedTarget&&(event.contains(relatedTarget)||[deleteBtn,editBtn,noteBtn].includes(relatedTarget))){
                return;
              }
              hideAllDayIcons();
            });
            
            [deleteBtn,editBtn,noteBtn].forEach(btn=>{
              btn.addEventListener('mouseenter',showAllDayIcons);
              btn.addEventListener('mouseleave',(e)=>{
                const relatedTarget=e.relatedTarget;
                if(relatedTarget&&event.contains(relatedTarget)){
                  return;
                }
                hideAllDayIcons();
              });
            });
            
            dayCol.appendChild(event);
            allDayY+=42;
          });
        }
        slot.appendChild(dayCol);
      }
      grid.appendChild(slot);
    }
    
    // 24 hours for this cycle - all cycles show same dates, just repeat hours
    for(let hour=0;hour<24;hour++){
      const slot=document.createElement('div');
      slot.className='cal-time-slot';
      const slotTop=headerHeight+allDayRowHeight+(cycle*24+hour)*timeSlotHeight;
      slot.style.top=slotTop+'px';
      slot.style.left='0';
      slot.style.width=totalWidth+'px';
      
      // Add horizontal line across entire calendar for this hour
      const hourLine=document.createElement('div');
      hourLine.style.position='absolute';
      hourLine.style.top='0';
      hourLine.style.left='0';
      hourLine.style.width='100%';
      hourLine.style.height='1px';
      hourLine.style.borderTop='1px solid var(--bdr)';
      hourLine.style.pointerEvents='none';
      hourLine.style.zIndex='1';
      slot.appendChild(hourLine);
      
      // Time column cell for this hour
      const timeCell=document.createElement('div');
      timeCell.className='cal-time-label';
      timeCell.style.position='sticky';
      timeCell.style.left='0';
      timeCell.style.top='0';
      timeCell.style.width=timeColumnWidth+'px';
      timeCell.style.height=timeSlotHeight+'px';
      timeCell.style.zIndex='10';
      timeCell.style.background='var(--bg1)';
      timeCell.style.borderRight='1px solid var(--bdr)';
      timeCell.style.display='flex';
      timeCell.style.alignItems='flex-start';
      timeCell.style.justifyContent='center';
      timeCell.style.paddingTop='4px';
      const displayHour=(cycle*24+hour)%24; // Repeat hours 0-23 for each cycle
      const timeStr=displayHour===0?'12:00 AM':displayHour<12?displayHour+':00 AM':displayHour===12?'12:00 PM':(displayHour-12)+':00 PM';
      timeCell.textContent=timeStr;
      slot.appendChild(timeCell);
      
      // Create day columns for this time slot - use all weeks (same for all cycles)
      // IMPORTANT: All cycles use the same firstWeekStart - dates never change with vertical scroll
      for(let dayIdx=0;dayIdx<totalDays;dayIdx++){
        const day=new Date(firstWeekStart);
        day.setDate(day.getDate()+dayIdx);
        const isToday=day.toDateString()===new Date().toDateString();
        const dayOfWeek=day.getDay();
        const isWeekend=dayOfWeek===0||dayOfWeek===6; // Sunday or Saturday
        const dateKey=day.toDateString();
      
        const dayCol=document.createElement('div');
        dayCol.className='cal-day-column'+(isToday?' today':'')+(isWeekend?' weekend':'');
        dayCol.style.left=(timeColumnWidth+dayIdx*dayWidth)+'px'; // After time column
        dayCol.style.width=dayWidth+'px';
        dayCol.style.height=timeSlotHeight+'px';
        dayCol.dataset.day=dayIdx;
        dayCol.dataset.hour=displayHour;
        dayCol.dataset.date=day.toISOString();
        // Click to add event
        dayCol.onclick=(e)=>{
          if(e.target.classList.contains('cal-event')||e.target.closest('.cal-event'))return;
          const rect=dayCol.getBoundingClientRect();
          const clickY=e.clientY-rect.top;
          const clickHour=displayHour;
          const clickMinuteRaw=Math.floor((clickY/timeSlotHeight)*60);
          // Snap to nearest 15-minute interval
          const clickMinute=Math.round(clickMinuteRaw/15)*15;
          const eventDate=new Date(day);
          eventDate.setHours(clickHour,clickMinute,0,0);
          openCalendarEventModal(eventDate.toISOString());
        };
        
        // Handle drop for dragging events (no hover highlight)
        dayCol.ondragover=(e)=>{
          // Check if this is a file drag (ICS import) - allow drop but let it bubble
          if(e.dataTransfer.types.includes('Files')){
            // Allow file drops but let them bubble to document-level handler
            e.preventDefault();
            return;
          }
          
          e.preventDefault();
          e.dataTransfer.dropEffect='move';
          // Auto-scroll during drag over
          const scrollContainer=document.getElementById('calendar-scroll-container');
          if(scrollContainer){
            const rect=scrollContainer.getBoundingClientRect();
            const mouseY=e.clientY;
            const scrollThreshold=100; // pixels from edge to start scrolling
            const scrollSpeed=10; // pixels per scroll
            
            if(mouseY-rect.top<scrollThreshold){
              // Near top - scroll up
              scrollContainer.scrollTop=Math.max(0,scrollContainer.scrollTop-scrollSpeed);
            }else if(rect.bottom-mouseY<scrollThreshold){
              // Near bottom - scroll down
              scrollContainer.scrollTop=Math.min(scrollContainer.scrollHeight-scrollContainer.clientHeight,scrollContainer.scrollTop+scrollSpeed);
            }
          }
        };
        dayCol.ondrop=(e)=>{
          // Always prevent default first to allow drop
          e.preventDefault();
          
          // Check if this is a file drop (ICS import) - let it bubble to document handler
          if(e.dataTransfer.files&&e.dataTransfer.files.length>0){
            const icsFile=Array.from(e.dataTransfer.files).find(file=>file.name.endsWith('.ics'));
            if(icsFile){
              // For file drops, don't stop propagation - let document handler process it
              return;
            }
          }
          
          // Stop propagation for todo item drops to prevent document handler from interfering
          e.stopPropagation();
          
          // Ignore drops directly on calendar events (they have their own handlers)
          // But allow drops on the day column itself or empty space
          const isCalendarEvent=e.target.classList.contains('cal-event')||e.target.closest('.cal-event');
          if(isCalendarEvent){
            return;
          }
          
          // Get nodeId from dataTransfer
          const nodeId=e.dataTransfer.getData('text/plain');
          if(!nodeId||nodeId.trim()===''){
            // If no nodeId, this might not be a todo item drop
            return;
          }
          
          // Calculate absolute position within the entire day column
          // Get the slot (parent of dayCol) to find its top position
          const slot=dayCol.parentElement;
          if(!slot)return;
          
          // Get the slot's absolute top position (from top of grid)
          const slotTop=parseFloat(slot.style.top)||0;
          
          // Get drop position relative to the day column
          const dayColRect=dayCol.getBoundingClientRect();
          const dropYRelative=e.clientY-dayColRect.top;
          
          // Calculate absolute position from start of day (after header and all-day row)
          // slotTop already includes headerHeight + allDayRowHeight + hour offset
          const positionFromDayStart=slotTop-headerHeight-allDayRowHeight+dropYRelative;
          
          // Calculate total hours and minutes from midnight
          const totalMinutes=(positionFromDayStart/timeSlotHeight)*60;
          let dropHour=Math.floor(totalMinutes/60);
          const dropMinuteRaw=totalMinutes%60;
          
          // Snap to nearest 15-minute interval (0, 15, 30, 45)
          // Use proper rounding to avoid :59 issues
          let dropMinute=Math.round(dropMinuteRaw/15)*15;
          // Handle edge case: if rounding gives us 60, move to next hour
          if(dropMinute>=60){
            dropMinute=0;
            dropHour+=1;
          }else if(dropMinute<0){
            dropMinute=0;
          }
          
          // Clamp hour to valid range (0-23)
          const finalHour=Math.max(0,Math.min(23,dropHour));
          const finalMinute=Math.max(0,Math.min(59,dropMinute));
          
          const newDate=new Date(day);
          newDate.setHours(finalHour,finalMinute,0,0);
          // Update or create event
          const node=G.nodes.find(n=>n.id===nodeId);
          if(!node)return;
          
          // Check if this is a routine event being moved
          if(node.calendarDate&&node.routine&&node.routineFrequency){
            // Get the original occurrence date from drag data
            const originalDateStr=e.dataTransfer.getData('occurrence-date');
            if(originalDateStr){
              const originalDate=new Date(originalDateStr);
              // Show modal for routine event
              if(showRoutineActionModal('changeTime',node.id,originalDate,newDate)){
                return; // Modal will handle the action
              }
            }
          }
          
          svWithUndo();
          // Use task name as event title (not category)
          const parentPath=nPath(nodeId);
          const eventDisplayName=node.name;
          
          // If node doesn't have calendarDate, create a new calendar event
          if(!node.calendarDate){
            // Create new event with task name as title
            node.calendarDate=newDate.toISOString();
            node.calendarDuration=60*60*1000; // Default 1 hour
            // When dropped on calendar, uncheck TBD (set to 'none')
            node.TBD='none';
            // Save categories - get all parent categories
            if(parentPath.length>1){
              // Store category path (excluding the node itself)
              const categories=parentPath.slice(0,-1).map(n=>n.id);
              node.calendarCategories=categories; // Store category IDs
            }
            // Set display name to parent task name for 2nd level tasks, otherwise task name
            node.calendarDisplayName=eventDisplayName;
            // Set timer for the event
            node.timer={startTime:newDate.toISOString(),endTime:new Date(newDate.getTime()+60*60*1000).toISOString(),duration:60*60*1000,remaining:60*60*1000};
          }else{
            // Update existing event
            node.calendarDate=newDate.toISOString();
            // When dropped on calendar, uncheck TBD (set to 'none')
            node.TBD='none';
            // Set default duration to 1 hour if not already set
            if(!node.calendarDuration){
              node.calendarDuration=60*60*1000; // 1 hour in milliseconds
            }
            // Set display name to task content only (not category or nested location)
            node.calendarDisplayName=eventDisplayName;
            if(node.timer){
              // Update timer start time to match
              const duration=node.timer.duration||node.calendarDuration||60*60*1000;
              node.timer.startTime=newDate.toISOString();
              node.timer.endTime=new Date(newDate.getTime()+duration).toISOString();
            }
          }
          sv();
          render();
          rPanel();
          renderCalendar();
          setTimeout(()=>renderTBDMicroTabs(),100);
        };
        
        // Add events for this time slot (only for first cycle to avoid duplicates)
        if(cycle===0){
          // Time-based events
          const dayMap=tasksByDateAndTime.get(dateKey);
          if(dayMap){
            dayMap.forEach((tasks,timeKey)=>{
              // Use actual startTime from the task, not timeKey, to ensure accuracy
              tasks.forEach(t=>{
                const eventStartHour=t.startTime.getHours();
                const eventStartMinute=t.startTime.getMinutes();
                // Only render if event starts in this hour slot
                if(eventStartHour===displayHour){
                  const event=document.createElement('div');
                  event.className='cal-event'+(t.node.status==='completed'?' completed-task':'');
                  event.style.borderLeftColor=t.node.color;
                  if(t.node.nah){ event.style.opacity='0.45'; event.style.filter='grayscale(0.35)'; }
                  event.dataset.nodeId=t.node.id;
                  // Check if event is priority and in the future
                  const now=new Date();
                  const isPriorityFuture=t.node.priority&&t.startTime>now&&priorityVisible;
                  if(isPriorityFuture){
                    event.classList.add('priority-future');
                    dayCol.classList.add('has-priority-future');
                  }
                  // Calculate top position based on actual minutes within the hour
                  const topPercent=(eventStartMinute/60)*100;
                  event.style.top=topPercent+'%';
                  // Calculate height based on duration
                  const durationHours=t.duration/(60*60*1000);
                  const minHeightPx=40; // Minimum height to show text
                  const calculatedHeight=(durationHours*timeSlotHeight);
                  const eventHeight=Math.max(minHeightPx,calculatedHeight);
                  event.style.height=eventHeight+'px';
                  event.style.minHeight=minHeightPx+'px';
                  
                  // Store event data for overlap detection (absolute position from day start)
                  // Calculate absolute top position from midnight (in pixels)
                  const absoluteTop=(eventStartHour*timeSlotHeight)+(eventStartMinute/60*timeSlotHeight);
                  const absoluteBottom=absoluteTop+eventHeight;
                  
                  // Store in dayEventsMap for later overlap processing
                  if(!dayEventsMap.has(dateKey))dayEventsMap.set(dateKey,[]);
                  dayEventsMap.get(dateKey).push({
                    event,
                    dayCol,
                    task:t,
                    top:absoluteTop,
                    bottom:absoluteBottom,
                    startTime:t.startTime,
                    duration:t.duration
                  });
                  
                  // All events can be dragged and edited (including past events). Multi-day
                  // segments are display-only slices of a single event — dragging/resizing one
                  // day's slice would corrupt the whole event, so they aren't draggable (edit via ✏️).
                  event.draggable=!t.multiDay;
                  event.style.cursor=t.multiDay?'pointer':'move';
                  event.dataset.startTime=t.startTime.toISOString();
                  event.dataset.duration=t.duration;
                  event.dataset.occurrenceDate=t.startTime.toISOString(); // Store occurrence date for routine events
                  let dragScrollInterval=null;
                  let dragMouseY=0;
                  event.ondragstart=(e)=>{
                    // Don't start drag if clicking on resize handle
                    if(e.target.classList.contains('cal-event-resize')){
                      e.preventDefault();
                      return false;
                    }
                    e.dataTransfer.setData('text/plain',t.node.id);
                    e.dataTransfer.setData('occurrence-date',t.startTime.toISOString()); // Store occurrence date
                    e.dataTransfer.effectAllowed='move';
                    event.style.opacity='0.5';
                    dragMouseY=e.clientY;
                    // Start auto-scroll during drag
                    const scrollContainer=document.getElementById('calendar-scroll-container');
                    if(scrollContainer){
                      // Track mouse position during drag
                      const trackMouse=(ev)=>{
                        dragMouseY=ev.clientY;
                      };
                      document.addEventListener('dragover',trackMouse);
                      
                      dragScrollInterval=setInterval(()=>{
                        const rect=scrollContainer.getBoundingClientRect();
                        const scrollThreshold=100; // pixels from edge to start scrolling
                        const scrollSpeed=10; // pixels per interval
                        
                        if(dragMouseY-rect.top<scrollThreshold){
                          // Near top - scroll up
                          scrollContainer.scrollTop=Math.max(0,scrollContainer.scrollTop-scrollSpeed);
                        }else if(rect.bottom-dragMouseY<scrollThreshold){
                          // Near bottom - scroll down
                          scrollContainer.scrollTop=Math.min(scrollContainer.scrollHeight-scrollContainer.clientHeight,scrollContainer.scrollTop+scrollSpeed);
                        }
                      },50); // Check every 50ms
                      
                      // Clean up on drag end
                      const cleanup=()=>{
                        if(dragScrollInterval){
                          clearInterval(dragScrollInterval);
                          dragScrollInterval=null;
                        }
                        document.removeEventListener('dragover',trackMouse);
                        document.removeEventListener('dragend',cleanup);
                      };
                      document.addEventListener('dragend',cleanup,{once:true});
                    }
                  };
                  event.ondragend=(e)=>{
                    event.style.opacity='1';
                  };
                  
                  // Click handler - toggle expand/collapse
                  event.onclick=(e)=>{
                    // Don't toggle if clicking on buttons or links
                    if(e.target.classList.contains('cal-event-delete')||e.target.classList.contains('cal-event-edit-btn')||e.target.classList.contains('cal-event-note-btn')||e.target.closest('.cal-event-note-btn')||e.target.closest('a')){
                      return;
                    }
                    e.stopPropagation();
                    // Toggle expanded state
                    const wasExpanded=event.classList.contains('expanded');
                    event.classList.toggle('expanded');
                    if(!wasExpanded){
                      // Expanding - store original z-index and set to top layer
                      if(!event.dataset.originalZIndex){
                        event.dataset.originalZIndex=event.style.zIndex||'10';
                      }
                      const contentHeight=event.scrollHeight;
                      const maxHeight=Math.min(contentHeight+10,timeSlotHeight*8); // Max 8 hours worth of height
                      event.style.height=Math.max(eventHeight,maxHeight)+'px';
                      event.style.zIndex='1000'; // Top layer when expanded
                    }else{
                      // Collapsing - restore original height and z-index
                      event.style.height=eventHeight+'px';
                      event.style.zIndex=event.dataset.originalZIndex||'10';
                    }
                  };
                  
                  const timeStr=t.startTime.toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'});
                  const endTime=new Date(t.startTime.getTime()+t.duration);
                  const endTimeStr=endTime.toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'});
                  // Time label: a multi-day segment shows continuation arrows so it reads as
                  // part of a span (start day: "9:00 AM →", end day: "→ 3:00 PM", middle: full day).
                  let timeLabel=`${timeStr}${t.duration>0?' - '+endTimeStr:''}`;
                  if(t.multiDay){
                    const fmt=(ms)=>new Date(ms).toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'});
                    const isStart=Math.abs(t.startTime.getTime()-t.eventStartMs)<1000;
                    const isEnd=Math.abs((t.startTime.getTime()+t.duration)-t.eventEndMs)<1000;
                    timeLabel=isStart?`${fmt(t.eventStartMs)} →`:isEnd?`→ ${fmt(t.eventEndMs)}`:'↕ all day';
                  }
                  // Create delete button (trash icon) that appears on hover at top-right
                  const deleteBtn=document.createElement('div');
                  deleteBtn.className='cal-event-delete';
                  deleteBtn.innerHTML='🗑️';
                  deleteBtn.title='Delete event';
                  deleteBtn.onclick=(e)=>{
                    e.stopPropagation();
                    const node=G.nodes.find(n=>n.id===t.node.id);
                    if(!node)return;
                    
                    // Check if this is a routine event
                    if(node.routine&&node.routineFrequency){
                      // Show modal for routine event
                      const occurrenceDate=new Date(t.startTime);
                      if(showRoutineActionModal('delete',node.id,occurrenceDate)){
                        return; // Modal will handle the action
                      }
                    }
                    
                    // Non-routine event - delete directly
                    svWithUndo();
                    node.calendarDate=null;
                    node.calendarDuration=null;
                    node.calendarDisplayName=null;
                    sv();
                    renderTodoList(); // Refresh todo list to update grey background
                    renderCalendar();
                  };
                  // Create edit button that appears on hover at bottom-right
                  const editBtn=document.createElement('div');
                  editBtn.className='cal-event-edit-btn';
                  editBtn.innerHTML='✏️';
                  editBtn.title='Edit event';
                  editBtn.onclick=(e)=>{
                    e.stopPropagation();
                    if(t.node.calendarDate){
                      openEditCalendarEvent(t.node.id,t.node.routine?t.startTime.toISOString():undefined);
                    }else{
                      openEdit(t.node.id);
                    }
                  };
                  // Create note button that appears on hover at bottom-left
                  const noteBtn=document.createElement('div');
                  noteBtn.className='cal-event-note-btn';
                  noteBtn.innerHTML='<svg width="10" height="10" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="3" y="2" width="18" height="20" rx="2" fill="#6C63FF" opacity="0.3" stroke="#6C63FF" stroke-width="1.5"/><rect x="3" y="2" width="18" height="5" rx="2" fill="#8b84ff" opacity="0.6"/><line x1="6" y1="5" x2="18" y2="5" stroke="#FFD700" stroke-width="1.5" stroke-linecap="round"/><line x1="6" y1="9" x2="15" y2="9" stroke="#87CEEB" stroke-width="1.2" stroke-linecap="round"/><circle cx="18" cy="18" r="2.5" fill="#FF6B35" opacity="0.8"/></svg>';
                  noteBtn.title='Open note';
                  noteBtn.onclick=(e)=>{
                    e.stopPropagation();
                    openCalendarEventNoteFromCalendar(t.node,t.startTime||t.node.calendarDate||null);
                  };
                  // Use calendarDisplayName if available, otherwise use node name
                  const displayName=t.node.calendarDisplayName||t.node.name;
                  // Create URL or location preview (partially visible when collapsed)
                  let previewHTML='';
                  if(t.node.link){
                    previewHTML=`<div class="cal-event-link-preview" onclick="event.stopPropagation();window.open('${esc(t.node.link)}','_blank')" title="${esc(t.node.link)}">🔗 ${esc(t.node.link.length>40?t.node.link.substring(0,40)+'...':t.node.link)}</div>`;
                  }else if(t.node.location){
                    const locationUrl=`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(t.node.location)}`;
                    previewHTML=`<div class="cal-event-location-preview" onclick="event.stopPropagation();window.open('${locationUrl}','_blank')" title="${esc(t.node.location)}">📍 ${esc(t.node.location.length>40?t.node.location.substring(0,40)+'...':t.node.location)}</div>`;
                  }
                  // Full content (shown when expanded)
                  const linkHTML=t.node.link?`<div class="cal-event-link" style="margin-top:4px;font-size:11px"><a href="${esc(t.node.link)}" target="_blank" rel="noopener noreferrer" style="color:var(--acc);text-decoration:underline;word-break:break-all" onclick="event.stopPropagation()">${esc(t.node.link)}</a></div>`:'';
                  const locationHTML=t.node.location?`<div class="cal-event-location" style="margin-top:4px;font-size:11px"><a href="https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(t.node.location)}" target="_blank" rel="noopener noreferrer" style="color:var(--acc);text-decoration:underline;word-break:break-all" onclick="event.stopPropagation()">📍 ${esc(t.node.location)}</a></div>`:'';
                  const eventDateKey=t.startTime?t.startTime.toISOString().split('T')[0]:null;
                  const eventDescription=getDescriptionContentForNode(t.node,eventDateKey);
                  event.innerHTML=`<div class="cal-event-time">${timeLabel}</div><div class="cal-event-name">${esc(displayName)}</div>${previewHTML}${eventDescription?`<div class="cal-event-desc" style="font-size:12px;color:var(--t2);margin-top:4px">${esc(eventDescription)}</div>`:''}${linkHTML}${locationHTML}`;
                  event.appendChild(deleteBtn);
                  event.appendChild(editBtn);
                  event.appendChild(noteBtn);
                  
                  // Add hover handlers - icons appear on hover, hide when cursor moves away
                  let hoverTimeout;
                  let isMouseOverEvent=false;
                  
                  const showIcons=()=>{
                    clearTimeout(hoverTimeout);
                    isMouseOverEvent=true;
                    event.classList.add('show-icons');
                  };
                  
                  const hideIcons=()=>{
                    clearTimeout(hoverTimeout);
                    isMouseOverEvent=false;
                    // Small delay to allow movement to icons
                    hoverTimeout=setTimeout(()=>{
                      // Double-check that mouse is truly outside
                      if(!isMouseOverEvent){
                        event.classList.remove('show-icons');
                      }
                    },100);
                  };
                  
                  // Handle hover on event itself
                  event.addEventListener('mouseenter',(e)=>{
                    showIcons();
                  });
                  event.addEventListener('mouseleave',(e)=>{
                    // Check if we're moving to a child element (like buttons)
                    const relatedTarget=e.relatedTarget;
                    if(relatedTarget&&(event.contains(relatedTarget)||[deleteBtn,editBtn,noteBtn].includes(relatedTarget))){
                      // Moving to a child, keep icons visible
                      return;
                    }
                    hideIcons();
                  });
                  
                  // Handle hover on icons to keep them visible
                  [deleteBtn,editBtn,noteBtn].forEach(btn=>{
                    btn.addEventListener('mouseenter',(e)=>{
                      showIcons();
                    });
                    btn.addEventListener('mouseleave',(e)=>{
                      // Check if we're moving back to the event
                      const relatedTarget=e.relatedTarget;
                      if(relatedTarget&&event.contains(relatedTarget)){
                        // Moving back to event, keep icons visible
                        return;
                      }
                      hideIcons();
                    });
                  });
                  
                  // Add resize handle at the bottom of the event
                  const resizeHandle=document.createElement('div');
                  resizeHandle.className='cal-event-resize';
                  resizeHandle.style.position='absolute';
                  resizeHandle.style.bottom='0';
                  resizeHandle.style.left='0';
                  resizeHandle.style.right='0';
                  resizeHandle.style.height='6px';
                  resizeHandle.style.cursor='ns-resize';
                  resizeHandle.style.background='transparent';
                  resizeHandle.style.borderBottom='2px solid rgba(255,255,255,0.3)';
                  resizeHandle.title='Drag to resize event duration';
                  resizeHandle.onmousedown=(e)=>{
                    e.stopPropagation();
                    e.preventDefault();
                    const startY=e.clientY;
                    const startHeight=event.offsetHeight;
                    const startTime=t.startTime;
                    const dayColRect=dayCol.getBoundingClientRect();
                    
                    const onMouseMove=(moveE)=>{
                      const deltaY=moveE.clientY-startY;
                      const deltaMinutes=(deltaY/timeSlotHeight)*60;
                      const newDuration=Math.max(15*60*1000,Math.min(24*60*60*1000,t.duration+deltaMinutes*60*1000)); // Min 15min, max 24hr
                      const newHeight=(newDuration/(60*60*1000))*timeSlotHeight;
                      event.style.height=Math.max(40,newHeight)+'px';
                    };
                    
                    const onMouseUp=(upE)=>{
                      const deltaY=upE.clientY-startY;
                      const deltaMinutes=(deltaY/timeSlotHeight)*60;
                      const newDuration=Math.max(15*60*1000,Math.min(24*60*60*1000,t.duration+deltaMinutes*60*1000));
                      if(newDuration!==t.duration){
                        svWithUndo();
                        const node=G.nodes.find(n=>n.id===t.node.id);
                        if(node){
                          node.calendarDuration=newDuration;
                          if(node.timer){
                            node.timer.duration=newDuration;
                            node.timer.endTime=new Date(new Date(node.calendarDate).getTime()+newDuration).toISOString();
                          }
                        }
                        sv();
                        renderCalendar();
                      }
                      document.removeEventListener('mousemove',onMouseMove);
                      document.removeEventListener('mouseup',onMouseUp);
                    };
                    
                    document.addEventListener('mousemove',onMouseMove);
                    document.addEventListener('mouseup',onMouseUp);
                  };
                  if(!t.multiDay)event.appendChild(resizeHandle);

                  dayCol.appendChild(event);
                }
              });
            });
          }
        }
        
        slot.appendChild(dayCol);
      }
      
      grid.appendChild(slot);
    }
  }
  
  // After all events are added, process overlaps for each day
  dayEventsMap.forEach((dayEvents,dateKey)=>{
    if(dayEvents.length===0)return;
    
    // First, reset all events to default (full width)
    dayEvents.forEach(evt=>{
      evt.event.classList.remove('overlapping');
      evt.event.style.left='2px';
      evt.event.style.right='2px';
      evt.event.style.width='auto';
      evt.event.style.zIndex='10'; // Default z-index
    });
    
    // Sort events by duration (longest first) - longer events go to background (lower z-index)
    const sortedByDuration=[...dayEvents].sort((a,b)=>{
      const durationA=a.bottom-a.top;
      const durationB=b.bottom-b.top;
      return durationB-durationA; // Longer first
    });
    
    // Assign z-index based on duration (longer = lower z-index = background layer)
    sortedByDuration.forEach((evt,idx)=>{
      // Longer events get lower z-index (background), shorter events get higher z-index (foreground)
      evt.event.style.zIndex=(10+idx).toString();
    });
    
    // Group events by overlap or by start time proximity (within 30 minutes)
    // Events that overlap OR start within 30 minutes of each other should be grouped
    const overlapGroups=[];
    const processed=new Set();
    const thirtyMinutesInPixels=timeSlotHeight/2; // 30 minutes = half an hour
    
    dayEvents.forEach((evt,idx)=>{
      if(processed.has(idx))return;
      
      // Check if this event overlaps with any other event OR starts within 30 minutes
      const overlappingEvents=[evt];
      processed.add(idx);
      
      // Find all events that overlap with this one OR start within 30 minutes
      dayEvents.forEach((otherEvt,otherIdx)=>{
        if(processed.has(otherIdx))return;
        
        // Check if events overlap (they overlap if one doesn't completely end before the other starts)
        const overlaps=!(evt.bottom<=otherEvt.top||evt.top>=otherEvt.bottom);
        
        // Check if events start within 30 minutes of each other
        const startTimeDiff=Math.abs(evt.top-otherEvt.top);
        const startsWithin30Mins=startTimeDiff<=thirtyMinutesInPixels;
        
        if(overlaps||startsWithin30Mins){
          overlappingEvents.push(otherEvt);
          processed.add(otherIdx);
        }
      });
      
      // Only create a group if there are multiple events
      if(overlappingEvents.length>1){
        overlapGroups.push(overlappingEvents);
      }
    });
    
    // Arrange overlapping groups side-by-side
    // Longer events stay at full width in the background (lower z-index)
    // Shorter events that overlap with each other are positioned side-by-side
    // Shorter events that only overlap with the long event (but not each other) stay full width
    overlapGroups.forEach(group=>{
      // Sort by duration - shorter events on top (higher z-index), longer events in background
      const sortedGroup=[...group].sort((a,b)=>{
        const durationA=a.bottom-a.top;
        const durationB=b.bottom-b.top;
        return durationA-durationB; // Shorter first
      });
      
      // Find the longest event in the group
      const longestEvent=sortedGroup[sortedGroup.length-1];
      const longestDuration=longestEvent.bottom-longestEvent.top;
      const otherEvents=sortedGroup.slice(0,-1); // All except the longest
      
      // Check if events in this group start within 30 minutes of each other
      // If so, position them all side-by-side (regardless of duration)
      const eventsStartingWithin30Mins=new Set();
      const allGroupEvents=[...group];
      
      // Find all events that start within 30 minutes of any other event in the group
      allGroupEvents.forEach((evt,idx)=>{
        allGroupEvents.forEach((otherEvt,otherIdx)=>{
          if(idx!==otherIdx){
            const startTimeDiff=Math.abs(evt.top-otherEvt.top);
            if(startTimeDiff<=thirtyMinutesInPixels){
              eventsStartingWithin30Mins.add(evt);
              eventsStartingWithin30Mins.add(otherEvt);
            }
          }
        });
      });
      
      // If we found events starting within 30 minutes, position them all side-by-side
      if(eventsStartingWithin30Mins.size>1){
        const eventsToPosition=Array.from(eventsStartingWithin30Mins);
        const groupWidth=100/eventsToPosition.length;
        eventsToPosition.forEach((evt,idx)=>{
          evt.event.classList.add('overlapping');
          evt.event.style.left=(idx*groupWidth)+'%';
          evt.event.style.width=groupWidth+'%';
          evt.event.style.right='auto';
          evt.event.style.boxSizing='border-box';
        });
      }else if(otherEvents.length>0&&longestDuration>otherEvents[0].bottom-otherEvents[0].top){
        // No events start within 30 minutes, but there's a longest event
        // Longest event stays at full width in background (already set with lower z-index)
        // Find events that overlap with EACH OTHER (not just with the longest event)
        const eventsOverlappingEachOther=[];
        const processedShort=new Set();
        
        otherEvents.forEach((evt,idx)=>{
          if(processedShort.has(idx))return;
          
          const overlappingWithThis=[evt];
          processedShort.add(idx);
          
          otherEvents.forEach((otherEvt,otherIdx)=>{
            if(processedShort.has(otherIdx))return;
            const overlaps=!(evt.bottom<=otherEvt.top||evt.top>=otherEvt.bottom);
            if(overlaps){
              overlappingWithThis.push(otherEvt);
              processedShort.add(otherIdx);
            }
          });
          
          if(overlappingWithThis.length>1){
            eventsOverlappingEachOther.push(overlappingWithThis);
          }
        });
        
        // Position overlapping events side-by-side
        eventsOverlappingEachOther.forEach(overlapSubgroup=>{
          const groupWidth=100/overlapSubgroup.length;
          overlapSubgroup.forEach((evt,idx)=>{
            evt.event.classList.add('overlapping');
            evt.event.style.left=(idx*groupWidth)+'%';
            evt.event.style.width=groupWidth+'%';
            evt.event.style.right='auto';
            evt.event.style.boxSizing='border-box';
          });
        });
      }else{
        // All events are same duration - arrange all side-by-side
        const groupWidth=100/group.length;
        group.forEach((evt,idx)=>{
          evt.event.classList.add('overlapping');
          evt.event.style.left=(idx*groupWidth)+'%';
          evt.event.style.width=groupWidth+'%';
          evt.event.style.right='auto';
          evt.event.style.boxSizing='border-box';
        });
      }
    });
  });
  
  // Mark all day columns for days that have priority future events
  // Find all priority future events and mark their day columns
  const priorityFutureDates=new Set();
  // Check all rendered events
  grid.querySelectorAll('.cal-event.priority-future,.cal-all-day-event.priority-future').forEach(event=>{
    const nodeId=event.dataset.nodeId;
    if(nodeId){
      const node=G.nodes.find(n=>n.id===nodeId);
      if(node&&node.calendarDate){
        const eventDate=new Date(node.calendarDate);
        eventDate.setHours(0,0,0,0);
        const dateKey=eventDate.toISOString().split('T')[0]; // YYYY-MM-DD
        priorityFutureDates.add(dateKey);
      }
    }
  });
  // Mark all day columns for these dates (match by date part of ISO string)
  priorityFutureDates.forEach(dateKey=>{
    grid.querySelectorAll('.cal-day-column[data-date]').forEach(dayCol=>{
      const dayColDate=dayCol.dataset.date;
      if(dayColDate&&dayColDate.startsWith(dateKey)){
        dayCol.classList.add('has-priority-future');
      }
    });
  });
  
  // Header row is now created above and inserted into grid
  
  // Add current time indicator (dotted line) - only in first cycle
  // Get current time in the selected timezone
  const now=new Date();
  let currentHour,currentMinute;
  if(calendarTimezone){
    // Convert to selected timezone using Intl.DateTimeFormat
    const tzFormatter=new Intl.DateTimeFormat('en-US',{
      timeZone:calendarTimezone,
      hour:'numeric',
      minute:'2-digit',
      hour12:false
    });
    const parts=tzFormatter.formatToParts(now);
    currentHour=parseInt(parts.find(p=>p.type==='hour').value);
    currentMinute=parseInt(parts.find(p=>p.type==='minute').value);
  }else{
    // Fallback to local time
    currentHour=now.getHours();
    currentMinute=now.getMinutes();
  }
  // Add current time indicator (dotted line) - shows current time passing
  // Calculate position: header + all-day row + hours * slot height + minutes
  // Show in first cycle (cycle 0) - currentHour is already 0-23
  const currentTimeY=headerHeight+allDayRowHeight+(currentHour*timeSlotHeight)+(currentMinute/60)*timeSlotHeight;
  const currentTimeLine=document.createElement('div');
  currentTimeLine.className='cal-current-time-line';
  currentTimeLine.style.top=currentTimeY+'px';
  currentTimeLine.style.left='0px';
  currentTimeLine.style.width=totalWidth+'px';
  grid.appendChild(currentTimeLine);
  
  // Ensure grid height is set correctly (force reflow)
  grid.offsetHeight; // Trigger reflow
  
  // Restore scroll, center on anchor date, or keep position when coming from notes
  if(scrollContainer){
    if(calendarPreserveFromNotesOpen){
      calendarPreserveFromNotesOpen=false;
      const maxScrollLeft=Math.max(0,grid.offsetWidth-scrollContainer.clientWidth);
      const maxScrollTop=Math.max(0,grid.offsetHeight-scrollContainer.clientHeight);
      scrollContainer.scrollLeft=Math.min(calendarScrollLeft??0,maxScrollLeft);
      scrollContainer.scrollTop=Math.min(calendarScrollTop??0,maxScrollTop);
      setTimeout(()=>{ if(typeof updateHeader==='function')updateHeader(); },50);
    }else if(calendarCenterOnAnchorNextRender){
      calendarCenterOnAnchorNextRender=false;
      const useSmooth=calendarSmoothRecenter;
      calendarSmoothRecenter=false;
      const anchorForScroll=new Date(calendarDate);
      anchorForScroll.setHours(0,0,0,0);
      const firstDayCenter=new Date(firstWeekStart);
      firstDayCenter.setHours(0,0,0,0);
      let dayIdx=Math.floor((anchorForScroll.getTime()-firstDayCenter.getTime())/86400000);
      if(dayIdx<0||dayIdx>=totalDays)dayIdx=Math.max(0,Math.min(totalDays-1,Math.floor(totalDays/2)));
      const anchorScrollLeft=timeColumnWidth+dayIdx*dayWidth+dayWidth/2;
      const targetLeft=Math.max(0,anchorScrollLeft-scrollContainer.clientWidth/2);
      const targetTop=Math.max(0,currentTimeY-scrollContainer.clientHeight/2);
      if(useSmooth&&scrollContainer.scrollTo){
        scrollContainer.scrollTo({left:targetLeft,top:targetTop,behavior:'smooth'});
      }else{
        scrollContainer.scrollLeft=targetLeft;
        scrollContainer.scrollTop=targetTop;
      }
      const syncScrollVars=()=>{
        calendarScrollLeft=scrollContainer.scrollLeft;
        calendarScrollTop=scrollContainer.scrollTop;
      };
      if(useSmooth){
        setTimeout(syncScrollVars,450);
      }else{
        syncScrollVars();
      }
      setTimeout(()=>{ if(typeof updateHeader==='function')updateHeader(); },useSmooth?120:50);
    }else{
      const maxScrollLeft=Math.max(0,grid.offsetWidth-scrollContainer.clientWidth);
      const maxScrollTop=Math.max(0,grid.offsetHeight-scrollContainer.clientHeight);
      scrollContainer.scrollLeft=Math.min(calendarScrollLeft??0,maxScrollLeft);
      scrollContainer.scrollTop=Math.min(calendarScrollTop??0,maxScrollTop);
      setTimeout(()=>{ if(typeof updateHeader==='function')updateHeader(); },50);
    }
  }
  
  // Time column is now part of the grid, no separate sync needed
  
  // Auto-add today's calendar events to todo list
  autoAddTodayCalendarEventsToTodoList();
  
  // Re-apply search highlights if there's an active search
  if(calendarSearchTerm){
    setTimeout(()=>{
      handleCalendarSearch._isRerender=true;
      handleCalendarSearch(calendarSearchTerm);
    },100);
  }
  
  // Re-setup selection modes if active
  if(calendarExportMode==='range'){
    setTimeout(()=>{
      setupRangeSelection();
      highlightEventsInRanges();
    },100);
  }else if(calendarExportMode==='events'){
    setTimeout(()=>{
      setupEventSelection();
    },100);
  }
  
  // Re-apply FindTime highlights if active
  if(findTimeMode==='auto'&&findTimeStartDate&&findTimeEndDate){
    setTimeout(()=>highlightFindTime(),100);
  }else if(findTimeMode==='manual'&&findTimeSelectedRanges.length>0){
    setTimeout(()=>{
      findTimeSelectedRanges.forEach(range=>highlightFindTimeManualRange(range.start,range.end));
    },100);
  }
}
function calendarPrevWeek(){
  const d=new Date(calendarDate);
  d.setHours(0,0,0,0);
  d.setDate(d.getDate()-7);
  calendarDate=d;
  calendarCenterOnAnchorNextRender=true;
  calendarPreserveFromNotesOpen=false;
  renderCalendar();
}
function calendarNextWeek(){
  const d=new Date(calendarDate);
  d.setHours(0,0,0,0);
  d.setDate(d.getDate()+7);
  calendarDate=d;
  calendarCenterOnAnchorNextRender=true;
  calendarPreserveFromNotesOpen=false;
  renderCalendar();
}

function renderTBDMicroTabs(){
  const container=document.getElementById('calendar-tbd-tabs-container');
  const header=document.getElementById('calendar-week-title');
  if(!container||!header)return;
  
  // Stop existing animation
  stopTBDTabFloating();
  
  // Clear existing tabs
  container.innerHTML='';
  
  // Get all tasks with TBD set (not 'none')
  let tbdTasks=G.nodes.filter(n=>n.TBD&&n.TBD!=='none');
  
  // Apply "show by" filter if set
  if(showByFilter){
    const {filteredTaskIds}=getFilteredTaskIds();
    
    // Filter TBD tasks to only include those in our filtered set
    tbdTasks=tbdTasks.filter(n=>filteredTaskIds.has(n.id));
  }
  
  if(tbdTasks.length===0)return;
  
  // Get header position and dimensions
  const headerRect=header.getBoundingClientRect();
  const containerRect=container.getBoundingClientRect();
  
  // Calculate available space around the title
  const headerCenterX=headerRect.left-containerRect.left+headerRect.width/2;
  const headerCenterY=headerRect.top-containerRect.top+headerRect.height/2;
  const containerWidth=containerRect.width;
  const containerHeight=containerRect.height;
  
  // Position tabs randomly in empty spaces around the title
  const tabWidth=80;
  const tabHeight=24;
  const spacing=10;
  
  // Store positions to avoid overlap
  const usedPositions=[];
  
  tbdTasks.forEach((task,index)=>{
    // Calculate random position within container bounds, avoiding title area
    let x,y,attempts=0;
    const titlePadding=headerRect.width/2+spacing;
    
    do{
      // Random position in available space
      x=Math.random()*(containerWidth-tabWidth-2*spacing)+spacing;
      y=Math.random()*(containerHeight-tabHeight-2*spacing)+spacing;
      
      // Avoid title area (center region)
      const distFromCenter=Math.sqrt(Math.pow(x-headerCenterX,2)+Math.pow(y-headerCenterY,2));
      if(distFromCenter<titlePadding){
        x=headerCenterX+Math.sign(Math.random()-0.5)*titlePadding+Math.random()*50;
        y=headerCenterY+Math.sign(Math.random()-0.5)*titlePadding+Math.random()*50;
      }
      
      // Check for overlap with existing tabs
      const overlaps=usedPositions.some(pos=>{
        const dx=Math.abs(x-pos.x);
        const dy=Math.abs(y-pos.y);
        return dx<tabWidth+spacing&&dy<tabHeight+spacing;
      });
      
      if(!overlaps||attempts>50)break;
      attempts++;
    }while(attempts<100);
    
    // Ensure tabs stay within container bounds
    x=Math.max(spacing,Math.min(x,containerWidth-tabWidth-spacing));
    y=Math.max(spacing,Math.min(y,containerHeight-tabHeight-spacing));
    
    usedPositions.push({x,y});
    
    // Create tab element with physics properties
    const tab=document.createElement('div');
    tab.className='tbd-micro-tab';
    tab.draggable=true;
    tab.dataset.nodeId=task.id;
    
    // Initialize physics properties
    const physics={
      x:x,
      y:y,
      vx:(Math.random()-0.5)*0.5, // Random initial velocity
      vy:(Math.random()-0.5)*0.5,
      isDragging:false,
      isExpanded:false
    };
    tab._physics=physics;
    
    // Calculate width based on content (with min/max constraints) - slightly smaller
    const displayName=task.calendarDisplayName||task.name;
    const nameLength=displayName.length;
    const tabMinWidth=50;
    const tabMaxWidth=100;
    const estimatedWidth=Math.max(tabMinWidth,Math.min(tabMaxWidth,nameLength*5+15)); // Rough estimate
    
    // Scale factor for proportional sizing (slightly smaller - about 50% of original)
    const scale=0.5;
    const scaledPadding=Math.round(3*scale);
    const scaledFontSize=9; // Slightly smaller font to match smaller box
    const scaledBorderWidth=Math.round(2*scale);
    const scaledBorderRadius=Math.round(3*scale);
    
    tab.style.cssText=`
      position:absolute;
      left:${x}px;
      top:${y}px;
      width:${estimatedWidth}px;
      min-height:${tabHeight}px;
      background:var(--bg3);
      border-left:${scaledBorderWidth}px solid ${task.color};
      padding:${scaledPadding}px ${Math.round(6*scale)}px;
      border-radius:${scaledBorderRadius}px;
      font-size:${scaledFontSize}px;
      cursor:move;
      pointer-events:all;
      white-space:nowrap;
      overflow:hidden;
      text-overflow:ellipsis;
      z-index:20;
      box-shadow:0 2px 6px rgba(0,0,0,0.2);
      user-select:none;
      transition:none;
      box-sizing:border-box;
    `;
    
    // Use the same structure as calendar events but without time (just name)
    tab.innerHTML=`<div class="cal-event-name" style="font-weight:500;color:var(--t0);font-size:${scaledFontSize}px;line-height:1.3;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(displayName)}</div>`;
    tab.title=task.name+' - Drag to calendar to schedule';
    
    // Create delete button (top-right) - appears on hover
    const deleteBtn=document.createElement('div');
    deleteBtn.className='cal-event-delete';
    deleteBtn.innerHTML='🗑️';
    deleteBtn.title='Remove TBD';
    deleteBtn.style.width='12px';
    deleteBtn.style.height='12px';
    deleteBtn.style.fontSize='8px';
    deleteBtn.onclick=(e)=>{
      e.stopPropagation();
      e.preventDefault();
      const node=G.nodes.find(n=>n.id===task.id);
      if(!node)return;
      
      svWithUndo();
      // Remove TBD property (set to 'none')
      node.TBD='none';
      // Optionally remove calendarDate if it was only set for TBD
      // Keep calendarDate if it was set independently
      sv();
      renderCalendar();
      setTimeout(()=>renderTBDMicroTabs(),100);
    };
    
    // Create edit button (bottom-right) - appears on hover
    const editBtn=document.createElement('div');
    editBtn.className='cal-event-edit-btn';
    editBtn.innerHTML='✏️';
    editBtn.title='Edit event';
    editBtn.style.width='12px';
    editBtn.style.height='12px';
    editBtn.style.fontSize='8px';
    editBtn.onclick=(e)=>{
      e.stopPropagation();
      e.preventDefault();
      if(task.calendarDate){
        openEditCalendarEvent(task.id);
      }else{
        openEdit(task.id);
      }
    };
    // Create note button (bottom-left) - appears on hover
    const noteBtn=document.createElement('div');
    noteBtn.className='cal-event-note-btn';
    noteBtn.innerHTML='<svg width="10" height="10" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="3" y="2" width="18" height="20" rx="2" fill="#6C63FF" opacity="0.3" stroke="#6C63FF" stroke-width="1.5"/><rect x="3" y="2" width="18" height="5" rx="2" fill="#8b84ff" opacity="0.6"/><line x1="6" y1="5" x2="18" y2="5" stroke="#FFD700" stroke-width="1.5" stroke-linecap="round"/><line x1="6" y1="9" x2="15" y2="9" stroke="#87CEEB" stroke-width="1.2" stroke-linecap="round"/><circle cx="18" cy="18" r="2.5" fill="#FF6B35" opacity="0.8"/></svg>';
    noteBtn.title='Open note';
    noteBtn.style.width='12px';
    noteBtn.style.height='12px';
    noteBtn.style.fontSize='8px';
    noteBtn.onclick=(e)=>{
      e.stopPropagation();
      e.preventDefault();
      openCalendarEventNoteFromCalendar(task,task.calendarDate||null);
    };
    
    tab.appendChild(deleteBtn);
    tab.appendChild(editBtn);
    tab.appendChild(noteBtn);
    
    // Drag handlers - make tabs draggable to calendar
    tab.ondragstart=function(e){
      physics.isDragging=true;
      e.dataTransfer.setData('text/plain',task.id);
      e.dataTransfer.effectAllowed='move';
      tab.style.opacity='0.5';
    };
    tab.ondragend=function(e){
      physics.isDragging=false;
      tab.style.opacity='1';
      // If drop was not accepted, restore position
      if(e.dataTransfer.dropEffect==='none'){
        // Position will be restored by physics loop
      }
    };
    
    tab.onmouseenter=function(){
      if(!physics.isDragging&&!physics.isExpanded){
        this.style.transform='translateX(2px)';
        this.style.boxShadow='0 2px 6px rgba(0,0,0,.2)';
        this.style.zIndex='20';
      }
    };
    tab.onmouseleave=function(){
      if(!physics.isDragging&&!physics.isExpanded){
        this.style.transform='translateX(0)';
        this.style.boxShadow='0 2px 6px rgba(0,0,0,0.2)';
        this.style.zIndex='20';
      }
    };
    
    // Click handler - toggle expand/collapse
    tab.onclick=function(e){
      if(e.defaultPrevented)return;
      // Don't toggle if clicking on buttons or links
      if(e.target.classList.contains('cal-event-delete')||e.target.classList.contains('cal-event-edit-btn')||e.target.classList.contains('cal-event-note-btn')||e.target.closest('.cal-event-note-btn')||e.target.closest('a')){
        return;
      }
      e.stopPropagation();
      
      // Toggle expanded state
      physics.isExpanded=!physics.isExpanded;
      
      if(physics.isExpanded){
        // Expanding - stop floating and show full content
        tab.classList.add('expanded');
        tab.style.whiteSpace='normal';
        tab.style.overflowY='auto';
        tab.style.maxHeight='calc(100vh - 200px)';
        tab.style.zIndex='1000';
        tab.style.cursor='default';
        
        // Build full content HTML
        const linkHTML=task.link?`<div class="cal-event-link" style="margin-top:4px;font-size:11px"><a href="${esc(task.link)}" target="_blank" rel="noopener noreferrer" style="color:var(--acc);text-decoration:underline;word-break:break-all" onclick="event.stopPropagation()">${esc(task.link)}</a></div>`:'';
        const locationHTML=task.location?`<div class="cal-event-location" style="margin-top:4px;font-size:11px"><a href="https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(task.location)}" target="_blank" rel="noopener noreferrer" style="color:var(--acc);text-decoration:underline;word-break:break-all" onclick="event.stopPropagation()">📍 ${esc(task.location)}</a></div>`:'';
        const taskDateKey=task.calendarDate?new Date(task.calendarDate).toISOString().split('T')[0]:null;
        const taskDescription=getDescriptionContentForNode(task,taskDateKey);
        const descHTML=taskDescription?`<div class="cal-event-desc" style="font-size:12px;color:var(--t2);margin-top:4px">${esc(taskDescription)}</div>`:'';
        // Build time HTML if calendarDate exists
        let timeHTML='';
        if(task.calendarDate){
          const startDate=new Date(task.calendarDate);
          const timeStr=startDate.toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'});
          if(task.calendarDuration&&task.calendarDuration>0){
            const endDate=new Date(startDate.getTime()+task.calendarDuration);
            const endTimeStr=endDate.toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'});
            timeHTML=`<div class="cal-event-time" style="font-size:12px;color:var(--t3);margin-bottom:2px">${timeStr} - ${endTimeStr}</div>`;
          }else{
            timeHTML=`<div class="cal-event-time" style="font-size:12px;color:var(--t3);margin-bottom:2px">${timeStr}</div>`;
          }
        }
        tab.innerHTML=`${timeHTML}<div class="cal-event-name" style="font-weight:500;color:var(--t0);font-size:${scaledFontSize}px;line-height:1.3;margin-bottom:4px">${esc(displayName)}</div>${descHTML}${linkHTML}${locationHTML}`;
        
        // Re-add buttons when expanded
        const deleteBtnExpanded=document.createElement('div');
        deleteBtnExpanded.className='cal-event-delete';
        deleteBtnExpanded.innerHTML='🗑️';
        deleteBtnExpanded.title='Remove TBD';
        deleteBtnExpanded.style.width='12px';
        deleteBtnExpanded.style.height='12px';
        deleteBtnExpanded.style.fontSize='8px';
        deleteBtnExpanded.onclick=(e)=>{
          e.stopPropagation();
          e.preventDefault();
          const node=G.nodes.find(n=>n.id===task.id);
          if(!node)return;
          
          svWithUndo();
          node.TBD='none';
          sv();
          renderCalendar();
          setTimeout(()=>renderTBDMicroTabs(),100);
        };
        
        const editBtnExpanded=document.createElement('div');
        editBtnExpanded.className='cal-event-edit-btn';
        editBtnExpanded.innerHTML='✏️';
        editBtnExpanded.title='Edit event';
        editBtnExpanded.style.width='12px';
        editBtnExpanded.style.height='12px';
        editBtnExpanded.style.fontSize='8px';
        editBtnExpanded.onclick=(e)=>{
          e.stopPropagation();
          e.preventDefault();
          if(task.calendarDate){
            openEditCalendarEvent(task.id);
          }else{
            openEdit(task.id);
          }
        };
        const noteBtnExpanded=document.createElement('div');
        noteBtnExpanded.className='cal-event-note-btn';
        noteBtnExpanded.innerHTML='<svg width="10" height="10" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="3" y="2" width="18" height="20" rx="2" fill="#6C63FF" opacity="0.3" stroke="#6C63FF" stroke-width="1.5"/><rect x="3" y="2" width="18" height="5" rx="2" fill="#8b84ff" opacity="0.6"/><line x1="6" y1="5" x2="18" y2="5" stroke="#FFD700" stroke-width="1.5" stroke-linecap="round"/><line x1="6" y1="9" x2="15" y2="9" stroke="#87CEEB" stroke-width="1.2" stroke-linecap="round"/><circle cx="18" cy="18" r="2.5" fill="#FF6B35" opacity="0.8"/></svg>';
        noteBtnExpanded.title='Open note';
        noteBtnExpanded.style.width='12px';
        noteBtnExpanded.style.height='12px';
        noteBtnExpanded.style.fontSize='8px';
        noteBtnExpanded.onclick=(e)=>{
          e.stopPropagation();
          e.preventDefault();
          openCalendarEventNoteFromCalendar(task,task.calendarDate||null);
        };
        
        tab.appendChild(deleteBtnExpanded);
        tab.appendChild(editBtnExpanded);
        tab.appendChild(noteBtnExpanded);
        
        // Keep width the same - only expand vertically
        tab.style.width=estimatedWidth+'px';
      }else{
        // Collapsing - resume floating and show compact view
        tab.classList.remove('expanded');
        tab.style.whiteSpace='nowrap';
        tab.style.overflow='hidden';
        tab.style.maxHeight='none';
        tab.style.zIndex='20';
        tab.style.cursor='move';
        tab.style.width=estimatedWidth+'px';
        
        // Restore compact content
        tab.innerHTML=`<div class="cal-event-name" style="font-weight:500;color:var(--t0);font-size:${scaledFontSize}px;line-height:1.3;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(displayName)}</div>`;
        
        // Re-add buttons when collapsed
        const deleteBtnCollapsed=document.createElement('div');
        deleteBtnCollapsed.className='cal-event-delete';
        deleteBtnCollapsed.innerHTML='🗑️';
        deleteBtnCollapsed.title='Remove TBD';
        deleteBtnCollapsed.style.width='12px';
        deleteBtnCollapsed.style.height='12px';
        deleteBtnCollapsed.style.fontSize='8px';
        deleteBtnCollapsed.onclick=(e)=>{
          e.stopPropagation();
          e.preventDefault();
          const node=G.nodes.find(n=>n.id===task.id);
          if(!node)return;
          
          svWithUndo();
          node.TBD='none';
          sv();
          renderCalendar();
          setTimeout(()=>renderTBDMicroTabs(),100);
        };
        
        const editBtnCollapsed=document.createElement('div');
        editBtnCollapsed.className='cal-event-edit-btn';
        editBtnCollapsed.innerHTML='✏️';
        editBtnCollapsed.title='Edit event';
        editBtnCollapsed.style.width='12px';
        editBtnCollapsed.style.height='12px';
        editBtnCollapsed.style.fontSize='8px';
        editBtnCollapsed.onclick=(e)=>{
          e.stopPropagation();
          e.preventDefault();
          if(task.calendarDate){
            openEditCalendarEvent(task.id);
          }else{
            openEdit(task.id);
          }
        };
        const noteBtnCollapsed=document.createElement('div');
        noteBtnCollapsed.className='cal-event-note-btn';
        noteBtnCollapsed.innerHTML='<svg width="10" height="10" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="3" y="2" width="18" height="20" rx="2" fill="#6C63FF" opacity="0.3" stroke="#6C63FF" stroke-width="1.5"/><rect x="3" y="2" width="18" height="5" rx="2" fill="#8b84ff" opacity="0.6"/><line x1="6" y1="5" x2="18" y2="5" stroke="#FFD700" stroke-width="1.5" stroke-linecap="round"/><line x1="6" y1="9" x2="15" y2="9" stroke="#87CEEB" stroke-width="1.2" stroke-linecap="round"/><circle cx="18" cy="18" r="2.5" fill="#FF6B35" opacity="0.8"/></svg>';
        noteBtnCollapsed.title='Open note';
        noteBtnCollapsed.style.width='12px';
        noteBtnCollapsed.style.height='12px';
        noteBtnCollapsed.style.fontSize='8px';
        noteBtnCollapsed.onclick=(e)=>{
          e.stopPropagation();
          e.preventDefault();
          openCalendarEventNoteFromCalendar(task,task.calendarDate||null);
        };
        
        tab.appendChild(deleteBtnCollapsed);
        tab.appendChild(editBtnCollapsed);
        tab.appendChild(noteBtnCollapsed);
      }
    };
    
    container.appendChild(tab);
  });
  
  // Start floating animation loop
  startTBDTabFloating();
}

// Floating animation for TBD tabs
let tbdAnimationFrame=null;
function startTBDTabFloating(){
  if(tbdAnimationFrame)return; // Already running
  
  const container=document.getElementById('calendar-tbd-tabs-container');
  if(!container)return;
  
  const tabs=container.querySelectorAll('.tbd-micro-tab');
  if(tabs.length===0)return;
  
  const spacing=10;
  const bounceDamping=0.8; // Energy loss on bounce
  const maxSpeed=1.5; // Maximum velocity
  const minSpeed=0.3; // Minimum velocity to keep moving
  
  function animate(){
    // Recalculate container dimensions in case of resize
    const containerRect=container.getBoundingClientRect();
    const containerWidth=containerRect.width;
    const containerHeight=containerRect.height;
    
    tabs.forEach(tab=>{
      const physics=tab._physics;
      if(!physics||physics.isDragging||physics.isExpanded)return; // Skip if dragging or expanded
      
      // Get actual tab width from DOM
      const tabWidth=tab.offsetWidth||80;
      const tabHeight=tab.offsetHeight||24;
      
      // Update position
      physics.x+=physics.vx;
      physics.y+=physics.vy;
      
      // Boundary collision and bouncing
      if(physics.x<=spacing){
        physics.x=spacing;
        physics.vx=Math.abs(physics.vx)*bounceDamping; // Bounce right
        // Add slight random variation
        physics.vy+=(Math.random()-0.5)*0.2;
      }else if(physics.x>=containerWidth-tabWidth-spacing){
        physics.x=containerWidth-tabWidth-spacing;
        physics.vx=-Math.abs(physics.vx)*bounceDamping; // Bounce left
        physics.vy+=(Math.random()-0.5)*0.2;
      }
      
      if(physics.y<=spacing){
        physics.y=spacing;
        physics.vy=Math.abs(physics.vy)*bounceDamping; // Bounce down
        physics.vx+=(Math.random()-0.5)*0.2;
      }else if(physics.y>=containerHeight-tabHeight-spacing){
        physics.y=containerHeight-tabHeight-spacing;
        physics.vy=-Math.abs(physics.vy)*bounceDamping; // Bounce up
        physics.vx+=(Math.random()-0.5)*0.2;
      }
      
      // Clamp velocity to max speed
      const speed=Math.sqrt(physics.vx*physics.vx+physics.vy*physics.vy);
      if(speed>maxSpeed){
        physics.vx=(physics.vx/speed)*maxSpeed;
        physics.vy=(physics.vy/speed)*maxSpeed;
      }else if(speed<minSpeed&&speed>0){
        // Maintain minimum speed
        physics.vx=(physics.vx/speed)*minSpeed;
        physics.vy=(physics.vy/speed)*minSpeed;
      }
      
      // Add slight random drift for organic movement
      if(Math.random()<0.02){ // 2% chance per frame
        physics.vx+=(Math.random()-0.5)*0.1;
        physics.vy+=(Math.random()-0.5)*0.1;
      }
      
      // Update DOM position
      tab.style.left=physics.x+'px';
      tab.style.top=physics.y+'px';
    });
    
    tbdAnimationFrame=requestAnimationFrame(animate);
  }
  
  animate();
}

// Stop animation when tabs are removed
function stopTBDTabFloating(){
  if(tbdAnimationFrame){
    cancelAnimationFrame(tbdAnimationFrame);
    tbdAnimationFrame=null;
  }
}
