let calendarSearchResults=[]; // DOM elements of highlighted events, for Enter cycling
let calendarSearchResultIndex=0;

function centerCalendarEventInView(eventEl){
  const scrollContainer=document.getElementById('calendar-scroll-container');
  if(!scrollContainer||!eventEl)return;
  const elemRect=eventEl.getBoundingClientRect();
  const containerRect=scrollContainer.getBoundingClientRect();
  const elemCenterX=elemRect.left+elemRect.width/2;
  const elemCenterY=elemRect.top+elemRect.height/2;
  const containerCenterX=containerRect.left+containerRect.width/2;
  const containerCenterY=containerRect.top+containerRect.height/2;
  // Delta: how far element center is from container center. To center, scroll content by this amount.
  const deltaX=elemCenterX-containerCenterX;
  const deltaY=elemCenterY-containerCenterY;
  let newScrollLeft=scrollContainer.scrollLeft+deltaX;
  let newScrollTop=scrollContainer.scrollTop+deltaY;
  const maxScrollLeft=Math.max(0,scrollContainer.scrollWidth-scrollContainer.clientWidth);
  const maxScrollTop=Math.max(0,scrollContainer.scrollHeight-scrollContainer.clientHeight);
  newScrollLeft=Math.max(0,Math.min(maxScrollLeft,newScrollLeft));
  newScrollTop=Math.max(0,Math.min(maxScrollTop,newScrollTop));
  scrollContainer.scrollTo({left:newScrollLeft,top:newScrollTop,behavior:'smooth'});
}

function handleCalendarSearchKeydown(e){
  if(e.key==='Escape'){
    hideCalendarSearch();
  }else if(e.key==='Enter'){
    e.preventDefault();
    if(calendarSearchResults.length<=1)return; // Only 1 result: stay put, no movement
    calendarSearchResultIndex=(calendarSearchResultIndex+1)%calendarSearchResults.length;
    const el=calendarSearchResults[calendarSearchResultIndex];
    if(el&&el.isConnected){
      centerCalendarEventInView(el);
      const countEl=document.getElementById('calendar-search-count');
      if(countEl){
        countEl.textContent=`${calendarSearchResultIndex+1}/${calendarSearchResults.length}`;
      }
    }
  }
}

function handleCalendarSearch(query){
  const searchTerm=query.trim().toLowerCase();
  const countEl=document.getElementById('calendar-search-count');
  calendarSearchTerm=searchTerm;
  document.querySelectorAll('.cal-event.search-highlight,.cal-all-day-event.search-highlight').forEach(el=>{
    el.classList.remove('search-highlight');
  });
  calendarSearchResults=[];
  calendarSearchResultIndex=0;
  if(!searchTerm){
    calendarSearchTerm='';
    if(countEl)countEl.textContent='';
    return;
  }
  const highlightedEvents=[];
  const allEvents=document.querySelectorAll('.cal-event,.cal-all-day-event');
  const scrollContainer=document.getElementById('calendar-scroll-container');
  let viewportCenterX=0,viewportCenterY=0;
  if(scrollContainer){
    const rect=scrollContainer.getBoundingClientRect();
    viewportCenterX=rect.left+rect.width/2;
    viewportCenterY=rect.top+rect.height/2;
  }
  allEvents.forEach(eventEl=>{
    const nodeId=eventEl.dataset.nodeId;
    if(!nodeId)return;
    const node=G.nodes.find(n=>n.id===nodeId);
    if(!node)return;
    const name=(node.calendarDisplayName||node.name||'').toLowerCase();
    const desc=(node.description||'').toLowerCase();
    const notes=(node.postEventNotes||'').toLowerCase();
    const location=(node.location||'').toLowerCase();
    const link=(node.link||'').toLowerCase();
    if(name.includes(searchTerm)||desc.includes(searchTerm)||notes.includes(searchTerm)||location.includes(searchTerm)||link.includes(searchTerm)){
      eventEl.classList.add('search-highlight');
      highlightedEvents.push(eventEl);
    }
  });
  calendarSearchResults=highlightedEvents;
  if(countEl){
    if(highlightedEvents.length>0){
      countEl.textContent=highlightedEvents.length>1?`1/${highlightedEvents.length} result${highlightedEvents.length!==1?'s':''}`:`${highlightedEvents.length} result`;
      countEl.style.color='var(--acc)';
    }else{
      countEl.textContent='No results';
      countEl.style.color='var(--t3)';
    }
  }
  if(highlightedEvents.length>0&&!handleCalendarSearch._isRerender){
    let closestEvent=null;
    let minDistance=Infinity;
    highlightedEvents.forEach(eventEl=>{
      const eventRect=eventEl.getBoundingClientRect();
      const eventCenterX=eventRect.left+eventRect.width/2;
      const eventCenterY=eventRect.top+eventRect.height/2;
      const distance=Math.sqrt(Math.pow(eventCenterX-viewportCenterX,2)+Math.pow(eventCenterY-viewportCenterY,2));
      if(distance<minDistance){
        minDistance=distance;
        closestEvent=eventEl;
      }
    });
    if(closestEvent){
      calendarSearchResultIndex=highlightedEvents.indexOf(closestEvent);
      setTimeout(()=>centerCalendarEventInView(closestEvent),50);
    }
  }
  handleCalendarSearch._isRerender=false;
}

