// Strip dangerous tags pasted from Word / web pages into note HTML.
// MS Office HTML clipboard includes <style> blocks (mso-* font definitions, MsoNormal
// rules etc.), <link rel> theme refs, and o:p/w:*/v:* XML-namespace placeholders.
// When that HTML is injected back into the editor via innerHTML, the <style> rules
// apply to the whole editor and can blow up margins / layout (manifesting as a
// "split / right-side-unreachable" view). Strip them defensively at save AND load.
function sanitizeNoteHtml(html){
  if(typeof html!=='string'||!html)return html;
  // Fast-path: nothing dangerous → return as-is.
  if(!/<(?:style|script|link|meta|head|base|title|o:|w:|v:|xml)\b/i.test(html))return html;
  try{
    const doc=document.implementation.createHTMLDocument('');
    doc.body.innerHTML=html;
    // Pure removals: inert tags that should never appear inside a note body.
    doc.querySelectorAll('style,script,link,meta,head,base,title,xml').forEach(el=>el.remove());
    // Unwrap MS Office XML-namespaced tags (o:p, w:WordDocument, v:shape, etc.) —
    // keep their text content but drop the wrapper, since browsers render them as
    // empty boxes that add unpredictable layout.
    const all=Array.from(doc.body.querySelectorAll('*'));
    for(const el of all){
      const tn=el.tagName||'';
      if(tn.indexOf(':')!==-1){
        const parent=el.parentNode;
        if(!parent)continue;
        while(el.firstChild)parent.insertBefore(el.firstChild,el);
        parent.removeChild(el);
      }
    }
    return doc.body.innerHTML;
  }catch(_){
    // Fallback regex strip if DOMParser path fails for any reason.
    return html
      .replace(/<style\b[\s\S]*?<\/style>/gi,'')
      .replace(/<script\b[\s\S]*?<\/script>/gi,'')
      .replace(/<link\b[^>]*>/gi,'')
      .replace(/<meta\b[^>]*>/gi,'')
      .replace(/<\/?(?:head|html|body|base|title|xml)\b[^>]*>/gi,'')
      .replace(/<\/?[ovw]:[a-zA-Z0-9]+[^>]*>/gi,'');
  }
}
// In-place version: strips the same dangerous nodes from a live DOM element
// (used right after a native paste so the user immediately sees a clean editor).
function sanitizeNoteEditorDom(container){
  if(!container||!container.querySelectorAll)return;
  try{
    container.querySelectorAll('style,script,link,meta,head,base,title,xml').forEach(el=>el.remove());
    const all=Array.from(container.querySelectorAll('*'));
    for(const el of all){
      const tn=el.tagName||'';
      if(tn.indexOf(':')!==-1){
        const parent=el.parentNode;
        if(!parent)continue;
        while(el.firstChild)parent.insertBefore(el.firstChild,el);
        parent.removeChild(el);
      }
    }
  }catch(_){/* best-effort */}
}
// Fix UTF-8 mojibake from calendar/ICS imports (Zoom, Outlook often use wrong encoding)
function fixMojibakeStr(s){
  if(typeof s!=='string'||!s)return s;
  let r=s.replace(/\n\u0022 (\d)/g,'\n\u2022 $1').replace(/\u00C2&nbsp;/g,'&nbsp;');
  // Notes with embedded data: URLs can be multi‑MB; skip heavy mojibake passes (spread + byte loop OOM / freeze).
  if(r.length>1200000)return r;
  if(!/ÃÂ|Ã¢|Â\s|Â&|[\u0080-\u0083]/.test(s))return r;
  const repl=[[/\u00C3[\u0082\u0083]\u00C2[\u0082\u0083]/g,'\u2022 '],[/\u00C3\u0083\u00C2\u00A2\u00C3\u0082\u00C2\u0080\u00C3\u0082\u00C2\u00A2/g,'\u2022'],[/\u00C3\u0082\u00C2\u00A2\u00C3\u0082\u00C2\u0080\u00C3\u0082\u00C2\u00A2/g,'\u2022'],[/\u00E2\u0080\u00A2/g,'\u2022'],[/\u00E2\u00A2/g,'\u2022'],[/\u00C2\u00A0/g,'\u00A0'],[/\u00C2[\u0080-\u00BF]/g,'\u2022 '],[/\u00C2\u2022/g,'\u2022'],[/\u00C2[\u0020\u00A0]\u00E2\u0080\u00A2/g,'\u2022'],[/\u00C2[\u0020\u00A0]/g,'\u2022 '],[/\u00C3\u00C2/g,'\u2022 '],[/\u00C3\u00C3/g,'\u2022 '],[/\u00C3\u2022/g,'\u2022'],[/\u00C3[\u0020\u00A0]/g,'\u2022 ']];
  for(const [re,rep] of repl)r=r.replace(re,rep);
  try{
    for(let i=0;i<5;i++){
      const bytes=new Uint8Array([...r].map(c=>c.charCodeAt(0)&0xFF));
      const fixed=new TextDecoder('utf-8').decode(bytes);
      if(fixed.includes('\uFFFD')||fixed===r)break;
      r=fixed;
    }
  }catch(e){}
  for(const [re,rep] of repl)r=r.replace(re,rep);
  return r;
}
function walkAndFixMojibake(obj){
  if(obj===null||typeof obj!=='object')return obj;
  if(Array.isArray(obj)){obj.forEach((item,i)=>{if(typeof item==='string')obj[i]=fixMojibakeStr(item);else walkAndFixMojibake(item);});return obj;}
  for(const k of Object.keys(obj)){
    if(typeof obj[k]==='string')obj[k]=fixMojibakeStr(obj[k]);
    else walkAndFixMojibake(obj[k]);
  }
  return obj;
}
// Parse ICS (iCalendar) file format
function parseICSFile(text){
  const events=[];
  const lines=text.split(/\r?\n/);
  let currentEvent=null;
  let currentProp='';
  
  for(let i=0;i<lines.length;i++){
    let line=lines[i];
    
    // Handle line continuation (lines starting with space)
    if(line.startsWith(' ')||line.startsWith('\t')){
      if(currentProp){
        currentProp+=line.substring(1);
      }
      continue;
    }
    
    // Save previous property if we have one
    if(currentProp&&currentEvent){
      const colonIndex=currentProp.indexOf(':');
      if(colonIndex>0){
        const propFull=currentProp.substring(0,colonIndex).toUpperCase();
        const propValue=currentProp.substring(colonIndex+1);
        
        // Extract base property name (before semicolon)
        const propName=propFull.split(';')[0];
        
        if(propName==='SUMMARY'){
          currentEvent.summary=propValue;
        }else if(propName==='DTSTART'){
          currentEvent.startDate=parseICSDate(propValue);
        }else if(propName==='DTEND'){
          currentEvent.endDate=parseICSDate(propValue);
        }else if(propName==='LOCATION'){
          currentEvent.location=propValue.replace(/\\n/g,'\n').replace(/\\,/g,',');
        }else if(propName==='URL'){
          currentEvent.url=propValue.replace(/\\,/g,',');
        }else if(propName==='DESCRIPTION'){
          currentEvent.description=propValue.replace(/\\n/g,'\n').replace(/\\,/g,',');
        }
      }
    }

    // Check for event start/end
    if(line.startsWith('BEGIN:VEVENT')){
      currentEvent={summary:'',startDate:'',endDate:'',location:'',description:'',url:'',calendarName:''};
      currentProp='';
    }else if(line.startsWith('END:VEVENT')){
      // Process the last property before ending
      if(currentProp&&currentEvent){
        const colonIndex=currentProp.indexOf(':');
        if(colonIndex>0){
          const propFull=currentProp.substring(0,colonIndex).toUpperCase();
          const propValue=currentProp.substring(colonIndex+1);
          const propName=propFull.split(';')[0];
          
          if(propName==='SUMMARY'){
            currentEvent.summary=propValue;
          }else if(propName==='DTSTART'){
            currentEvent.startDate=parseICSDate(propValue);
          }else if(propName==='DTEND'){
            currentEvent.endDate=parseICSDate(propValue);
          }else if(propName==='LOCATION'){
            currentEvent.location=propValue.replace(/\\n/g,'\n').replace(/\\,/g,',');
          }else if(propName==='URL'){
            currentEvent.url=propValue.replace(/\\,/g,',');
          }else if(propName==='DESCRIPTION'){
            currentEvent.description=propValue.replace(/\\n/g,'\n').replace(/\\,/g,',');
          }
        }
      }

      if(currentEvent&&currentEvent.startDate){
        events.push(currentEvent);
      }
      currentEvent=null;
      currentProp='';
    }else if(line.includes(':')){
      currentProp=line;
    }else{
      currentProp='';
    }
  }
  
  return events;
}

// Parse ICS date format (YYYYMMDDTHHMMSSZ or YYYYMMDD)
function parseICSDate(dateStr){
  if(!dateStr)return '';
  
  // Remove timezone and format indicators
  dateStr=dateStr.replace(/Z$/,'').replace(/;.*$/,'');
  
  // Check if it's date-only (YYYYMMDD) or date-time (YYYYMMDDTHHMMSS)
  if(dateStr.length===8){
    // Date only: YYYYMMDD
    const year=dateStr.substring(0,4);
    const month=dateStr.substring(4,6);
    const day=dateStr.substring(6,8);
    return `${year}-${month}-${day}T00:00:00`;
  }else if(dateStr.includes('T')){
    // Date-time: YYYYMMDDTHHMMSS
    const datePart=dateStr.split('T')[0];
    const timePart=dateStr.split('T')[1]||'000000';
    const year=datePart.substring(0,4);
    const month=datePart.substring(4,6);
    const day=datePart.substring(6,8);
    const hour=timePart.substring(0,2)||'00';
    const minute=timePart.substring(2,4)||'00';
    const second=timePart.substring(4,6)||'00';
    return `${year}-${month}-${day}T${hour}:${minute}:${second}`;
  }
  
  return '';
}

// Pull a meeting/join URL out of a parsed calendar event so it lands in the node's
// `link` field (the calendar "Link" input). Prefers a known video-meeting provider,
// then any explicit URL property, then a bare URL used as the location.
function extractMeetingLink(event){
  if(!event)return '';
  const providerRe=/(https?:\/\/[^\s<>"']*(?:zoom\.us|meet\.google\.com|teams\.microsoft\.com|teams\.live\.com|webex\.com|whereby\.com|gotomeet(?:ing)?\.com|bluejeans\.com|meet\.jit\.si|chime\.aws)[^\s<>"']*)/i;
  const candidates=[event.url,event.location,event.description];
  for(const c of candidates){
    if(typeof c==='string'){
      const m=c.match(providerRe);
      if(m)return m[1].replace(/[).,;]+$/,'');
    }
  }
  // No recognized provider — fall back to an explicit URL property, then a URL-only location.
  if(typeof event.url==='string'&&/^https?:\/\//i.test(event.url.trim()))return event.url.trim();
  if(typeof event.location==='string'&&/^https?:\/\/\S+$/i.test(event.location.trim()))return event.location.trim();
  return '';
}

// Process calendar import from a file (used by both file picker and drag-and-drop)
async function processCalendarImport(file){
  if(!file)return;
  
  const btn=document.getElementById('calendar-import-btn');
  if(btn)btn.disabled=true;
  if(btn)btn.textContent='Importing...';
  
  try{
    // Read file
    const text=await file.text();
    let events=[];
    
    // Detect file type and parse accordingly
    if(file.name.endsWith('.ics')||text.includes('BEGIN:VCALENDAR')||text.includes('BEGIN:VEVENT')){
      // ICS file format
      events=parseICSFile(text);
      if(events.length===0){
        alert('No calendar events found in this ICS file.');
        if(btn){
          btn.disabled=false;
          btn.innerHTML='<span style="display:inline-block;width:8px;height:8px;background:var(--red);border-radius:50%;margin-right:6px"></span>Import';
        }
        return;
      }
    }else{
      // JSON file format
      const data=JSON.parse(text);
      if(!data.events||!Array.isArray(data.events)||data.events.length===0){
        alert('No calendar events found in this file. Make sure you exported calendar events using: node export-calendar.js');
        if(btn){
          btn.disabled=false;
          btn.innerHTML='<span style="display:inline-block;width:8px;height:8px;background:var(--red);border-radius:50%;margin-right:6px"></span>Import';
        }
        return;
      }
      events=data.events;
    }
    
    // Import events into app
    let importedCount=0;
    let skippedCount=0;
    let firstImportedDate=null;

    svWithUndo();
    
    for(const event of events){
    // Check if event already exists (by title and start date)
    const existingNode=G.nodes.find(n=>{
      if(n.calendarDate&&n.name===event.summary){
        const existingDate=new Date(n.calendarDate);
        const eventDate=new Date(event.startDate);
        // Check if same day and similar time (within 1 hour)
        return existingDate.toDateString()===eventDate.toDateString()&&
               Math.abs(existingDate.getTime()-eventDate.getTime())<60*60*1000;
      }
      return false;
    });
    
    if(existingNode){
      skippedCount++;
      continue;
    }
    
    // Create new node for calendar event
    const startDate=new Date(event.startDate);
    const endDate=new Date(event.endDate);
    const duration=endDate.getTime()-startDate.getTime();
    
    // Default to 1 hour if duration is 0 or invalid
    const eventDuration=duration>0?duration:60*60*1000;
    
    const nodeId='n'+Date.now()+'_'+Math.random().toString(36).slice(2,9);
    const safeSummary=fixMojibakeStr(event.summary||'');
    const safeDesc=fixMojibakeStr(event.description||'');
    const safeLoc=fixMojibakeStr(event.location||'');
    // Carry over a meeting/join URL (Zoom, Meet, Teams, …) into the node's link field.
    // event.link covers JSON imports; extractMeetingLink covers ICS (URL prop / description / location).
    const meetingLink=fixMojibakeStr(event.link||extractMeetingLink(event)||'');
    const importType=event.type||(getDefaultTypeFromTitle(safeSummary)==='meeting'?'meeting':'event');
    const node={
      id:nodeId,
      name:safeSummary||'Untitled Event',
      color:P[G.nodes.length%P.length],
      description:safeDesc,
      status:'active',
      parentId:null,
      wsId:G.cws||'home',
      progress:[],
      notes:safeDesc,
      calendarDate:startDate.toISOString(),
      calendarDuration:eventDuration,
      calendarDisplayName:safeSummary||'Untitled Event',
      location:safeLoc,
      link:meetingLink,
      repeat:event.repeat||'none',
      routine:event.repeat&&event.repeat!=='none',
      routineFrequency:(event.repeat&&event.repeat!=='none')?(event.repeat==='weekly'?'weekly':event.repeat==='biweekly'?'biweekly':event.repeat==='monthly'?'monthly':'daily'):null,
      priority:false,
      buffer:false,
      TBD:'none',
      type:importType
    };
    if(event.typeInput)node.typeInput=event.typeInput;
    
    // Add timer if event has duration
    if(eventDuration>0){
      node.timer={
        startTime:startDate.toISOString(),
        endTime:endDate.toISOString(),
        duration:eventDuration,
        remaining:eventDuration
      };
    }
    
      G.nodes.push(node);
      importedCount++;
      if(!firstImportedDate&&!isNaN(startDate.getTime()))firstImportedDate=startDate;
    }

    sv();
    render();
    rPanel();
    // Jump the calendar to the imported event's week so a freshly dropped event is actually
    // visible (otherwise a single event dated in another week looks like nothing happened).
    if(currentView==='calendar'&&firstImportedDate){
      calendarDate=new Date(firstImportedDate);
      calendarCenterOnAnchorNextRender=true;
    }
    if(currentView==='calendar')renderCalendar();
    
    // Show success message only if there's more than 1 event (for both file picker and drag-and-drop)
    if(events.length>1){
      alert(`Successfully imported ${importedCount} calendar event${importedCount!==1?'s':''}${skippedCount>0?` (${skippedCount} skipped as duplicates)`:''}.`);
    }
    
  }catch(error){
    console.error('Calendar import error:',error);
    if(error.message.includes('JSON')&&!file.name.endsWith('.ics')){
      alert('Invalid file format. Please select either:\n- An ICS file (.ics) exported from Calendar.app\n- A JSON file created by: node export-calendar.js');
    }else{
      alert('Failed to import calendar events: '+error.message);
    }
  }finally{
    if(btn){
      btn.disabled=false;
      btn.innerHTML='<span style="display:inline-block;width:8px;height:8px;background:var(--red);border-radius:50%;margin-right:6px"></span>Import';
    }
  }
}

function importMacCalendar(){
  // Create file input for importing calendar JSON or ICS
  const input=document.createElement('input');
  input.type='file';
  input.accept='.json,.ics';
  input.style.display='none';
  
  input.onchange=async (e)=>{
    const file=e.target.files[0];
    if(!file)return;
    
    await processCalendarImport(file);
    
    // Clean up file input
    document.body.removeChild(input);
  };
  
  // Trigger file picker
  document.body.appendChild(input);
  input.click();
}
let calendarExportMode=null; // 'range', 'events', or null
let selectedRanges=[]; // Array of {start: Date, end: Date}
let selectedEventIds=new Set(); // Set of node IDs
let rangeSelectionStart=null;
let rangeSelectionElement=null;

function toggleExportCalendarDropdown(){
  const dropdown=document.getElementById('calendar-export-dropdown');
  if(dropdown){
    dropdown.style.display=dropdown.style.display==='none'?'block':'none';
  }
}
function toggleFindTimeDropdown(){
  const dropdown=document.getElementById('calendar-findtime-dropdown');
  if(dropdown){
    const isOpen=dropdown.style.display!=='none';
    dropdown.style.display=isOpen?'none':'block';
    // Update unit display
    const unitDisplay=document.getElementById('findtime-unit-display');
    if(unitDisplay)unitDisplay.textContent=findTimeUnitMinutes+'min';
    if(!isOpen&&!findTimeMode){
      // Default: highlight 7 work days (skip weekends) starting from tomorrow, 9am-6pm
      const tomorrow=new Date();
      tomorrow.setDate(tomorrow.getDate()+1);
      tomorrow.setHours(0,0,0,0);
      
      // Find next 7 work days (skip weekends)
      let workDays=[];
      let currentDate=new Date(tomorrow);
      while(workDays.length<7){
        const dayOfWeek=currentDate.getDay();
        if(dayOfWeek!==0&&dayOfWeek!==6){ // Not Sunday (0) or Saturday (6)
          workDays.push(new Date(currentDate));
        }
        currentDate.setDate(currentDate.getDate()+1);
      }
      
      if(workDays.length>0){
        findTimeStartDate=workDays[0];
        findTimeEndDate=workDays[workDays.length-1];
        findTimeStartDate.setHours(9,0,0,0);
        findTimeEndDate.setHours(18,0,0,0);
        findTimeMode='auto';
        highlightFindTime();
      }
    }
  }
}
function changeFindTimeRange(){
  toggleFindTimeDropdown();
  // Clear highlights when opening modal
  clearFindTimeHighlights();
  
  // Open modal
  const modal=document.getElementById('m-findtime-range');
  const startInput=document.getElementById('findtime-start');
  const endInput=document.getElementById('findtime-end');
  
  // Set default values
  if(findTimeStartDate){
    const startDate=new Date(findTimeStartDate);
    const year=startDate.getFullYear();
    const month=String(startDate.getMonth()+1).padStart(2,'0');
    const day=String(startDate.getDate()).padStart(2,'0');
    const hours=String(startDate.getHours()).padStart(2,'0');
    const minutes=String(startDate.getMinutes()).padStart(2,'0');
    startInput.value=`${year}-${month}-${day}T${hours}:${minutes}`;
  }else{
    const tomorrow=new Date();
    tomorrow.setDate(tomorrow.getDate()+1);
    tomorrow.setHours(9,0,0,0);
    const year=tomorrow.getFullYear();
    const month=String(tomorrow.getMonth()+1).padStart(2,'0');
    const day=String(tomorrow.getDate()).padStart(2,'0');
    startInput.value=`${year}-${month}-${day}T09:00`;
  }
  
  if(findTimeEndDate){
    const endDate=new Date(findTimeEndDate);
    const year=endDate.getFullYear();
    const month=String(endDate.getMonth()+1).padStart(2,'0');
    const day=String(endDate.getDate()).padStart(2,'0');
    const hours=String(endDate.getHours()).padStart(2,'0');
    const minutes=String(endDate.getMinutes()).padStart(2,'0');
    endInput.value=`${year}-${month}-${day}T${hours}:${minutes}`;
  }else{
    const endDate=new Date();
    endDate.setDate(endDate.getDate()+8);
    endDate.setHours(18,0,0,0);
    const year=endDate.getFullYear();
    const month=String(endDate.getMonth()+1).padStart(2,'0');
    const day=String(endDate.getDate()).padStart(2,'0');
    endInput.value=`${year}-${month}-${day}T18:00`;
  }
  clearFindTimeDatetimeInputs();
  modal.classList.add('open');
  setupModalKeyboardNavigation('m-findtime-range');
  setTimeout(()=>startInput.focus(),100);
}
