function startFindTimeManualSelection(){
  toggleFindTimeDropdown();
  if(findTimeMode==='manual'){
    // Finalize selection
    exitFindTimeManualSelection();
    return;
  }
  // Clear any existing highlights
  clearFindTimeHighlights();
  findTimeMode='manual';
  findTimeSelectedRanges=[];
  const btn=document.getElementById('calendar-findtime-btn');
  if(btn)btn.innerHTML='<span style="display:inline-block;width:6px;height:6px;background:#eab308;border-radius:50%;margin-right:4px"></span>FindTime (Selecting...)';
  setupFindTimeManualSelection();
}
function exitFindTimeManualSelection(){
  findTimeMode=null;
  findTimeSelectedRanges=[];
  clearFindTimeHighlights();
  const btn=document.getElementById('calendar-findtime-btn');
  if(btn)btn.innerHTML='<span style="display:inline-block;width:6px;height:6px;background:#eab308;border-radius:50%;margin-right:4px"></span>FindTime';
  const grid=document.getElementById('calendar-time-grid');
  if(grid&&grid._findTimeManualHandlers){
    const h=grid._findTimeManualHandlers;
    grid.removeEventListener('mousedown',h.mousedown);
    document.removeEventListener('mousemove',h.mousemove);
    document.removeEventListener('mouseup',h.mouseup);
    document.removeEventListener('keydown',h.keydown);
    grid.style.cursor='';
    grid.style.pointerEvents='';
    delete grid._findTimeManualHandlers;
  }
  // Re-enable calendar features
  const dayCols=document.querySelectorAll('.cal-day-column');
  dayCols.forEach(col=>{
    col.style.pointerEvents='';
    col.style.outline='';
    col.style.outlineOffset='';
  });
  const events=document.querySelectorAll('.cal-event,.cal-all-day-event');
  events.forEach(evt=>{
    evt.style.pointerEvents='';
  });
}
function cancelFindTime(){
  toggleFindTimeDropdown();
  if(findTimeMode==='manual'){
    exitFindTimeManualSelection();
  }else{
    clearFindTimeHighlights();
    findTimeMode=null;
    findTimeStartDate=null;
    findTimeEndDate=null;
  }
}
function highlightFindTime(){
  clearFindTimeHighlights();
  if(!findTimeStartDate||!findTimeEndDate)return;
  
  const start=new Date(findTimeStartDate);
  const end=new Date(findTimeEndDate);
  
  // Get all events in the date range (including routine events)
  const eventsInRange=[];
  G.nodes.forEach(n=>{
    if(n.calendarDate){
      const eventDate=new Date(n.calendarDate);
      if(eventDate>=start&&eventDate<=end){
        eventsInRange.push(n);
      }
    }
    // Also check routine events
    if(n.routine&&n.routineFrequency&&n.calendarDate){
      const originalDate=new Date(n.calendarDate);
      let currentDate=new Date(originalDate);
      const originalHour=originalDate.getHours();
      const originalMinute=originalDate.getMinutes();
      const routineEnd=n.routineEndDate?new Date(n.routineEndDate):null;

      // Generate occurrences in the range
      while(currentDate<=end){
        if(routineEnd&&currentDate>routineEnd)break;
        if(currentDate>=start){
          const dateKeyISO=currentDate.toISOString().split('T')[0];
          if(!n.exceptionDates||!n.exceptionDates.includes(dateKeyISO)){
            let occurrenceStart; let occurrenceDuration;
            if(n.routineTimeOverrides&&n.routineTimeOverrides[dateKeyISO]){
              const ov=n.routineTimeOverrides[dateKeyISO];
              occurrenceStart=new Date(ov.start);
              occurrenceDuration=ov.duration||n.calendarDuration||60*60*1000;
            }else{
              occurrenceStart=new Date(currentDate);
              occurrenceStart.setHours(originalHour,originalMinute,0,0);
              occurrenceDuration=n.calendarDuration||60*60*1000;
            }
            if(occurrenceStart>=start&&occurrenceStart<=end){
              eventsInRange.push({
                calendarDate:occurrenceStart.toISOString(),
                calendarDuration:occurrenceDuration
              });
            }
          }
        }
        let nextDate=new Date(currentDate);
        if(n.routineFrequency==='daily'){
          nextDate.setDate(nextDate.getDate()+1);
        }else if(n.routineFrequency==='weekly'){
          nextDate.setDate(nextDate.getDate()+7);
        }else if(n.routineFrequency==='biweekly'){
          nextDate.setDate(nextDate.getDate()+14);
        }else if(n.routineFrequency==='monthly'){
          nextDate.setMonth(nextDate.getMonth()+1);
        }else{
          break;
        }
        currentDate=nextDate;
      }
    }
  });

  // Helper to get hour in selected timezone
  const getHourInTimezone=(date)=>{
    if(calendarTimezone){
      const tzFormatter=new Intl.DateTimeFormat('en-US',{
        timeZone:calendarTimezone,
        hour:'numeric',
        minute:'numeric',
        hour12:false
      });
      const parts=tzFormatter.formatToParts(date);
      const hour=parseInt(parts.find(p=>p.type==='hour').value);
      const minute=parseInt(parts.find(p=>p.type==='minute').value);
      return{hour,minute};
    }
    return{hour:date.getHours(),minute:date.getMinutes()};
  };
  
  // Create a map of busy times (in selected timezone)
  const busySlots=new Map(); // dateKey -> Set of time slots (minutes from midnight in timezone)
  eventsInRange.forEach(n=>{
    const eventStart=new Date(n.calendarDate);
    const duration=n.calendarDuration||60*60*1000;
    const eventEnd=new Date(eventStart.getTime()+duration);
    
    // Get date key in timezone
    const eventDateInTz=new Date(eventStart);
    if(calendarTimezone){
      // Convert to timezone for date key
      const tzDateStr=new Intl.DateTimeFormat('en-US',{
        timeZone:calendarTimezone,
        year:'numeric',
        month:'2-digit',
        day:'2-digit'
      }).format(eventStart);
      const dateKey=tzDateStr; // Use timezone date as key
      
      // Get hours in timezone
      const startTz=getHourInTimezone(eventStart);
      const endTz=getHourInTimezone(eventEnd);
      
      if(!busySlots.has(dateKey))busySlots.set(dateKey,new Set());
      const slots=busySlots.get(dateKey);
      const startMinutes=startTz.hour*60+startTz.minute;
      const endMinutes=endTz.hour*60+endTz.minute;
      for(let m=startMinutes-findTimeFlexMinutes;m<=endMinutes+findTimeFlexMinutes;m++){
        if(m>=0&&m<24*60)slots.add(m);
      }
    }else{
      const dateKey=eventStart.toDateString();
      if(!busySlots.has(dateKey))busySlots.set(dateKey,new Set());
      const slots=busySlots.get(dateKey);
      const startMinutes=eventStart.getHours()*60+eventStart.getMinutes();
      const endMinutes=eventEnd.getHours()*60+eventEnd.getMinutes();
      for(let m=startMinutes-findTimeFlexMinutes;m<=endMinutes+findTimeFlexMinutes;m++){
        if(m>=0&&m<24*60)slots.add(m);
      }
    }
  });
  
  // Highlight empty slots (9am-6pm, work days only) - shade each 1-hour cell individually
  const grid=document.getElementById('calendar-time-grid');
  if(!grid)return;
  
  let currentDate=new Date(start);
  currentDate.setHours(0,0,0,0);
  const endDate=new Date(end);
  endDate.setHours(23,59,59,999);
  
  while(currentDate<=endDate){
    const dayOfWeek=currentDate.getDay();
    // Skip weekends
    if(dayOfWeek!==0&&dayOfWeek!==6){
      // Get date key in timezone for busy slots lookup
      let dateKey;
      if(calendarTimezone){
        const tzDateStr=new Intl.DateTimeFormat('en-US',{
          timeZone:calendarTimezone,
          year:'numeric',
          month:'2-digit',
          day:'2-digit'
        }).format(currentDate);
        dateKey=tzDateStr;
      }else{
        dateKey=currentDate.toDateString();
      }
      
      const busy=busySlots.get(dateKey)||new Set();
      
      // Extract date range and time window from findTimeStartDate and findTimeEndDate
      const rangeStart=new Date(findTimeStartDate);
      const rangeEnd=new Date(findTimeEndDate);
      
      // Extract time portions (hour/minute) from start and end dates
      // These will be applied to EVERY day in the date range
      const startHour=rangeStart.getHours();
      const startMinute=rangeStart.getMinutes();
      const endHour=rangeEnd.getHours();
      const endMinute=rangeEnd.getMinutes();
      
      // Check if this date is within the date range (ignoring time)
      const dateStr=currentDate.toISOString().split('T')[0];
      const rangeStartStr=rangeStart.toISOString().split('T')[0];
      const rangeEndStr=rangeEnd.toISOString().split('T')[0];
      
      if(dateStr>=rangeStartStr&&dateStr<=rangeEndStr){
        // For each day in the range, use the same time window (startHour:startMinute to endHour:endMinute)
        
        // Find all time slots for this date
        const timeSlots=grid.querySelectorAll(`.cal-time-slot`);
        const unitMinutes=findTimeUnitMinutes; // 30 minutes default
        
        timeSlots.forEach(slot=>{
          const dayCols=slot.querySelectorAll(`.cal-day-column[data-date*="${dateStr}"]`);
          dayCols.forEach(dayCol=>{
            const hour=parseInt(dayCol.dataset.hour)||0;
            
            // Check each 30-minute unit in this hour
            for(let unit=0;unit<2;unit++){ // 2 units per hour (30min each)
              const unitStartMinute=unit*unitMinutes;
              const unitEndMinute=(unit+1)*unitMinutes;
              const unitStartMinutes=hour*60+unitStartMinute;
              const unitEndMinutes=hour*60+unitEndMinute;
              
              // Check if this unit is within the time window (same for all days in range)
              const rangeStartMinutes=startHour*60+startMinute;
              const rangeEndMinutes=endHour*60+endMinute;
              
              if(unitStartMinutes<rangeEndMinutes&&unitEndMinutes>rangeStartMinutes){
                // Check if this 30-minute unit is available (not busy)
                let isAvailable=true;
                for(let m=unitStartMinutes;m<unitEndMinutes;m+=15){
                  if(busy.has(m)){
                    isAvailable=false;
                    break;
                  }
                }
                
                if(isAvailable){
                  // Shade this 30-minute unit (half of the hour cell)
                  const highlight=document.createElement('div');
                  highlight.className='findtime-highlight';
                  highlight.style.position='absolute';
                  highlight.style.left='0';
                  highlight.style.top=(unitStartMinute/60*60)+'px'; // 0 or 30px
                  highlight.style.width='100%';
                  highlight.style.height=(unitMinutes/60*60)+'px'; // 30px
                  highlight.style.background='rgba(255,255,200,0.4)'; // Light yellow, half transparent
                  highlight.style.border='none';
                  highlight.style.borderRadius='4px'; // Slightly rounded edges
                  highlight.style.pointerEvents='none';
                  highlight.style.zIndex='5';
                  dayCol.appendChild(highlight);
                }
              }
            }
          });
        });
      }
    }
    
    currentDate.setDate(currentDate.getDate()+1);
  }
}
function clearFindTimeHighlights(){
  // Remove highlight divs
  const highlights=document.querySelectorAll('.findtime-highlight');
  highlights.forEach(h=>h.remove());
  // Remove cell background shading
  const cells=document.querySelectorAll('.findtime-highlight-cell');
  cells.forEach(cell=>{
    cell.style.background='';
    cell.style.borderRadius='';
    cell.classList.remove('findtime-highlight-cell');
  });
}
function confirmFindTime(){
  toggleFindTimeDropdown();
  
  // Collect all available time slots from highlights
  const availableSlots=[];
  
  if(findTimeMode==='auto'&&findTimeStartDate&&findTimeEndDate){
    // Get all events in the date range
    const start=new Date(findTimeStartDate);
    const end=new Date(findTimeEndDate);
    const eventsInRange=[];
    
    G.nodes.forEach(n=>{
      if(n.calendarDate){
        const eventDate=new Date(n.calendarDate);
        if(eventDate>=start&&eventDate<=end){
          eventsInRange.push(n);
        }
      }
      // Also check routine events
      if(n.routine&&n.routineFrequency&&n.calendarDate){
        const originalDate=new Date(n.calendarDate);
        let currentDate=new Date(originalDate);
        const originalHour=originalDate.getHours();
        const originalMinute=originalDate.getMinutes();
        const routineEnd=n.routineEndDate?new Date(n.routineEndDate):null;

        while(currentDate<=end){
          if(routineEnd&&currentDate>routineEnd)break;
          if(currentDate>=start){
            const dateKeyISO=currentDate.toISOString().split('T')[0];
            if(!n.exceptionDates||!n.exceptionDates.includes(dateKeyISO)){
              let occurrenceStart; let occurrenceDuration;
              if(n.routineTimeOverrides&&n.routineTimeOverrides[dateKeyISO]){
                const ov=n.routineTimeOverrides[dateKeyISO];
                occurrenceStart=new Date(ov.start);
                occurrenceDuration=ov.duration||n.calendarDuration||60*60*1000;
              }else{
                occurrenceStart=new Date(currentDate);
                occurrenceStart.setHours(originalHour,originalMinute,0,0);
                occurrenceDuration=n.calendarDuration||60*60*1000;
              }
              if(occurrenceStart>=start&&occurrenceStart<=end){
                eventsInRange.push({
                  calendarDate:occurrenceStart.toISOString(),
                  calendarDuration:occurrenceDuration
                });
              }
            }
          }
          let nextDate=new Date(currentDate);
          if(n.routineFrequency==='daily'){
            nextDate.setDate(nextDate.getDate()+1);
          }else if(n.routineFrequency==='weekly'){
            nextDate.setDate(nextDate.getDate()+7);
          }else if(n.routineFrequency==='biweekly'){
            nextDate.setDate(nextDate.getDate()+14);
          }else if(n.routineFrequency==='monthly'){
            nextDate.setMonth(nextDate.getMonth()+1);
          }else{
            break;
          }
          currentDate=nextDate;
        }
      }
    });
    
    // Create busy slots map
    const busySlots=new Map();
    eventsInRange.forEach(n=>{
      const eventStart=new Date(n.calendarDate);
      const duration=n.calendarDuration||60*60*1000;
      const eventEnd=new Date(eventStart.getTime()+duration);
      const dateKey=eventStart.toDateString();
      if(!busySlots.has(dateKey))busySlots.set(dateKey,new Set());
      const slots=busySlots.get(dateKey);
      const startMinutes=eventStart.getHours()*60+eventStart.getMinutes();
      const endMinutes=eventEnd.getHours()*60+eventEnd.getMinutes();
      for(let m=startMinutes-findTimeFlexMinutes;m<=endMinutes+findTimeFlexMinutes;m++){
        if(m>=0&&m<24*60)slots.add(m);
      }
    });
    
    // Find available slots (9am-6pm, work days only)
    let currentDate=new Date(start);
    currentDate.setHours(0,0,0,0);
    const endDate=new Date(end);
    endDate.setHours(23,59,59,999);
    
    while(currentDate<=endDate){
      const dayOfWeek=currentDate.getDay();
      if(dayOfWeek!==0&&dayOfWeek!==6){ // Work days only
        const dateKey=currentDate.toDateString();
        const busy=busySlots.get(dateKey)||new Set();
        
        // Extract time window from findTimeStartDate and findTimeEndDate
        const rangeStart=new Date(findTimeStartDate);
        const rangeEnd=new Date(findTimeEndDate);
        const startHour=rangeStart.getHours();
        const startMinute=rangeStart.getMinutes();
        const endHour=rangeEnd.getHours();
        const endMinute=rangeEnd.getMinutes();
        
        // Find continuous available slots in the time window (startHour:startMinute to endHour:endMinute)
        let slotStart=null;
        for(let hour=startHour;hour<=endHour;hour++){
          const minuteStart=(hour===startHour?startMinute:0);
          const minuteEnd=(hour===endHour?endMinute:59);
          for(let minute=minuteStart;minute<=minuteEnd;minute+=15){
            const slotMinutes=hour*60+minute;
            if(!busy.has(slotMinutes)){
              if(!slotStart){
                slotStart={hour,minute};
              }
            }else{
              if(slotStart){
                const slotDate=new Date(currentDate);
                slotDate.setHours(slotStart.hour,slotStart.minute,0,0);
                const slotEnd=new Date(currentDate);
                slotEnd.setHours(hour,minute,0,0);
                availableSlots.push({start:slotDate,end:slotEnd});
                slotStart=null;
              }
            }
          }
        }
        // Add final slot if any
        if(slotStart){
          const slotDate=new Date(currentDate);
          slotDate.setHours(slotStart.hour,slotStart.minute,0,0);
          const slotEnd=new Date(currentDate);
          slotEnd.setHours(endHour,endMinute,0,0);
          availableSlots.push({start:slotDate,end:slotEnd});
        }
      }
      currentDate.setDate(currentDate.getDate()+1);
    }
  }else if(findTimeMode==='manual'&&findTimeSelectedRanges.length>0){
    // Use manually selected ranges
    findTimeSelectedRanges.forEach(range=>{
      availableSlots.push({start:new Date(range.start),end:new Date(range.end)});
    });
  }
  
  if(availableSlots.length===0){
    alert('No available time slots found');
    return;
  }
  
  // Export as ICS
  let icsContent='BEGIN:VCALENDAR\r\n';
  icsContent+='VERSION:2.0\r\n';
  icsContent+='PRODID:-//My Cosmos//Available Time Slots//EN\r\n';
  icsContent+='CALSCALE:GREGORIAN\r\n';
  icsContent+='METHOD:PUBLISH\r\n';
  
  // Export all available slots as multiple chunks under the same name "Available Time"
  availableSlots.forEach((slot,idx)=>{
    icsContent+='BEGIN:VEVENT\r\n';
    icsContent+='UID:available-time-'+Date.now()+'-'+idx+'@my-cosmos\r\n';
    icsContent+='DTSTART:'+formatICSDate(slot.start)+'\r\n';
    icsContent+='DTEND:'+formatICSDate(slot.end)+'\r\n';
    icsContent+='SUMMARY:Available Time\r\n';
    icsContent+='DESCRIPTION:Available time slot found using FindTime feature\r\n';
    icsContent+='END:VEVENT\r\n';
  });
  
  icsContent+='END:VCALENDAR\r\n';
  
  // Download file
  const blob=new Blob([icsContent],{type:'text/calendar;charset=utf-8'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;
  a.download='available-time-slots.ics';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  
  alert(`Exported ${availableSlots.length} available time slot${availableSlots.length!==1?'s':''} to available-time-slots.ics`);
}
function setupFindTimeManualSelection(){
  const grid=document.getElementById('calendar-time-grid');
  if(!grid)return;
  
  // Disable calendar features
  const dayCols=document.querySelectorAll('.cal-day-column');
  dayCols.forEach(col=>{
    col.style.pointerEvents='auto'; // Enable interactions
    col.onclick=null; // Remove existing click handlers
  });
  const events=document.querySelectorAll('.cal-event,.cal-all-day-event');
  events.forEach(evt=>{
    evt.style.pointerEvents='none';
  });
  grid.style.pointerEvents='auto';
  grid.style.cursor='crosshair';
  
  let isDragging=false;
  let startCell=null;
  let currentCell=null;
  let selectionOverlay=null;
  let highlightedCells=new Set(); // Track which cells are currently highlighted during drag
  
  const getCellFromPoint=(x,y)=>{
    const gridRect=grid.getBoundingClientRect();
    const scrollContainer=document.getElementById('calendar-scroll-container');
    const scrollLeft=scrollContainer?scrollContainer.scrollLeft:0;
    const scrollTop=scrollContainer?scrollContainer.scrollTop:0;
    
    const timeColumnWidth=120;
    const dayWidth=Math.floor((grid.clientWidth-timeColumnWidth)/7);
    const timeSlotHeight=60; // 60px per hour
    
    const relativeX=x-gridRect.left+scrollLeft;
    const relativeY=y-gridRect.top+scrollTop;
    
    if(relativeX<timeColumnWidth)return null;
    
    const dayIdx=Math.floor((relativeX-timeColumnWidth)/dayWidth);
    const hour=Math.floor(relativeY/timeSlotHeight);
    const minuteRaw=(relativeY%timeSlotHeight)/timeSlotHeight*60;
    
    // Snap to 30-minute units
    const unitMinutes=findTimeUnitMinutes;
    const minute=Math.floor(minuteRaw/unitMinutes)*unitMinutes;
    
    return{dayIdx,hour,minute};
  };
  
  const getDateFromDayIdx=(dayIdx)=>{
    // Get the actual date for this day from any day column with this dayIdx
    const timeSlots=grid.querySelectorAll('.cal-time-slot');
    for(let i=0;i<timeSlots.length;i++){
      const dayCols=timeSlots[i].querySelectorAll('.cal-day-column');
      for(let j=0;j<dayCols.length;j++){
        const dc=dayCols[j];
        if(parseInt(dc.dataset.day)===dayIdx){
          return dc.dataset.date;
        }
      }
    }
    return null;
  };
  
  const highlightCellsDuringDrag=(start,end)=>{
    // Clear previous highlights
    highlightedCells.forEach(cellKey=>{
      const [dayIdx,hour,minute]=cellKey.split(',').map(Number);
      const dateStr=getDateFromDayIdx(dayIdx);
      if(dateStr){
        const timeSlots=grid.querySelectorAll('.cal-time-slot');
        timeSlots.forEach(slot=>{
          const dayCols=slot.querySelectorAll(`.cal-day-column[data-date*="${dateStr}"]`);
          dayCols.forEach(dc=>{
            const dcHour=parseInt(dc.dataset.hour)||0;
            if(dcHour===hour){
              dc.style.background='';
              dc.classList.remove('findtime-drag-highlight');
            }
          });
        });
      }
    });
    highlightedCells.clear();
    
    if(!start||!end||start.dayIdx!==end.dayIdx)return;
    
    // Calculate all cells between start and end
    const dateStr=getDateFromDayIdx(start.dayIdx);
    if(!dateStr)return;
    
    const startMinutes=start.hour*60+start.minute;
    const endMinutes=end.hour*60+end.minute;
    const minMinutes=Math.min(startMinutes,endMinutes);
    const maxMinutes=Math.max(startMinutes,endMinutes);
    
    // Highlight all cells in the range
    const timeSlots=grid.querySelectorAll('.cal-time-slot');
    timeSlots.forEach(slot=>{
      const dayCols=slot.querySelectorAll(`.cal-day-column[data-date*="${dateStr}"]`);
      dayCols.forEach(dc=>{
        const hour=parseInt(dc.dataset.hour)||0;
        const unitMinutes=findTimeUnitMinutes;
        
        // Check each 30-minute unit in this hour
        for(let unit=0;unit<2;unit++){
          const unitStartMinute=unit*unitMinutes;
          const unitEndMinute=(unit+1)*unitMinutes;
          const unitStartMinutes=hour*60+unitStartMinute;
          const unitEndMinutes=hour*60+unitEndMinute;
          
          // Check if this unit overlaps with the selection
          if(unitStartMinutes<maxMinutes&&unitEndMinutes>minMinutes){
            const cellKey=`${start.dayIdx},${hour},${unitStartMinute}`;
            if(!highlightedCells.has(cellKey)){
              highlightedCells.add(cellKey);
              // Highlight this cell
              const highlight=document.createElement('div');
              highlight.className='findtime-drag-highlight';
              highlight.style.position='absolute';
              highlight.style.left='0';
              highlight.style.top=(unitStartMinute/60*60)+'px';
              highlight.style.width='100%';
              highlight.style.height=(unitMinutes/60*60)+'px';
              highlight.style.background='rgba(255,255,200,0.6)'; // Light yellow, more opaque during drag
              highlight.style.border='none';
              highlight.style.borderRadius='4px';
              highlight.style.pointerEvents='none';
              highlight.style.zIndex='10';
              dc.appendChild(highlight);
            }
          }
        }
      });
    });
  };
  
  const mousedownHandler=(e)=>{
    // Don't start if clicking on existing highlights or events
    if(e.target.closest('.cal-event')||e.target.closest('.cal-all-day-event'))return;
    
    e.preventDefault();
    e.stopPropagation();
    
    const cell=getCellFromPoint(e.clientX,e.clientY);
    if(cell){
      isDragging=true;
      startCell=cell;
      currentCell=cell;
      highlightCellsDuringDrag(startCell,currentCell);
    }
  };
  
  const mousemoveHandler=(e)=>{
    if(!isDragging||!startCell)return;
    
    e.preventDefault();
    const cell=getCellFromPoint(e.clientX,e.clientY);
    if(cell&&cell.dayIdx===startCell.dayIdx){
      currentCell=cell;
      highlightCellsDuringDrag(startCell,currentCell);
    }
  };
  
  const mouseupHandler=(e)=>{
    if(!isDragging||!startCell||!currentCell)return;
    
    isDragging=false;
    e.preventDefault();
    e.stopPropagation();
    
    // Finalize the selection
    if(startCell.dayIdx===currentCell.dayIdx){
      const dateStr=getDateFromDayIdx(startCell.dayIdx);
      if(dateStr){
        const selectedDate=new Date(dateStr);
        
        const startTime=new Date(selectedDate);
        startTime.setHours(startCell.hour,startCell.minute,0,0);
        const endTime=new Date(selectedDate);
        endTime.setHours(currentCell.hour,currentCell.minute,0,0);
        
        // Ensure end is at least one unit after start
        if(endTime<=startTime){
          endTime.setTime(startTime.getTime()+findTimeUnitMinutes*60*1000);
        }
        
        // Round to unit boundaries
        const startMinutes=startTime.getMinutes();
        const startRounded=Math.floor(startMinutes/findTimeUnitMinutes)*findTimeUnitMinutes;
        startTime.setMinutes(startRounded,0,0);
        
        const endMinutes=endTime.getMinutes();
        const endRounded=Math.ceil(endMinutes/findTimeUnitMinutes)*findTimeUnitMinutes;
        if(endRounded>=60){
          endTime.setHours(endTime.getHours()+1);
          endTime.setMinutes(0,0,0);
        }else{
          endTime.setMinutes(endRounded,0,0);
        }
        
        findTimeSelectedRanges.push({start:new Date(startTime),end:new Date(endTime)});
        highlightFindTimeManualRange(startTime,endTime);
      }
    }
    
    // Clear drag highlights
    highlightedCells.forEach(cellKey=>{
      const [dayIdx,hour,minute]=cellKey.split(',').map(Number);
      const dateStr=getDateFromDayIdx(dayIdx);
      if(dateStr){
        const timeSlots=grid.querySelectorAll('.cal-time-slot');
        timeSlots.forEach(slot=>{
          const dayCols=slot.querySelectorAll(`.cal-day-column[data-date*="${dateStr}"]`);
          dayCols.forEach(dc=>{
            const dcHour=parseInt(dc.dataset.hour)||0;
            if(dcHour===hour){
              const highlights=dc.querySelectorAll('.findtime-drag-highlight');
              highlights.forEach(h=>h.remove());
            }
          });
        });
      }
    });
    highlightedCells.clear();
    
    startCell=null;
    currentCell=null;
  };
  
  const keydownHandler=(e)=>{
    if(e.key==='Escape'){
      // Cancel current selection
      if(isDragging){
        // Clear drag highlights
        highlightedCells.forEach(cellKey=>{
          const [dayIdx,hour,minute]=cellKey.split(',').map(Number);
          const dateStr=getDateFromDayIdx(dayIdx);
          if(dateStr){
            const timeSlots=grid.querySelectorAll('.cal-time-slot');
            timeSlots.forEach(slot=>{
              const dayCols=slot.querySelectorAll(`.cal-day-column[data-date*="${dateStr}"]`);
              dayCols.forEach(dc=>{
                const dcHour=parseInt(dc.dataset.hour)||0;
                if(dcHour===hour){
                  const highlights=dc.querySelectorAll('.findtime-drag-highlight');
                  highlights.forEach(h=>h.remove());
                }
              });
            });
          }
        });
        highlightedCells.clear();
      }
      isDragging=false;
      startCell=null;
      currentCell=null;
      exitFindTimeManualSelection();
    }
  };
  
  // Add event listeners
  grid.addEventListener('mousedown',mousedownHandler);
  document.addEventListener('mousemove',mousemoveHandler);
  document.addEventListener('mouseup',mouseupHandler);
  document.addEventListener('keydown',keydownHandler);
  
  // Store handlers for cleanup
  grid._findTimeManualHandlers={mousedown:mousedownHandler,mousemove:mousemoveHandler,mouseup:mouseupHandler,keydown:keydownHandler};
}
function highlightFindTimeManualRange(start,end){
  const grid=document.getElementById('calendar-time-grid');
  if(!grid)return;
  
  const timeSlotHeight=60;
  const timeColumnWidth=120;
  const dayWidth=Math.floor((grid.clientWidth-timeColumnWidth)/7);
  
  // Find all time slots and shade the appropriate 30-minute units
  const dateStr=start.toISOString().split('T')[0];
  const timeSlots=grid.querySelectorAll('.cal-time-slot');
  const unitMinutes=findTimeUnitMinutes; // 30 minutes default
  
  timeSlots.forEach(slot=>{
    const dayCols=slot.querySelectorAll(`.cal-day-column[data-date*="${dateStr}"]`);
    dayCols.forEach(dayCol=>{
      const hour=parseInt(dayCol.dataset.hour)||0;
      const startHour=start.getHours();
      const startMinute=start.getMinutes();
      const endHour=end.getHours();
      const endMinute=end.getMinutes();
      
      // Check each 30-minute unit in this hour
      for(let unit=0;unit<2;unit++){ // 2 units per hour (30min each)
        const unitStartMinute=unit*unitMinutes;
        const unitEndMinute=(unit+1)*unitMinutes;
        const unitStartMinutes=hour*60+unitStartMinute;
        const unitEndMinutes=hour*60+unitEndMinute;
        const rangeStartMinutes=startHour*60+startMinute;
        const rangeEndMinutes=endHour*60+endMinute;
        
        // Check if this unit overlaps with the range
        if(unitStartMinutes<rangeEndMinutes&&unitEndMinutes>rangeStartMinutes){
          // This unit overlaps - shade it
          const highlight=document.createElement('div');
          highlight.className='findtime-highlight';
          highlight.style.position='absolute';
          highlight.style.left='0';
          highlight.style.top=(unitStartMinute/60*timeSlotHeight)+'px'; // 0 or 30px
          highlight.style.width='100%';
          highlight.style.height=(unitMinutes/60*timeSlotHeight)+'px'; // 30px
          highlight.style.background='rgba(255,255,200,0.4)'; // Light yellow, same as auto mode
          highlight.style.border='none';
          highlight.style.borderRadius='4px';
          highlight.style.pointerEvents='none';
          highlight.style.zIndex='15';
          dayCol.appendChild(highlight);
        }
      }
    });
  });
}

