function setupRangeSelection(){
  const grid=document.getElementById('calendar-time-grid');
  const scrollContainer=document.getElementById('calendar-scroll-container');
  if(!grid||!scrollContainer)return;
  
  let isSelecting=false;
  let startCell=null;
  let endCell=null;
  let selectionOverlay=null;
  
  const getCellFromPoint=(x,y)=>{
    const rect=grid.getBoundingClientRect();
    const scrollLeft=scrollContainer.scrollLeft;
    const scrollTop=scrollContainer.scrollTop;
    const relX=x-rect.left+scrollLeft;
    const relY=y-rect.top+scrollTop;
    
    // Find which day column element is at this point
    const dayCols=grid.querySelectorAll('.cal-day-column');
    let targetDayCol=null;
    let minDist=Infinity;
    
    dayCols.forEach(col=>{
      const colRect=col.getBoundingClientRect();
      const colLeft=colRect.left-rect.left+scrollLeft;
      const colRight=colLeft+colRect.width;
      const colTop=colRect.top-rect.top+scrollTop;
      const colBottom=colTop+colRect.height;
      
      if(relX>=colLeft&&relX<=colRight&&relY>=colTop&&relY<=colBottom){
        const dist=Math.abs(relX-(colLeft+colRect.width/2))+Math.abs(relY-(colTop+colRect.height/2));
        if(dist<minDist){
          minDist=dist;
          targetDayCol=col;
        }
      }
    });
    
    if(!targetDayCol)return null;
    
    const dateStr=targetDayCol.dataset.date;
    const hour=parseInt(targetDayCol.dataset.hour)||0;
    const timeSlotHeight=60;
    const minute=Math.floor(((relY-(targetDayCol.getBoundingClientRect().top-rect.top+scrollTop))%timeSlotHeight)/timeSlotHeight*60);
    
    return{dateStr,hour,minute,x:relX,y:relY};
  };
  
  const createSelectionOverlay=(start,end)=>{
    if(selectionOverlay)selectionOverlay.remove();
    selectionOverlay=document.createElement('div');
    selectionOverlay.style.position='absolute';
    selectionOverlay.style.pointerEvents='none';
    selectionOverlay.style.background='rgba(255,235,59,0.3)';
    selectionOverlay.style.border='2px solid #ffeb3b';
    selectionOverlay.style.zIndex='50';
    grid.appendChild(selectionOverlay);
    
    const left=Math.min(start.x,end.x);
    const top=Math.min(start.y,end.y);
    const width=Math.abs(end.x-start.x);
    const height=Math.abs(end.y-start.y);
    
    selectionOverlay.style.left=left+'px';
    selectionOverlay.style.top=top+'px';
    selectionOverlay.style.width=width+'px';
    selectionOverlay.style.height=height+'px';
  };
  
  const mousedown=(e)=>{
    if(e.target.closest('.cal-event')||e.target.closest('.cal-all-day-event'))return;
    isSelecting=true;
    startCell=getCellFromPoint(e.clientX,e.clientY);
    endCell=startCell;
    createSelectionOverlay(startCell,endCell);
    e.preventDefault();
  };
  
  const mousemove=(e)=>{
    if(!isSelecting)return;
    endCell=getCellFromPoint(e.clientX,e.clientY);
    createSelectionOverlay(startCell,endCell);
  };
  
  const mouseup=(e)=>{
    if(!isSelecting)return;
    isSelecting=false;
    
    if(startCell&&endCell&&startCell.dateStr&&endCell.dateStr){
      // Calculate date range from actual dates
      const startDay=new Date(startCell.dateStr);
      startDay.setHours(startCell.hour,startCell.minute,0,0);
      
      const endDay=new Date(endCell.dateStr);
      endDay.setHours(endCell.hour,endCell.minute,0,0);
      
      // Ensure start is before end
      let rangeStart=startDay;
      let rangeEnd=endDay;
      if(rangeStart>rangeEnd){
        const temp=rangeStart;
        rangeStart=rangeEnd;
        rangeEnd=temp;
      }
      
      selectedRanges.push({start:rangeStart,end:rangeEnd});
      highlightEventsInRanges();
    }
    
    if(selectionOverlay){
      selectionOverlay.style.display='none';
    }
  };
  
  const keydown=(e)=>{
    if(e.key==='Escape'){
      exitRangeSelection();
    }
  };
  
  grid.addEventListener('mousedown',mousedown);
  document.addEventListener('mousemove',mousemove);
  document.addEventListener('mouseup',mouseup);
  document.addEventListener('keydown',keydown);
  
  // Store handlers for cleanup
  grid._rangeSelectionHandlers={mousedown,mousemove,mouseup,keydown};
}

function setupEventSelection(){
  const allEvents=document.querySelectorAll('.cal-event,.cal-all-day-event');
  allEvents.forEach(eventEl=>{
    eventEl.style.cursor='pointer';
    const nodeId=eventEl.dataset.nodeId;
    if(!nodeId)return;
    
    const clickHandler=(e)=>{
      e.stopPropagation();
      const node=G.nodes.find(n=>n.id===nodeId);
      const isRoutine=node&&node.routine&&node.routineFrequency;
      
      if(selectedEventIds.has(nodeId)){
        // Deselect: remove from selection and remove highlights from all occurrences
        selectedEventIds.delete(nodeId);
        const allOccurrences=document.querySelectorAll(`[data-node-id="${nodeId}"]`);
        allOccurrences.forEach(occ=>occ.classList.remove('event-selected'));
      }else{
        // Select: add to selection and highlight all occurrences
        selectedEventIds.add(nodeId);
        const allOccurrences=document.querySelectorAll(`[data-node-id="${nodeId}"]`);
        allOccurrences.forEach(occ=>occ.classList.add('event-selected'));
        
        // If it's a routine event, show a brief message
        if(isRoutine){
          const count=allOccurrences.length;
          // Could show a tooltip or notification here if desired
        }
      }
    };
    
    eventEl.addEventListener('click',clickHandler);
    eventEl._eventSelectionHandler=clickHandler;
  });
  
  // Add escape handler
  const escapeHandler=(e)=>{
    if(e.key==='Escape'){
      exitEventSelection();
    }
  };
  document.addEventListener('keydown',escapeHandler);
  document._eventSelectionEscapeHandler=escapeHandler;
}

function highlightEventsInRanges(){
  // Remove existing range highlights
  document.querySelectorAll('.cal-event.range-selected,.cal-all-day-event.range-selected').forEach(el=>{
    el.classList.remove('range-selected');
  });
  
  // Highlight events in selected ranges
  G.nodes.forEach(node=>{
    if(!node.calendarDate)return;
    const eventDate=new Date(node.calendarDate);
    const eventEnd=new Date(eventDate.getTime()+(node.calendarDuration||60*60*1000));
    
    const inRange=selectedRanges.some(range=>{
      return(eventDate>=range.start&&eventDate<=range.end)||
            (eventEnd>=range.start&&eventEnd<=range.end)||
            (eventDate<=range.start&&eventEnd>=range.end);
    });
    
    if(inRange){
      const eventEl=document.querySelector(`[data-node-id="${node.id}"]`);
      if(eventEl){
        eventEl.classList.add('range-selected');
      }
    }
  });
}

function exitRangeSelection(){
  calendarExportMode=null;
  selectedRanges=[];
  document.body.style.cursor='';
  const btn=document.getElementById('calendar-export-btn');
  if(btn)btn.innerHTML='<span style="display:inline-block;width:8px;height:8px;background:#22c55e;border-radius:50%;margin-right:6px"></span>Export';
  const grid=document.getElementById('calendar-time-grid');
  if(grid&&grid._rangeSelectionHandlers){
    const h=grid._rangeSelectionHandlers;
    grid.removeEventListener('mousedown',h.mousedown);
    document.removeEventListener('mousemove',h.mousemove);
    document.removeEventListener('mouseup',h.mouseup);
    document.removeEventListener('keydown',h.keydown);
    delete grid._rangeSelectionHandlers;
  }
  document.querySelectorAll('.cal-event.range-selected,.cal-all-day-event.range-selected').forEach(el=>{
    el.classList.remove('range-selected');
  });
  const overlay=document.querySelector('#calendar-time-grid > div[style*="rgba(255,235,59"]');
  if(overlay)overlay.remove();
}

function exitEventSelection(){
  calendarExportMode=null;
  selectedEventIds.clear();
  const btn=document.getElementById('calendar-export-btn');
  if(btn)btn.innerHTML='<span style="display:inline-block;width:8px;height:8px;background:#22c55e;border-radius:50%;margin-right:6px"></span>Export';
  const allEvents=document.querySelectorAll('.cal-event,.cal-all-day-event');
  allEvents.forEach(eventEl=>{
    eventEl.style.cursor='';
    eventEl.classList.remove('event-selected');
    if(eventEl._eventSelectionHandler){
      eventEl.removeEventListener('click',eventEl._eventSelectionHandler);
      delete eventEl._eventSelectionHandler;
    }
  });
  if(document._eventSelectionEscapeHandler){
    document.removeEventListener('keydown',document._eventSelectionEscapeHandler);
    delete document._eventSelectionEscapeHandler;
  }
}

function exportSelectedRanges(){
  const events=G.nodes.filter(n=>{
    if(!n.calendarDate)return false;
    const eventDate=new Date(n.calendarDate);
    const eventEnd=new Date(eventDate.getTime()+(n.calendarDuration||60*60*1000));
    return selectedRanges.some(range=>{
      return(eventDate>=range.start&&eventDate<=range.end)||
            (eventEnd>=range.start&&eventEnd<=range.end)||
            (eventDate<=range.start&&eventEnd>=range.end);
    });
  });
  exportEventsToICS(events,'calendar-export-ranges.ics');
  exitRangeSelection();
}

function exportSelectedEvents(){
  const events=G.nodes.filter(n=>selectedEventIds.has(n.id));
  exportEventsToICS(events,'calendar-export-selected.ics');
  exitEventSelection();
}

function exportEventsToICS(events,filename){
  if(events.length===0){
    alert('No events to export.');
    return;
  }
  
  let icsContent='BEGIN:VCALENDAR\r\n';
  icsContent+='VERSION:2.0\r\n';
  icsContent+='PRODID:-//My Cosmos//Calendar Export//EN\r\n';
  icsContent+='CALSCALE:GREGORIAN\r\n';
  icsContent+='METHOD:PUBLISH\r\n';
  
  let totalExported=0;
  
  events.forEach(node=>{
    if(!node.calendarDate)return;
    const originalStartDate=new Date(node.calendarDate);
    const duration=node.calendarDuration||60*60*1000;
    const originalHour=originalStartDate.getHours();
    const originalMinute=originalStartDate.getMinutes();
    
    // Check if this is a routine event
    const isRoutine=node.routine&&node.routineFrequency;
    
    const startDate=originalStartDate;
    const endDate=new Date(startDate.getTime()+duration);
    
    icsContent+='BEGIN:VEVENT\r\n';
    icsContent+='UID:'+node.id+'@my-cosmos\r\n';
    icsContent+='DTSTART:'+formatICSDate(startDate)+'\r\n';
    icsContent+='DTEND:'+formatICSDate(endDate)+'\r\n';
    
    // Add RRULE for recurring events
    if(isRoutine){
      let rrule='RRULE:';
      if(node.routineFrequency==='daily'){
        rrule+='FREQ=DAILY';
      }else if(node.routineFrequency==='weekly'){
        rrule+='FREQ=WEEKLY;INTERVAL=1';
      }else if(node.routineFrequency==='biweekly'){
        rrule+='FREQ=WEEKLY;INTERVAL=2';
      }else if(node.routineFrequency==='monthly'){
        rrule+='FREQ=MONTHLY';
      }else if(node.routineFrequency==='2-5/week'){
        // For 2-5/week, use daily with BYDAY to approximate (or use WEEKLY with COUNT)
        // Since it's irregular, we'll use FREQ=DAILY with INTERVAL=3 as approximation
        rrule+='FREQ=DAILY;INTERVAL=3';
      }
      if(node.routineEndDate){
        // UNTIL bound so iCal importers honour an "all-future" split too.
        rrule+=';UNTIL='+formatICSDate(new Date(node.routineEndDate));
      }
      icsContent+=rrule+'\r\n';
    }
    
    icsContent+='SUMMARY:'+escapeICSValue(node.calendarDisplayName||node.name||'Untitled Event')+'\r\n';
    if(node.description){
      icsContent+='DESCRIPTION:'+escapeICSValue(node.description)+'\r\n';
    }
    if(node.location){
      icsContent+='LOCATION:'+escapeICSValue(node.location)+'\r\n';
    }
    if(node.link){
      icsContent+='URL:'+escapeICSValue(node.link)+'\r\n';
    }
    icsContent+='END:VEVENT\r\n';
    totalExported++;
  });
  
  icsContent+='END:VCALENDAR\r\n';
  
  // Download file
  const blob=new Blob([icsContent],{type:'text/calendar;charset=utf-8'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;
  a.download=filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  
  alert(`Exported ${totalExported} event${totalExported!==1?'s':''} to ${filename}`);
}

function formatICSDate(date){
  const year=date.getFullYear();
  const month=String(date.getMonth()+1).padStart(2,'0');
  const day=String(date.getDate()).padStart(2,'0');
  const hour=String(date.getHours()).padStart(2,'0');
  const minute=String(date.getMinutes()).padStart(2,'0');
  const second=String(date.getSeconds()).padStart(2,'0');
  return `${year}${month}${day}T${hour}${minute}${second}`;
}

function escapeICSValue(value){
  if(!value)return'';
  return value.toString()
    .replace(/\\/g,'\\\\')
    .replace(/;/g,'\\;')
    .replace(/,/g,'\\,')
    .replace(/\n/g,'\\n');
}

function expandCalendarEvent(nodeId,eventEl){
  // Toggle expanded state
  if(calendarExpandedEvent===nodeId){
    eventEl.classList.remove('expanded');
    calendarExpandedEvent=null;
  }else{
    // Close any other expanded event
    document.querySelectorAll('.cal-event.expanded').forEach(el=>el.classList.remove('expanded'));
    eventEl.classList.add('expanded');
    calendarExpandedEvent=nodeId;
    // Click outside to close
    setTimeout(()=>{
      const closeHandler=(e)=>{
        if(!eventEl.contains(e.target)){
          eventEl.classList.remove('expanded');
          calendarExpandedEvent=null;
          document.removeEventListener('click',closeHandler);
        }
      };
      document.addEventListener('click',closeHandler);
    },10);
  }
  // Option to edit
  const node=G.nodes.find(n=>n.id===nodeId);
  if(node){
    if(!eventEl.querySelector('.cal-event-edit')){
      const editDiv=document.createElement('div');
      editDiv.className='cal-event-edit';
      const editBtn=document.createElement('button');
      editBtn.textContent='Edit';
      editBtn.className='btn btn-sm';
      editBtn.style.marginTop='4px';
      editBtn.onclick=(e)=>{
        e.stopPropagation();
        openEdit(nodeId);
        eventEl.classList.remove('expanded');
        calendarExpandedEvent=null;
      };
      editDiv.appendChild(editBtn);
      eventEl.appendChild(editDiv);
    }
  }
}

