function openEditCalendarEvent(id,occurrenceDateOpt){
  const n=G.nodes.find(x=>x.id===id);
  if(!n)return;
  editId=id;
  // When editing a routine occurrence from the calendar grid, pass the occurrence date so "Only this event" applies to the correct date
  editCalendarOccurrenceDate=(occurrenceDateOpt!=null)?(typeof occurrenceDateOpt==='string'?occurrenceDateOpt:occurrenceDateOpt.toISOString()):null;
  document.getElementById('cal-ev-t').textContent='Edit Calendar Event';
  document.getElementById('cal-ev-save-btn').textContent='Save Event';
  document.getElementById('cal-ev-title').value=n.name;
  // Build category dropdown: all task nodes sorted hierarchically (level1, then level2 by level1, etc.)
  const categoryOptions='<option value="">— Select category —</option>'+getCategoryOptionsSorted(isTaskNode,null).map(n=>{
    const path=nPath(n.id);
    const pathStr=path.map(x=>x.name).join(' › ');
    return `<option value="${n.id}">${esc(pathStr)}</option>`;
  }).join('');
  document.getElementById('cal-ev-cat').innerHTML=categoryOptions;
  // Set selected category - use the direct parent (last in calendarCategories chain) or parentId
  let selectedCategoryId='';
  if(n.calendarCategories&&n.calendarCategories.length>0){
    // Use the last category in the chain (the direct parent)
    selectedCategoryId=n.calendarCategories[n.calendarCategories.length-1];
  }else if(n.parentId){
    // Fallback to parentId
    selectedCategoryId=n.parentId;
  }
  document.getElementById('cal-ev-cat').value=selectedCategoryId;
  // Set start/end times: for routine occurrence use the passed occurrence date so form shows the slot we're editing
  let startDate,endDate;
  if(n.routine&&editCalendarOccurrenceDate){
    startDate=new Date(editCalendarOccurrenceDate);
    const duration=n.calendarDuration||(n.timer&&n.timer.duration)||60*60*1000;
    endDate=new Date(startDate.getTime()+duration);
  }else if(n.timer&&n.timer.startTime){
    startDate=new Date(n.timer.startTime);
    endDate=n.timer.endTime?new Date(n.timer.endTime):new Date(startDate.getTime()+60*60*1000);
  }else if(n.calendarDate){
    startDate=new Date(n.calendarDate);
    endDate=new Date(startDate.getTime()+60*60*1000);
  }else{
    startDate=new Date();
    endDate=new Date(startDate.getTime()+60*60*1000);
  }
  const year=startDate.getFullYear();
  const month=String(startDate.getMonth()+1).padStart(2,'0');
  const day=String(startDate.getDate()).padStart(2,'0');
  const hours=String(startDate.getHours()).padStart(2,'0');
  const minutes=String(startDate.getMinutes()).padStart(2,'0');
  document.getElementById('cal-ev-start').value=`${year}-${month}-${day}T${hours}:${minutes}`;
  const endYear=endDate.getFullYear();
  const endMonth=String(endDate.getMonth()+1).padStart(2,'0');
  const endDay=String(endDate.getDate()).padStart(2,'0');
  const endHours=String(endDate.getHours()).padStart(2,'0');
  const endMinutes=String(endDate.getMinutes()).padStart(2,'0');
  document.getElementById('cal-ev-end').value=`${endYear}-${endMonth}-${endDay}T${endHours}:${endMinutes}`;
  document.getElementById('cal-ev-loc').value=n.location||'';
  document.getElementById('cal-ev-link').value=n.link||'';
  // Set repeat based on routineFrequency if routine is true, otherwise use repeat property
  if(n.routine&&n.routineFrequency){
    // Map routineFrequency to repeat
    const freqToRepeat={'weekly':'weekly','biweekly':'biweekly','monthly':'monthly','daily':'weekly','2-5/week':'weekly'};
    document.getElementById('cal-ev-repeat').value=freqToRepeat[n.routineFrequency]||n.repeat||'none';
  }else{
    document.getElementById('cal-ev-repeat').value=n.repeat||'none';
  }
  document.getElementById('cal-ev-routine').checked=n.routine||false;
  document.getElementById('cal-ev-routine-freq').value=n.routineFrequency||'daily';
  document.getElementById('cal-ev-routine-freq-div').style.display=(n.routine||false)?'block':'none';
  document.getElementById('cal-ev-priority').checked=n.priority||false;
  document.getElementById('cal-ev-buffer').checked=n.buffer||false;
  const tbdChecked=(n.TBD&&n.TBD!=='none')||false;
  document.getElementById('cal-ev-tbd').checked=tbdChecked;
  const calNahEl=document.getElementById('cal-ev-nah');
  if(calNahEl)calNahEl.checked=!!n.nah;
  // Handle TBD state - show "???" if TBD is checked
  if(tbdChecked){
    // TBD is checked - show "???" in time fields
    const startInput=document.getElementById('cal-ev-start');
    const endInput=document.getElementById('cal-ev-end');
    if(startInput){
      startInput.type='text';
      startInput.value='???';
      startInput.disabled=true;
      startInput.style.opacity='0.6';
      startInput.style.cursor='not-allowed';
    }
    if(endInput){
      endInput.type='text';
      endInput.value='???';
      endInput.disabled=true;
      endInput.style.opacity='0.6';
      endInput.style.cursor='not-allowed';
    }
  }else{
    // TBD is not checked - show actual times
    const startInput=document.getElementById('cal-ev-start');
    const endInput=document.getElementById('cal-ev-end');
    if(startInput){
      startInput.type='datetime-local';
      startInput.disabled=false;
      startInput.style.opacity='1';
      startInput.style.cursor='';
    }
    if(endInput){
      endInput.type='datetime-local';
      endInput.disabled=false;
      endInput.style.opacity='1';
      endInput.style.cursor='';
    }
  }
  const eventType=n.type||getDefaultTypeFromTitle(n.name);
  document.getElementById('cal-ev-type').value=eventType;
  if(eventType==='input'&&n.typeInput){
    document.getElementById('cal-ev-type-input').value=n.typeInput;
    document.getElementById('cal-ev-type-input-div').style.display='block';
  }else{
    document.getElementById('cal-ev-type-input').value='';
    document.getElementById('cal-ev-type-input-div').style.display='none';
  }
  const editCalendarEventDateKey=startDate?startDate.toISOString().split('T')[0]:null;
  document.getElementById('cal-ev-notes').value=getDescriptionContentForNode(n,editCalendarEventDateKey)||'';
  document.getElementById('cal-ev-post-notes').value=getNoteContentForNode(n,editCalendarEventDateKey)||'';
  document.getElementById('cal-ev-post-notes').dataset.editDateKey=editCalendarEventDateKey||'';
  document.getElementById('m-cal-event').classList.add('open');
  setupModalKeyboardNavigation('m-cal-event');
  setTimeout(()=>{
    const titleInput=document.getElementById('cal-ev-title');
    titleInput.focus();
  },100);
  clearCalEvDatetimeInputs();
}

function saveCalendarEvent(){
  const title=document.getElementById('cal-ev-title').value.trim();
  if(!title){
    alert('Title is required');
    return;
  }
  const categoryId=document.getElementById('cal-ev-cat').value;
  const startStr=document.getElementById('cal-ev-start').value;
  const endStr=document.getElementById('cal-ev-end').value;
  const location=document.getElementById('cal-ev-loc').value.trim();
  const link=document.getElementById('cal-ev-link').value.trim();
  const repeat=document.getElementById('cal-ev-repeat').value;
  const routine=document.getElementById('cal-ev-routine').checked||false;
  const routineFrequency=document.getElementById('cal-ev-routine-freq').value||null;
  const priority=document.getElementById('cal-ev-priority').checked||false;
  const buffer=document.getElementById('cal-ev-buffer').checked||false;
  const tbdChecked=document.getElementById('cal-ev-tbd').checked||false;
  const nahEl=document.getElementById('cal-ev-nah');
  const nahChecked=nahEl?!!nahEl.checked:false;
  const typeValue=document.getElementById('cal-ev-type').value;
  const type=typeValue==='input'?document.getElementById('cal-ev-type-input').value.trim()||'task':typeValue;
  const typeInput=typeValue==='input'?document.getElementById('cal-ev-type-input').value.trim():null;
  const notes=document.getElementById('cal-ev-notes').value.trim();
  const postEventNotes=document.getElementById('cal-ev-post-notes').value.trim();
  const editDateKey=document.getElementById('cal-ev-post-notes').dataset.editDateKey||null;
  
  // Handle TBD case - if TBD is checked and times show "???", don't parse them
  let startDate,endDate,duration;
  if(tbdChecked&&(startStr==='???'||endStr==='???')){
    // TBD is checked - use existing calendarDate if editing, or set default if new
    if(editId){
      const node=G.nodes.find(n=>n.id===editId);
      if(node&&node.calendarDate){
        startDate=new Date(node.calendarDate);
        endDate=node.calendarDuration?new Date(startDate.getTime()+node.calendarDuration):new Date(startDate.getTime()+60*60*1000);
        duration=endDate.getTime()-startDate.getTime();
      }else{
        // No existing date, use default (9 AM today)
        const now=new Date();
        startDate=new Date(now);
        startDate.setHours(9,0,0,0);
        endDate=new Date(startDate.getTime()+60*60*1000);
        duration=60*60*1000;
      }
    }else{
      // New event with TBD - use default (9 AM today)
      const now=new Date();
      startDate=new Date(now);
      startDate.setHours(9,0,0,0);
      endDate=new Date(startDate.getTime()+60*60*1000);
      duration=60*60*1000;
    }
  }else{
    // Normal case - parse the times
    startDate=startStr&&startStr!=='???'?new Date(startStr):new Date();
    endDate=endStr&&endStr!=='???'?new Date(endStr):new Date(startDate.getTime()+60*60*1000);
    duration=endDate.getTime()-startDate.getTime();
  }
  
  if(editId){
    // Edit existing event
    const node=G.nodes.find(n=>n.id===editId);
    if(node){
      // Check if this is a routine event being edited
      if(node.routine&&node.routineFrequency&&node.calendarDate){
        // Use the occurrence date we're editing (set when opening from calendar grid); otherwise fall back to node.calendarDate
        const originalDate=editCalendarOccurrenceDate?new Date(editCalendarOccurrenceDate):new Date(node.calendarDate);
        // If the ONLY change is to the note/description, save it to THIS occurrence alone
        // (per-date) and skip the "this / all future" prompt entirely — notes are inherently
        // per-occurrence (different weeks of the same routine can have different notes).
        const occKey=originalDate.toISOString().split('T')[0];
        const occDuration=(node.routineTimeOverrides&&node.routineTimeOverrides[occKey]&&node.routineTimeOverrides[occKey].duration)||node.calendarDuration||(node.timer&&node.timer.duration)||60*60*1000;
        const occEndDate=new Date(originalDate.getTime()+occDuration);
        const isNoteOnlyOccurrenceEdit=
          title===node.name&&
          (categoryId||null)===(node.parentId||null)&&
          (location||'')===(node.location||'')&&
          (link||'')===(node.link||'')&&
          (repeat||'none')===(node.repeat||'none')&&
          routine===!!node.routine&&
          (routine?routineFrequency:null)===(node.routine?node.routineFrequency:null)&&
          priority===!!node.priority&&
          buffer===!!node.buffer&&
          (type||node.type||'task')===(node.type||'task')&&
          (typeInput||null)===(node.typeInput||null)&&
          tbdChecked===!!(node.TBD&&node.TBD!=='none')&&
          nahChecked===!!node.nah&&
          startDate.getTime()===originalDate.getTime()&&
          endDate.getTime()===occEndDate.getTime();
        if(isNoteOnlyOccurrenceEdit){
          saveState();
          setDescriptionContentForNode(node,occKey,notes||'');
          setNoteContentForNode(node,occKey,postEventNotes||'');
          editCalendarOccurrenceDate=null;
          sv();
          render();
          rPanel();
          renderTodoList();
          if(currentView==='notes'){renderNotes();}
          clMo('m-cal-event');
          if(currentView==='calendar'){
            const sc=document.getElementById('calendar-scroll-container');
            if(sc){calendarScrollLeft=sc.scrollLeft;calendarScrollTop=sc.scrollTop;}
            calendarCenterOnAnchorNextRender=false;
            calendarPreserveFromNotesOpen=false;
            renderCalendar();
            setTimeout(()=>renderTBDMicroTabs(),100);
          }
          return;
        }
        // Store edit data in pendingRoutineAction
        pendingRoutineAction={
          action:'edit',
          nodeId:editId,
          occurrenceDate:originalDate,
          editData:{
            title,startDate,endDate,duration,categoryId,location,link,repeat,routine,routineFrequency,priority,buffer,notes,postEventNotes,type,typeInput,tbdChecked,nahChecked
          }
        };
        editCalendarOccurrenceDate=null;
        // Show modal
        const modal=document.getElementById('m-routine-action');
        const titleEl=document.getElementById('routine-action-title');
        const messageEl=document.getElementById('routine-action-message');
        titleEl.textContent='Edit Routine Event';
        messageEl.textContent='This is a repeating event. What would you like to do?';
        modal.classList.add('open');
        setupModalKeyboardNavigation('m-routine-action');
        clMo('m-cal-event'); // Close the edit modal
        return; // Wait for user to choose (handleRoutineAction persists after applying)
      }
      saveState();
      node.name=title;
      node.description=notes||'';
      setNoteContentForNode(node,editDateKey||undefined,postEventNotes||'');
      node.location=location||'';
      node.link=link||'';
      node.repeat=repeat||'none';
      // Update parentId and calendarCategories based on selected category
      // The selected category becomes the direct parent
      node.parentId=categoryId||null;
      // Update calendarCategories to store full parent chain from selected category to root
      // This is the coordinate system: [root, parent1, parent2, ..., selectedCategory]
      // This represents the full hierarchy: mother, grandmother, etc. up to top level
      if(categoryId){
        const categoryPath=nPath(categoryId);
        // Store all parent IDs (full chain from root to selected category)
        node.calendarCategories=categoryPath.map(n=>n.id);
      }else{
        // No category selected - clear calendarCategories
        delete node.calendarCategories;
      }
      // Update calendarDisplayName to reflect the full category chain
      // Helper function to create detailed display name: "task content, nested node, category, ..."
      const createDetailedDisplayName=(nodeId)=>{
        const fullPath=nPath(nodeId);
        if(fullPath.length===0)return '';
        // Reverse the path so task is first, then parents in reverse order
        const reversedPath=[...fullPath].reverse();
        // Join with commas: "task name, parent1, parent2, ..."
        return reversedPath.map(n=>n.name).join(', ');
      };
      node.calendarDisplayName=createDetailedDisplayName(editId);
      // Set routine, priority, buffer properties
      node.routine=routine;
      node.routineFrequency=routine?routineFrequency:null;
      // If repeat is set but routine is not explicitly checked, set routine based on repeat
      if(repeat&&repeat!=='none'&&!routine){
        node.routine=true;
        node.routineFrequency=repeat==='weekly'?'weekly':repeat==='biweekly'?'biweekly':repeat==='monthly'?'monthly':'daily';
      }
      node.priority=priority;
      node.buffer=buffer;
      node.nah=nahChecked;
      node.type=type;
      if(typeInput)node.typeInput=typeInput;else delete node.typeInput;
      node.calendarDate=startDate.toISOString();
      // Handle TBD checkbox
      if(tbdChecked){
        node.TBD=startDate.toISOString();
      }else{
        node.TBD='none';
      }
      if(duration>0){
        node.timer={startTime:startDate.toISOString(),endTime:endDate.toISOString(),duration:duration,remaining:duration};
        node.calendarDuration=duration;
      }
      // Update edges
      const oldEdge=G.edges.find(e=>eI(e.target)===editId);
      if(oldEdge&&oldEdge.source!==categoryId){
        G.edges=G.edges.filter(e=>!(eI(e.target)===editId));
        if(categoryId)G.edges.push({source:categoryId,target:editId});
      }else if(categoryId&&!oldEdge){
        G.edges.push({source:categoryId,target:editId});
      }
      sv();
      render();
      rPanel();
      // Refresh todo list to show updated properties
      renderTodoList();
      // Refresh notes view if it's open
      if(currentView==='notes'){
        renderNotes();
      }
      clMo('m-cal-event');
      if(currentView==='calendar'){
        const scrollContainer=document.getElementById('calendar-scroll-container');
        if(scrollContainer){
          calendarScrollLeft=scrollContainer.scrollLeft;
          calendarScrollTop=scrollContainer.scrollTop;
        }
        calendarCenterOnAnchorNextRender=false;
        calendarPreserveFromNotesOpen=false;
        renderCalendar();
        setTimeout(()=>renderTBDMicroTabs(),100);
      }
    }
  }else{
    // Create new event (allows multiple events with the same name in the same category/type per week)
    saveState();
    const id='n'+Date.now();
    // Determine routine status: explicit checkbox OR if repeat is set
    const isRoutine=routine||(repeat&&repeat!=='none');
    const finalRoutineFreq=isRoutine?(routine?routineFrequency:(repeat==='weekly'?'weekly':repeat==='biweekly'?'biweekly':repeat==='monthly'?'monthly':'daily')):null;
    const defaultType=getDefaultTypeFromTitle(title);
    const finalType=type||defaultType;
    const node={id,name:title,color:P[G.nodes.length%P.length],description:notes||'',status:'active',parentId:categoryId||null,wsId:G.cws||'home',progress:[],calendarDate:startDate.toISOString(),location:location||'',link:link||'',repeat:repeat||'none',routine:isRoutine,routineFrequency:finalRoutineFreq,priority:priority,buffer:buffer,nah:nahChecked,TBD:tbdChecked?startDate.toISOString():'none',type:finalType};
    if(editDateKey){ if(!node.postEventNotesByDate)node.postEventNotesByDate={}; node.postEventNotesByDate[editDateKey]=postEventNotes||''; }else{ node.postEventNotes=postEventNotes||''; }
    if(typeInput)node.typeInput=typeInput;
    // Set calendarCategories to store full parent chain from selected category to root
    // This is the coordinate system: [root, parent1, parent2, ..., selectedCategory]
    // This represents the full hierarchy: mother, grandmother, etc. up to top level
    if(categoryId){
      const categoryPath=nPath(categoryId);
      // Store all parent IDs (full chain from root to selected category)
      node.calendarCategories=categoryPath.map(n=>n.id);
    }
  if(duration>0){
    node.timer={startTime:startDate.toISOString(),endTime:endDate.toISOString(),duration:duration,remaining:duration};
    node.calendarDuration=duration;
  }
  G.nodes.push(node);
  // Set calendarDisplayName to reflect the full category chain
  // For new events, construct from category path + event name
  if(categoryId){
    const categoryPath=nPath(categoryId);
    // Build display name: "event name, category, parent category, ..." (reversed)
    const categoryNames=categoryPath.map(n=>n.name).reverse();
    node.calendarDisplayName=[title,...categoryNames].join(', ');
  }else{
    node.calendarDisplayName=title;
  }
  if(categoryId)G.edges.push({source:categoryId,target:id});
  
  sv();
  // Routine tasks appear on calendar at multiple dates but only have ONE node in the network
  // They use routineFrequency, not createRecurringEvents
  // createRecurringEvents is only for non-routine repeating events
  render();
  rPanel();
  // Refresh todo list to show updated properties
  renderTodoList();
  // Refresh notes view if it's open
  if(currentView==='notes'){
    renderNotes();
  }
  clMo('m-cal-event');
  if(currentView==='calendar'){
    // Preserve scroll position when re-rendering after adding event
    const scrollContainer=document.getElementById('calendar-scroll-container');
    if(scrollContainer){
      calendarScrollLeft=scrollContainer.scrollLeft;
      calendarScrollTop=scrollContainer.scrollTop;
    }
    calendarCenterOnAnchorNextRender=false;
    calendarPreserveFromNotesOpen=false;
    renderCalendar();
    setTimeout(()=>renderTBDMicroTabs(),100);
  }
  }
}

// Function to create recurring events
function createRecurringEvents(originalNode,repeat,startDate,endDate,duration,categoryId,notes,location,link){
  const maxDate=new Date();
  maxDate.setFullYear(maxDate.getFullYear()+1); // Create events up to 1 year ahead
  
  let currentStart=new Date(startDate);
  let currentEnd=new Date(endDate);
  
  // Create recurring events starting from the next occurrence (after the original)
  while(currentStart<maxDate){
    // Move to next occurrence
    if(repeat==='weekly'){
      currentStart.setDate(currentStart.getDate()+7);
      currentEnd.setDate(currentEnd.getDate()+7);
    }else if(repeat==='biweekly'){
      currentStart.setDate(currentStart.getDate()+14);
      currentEnd.setDate(currentEnd.getDate()+14);
    }else if(repeat==='monthly'){
      currentStart.setMonth(currentStart.getMonth()+1);
      currentEnd.setMonth(currentEnd.getMonth()+1);
    }else{
      break;
    }
    
    if(currentStart>maxDate)break;
    
    const recurringId='n'+Date.now()+'_'+Math.random().toString(36).slice(2,9);
    const recurringNode={id:recurringId,name:originalNode.name,color:originalNode.color,description:notes||'',status:'active',parentId:categoryId||null,wsId:G.cws||'home',progress:[],notes:notes||'',calendarDate:currentStart.toISOString(),location:location||'',link:link||'',repeat:repeat,originalEventId:originalNode.id,routine:originalNode.routine||false,routineFrequency:originalNode.routineFrequency||null,priority:originalNode.priority||false,buffer:originalNode.buffer||false,type:originalNode.type,typeInput:originalNode.typeInput};
    if(duration>0){
      recurringNode.timer={startTime:currentStart.toISOString(),endTime:currentEnd.toISOString(),duration:duration,remaining:duration};
      recurringNode.calendarDuration=duration;
    }
    G.nodes.push(recurringNode);
    if(categoryId)G.edges.push({source:categoryId,target:recurringId});
  }
}

