/* ── Workspaces ── */
function bldWS(){document.getElementById('ls-ws').innerHTML=G.workspaces.filter(w=>w.id!=='home').map(w=>`<div class="lt ${w.id===G.cws?'on':''}" onclick="swWS('${w.id}')" title="${esc(w.name)}">${w.icon||'📁'}<span class="tip">${esc(w.name)}</span></div>`).join('');document.getElementById('lt-home').classList.toggle('on',G.cws==='home'&&currentView==='home')}
function swWS(id){G.cws=id;viewStack=[];expandedId=null;rpLevel=0;bldWS();sv();render();updBC();rPanel();if(currentView==='pagetree')renderPageTree();}
function addWS(){document.getElementById('ws-n').value='';document.getElementById('ws-i').value='📁';document.getElementById('m-ws').classList.add('open');setupModalKeyboardNavigation('m-ws');setTimeout(()=>document.getElementById('ws-n').focus(),100)}
function saveWS(){const n=document.getElementById('ws-n').value.trim();if(!n)return;svWithUndo();const id='ws'+Date.now();G.workspaces.push({id,name:n,icon:document.getElementById('ws-i').value||'📁'});G.cws=id;sv();bldWS();viewStack=[];expandedId=null;render();updBC();clMo('m-ws')}

/* ── Undo/Redo ── */
let undoStack=[],redoStack=[],maxUndo=10;
function saveState(){
  if(undoStack.length>=maxUndo)undoStack.shift();
  try{
    undoStack.push(JSON.parse(JSON.stringify(G)));
  }catch(e){
    console.warn('Undo snapshot skipped (graph clone failed, often due to very large embedded assets)',e);
  }
  redoStack=[];
  updateUndoRedoButtons();
}
function doUndo(){
  if(undoStack.length===0)return;
  redoStack.push(JSON.parse(JSON.stringify(G)));
  if(redoStack.length>maxUndo)redoStack.shift();
  G=undoStack.pop();
  dirtyNodeMap();
  syncTodoStateFromGraph();
  try{localStorage.setItem('todayTodos',JSON.stringify(todayTodos));}catch(e){}
  updateUndoRedoButtons();
  render();rPanel();updBC();
  renderTodoList();
  if(currentView==='calendar'){renderCalendar();setTimeout(()=>renderTBDMicroTabs(),100);}
  if(currentView==='notes'){ renderNotes(); refreshNotesEditorContent(); }
  if(currentView==='pagetree')renderPageTree();
  if(G.autoSave)ST.save(CU,G);
}
function doRedo(){
  if(redoStack.length===0)return;
  undoStack.push(JSON.parse(JSON.stringify(G)));
  if(undoStack.length>maxUndo)undoStack.shift();
  G=redoStack.pop();
  dirtyNodeMap();
  syncTodoStateFromGraph();
  try{localStorage.setItem('todayTodos',JSON.stringify(todayTodos));}catch(e){}
  updateUndoRedoButtons();
  render();rPanel();updBC();
  renderTodoList();
  if(currentView==='calendar'){renderCalendar();setTimeout(()=>renderTBDMicroTabs(),100);}
  if(currentView==='notes'){ renderNotes(); refreshNotesEditorContent(); }
  if(currentView==='pagetree')renderPageTree();
  if(G.autoSave)ST.save(CU,G);
}
function refreshNotesEditorContent(){
  const editorEl=document.getElementById('notes-editor-content');
  const editor=document.getElementById('notes-editor');
  if(!editorEl||!editor||editor.style.display==='none'||!currentNoteId)return;
  const n=G.nodes.find(x=>x.id===currentNoteId);
  if(!n)return;
  const content=getNoteContentForNode(n,currentNoteDateKey)||'';
  editorEl.innerHTML=content.trim()||'<p><br></p>';
}
function updateUndoRedoButtons(){
  document.getElementById('tb-undo').disabled=undoStack.length===0;
  document.getElementById('tb-redo').disabled=redoStack.length===0;
  const notesUndo=document.getElementById('notes-undo');
  const notesRedo=document.getElementById('notes-redo');
  if(notesUndo)notesUndo.disabled=undoStack.length===0;
  if(notesRedo)notesRedo.disabled=redoStack.length===0;
}

/* ── Copy/Paste ── */
function copyNode(){
  let nodeToCopy=null;
  // Priority: selected node > node under cursor > node selector
  if(currentView==='home'){
    if(nodeSelectorId){
      nodeToCopy=G.nodes.find(n=>n.id===nodeSelectorId);
    }else if(nodeUnderCursor){
      nodeToCopy=G.nodes.find(n=>n.id===nodeUnderCursor);
    }
  }else if(currentView==='calendar'){
    // For calendar, check if there's a currently edited event
    if(editId){
      nodeToCopy=G.nodes.find(n=>n.id===editId);
    }
    // If not editing, check for expanded event
    if(!nodeToCopy&&calendarExpandedEvent){
      nodeToCopy=G.nodes.find(n=>n.id===calendarExpandedEvent);
    }
    // If still not found, try to find event under cursor (hover state)
    if(!nodeToCopy){
      const hoveredEvent=document.querySelector('.cal-event:hover');
      if(hoveredEvent){
        const eventNodeId=hoveredEvent.dataset.nodeId;
        if(eventNodeId){
          nodeToCopy=G.nodes.find(n=>n.id===eventNodeId);
        }
      }
    }
  }
  if(nodeToCopy){
    // Deep copy the node data, excluding ID and parentId (will be regenerated on paste)
    copiedNodeData=JSON.parse(JSON.stringify(nodeToCopy));
    // Store the type so we know if it's a calendar event
    copiedNodeData._isCalendarEvent=!!(nodeToCopy.calendarDate||nodeToCopy.timer);
  }
}
function pasteNode(){
  if(!copiedNodeData)return;
  svWithUndo();
  // Generate new ID
  const newId='n'+Date.now()+'_'+Math.random().toString(36).slice(2,9);
  // Create new node from copied data
  const newNode={...copiedNodeData};
  newNode.id=newId;
  // Remove the temporary flag
  delete newNode._isCalendarEvent;
  // Reset some properties that shouldn't be copied
  newNode.sphereOpen=false;
  // For calendar events, adjust the date/time
  if(newNode.calendarDate){
    const oldDate=new Date(newNode.calendarDate);
    const duration=newNode.timer?newNode.timer.duration:60*60*1000;
    // Set to current time (or next hour)
    const now=new Date();
    const newStart=new Date(now.getFullYear(),now.getMonth(),now.getDate(),now.getHours()+1,0,0);
    newNode.calendarDate=newStart.toISOString();
    if(newNode.timer){
      newNode.timer.startTime=newStart.toISOString();
      newNode.timer.endTime=new Date(newStart.getTime()+duration).toISOString();
    }
  }
  // For home page nodes, set parent to current context
  if(currentView==='home'&&!newNode.calendarDate){
    // Set parent to current expanded node or root
    newNode.parentId=expandedId||null;
  }
  // Add node to graph
  G.nodes.push(newNode);
  // Add edge if there's a parent
  if(newNode.parentId){
    G.edges.push({source:newNode.parentId,target:newId});
  }
  sv();
  render();
  rPanel();
  if(currentView==='calendar')renderCalendar();
  updBC();
}

/* ── Save ── */
function togAS(){G.autoSave=!G.autoSave;document.getElementById('tb-as').classList.toggle('on',G.autoSave);ST.save(CU,G)}
function togPriority(){
  priorityVisible=!priorityVisible;
  const btn=document.getElementById('tb-priority');
  if(btn){
    btn.classList.toggle('on',priorityVisible);
  }
  // Clean up any existing priority classes from calendar if turning off
  if(!priorityVisible){
    const grid=document.getElementById('calendar-time-grid');
    if(grid){
      grid.querySelectorAll('.cal-event.priority-future,.cal-all-day-event.priority-future').forEach(event=>{
        event.classList.remove('priority-future');
      });
      grid.querySelectorAll('.cal-day-column.has-priority-future').forEach(dayCol=>{
        dayCol.classList.remove('has-priority-future');
      });
    }
  }
  render();
  if(typeof renderCalendar==='function')renderCalendar();
}

function toggleShowByDropdown(event){
  event.stopPropagation();
  const menu=document.getElementById('tb-showby-menu');
  const isShowing=menu.classList.contains('show');
  
  // Close other dropdowns
  document.querySelectorAll('.tb-showby-menu.show').forEach(m=>m.classList.remove('show'));
  
  if(!isShowing){
    menu.classList.add('show');
    populateShowByCategories();
    // Close on outside click
    setTimeout(()=>{
      const closeDropdown=(e)=>{
        if(!menu.contains(e.target)&&!e.target.closest('.tb-showby-btn')){
          menu.classList.remove('show');
          document.removeEventListener('click',closeDropdown);
        }
      };
      document.addEventListener('click',closeDropdown);
    },10);
  }
}

function populateShowByCategories(){
  const catContainer=document.getElementById('tb-showby-categories');
  if(!catContainer)return;
  
  // Get only level 1 task nodes (categories with no parent)
  const rootCategories=G.nodes.filter(n=>!n.parentId&&isTaskNode(n));
  
  // Build HTML - only level 1 categories
  let html='';
  rootCategories.sort((a,b)=>a.name.localeCompare(b.name)).forEach(cat=>{
    const isActive=showByFilter===cat.id;
    html+=`<div class="tb-showby-option ${isActive?'active':''}" onclick="setShowByFilter('${cat.id}')" data-filter="${cat.id}">${esc(cat.name)}</div>`;
  });
  
  catContainer.innerHTML=html;
  
  // Also update the "All" option active state
  const allOption=document.querySelector('.tb-showby-option[data-filter=""]');
  if(allOption){
    allOption.classList.toggle('active',!showByFilter);
  }
}

function setShowByFilter(filter){
  // Update filter (null or empty string means no filter)
  showByFilter=filter||null;
  
  // Update UI
  document.querySelectorAll('.tb-showby-option').forEach(opt=>{
    opt.classList.remove('active');
    const filterValue=filter||'';
    if(opt.dataset.filter===filterValue){
      opt.classList.add('active');
    }
  });
  
  // Update container appearance and button active states
  const container=document.querySelector('.tb-showby-container');
  const showByBtn=document.getElementById('tb-showby-btn');
  const bringEdgesBtn=document.getElementById('tb-bring-edges-btn');
  
  // Update show by button active state
  if(showByBtn){
    if(showByFilter){
      showByBtn.style.color='var(--acc)';
      showByBtn.classList.add('active');
    }else{
      showByBtn.style.color='var(--t2)';
      showByBtn.classList.remove('active');
    }
  }
  
  // Update bring edges button active state
  if(bringEdgesBtn){
    if(bringEdgesEnabled){
      bringEdgesBtn.style.color='var(--acc)';
      bringEdgesBtn.classList.add('active');
    }else{
      bringEdgesBtn.style.color='var(--t2)';
      bringEdgesBtn.classList.remove('active');
    }
  }
  
  // Update container appearance (active if either filter is enabled)
  if(container){
    if(showByFilter||bringEdgesEnabled){
      container.style.borderColor='var(--acc)';
      container.style.background='var(--accbg)';
    }else{
      container.style.borderColor='var(--bdr)';
      container.style.background='var(--bg2)';
    }
  }
  
  // Close dropdown
  document.getElementById('tb-showby-menu').classList.remove('show');
  
  // Re-render based on current view
  if(currentView==='home'){
    render();
    rPanel();
  }else if(currentView==='calendar'){
    renderCalendar();
    setTimeout(()=>renderTBDMicroTabs(),100);
  }else if(currentView==='notes'){
    renderNotes();
  }else if(currentView==='progress'){
    renderProgress();
  }else if(currentView==='pathbehind'){
    renderPathBehind();
  }else if(currentView==='pagetree'){
    renderPageTree();
  }
}

